INSERT INTO `berita` VALUES (3,'Dinas Kominfosta Kota Sungai Penuh, ASN Dan Non ASN Kominfosta Kota Sungai Penuh Takziah Kerumah Almarhum BUYA NOVERI SAPTA, SHi.','<div>SUNGAI PENUH -Dinas Kominfosta Kota Sungai Penuh, ASN Dan Non ASN Kominfosta Kota Sungai Penuh Takziah Kerumah Almarhum BUYA NOVERI SAPTA, SHi. Adik Dari Pak Kadis kominfosta.<br>Semoga almarhum diampuni seluruh kesalahannya serta diterima semua amal ibadahnya oleh Allah. Semoga keluarga yang ditinggalkan juga diberikan ketabahan, kesabaran dan kekuatan untuk menghadapi cobaan ini. Aamiin.</div>','upload/berita/shwkEoUkeWHg6EGHyLsTLjGO4Hyt9ko0VJwF1LLq.png','rahmatrefo','dinas-kominfosta-kota-sungai-penuh-asn-dan-non-asn-kominfosta-kota-sungai-penuh-takziah-kerumah-almarhum-buya-noveri-sapta-shi','2023-08-01 09:54:40','2023-08-01 09:54:40'),(5,'Diskominfosta Sungai Penuh, Gotong Royong Bersama,','<div>SUNGAI PENUH -Jalan Pancasila Simpang Raya.<br>Diskominfosta Sungai Penuh, Gotong Royong Bersama,<br>Dalam Rangka Menyambut Hari Kemerdekaan Republik Indonesia Yang ke 78.</div>','upload/berita/bCG5x9oP5tGeMgZ9WLdPqukuMnQjPNFUEw61a2hx.png','rahmatrefo','diskominfosta-sungai-penuh-gotong-royong-bersama','2023-08-01 10:28:04','2023-08-01 10:28:04'),(6,'Diskominfosta  Kota Sungai Penuh, Memeriahkan Hari Kemerdekaan Indonesia  Yang ke-78th','<div>SUNGAI PENUH - Sabtu 19 agustus 2023.</div><div>Diskominfosta&nbsp; Kota Sungai Penuh, Memeriahkan Hari Kemerdekaan Indonesia&nbsp; Yang ke-78th. Yaitu Mengikuti Pawai Yang Dilaksanakan di Lapangan Merdeka kota Sungai Penuh.</div>','upload/berita/n7TuCXXznOOmrONqaG5onnnhRKHHKaHZOuQcPZSs.jpg','rahmatrefo','diskominfosta-kota-sungai-penuh-memeriahkan-hari-kemerdekaan-indonesia-yang-ke-78th','2023-08-20 09:04:03','2023-08-20 09:04:03'),(7,'Penandatanganan MoU antara RRI Pemerintah Kota Sungai Penuh','<div>JAMBI -Kepala Dinas Kominfosta Kota Sungai Penuh Menghadiri&nbsp; Penandatanganan MoU (MEMORANDUM OF UNDERSTANDING) antara Lembaga Penyiaran Publik Republik Indonesia(RRI) Dengan Pemerintah Kota Sungai Penuh</div>','upload/berita/QyoUCGvvoEhh1vxwrZWjgJXNchGtQTjmQQBWnvXL.jpg','rahmatrefo','penandatanganan-mou-antara-rri-pemerintah-kota-sungai-penuh','2023-08-22 12:00:14','2023-08-22 12:00:14'),(8,'Memeriahkan Hari Kemerdekaan Indonesia Ke 78th','<div>SUNGAI PENUH - Rabu 23 Agustus 2023 Diskominfosta Kota Sungai Penuh Memeriahkan Hari Kemerdekaan Indonesia Yang Ke 78th. Bertempat Dikantor Diskominfosta Sungai Penuh</div>','upload/berita/yM3zh93LG4hSpRRtBXBj6BE4FcYgg58LEM3ooSQ0.jpg','rahmatrefo','memeriahkan-hari-kemerdekaan-indonesia-ke-78th','2023-08-24 09:19:49','2023-08-24 09:19:49'),(9,'Kadis  Kominfo Josrizal Helman Kota Sungai Penuh Menghadiri Rapat Koordinasi Nasional','<div>JAKARTA - Kadis Kominfo Josrizal Helman Menghadiri Rapat Koordinasi Nasional, Kolaborasi Implementasi Sistem Pemerintahan Berbasis Elektronik Nasional Bertempat di Hotel Aulia Jakarta.</div>','upload/berita/TjH6DU5AKYO54CLUf2dE8WBwVWxMlgPGp7UVVMlF.jpg','rahmatrefo','kadis-kominfo-josrizal-helman-kota-sungai-penuh-menghadiri-rapat-koordinasi-nasional','2023-10-24 11:48:41','2023-10-24 11:48:41'),(10,'Visitasi Monitoring Dan Evaluasi (Money) Keterbukaan Informasi Badan Publik Se-Provinsi Jambi Tahun 2023','<div>SUNGAI PENUH-Visitasi Monitoring Dan Evaluasi (Money) Keterbukaan Informasi Badan Publik Se-Provinsi Jambi Tahun 2023,Oleh Pimpinan Dan Anggota Komisi Informasi Provinsi Jambi Di Dinas Komunikasi Informatika dan Statistik Kota Sungai Penuh</div>','upload/berita/EY8jIz7lpzHBUcQQOkcW8YC8COiTxnKbpZx2xyPT.jpg','rahmatrefo','visitasi-monitoring-dan-evaluasi-money-keterbukaan-informasi-badan-publik-se-provinsi-jambi-tahun-2023','2023-10-26 09:44:33','2023-10-26 09:44:33'),(11,'lOMBA CIPTA MENU TAHUN 2023','<div>SUNGAI PENUH - Lomba Cipta Menu Tahun 2023 ,Melalui Pemanfaatan Pangan Lokal Dan Olaharaga Untuk Mencegah stunting , Tema - Sehat Bahagia Dengan Pangan Lokal.<br>-Kenyang Tidak Harus Nasi<br>-Cegah Stunting Dengan Pola Makan B25A (Beragam,Bergizi,Seimbang Dan Amanah)<br><br></div>','upload/berita/fEffD55QXPeRZ5jo80rcIZPlDUwdzWeywEUorhwz.jpg','rahmatrefo','lomba-cipta-menu-tahun-2023','2023-11-07 09:07:06','2023-11-07 09:07:06'),(12,'MARI MENGGUNAKAN TWIBBON UNTUK MEMERIAHKAN HUT KOTA SUNGAI PENUH YANG KE-15,','<div>SUNGAI PENUH - Mari Menggunkan twibbon untuk memeriahkan hut kota sungai penuh yang ke-15<br>KLIK LINK Dibawah ini Untuk Menggunkan TWIBBON<br>https://twb.nz/hut15spndiskominfosta</div>','upload/berita/yrHVd2ggwCoNYeeAkEWNyL9dsZUTGZGy1eMbb1uS.jpg','rahmatrefo','mari-menggunakan-twibbon-untuk-memeriahkan-hut-kota-sungai-penuh-yang-ke-15','2023-11-07 09:12:01','2023-11-07 09:12:01'),(13,'Pemerintah Kota Sungai Penuh Meraih Penghargaan Tertinggi Berupa Predikat Informatif Pada Anugerah Keterbukaan Informasi Publik Tahun 2023','<div>JAMBI - Allhamdulillah , Selamat dan Sukses , Bertempat Di Hotel Wiltop Jambi , Walikota Sungai Penuh Drs . Ahmadi Zubir , MM atas nama&nbsp; Pemerintah Kota Sungai Penuh Meraih Penghargaan Tertinggi Berupa Predikat Informatif Pada Anugerah Keterbukaan Informasi Publik Tahun 2023 untuk kategori pemerintah kab/kota.<br>Pemberian anugerah diberikan langsung oleh Wakil Ketua Komisi Informasi Republik Indonesia Arya Sandhiyudha, P.hD disaksikan Gubernur Jambi, Bupati/Walikota se Jambi , Pimpinan KI Prov Jambi dan para tamu undangan.</div>','upload/berita/0Mh7AKRCsDyoqwPbdD7rSRGA62uLb2jPIQs0TELO.jpg','rahmatrefo','pemerintah-kota-sungai-penuh-meraih-penghargaan-tertinggi-berupa-predikat-informatif-pada-anugerah-keterbukaan-informasi-publik-tahun-2023','2023-11-20 10:14:00','2023-11-20 10:14:00'),(14,'Walikota Sungai Penuh Drs. Ahmadi Zubir, MM menerima kunjungan kerja rombongan Kepala LPP RRI Jambi.','<div>SUNGAI PENUH- Walikota Sungai Penuh Drs. Ahmadi Zubir, MM menerima kunjungan kerja rombongan Kepala LPP RRI Jambi.<br>Kunjungan ini dimaksud Sebagai tindak lanjut dari Kesepakatan Bersama antara Direktur Utama LPP RRI Pusat dengan Walikota Sungai Penuh tanggal 21 Agustus 2023 yg lalu.&nbsp;<br>Kepala LPP RRI Jambi Ibu Yuliana Marta Doky dan Kepala Dinas Kominfo Kota Sungai Penuh Bapak H. Jozrizal Helman menandatangani Perjanjian Kerja Sama (PKS) tentang Penyelenggaraan Operasional LPP RRI di Kota Sungai Penuh.&nbsp;<br>Pemerintah Kota Sungai Penuh akan memfasilitasi RRI Sungai Penuh, sementara itu RRI akan menjadi mitra startegis Pemkot Sungai Penuh dalam hal pemberitaan.&nbsp;<br>Penandatangan PKS ini disaksikan langsung oleh Walikota Sungai Penuh Drs. Ahmadi Zubir, MM diruang kerja Walikota Sungai Penuh.<br><br></div>','upload/berita/LE1L0uDOaprnceUAaiYtqRQA3qrN227VpSLTy4jI.jpg','rahmatrefo','walikota-sungai-penuh-drs-ahmadi-zubir-mm-menerima-kunjungan-kerja-rombongan-kepala-lpp-rri-jambi','2023-11-22 16:15:32','2023-11-22 16:15:32'),(15,'Kegiatan Pembinaan Kelompok Informasi Masyarakat(KIM)','<div>SUNGAI PENUH - Kita Gal Pembentukan Forum Masyarakat Informasi Desa Dengan Memanfaatkan Teknologi Digital Menuju Jambi Mantab 2024 serta Sungai penuh yang maju dan Berkeadilan.</div>','upload/berita/4303AJPiJPi1ZJ95w4NyepBlcP4ysdedm1PQNkyL.jpg','rahmatrefo','kegiatan-pembinaan-kelompok-informasi-masyarakat-kim','2023-12-05 10:32:54','2023-12-05 10:32:54'),(16,'Lauching srikandi dan TTE(tanda tangan elektronik) provinsi jambi.','<div>JAMBI - Lauching srikandi dan TTE(tanda tangan elektronik) provinsi jambi. Alhamdulillah Kota Sungai Penuh memperoleh piagam penghargaan peringkat 3 pengelolaan kearsipan tingkat kab/kot seprovinsi Jambi.</div>','upload/berita/aqrKRf6FxK1TJQ4UnOQ3lngdiviJ9jeKJEL7yFqv.jpg','rahmatrefo','lauching-srikandi-dan-tte-tanda-tangan-elektronik-provinsi-jambi','2023-12-21 09:47:13','2023-12-21 09:47:13'),(17,'Wako Ahmadi Resmi Lauching Internet Gratis Diarea Lapangan Merdeka','<div>SUNGAI PENUH - Walikota Sungai Penuh Drs.Ahmadi Zubir, MM secara resmi melaucing layanan internet gratis di area Lapangan Merdeka, Kamis (6/6)&nbsp;</div><div>Turut hadir pada kesempatan tersebut Unsur Forkopimda, Sekda Alpian, Kepala OPD dalam lingkup Pemerintah Kota Sungai Penuh, dan Kader PKK Se-Kota Sungai Penuh, beserta masyarakat.&nbsp;</div><div>Dalam era digital seperti saat ini, akses terhadap informasi dan komunikasi menjadi kebutuhan mendasar bagi setiap individu. Kota Sungai Penuh, melalui Dinas Komunikasi dan Informatika (Diskominfo), berkomitmen untuk terus meningkatkan pelayanan publik dan kesejahteraan masyarakat melalui pemanfaatan teknologi informasi.</div><div>Wako Ahmadi Menyampaikan,program ini adalah bagian dari visi besar pemerintah kota untuk menjadikan Sungai Penuh sebagai kota cerdas, yang tidak hanya modern tetapi juga inklusif bagi seluruh lapisan masyarakat.&nbsp;</div><div>&nbsp;\" Penyediaan internet gratis di area Lapangan Merdeka merupakan wujud nyata dari komitmen tersebut melalui Dinas Komunikasi dan Informatika (Diskominfo) Kota Sungai Penuh bekerja sama dengan icon-net plus memegang peranan penting dalam merealisasikan Program ini \"Ujarnya (HMS)</div>','upload/berita/cQOwVnobIZEkIKO2yCUpFD08AgGtLMTIe9XPiCEX.jpg','diskominfo','wako-ahmadi-resmi-lauching-internet-gratis-diarea-lapangan-merdeka','2024-06-28 10:58:30','2024-06-28 10:58:30'),(18,'SELAMAT MENUNAIKAN IBADAH PUASA 1446H/2025M','<div>KELUARGA BESAR DINAS KOMUNIKASI, INFORMATIKA DAN STATISTIK</div><div>KOTASUNGAIPENUH Mengucapkan SELAMAT MENUNAIKAN IBADAH PUASA 1446H/2025M.</div><div>\"Makan Nasi Jangan Berdiri</div><div>Kalau Jatuh Rugi Sendiri</div><div>Hilangkan Iri Dan Dengki</div><div>Sambut Ramadhan&nbsp;</div><div>Dengan Senang Hati\"</div>','upload/berita/SQI7VPbdgFeCnn4i8M9LvRTebLr9LSjq0KYkcqiU.jpg','diskominfo','test','2025-03-07 09:48:29','2025-03-07 09:48:29'),(19,'Perjuangkan Bantuan Sosial Dan Pemberdayaan Ekonomi Masyarakat, Wako Alfin Gelar Audiensi Bersama Mensos RI','<div>JAKARTA- Walikota Sungai Penuh, Alfin, SH bersama Gubernur Jambi Al Haris , Bupati dan Walikota se Provinsi Jambi audiensi bersama Menteri Sosial Republik Indonesia.&nbsp;</div><div>Audiensi ini dilaksanakan di Gedung Kementerian Sosial RI di Jakarta pada hari selasa 15/7/2025</div><div>Audiensi tersebut menjadi forum penting untuk seluruh kepala Daerah kabupaten / Kota. Adapun berbagai program yakni tentang tantangan sosial di daerah masing masing. Tujuanya, untuk memperkuat sinergi dengan Kementerian dalam penanganan isu isu kesejahteraan masyarakat.</div><div>Walikota Sungai Penuh Alfin, SH juga menyampaikan sejumlah persoalan sosial yang dihadapi di Kota Sungai Penuh, termasuk upaya penanggulangan kemiskinan, perlindungan sosial, dan pemberdayaan kelompok rentan.&nbsp;</div><div>Selain itu wako alfin juga mendorong peningkatan dukungan program dari Kementerian Sosial, khususnya dalam hal bantuan sosial dan pemberdayaan ekonomi masyarakat termasuk Penambahan kepesertaan Jaminan Kesehatan.&nbsp;</div><div>\"Kami berharap sinergi antara pemerintah pusat dan daerah semakin kuat, demi mewujudkan masyarakat Sungai Penuh yang sejahtera dan berdaya\"ujarnya.</div><div>Menteri Sosial RI menegaskan bahwa komitmen pemerintah pusat akan terus memberikan perhatian kepada daerah daerah, serta mendorong pelaksanaan program sosial yang tepat sasaran dan berkelanjutan.</div><div>\"Pertemuan ini diharapkan mampu memperkuat koordinasi lintas sektor dan mendorong akselerasi pelayanan sosial di seluruh wilayah Provinsi Jambi, termasuk Kota Sungai Penuh\" []&nbsp;</div><div>(Mc Kominfo)</div>','upload/berita/JeTlkm3UQPsFAL7ajA51VYEWYayJgwfdjk4imfQM.jpg','diskominfo','perjuangkan-bantuan-sosial-dan-pemberdayaan-ekonomi-masyarakat-wako-alfin-gelar-audiensi-bersama-mensos-ri','2025-07-18 10:03:31','2025-07-18 10:03:31'),(20,'Pengukuhan Pokja Bunda Paud, Wawako Azhar: Mari Jalankan Amanah Ini Dengan Semangat','<div>SUNGAI PENUH- Wakil Walikota Sungai Azhar Hamzah hadiri Pengukuhan Pokja Bunda Paud Kota Sungai Penuh Periode 2025/ 2030.&nbsp; Kamis 17/7/2025</div><div>Acara pengukuhan ini bertempat di Aula Kantor Walikota Sungai Penuh. Dihadiri oleh Sekretaris Daerah (Sekda) Alpian, Asisten, Dinas terkait, Kepala SKPD lingkup Kota Sungai Penuh dan tamu undangan lainya.</div><div>Acara ini mengusung tema “Anak Sehat, Cerdas Menuju Sungai Penuh Juara”. Selain itu juga diadakan kegiatan Sosialisasi wajib belajar 13 tahun.&nbsp;</div><div>Melalui pengukuhan ini Keseriusan Pemerintah Daerah Kota Sungai Penuh akan berkomitmen mewujudkan pendidikan yang berkualitas.</div><div>Adapun pengurus Pokja Bunda Paud diketuai, Winda Rahayu, Wakil Ketua, Reni Kurnia, Sekretaris Irma Febrianti dan para Ketua Bunda Paud Kecamatan dan Desa . Pengurus pokja ini dikukuhkan oleh Bunda Paud Kota Sungai Penuh, Sri Kartini Alfin.</div><div>Ketua Bunda Paud Kota Sungai Penuh Sri Kartini Alfin mengatakan, bunda paud merupakan Penggerak untuk menuju perubahan, mewujudkan Paud yang berkualitas.&nbsp;</div><div>\"Kita adalah penggerak perubahan untuk anak usia dini termasuk, motifator, fasilitator untuk mendukung paud yang berkualitas. Kita adalah penggerak perubahan untuk anak usia dini. ujarnya</div><div>Wawako Azhar Hamzah juga menyampaikan bahwa Pendidikan Anak Usia Dini mutlak diperhatikan. Pengukuhan ini sebagai amanah agar dapat dijalankan dengan penuh tanggung jawab.</div><div>“Mari kita jalankan amanah ini dengan semangat, penuh tanggung jawab. Melalui langkah langkah konkret dan komitmen yang kuat bunda paud dapat menjadi pionir dalam menciptakan masa depan yang cerah dan bermartabat untuk generasi penerus kita’’[].</div><div>(Mc Kominfo)</div>','upload/berita/dmFzXplvONskLdibKhO3zP55yragZUdrd6U6QkCy.jpg','diskominfo','pengukuhan-pokja-bunda-paud-wawako-azhar-mari-jalankan-amanah-ini-dengan-semangat','2025-07-18 10:06:31','2025-07-18 10:06:31'),(21,'MPLS Tingkat SD dan Paud, Wawako Azhar: Saya Yakin Nantinya Anak Anak Akan Tumbuh Menjadi Pribadi Yang Cerdas','<div>SUNGAI PENUH -&nbsp; Wakil Walikota Sungai Penuh Azhar Hamzah kembali melakukan pemantauan pelaksanaan Masa Pengenalan Lingkungan Satuan Pendidikan (MPLS). Rabu (16/7).</div><div>Disela itu, Wawako Azhar Hamzah bersama Bunda Paud, Sri Kartini Alfin, Ketua GOW, Mawarti Azhar, Ketua Dharma Wanita, Winda Rahayu dan rombongan melakukan peninjauan proses belajar bagi peserta didik.</div><div>Memasuki hari ketiga ajaran baru Sekolah Tahun 2025-2026, pemantauan MPLS dilakukan bagi anak didik tingkat Sekolah Dasar dan Paud dalam Kota Sungai Penuh.</div><div>Wawako, Azhar Hamzah mengapresiasi para guru TK Pembina yang telah berpartisipasi mendukung kegiatan program pelaksanaan MPLS.</div><div>\"Peran ibu guru dalam mengenali lingkungan sekolah yang ramah menyenangkan dan mendidik, saya yakin nantinya anak-anak akan tumbuh menjadi pribadi yang cerdas, sehat dan berkarakter\" ungkapnya\'\'. (MC Kominfo)</div>','upload/berita/w3o9ApgbQUW0fjhCIUqldOA1YYnuGT1OH4a1bjXP.jpg','mc','mpls-tingkat-sd-dan-paud-wawako-azhar-saya-yakin-nantinya-anak-anak-akan-tumbuh-menjadi-pribadi-yang-cerdas','2025-07-18 10:10:23','2025-07-18 10:10:23'),(22,'Wako Alfin Audiensi Bersama Menko Infrastruktur dan Pembangunan Kewilayahan RI','<div>JAKARTA - Walikota Sungai Penuh, Alfin, SH mengikuti audiensi bersama&nbsp; Menteri Koordinator Infrastruktur dan Pembangunan Kewilayahan Republik Indonesia. Rabu 16/7/2025</div><div>Bersama Gubernur Jambi Al Haris dan para Bupati/Walikota se-Provinsi Jambi bersama. Audiensi ini&nbsp; dilaksanakan di gedung Kemenko Infrastruktur dan Pembangunan Kewilayahan RI di Jakarta.</div><div>Hal ini menjadi objek penting bagi Pemerintah Kota Sungai Penuh. Yakni menyuarakan berbagai program prioritas pembangunan Daerah. Selain itu juga memerlukan dukungan pemerintah pusat yakni aspek infrastruktur dan pengembangan wilayah.</div><div>Walikota Sungai Penuh Alfin memaparkan sejumlah program unggulan yakni :</div><div>Pengembangan Sekolah Menengah Unggulan Terintegrasi, Peningkatan layanan RSUD Mayjen H.A. Thalib, Pengendalian banjir, Pengembangan Tempat Pengolahan Sampah Terpadu (TPST) dan Instalasi Pengolahan Lumpur Tinja (IPLT), Pembangunan Instalasi Pengolahan Air (IPA), Pengembangan Infrastruktur Ruang Terbuka Hijau (RTH), Penanganan infrastruktur jalan, Revitalisasi Pasar Tanjung Bajure.</div><div>Walikota Alfin menambahkan, pentingnya sinergi dan dukungan berkelanjutan dari Kementerian Koordinator Infrastruktur dan Pembangunan untuk mempercepat pencapaian kesejahteraan masyarakat</div><div>\"Kami berharap berbagai usulan ini dapat diakomodir dan menjadi bagian dari program strategis nasional, mengingat urgensinya bagi masyarakat Kota Sungai Penuh\'\'ujarnya.</div><div>\"Semoga menjadi langkah awal penguatan koordinasi antara pemerintah daerah dengan pemerintah pusat dalam mewujudkan pembangunan yang merata dan berkelanjutan di Provinsi Jambi, khususnya di Kota Sungai Penuh\"[] (MC Kominfo)</div><div><br><br></div>','upload/berita/C5WYpopvpt7HKSiD8ayH8YRavTKofwTF9Sm7osd6.jpg','mc','wako-alfin-audiensi-bersama-menko-infrastruktur-dan-pembangunan-kewilayahan-ri','2025-07-18 10:13:08','2025-07-18 10:13:08'),(23,'Walikota Solok Berkunjung Ke Kota Sungai Penuh, Wako Alfin: Saling Mendukung','<div>SUNGAI PENUH- Walikota Solok Dr. Ramadhani Kirana Putra <a href=\"http://se.mm/?fbclid=IwZXh0bgNhZW0CMTAAYnJpZBEwZG1wU0E1ckkzbnBGRko5TQEeIGgrRSubtlkrz8Imrl57E50dBdmkdcSTQPL8Pe-um0pFdkhHsN7gmfU5DJ4_aem_UtWp_-JzaxgJV2rIz032OA\"><strong>SE.MM</strong></a> beserta rombongan berkunjung ke Kota Sungai Penuh.&nbsp;</div><div>Kunjungan ini pada hari Jum\'at 18/Juli/2025. Disambut langsung oleh Walikota Sungai Penuh Alfin dalam rangka sharing informasi dan pengalaman terkait pelaksanaan program PKK (Pemberdayaan dan Kesejahteraan Keluarga), GOW (Gabungan Organisasi Wanita), serta DWP (Dharma Wanita Persatuan).&nbsp;</div><div>Dalam pertemuan ini, keduanya berdiskusi mengenai berbagai inovasi dan strategi pemberdayaan perempuan, peningkatan peran keluarga dalam pembangunan, serta sinergi antar organisasi wanita dalam mendukung program pemerintah daerah.&nbsp;</div><div>\"Ini bukan hanya bentuk silaturahmi, tapi juga wujud nyata sinergi antar pemimpin daerah untuk saling belajar dan saling mendukung\"katanya</div><div>Walikota Solok juga apresiasi atas sambutan yang diberikan, serta keterbukaan Pemerintah Kota Sungai Penuh dalam berbagi pengalaman dan strategi yang telah dilaksanakan.&nbsp;</div><div>\"Kunjungan ini menjadi ajang silaturahmi sekaligus wadah bertukar informasi yang sangat bermanfaat dalam memperkuat program pemberdayaan perempuan dan keluarga di daerah masing-masing\"[] (Mc Kominfo)</div>','upload/berita/WhLD6hLbYGpQt4XJXlxnfTzBeeu8WLUIIm6rJR6i.jpg','mc','walikota-solok-berkunjung-ke-kota-sungai-penuh-wako-alfin-saling-mendukung','2025-07-21 11:14:28','2025-07-21 11:14:28'),(24,'Dewan Setuju 5 Ranperda Kota Sungai Penuh','<div>SUNGAI PENUH - Wakil Walikota Sungai Penuh Azhar Hamzah menghadiri Rapat Paripurna Dewan Perwakilan Rakyat Daerah Kota Sungai Penuh dengan agenda Penyampaian pendapat akhir Fraksi-Fraksi Dewan terhadap 5 Ranperda Kota Sungai Penuh.</div><div>Berlangsung diruang aula DPRD, Paripurna dipimpin langsung, Ketua DPRD, Hutri Randa, S.Sos.,MM, Wakil Ketua I, Hardizal,S.Sos., MH, Wakil Ketua II, Emrizal, <a href=\"https://l.facebook.com/l.php?u=http%3A%2F%2FS.Pt%2F%3Ffbclid%3DIwZXh0bgNhZW0CMTAAYnJpZBEwZG1wU0E1ckkzbnBGRko5TQEeIGgrRSubtlkrz8Imrl57E50dBdmkdcSTQPL8Pe-um0pFdkhHsN7gmfU5DJ4_aem_UtWp_-JzaxgJV2rIz032OA&amp;h=AT2l0sZ_pAmjYBjMMQLyPcbSifsXrUlQg_c3qJbw13eXD1dYTgCXSlf2wwrxLZmutDOsneAXmKAtl38RL5Lpwpwd8oADSLmJ6QvUvC38PVrfLtnplXlZzklsPz76D05DC9dDKxCbEQ9Pyg&amp;__tn__=-UK-R&amp;c[0]=AT3jfwS4zVQZdx2tVyOggJPYjVXpsI31JLhfD00Mj9JgtEn9bfFx6BL34jknjNU1J0aWiq7UKbcO6aqmsYcO24PoLfY95wO0EVA77sAQWpm_xDCjbCl4-FocJKR1hKBd8V6yobg5sBiE7EXvTcC8gWvMwCN0gJZuNmOM7N1RZvTgb4XMgegWjXOEpSU1neDAWNLaCHz6S5kjSbfFe4mLDQlr3w\"><strong>S.Pt</strong></a>, Jum\'at ( 18/7).</div><div>Dalam pendapat akhir Fraksi-Fraksi Dewan Perwakilan Rakyat Daerah terhadap 5 Ranperda Kota Sungai Penuh DPRD menyetujui disahkan sebagai perda.&nbsp;</div><div>Ranperda tentang rencana pembangunan jangka menengah Daerah (RPJMD) Kota Sungai Penuh Tahun 2025-2029.</div><div>Ranperda tentang perubahan atas peraturan Daerah Kota Sungai Penuh Nomor 1 Tahun 2024 tentang :</div><div>1. Pajak Daerah dan Retribusi Daerah.&nbsp;</div><div>2. Penghormatan perlindungan pemenuhan hak penyandang disabilitas.</div><div>3. peningkatan kesejahteraan sosial lanjut usia.&nbsp;</div><div>4. penyelenggaraan pendidikan.</div><div>5. pengelolaan ruang terbuka hijau.</div><div>Wakil Walikota, Azhar Hamzah pada kesempatan tersebut menyampaikan terima kasih kepada pimpinan DPRD dan seluruh Anggota DPRD Kota Sungai Penuh atas komitmen bersama dalam proses pembangunan daerah. Hal ini dibuktikan dengan disetujuinya Ranperda.</div><div>\" Ini merupakan perwujudan dari adanya komitmen yang kuat, kesungguhan dan semangat serta keseriusan dalam melaksanakan sehingga adanya persetujuan hari ini\'\' tutupnya (Mc Diskominfo)</div>','upload/berita/sQG1bk0iXUBb7ZgdNRj5IOrmf2jcNaRhF6fPg452.jpg','mc','dewan-setuju-5-ranperda-kota-sungai-penuh','2025-07-21 11:16:23','2025-07-21 11:16:23'),(26,'Wako Alfin Serahkan Bantuan Pangan Beras Bagi 4520 Keluarga','<div>SUNGAI PENUH - Walikota Sungai Penuh, Alfin, SH resmi melaunching penyaluran Bantuan Pangan Beras Periode Juni- Juli Tahun 2025.</div><div>Sebanyak 4.520 bantuan diserah disetiap kecamatan dengan sasaran keluarga miskin dan keluarga rawan miskin berdasarkan data terpadu ekonomi nasional (DTSEN) yang bersumber dari Kementerian Sosial RI.</div><div>Penyaluran beras tersebut diserahkan langsung Walikota Sungai Penuh Alfin secara simbolis kepada perwakilan yang berlangsung di Aula Kantor Wali Kota Sungai Penuh, Sabtu (19/7).</div><div>\" Kita berharap bantuan beras dapat mendorong pertumbuhan ekonomi serta memenuhi ketersediaan pangan bagi masyarakat Kota Sungai Penuh. Ujar Wako Alfin.</div><div>\" Insya allah, berbagai program yang menyentuh langsung masyarakat akan terus kita gulingkan,\" tutupnya. [] (Mc Kominfo)</div>','upload/berita/hL077y2iiKIiqHmVb0gWVTPFU7jyMuVH09WULcWB.jpg','mc','wako-alfin-serahkan-bantuan-pangan-beras-bagi-4520-keluarga','2025-07-21 11:32:06','2025-07-21 11:32:06'),(27,'Diskominfo Kota Sungai Penuh Terima Penghargaan Atas Partisipasi Dan Kontribusi Dalam Pengurangan Sampah','<div>SUNGAI PENUH- Dinas Komunikasi, Informasi dan Statistik Kota Sungai Penuh terima penghargaan dari Walikota Sungai Penuh Alfin, SH.</div><div>Pengghargaan ini diterima langsung oleh Kadis Diskominfosta H.Josrizal Helman <a href=\"https://l.facebook.com/l.php?u=http%3A%2F%2FS.Si%2F%3Ffbclid%3DIwZXh0bgNhZW0CMTAAYnJpZBExdDJnNll1Z21CWEZFcmVwVAEe6PBRf438CtRSoVwnkDmD4MywDXost8PV2uNNrzG9zsxB53eY2ozi1uviT34_aem_DK0SQ-RiQDTZ_fWh0xtGSg&amp;h=AT275LIVZLm7h9wxuavaWAdtz7a_XiXR1FznVSspseK754K8uaSuhEqs4_ICoGgUXDjqYKQ6zg2H-UWnrx-87EIVH5IJG9N5Fv78xUcWngKbM7j96Avqc1xi6dNjGaRCSxWxAuHKdhSgYA&amp;__tn__=-UK-R&amp;c[0]=AT268T97B2Ef-4eN3Aqo-h8JDKj8loIfa4PSq-DpLm7ODB3x-HxkyddiV_gF0-uxBLf0CR5YWwCgjjyLmqZcg11BHT_UpM2Eat8XmxJP98r-FrR6m3lBFdggPNrnwYtVHLJKGugsrZHIuiEb6wC0EBbI5cIRB2xgG4ZiuINVvuvDkP5v_olVp1_UW_gRuYSd46zwMBeVl5JR7zn0ZaRkCo6qpg\"><strong>S.Si</strong></a>, Apt, diserahkan oleh Wako Alfin di Halaman Kantor Walikota Sungai Penuh sebagai bentuk&nbsp; apresiasi.</div><div>Hal ini sebagai partisipasi dan berkontribusi dalam pengurangan sampah melalui bank sampah mapan Kota Sungai Penuh.</div><div>Selain itu, Wako Alfin juga menyerahkan sertifikat apresiasi kepada bank sampah tingkat dinas dan desa yang konsisten dalam pengelolaan sampah berbasis masyarakat.&nbsp;</div><div>“Program ini merupakan bagian dari upaya strategis Pemkot Sungai Penuh. yakni menciptakan lingkungan bersih dan berkelanjutan dan&nbsp; menunjukkan komitmen terhadap pelestarian budaya, perlindungan sosial bagi petugas lapangan, serta penguatan partisipasi masyarakat dalam pengelolaan lingkungan” []&nbsp;</div><div>(Mc Diskominfosta)</div>','upload/berita/IrBI7n0wWI4aDXXyMgP04WKgnHIUNfGEc9RFM1gW.jpg','mc','diskominfo-kota-sungai-penuh-terima-penghargaan-atas-partisipasi-dan-kontribusi-dalam-pengurangan-sampah','2025-07-21 17:17:16','2025-07-21 17:17:16'),(28,'Wako Alfin Terima Penghargaan Festival Bahasa Ibu Tingkat Nasional','<div>SUNGAI PENUH- Walikota Sungai Penuh, Alfin, SH, Tenerima penghargaan bergengsi dari Kementerian Pendidikan Menengah dan Dasar Republik Indonesia. Senin 21/7/2025</div><div>Hal ini merupakan komitmen Wako Alfin yakni tentang pelestarian budaya dan bahasa daerah. Penghargaan ini diberikan atas Festival Bahasa Ibu Tingkat Nasional.</div><div>Selain itu, Penghargaan ini juga diterima oleh 13 orang siswa siswi perwakilan sekolah dasar dan menengah di Kota Sungai Penuh pada Festival Bahasa Ibu Tingkat Nasional. Dihadiri oleh, Wawako Azhar, Sekda Alpian, Ketua TP PKK Kota Sungai Penuh, SKPD lingkup Kota Sungai Penuh.</div><div>Penghargaan yang diterima ini juga sebagai bentuk apresiasi terhadap pemerintah daerah yang aktif menjaga dan mengembangkan bahasa ibu sebagai identitas budaya.</div><div>\"Bahasa ibu adalah jati diri daerah. Kita akan terus berkomitmen melestarikan bahasa daerah agar tidak punah dan tetap hidup di tengah masyarakat, khususnya generasi muda’’pungkasnya&nbsp;</div><div>(Mc Diskominfosta)</div>','upload/berita/fxiFZZDefwUJJ4vIITzHwFrODBsKgyFAg9UlMTiS.jpg','mc','wako-alfin-terima-penghargaan-festival-bahasa-ibu-tingkat-nasional','2025-07-21 17:19:37','2025-07-21 17:19:37'),(29,'Wako Alfin Komit Dukung Program Presiden RI Tentang Koperasi Merah Putih','<div>SUNGAI PENUH - Walikota Sungai Penuh Alfin, SH Komitmen mendukung Program Presiden Republik Indonesia Prabowo Subianto tentang pengembangan Koperasi Merah Putih di lingkup Kota Sungai Penuh.</div><div>Program Koperasi Merah Putih bertujuan untuk memperkuat Ekonomi Masyarakat. Dalam hal ini telah resmi diluncurkan oleh Presiden RI. Walikota Alfin juga mengingatkan Dinas Koperasi dan UMKM meminta untuk segera mengadakan pelatihan dan memberikan pendampingan bagi pengurus dengan maksud meningkatkan kapasitas dalam melaksanakan tugas.</div><div>Selain itu, Walikota Alfin,SH bersama Wakil Walikota Sungai Penuh Azhar Hamzah juga mengikuti Zoom Meeting. Peluncuran Kelembagaan 80, 000 Koperasi Desa/Kelurahan Merah Putih yang di selenggarakan oleh Kementerian Koordinator Bidang Pangan.</div><div>Dalam kegiatan dan dukungan ini, Walikota dan Wakil Walikota Sungai Penuh didampingi oleh Sekretaris Daerah Alpian, Asisten, Kepala Perangkat Daerah, Camat termasuk Kepala Desa dalam lingkup Kota Sungai Penuh. Senin 21/7/2025</div><div>Peluncuran Koperasi Merah Putih yang dilaksanakan secara serentak se Indonesia dibuka langsung Presiden RI. Wako alfin juga mengajak pengurus Koperasi tersebut dalam wilayah Kota Sungai Penuh untuk menjalankan program ini dengan serius.</div><div>\"Untuk itu, mari kita laksanakan program dengan penuh keseriusan karena Koperasi Merah Putih merupakan program yang tepat untuk mengangkat pertumbuhan ekonomi masyarakat\" []&nbsp;</div><div>( Mc Kominfo )</div>','upload/berita/IF6Pw3Y6XNLQak8E77MPxnsT91Nlsb1jIRtmCJQS.jpg','mc','wako-alfin-komit-dukung-program-presiden-ri-tentang-koperasi-merah-putih','2025-07-22 10:23:58','2025-07-22 10:23:58'),(30,'Wako Alfin Sharing Bersama Pedagang Pasar Beringin Tentang Rencana Relokasi Ke Kincai Plaza','<div>SUNGAI PENUH - Wali Kota Sungai Penuh, Alfin SH, menggelar pertemuan bersama para pedagang Pasar Beringin Jaya dalam rangka menjaring aspirasi dan berbagi pandangan terkait rencana relokasi ke Kincai Plaza, Bertempat dirumah Dinas Walikota Sungai Penuh, Senin 22/7/2025.&nbsp;</div><div>Dalam suasana yang penuh kekeluargaan dan dialog terbuka, Wali Kota menyampaikan bahwa relokasi ini hanya untuk sementara menjelang selesainya pembangunan pasar beringin jaya.&nbsp;</div><div>\"Pemerintah Kota Sungai Penuh berharap pembangunan pasar beringin jaya ini dapat meningkatkan kenyamanan dan kelayakan fasilitas berdagang bagi para pedagang, sekaligus mendukung penataan kawasan pasar yang lebih tertib dan moderen\" pungkasnya.</div><div>(Mc Diskominfo)</div>','upload/berita/OQiVa8zBo351TSmDvPG2ltoo7tTvUoCuSxPFOyZD.jpg','mc','wako-alfin-sharing-bersama-pedagang-pasar-beringin-tentang-rencana-relokasi-ke-kincai-plaza','2025-07-23 10:33:21','2025-07-23 10:33:21'),(31,'Ranperda Pertanggung Jawaban APBD Tahun 2024, Rancangan Perubahan KUA PPAS 2025 Disampaikan Wako Alfin Ke Dewan','<div>SUNGAI PENUH - Ranperda Pertanggung Jawaban APBD Tahun 2024 dan rancangan perubahan KUA PPAS 2025 disampaikan oleh Walikota Sungai Penuh, Alfin, SH ke Dewan Perwakilan Rakyat Daerah (DPRD).</div><div>Selain Wako Alfin, Wakil Walikota Azhar Hamzah juga hadir pada penyampaian pengantar Ranperda tentang Pertanggung jawaban Pelaksanaan APBD Tahun Anggaran 2024 serta Rencanggan Perubahan Kebijakan Umum APBD serta rancangan Perubahan PPAS tahun 2025 melalui Rapat Paripurna.</div><div>Kegiatan ini berlangsung di gedung aula DPRD Kota Sungai Penuh. dipimpin oleh Ketua DPRD, Hutri Randa, S.Sos.,MM, Wakil Ketua I, Hardizal,S.Sos., MH, Wakil Ketua II, Emrizal, <a href=\"https://l.facebook.com/l.php?u=http%3A%2F%2FS.Pt%2F%3Ffbclid%3DIwZXh0bgNhZW0CMTAAYnJpZBExaDFDYm5EOVBvTW0wUzdOTQEehqa4PLd1vn4_iUfAdBy9GO56aBaquo6UpkkUUUleruUaSgs00aTtctnX-u8_aem_UKf2r0zBzoIEFJtbI6hIUA&amp;h=AT23eUaBxToUyH41l-i90gwKl35hDCwWEw6qniV4U8AaaGIX533LQS6sfl9SIgZQdRcsSeLlstOyCf2uc0z-q69jXZpEu-rHjFbdPfVDzhh6qk6JGfQlq76TrTXrJIXYpLpwbaCil7IKsg&amp;__tn__=-UK-R&amp;c[0]=AT1eCIzdMJUL4Zz2pu5od1DzbmYNiCH4793qYkzf1klNBWo9umpxC6XD5URgAZJzhAnhhuyYK9L2mxpGE1IgD0ImsjslGn-jW0ZANDGdSUE0fvqU7xjOVZ8GhWTwaQO0KGTBFsnPF_3jB8UVITWaxkpZ9gUCj6HnxJULkfrtuTvAwawMldeSiZzsIc51Cp6WarD2bhUxmtVKasuNjjwSU5-QtQ\"><strong>S.Pt</strong></a> yang juga dihadiri oleh Para Forkompinda, Sekda Alpian, Asisten dan Kepala Perangkat Daerah.</div><div>Wako Alfin memaparkan, bahwa anggaran dan realisasi APBD tahun anggaran 2024 meliputi pendapatan daerah, belanja daerah dan pembiayaan daerah. Kemudian menyampaikan secara ringkas rancangan perubahan kebijakan umum APBD dan rancangan perubahan PPAS Kota Sungai Penuh tahun 2025. []&nbsp;</div><div>(Mc Kominfo)</div>','upload/berita/RWLs4K0cO6PocbOR9h6eRuAKFx7eSCv6X2ylLuar.jpg','mc','ranperda-pertanggung-jawaban-apbd-tahun-2024-rancangan-perubahan-kua-ppas-2025-disampaikan-wako-alfin-ke-dewan','2025-07-24 07:28:06','2025-07-24 07:28:06'),(32,'Kunker Menteri Pertanian RI, Wako Alfin Siap Bersinergi Dengan Pemerintah Pusat','<div>KERINCI- Menteri Pertanian Republik Indonesia Dr. Ir. H. Andi Amran Sulaiman, M.P menekankan pentingnya kolaborasi antara Pemerintah Pusat, Provinsi, dan Daerah untuk menjaga ketersediaan dan stabilitas Pangan Nasional.</div><div>Hal ini dikatakannya saat Kunjungan Kerja (Kunker) di Kabupaten Kerinci dan Kota Sungai Penuh atas komitmen mendukung para petani. Menteri Pertanian RI juga mengapresiasi peran aktif Walikota Sungai Penuh dan Gubernur Jambi yang mendukung para petani dan terus memajukan sektor Pertanian.</div><div>Kunker ini dalam rangka pelaksanaan Gerakan Tanam Padi (Gertam) sekaligus dialog bersama masyarakat dan petani guna untuk mendukung upaya swasembada pangan Nasional di Tanjung Mudo, Kecamatan Sitinjau Laut Kabupaten Kerinci. Rabu 23/7/2025</div><div>Kegiatan Gertam ini menjadi bagian dari strategi nasional untuk memperkuat ketahanan pangan daerah, sekaligus bentuk dukungan langsung Pemerintah pusat terhadap sektor pertanian di wilayah Jambi, Kabupaten Kerinci dan Kota Sungai Penuh.</div><div>Walikota Sungai Penuh, Alfin, SH, bersama Gubernur Jambi, H. Al Haris, S.Sos., M.H, menyambut baik Kunker Menteri Pertanian RI atas komitmen dan dukungan terhadap Petani.</div><div>Walikota Sungai Penuh, Alfin, SH, menyampaikan sangat menyambut baik pelaksanaan Gertam dan akan bersinergi dengan Pemerintah Pusat.</div><div>\"kami menyambut baik pelaksanaan Gertam, menyatakan bahwa Pemerintah Kota Sungai Penuh siap bersinergi dengan pemerintah pusat dalam mendukung program strategis bidang pertanian demi kesejahteraan petani dan masyarakat secara umum\'\' tutupnya.</div><div>(Mc Diskominfo)</div>','upload/berita/7zcrbSA2DoIonubK2NaDK9Zsn8Hyqc6kWJaAYGMA.jpg','mc','kunker-menteri-pertanian-ri-wako-alfin-siap-bersinergi-dengan-pemerintah-pusat','2025-07-24 10:47:28','2025-07-24 10:47:28'),(33,'Wako Alfin Apresiasi Menteri Pertanian RI','<div>KERINCI - Walikota Sungai Penuh, Alfin, SH mengapresiasi Menteri Pertanian Republik Indonesia Dr. Ir. H. Andi Amran Sulaiman, M.P. Hal ini sebagai upaya peningkatan produksi pangan, khususnya Padi.</div><div>Walikota Alfin menyampaikan rasa terima kasih dan apresiasi atas perhatian pemerintah pusat terhadap sektor pertanian di Sungai Penuh. Ia menegaskan bahwa kunjungan ini menjadi dorongan besar dalam upaya peningkatan produksi pangan.</div><div>Selain itu, Wako Alfin sangat menyambut baik kedatangan kunjungan kerja (kunker) Menteri Pertanian Republik Indonesia, Dr. Ir. H. Andi Amran Sulaiman, M.P. Rabu 23/7/2025</div><div>Menteri Pertanian di Bandara Depati Parbo beserta rombongan disambut baik oleh Gubernur Jambi , Bupati Kerinci Kepala Daerah se Provinsi Jambi jajaran Forkopimda, Kepala Dinas Terkait, serta sejumlah tokoh masyarakat.</div><div>\"Kehadiran Bapak Menteri merupakan motivasi besar bagi kami di daerah. Kami siap mendukung penuh program strategis pertanian nasional demi ketahanan pangan dan kesejahteraan petani. Kegiatan ini menjadi momentum strategis dalam mendorong produktivitas sektor pertanian lokal sekaligus memperkuat sinergi antara pemerintah pusat dan daerah\" [] (Mc Diskominfo)</div>','upload/berita/XkC61CYAhx2JJMIQ4K38kkqrlWlTVb1wkKOYe62C.jpg','mc','wako-alfin-apresiasi-menteri-pertanian-ri','2025-07-24 11:00:14','2025-07-24 11:00:14'),(34,'Wako Alfin Usulkan Normalisasi Sungai Batang Marao, BBI Ke Menteri Pertanian RI','<div>SUNGAI PENUH- Walikota Sungai Penuh Alfin, SH memberikan usulan Normalisasi Sungai batang Merao termasuk Balai Benih Induk (BBI) ke Menteri Pertanian Republik Indonesia Dr. Ir. H. Andi Amran Sulaiman.</div><div>Hal ini disampaikan Wako Alfin saat rapat koordinasi bersama Menteri Pertanian RI tentang pembahasan isu penting swasembada dalam Provinsi Jambi. Bertempat di Grand Hotel Kerinci Kota Sungai Penuh, juga hadir Gubernur Jambi, Al Haris Bupati dan Walikota lingkup Provinsi Jambi. Kamis 23/7/2025</div><div>Selian itu, pada rapat tersebut Walikota/Bupati juga menyampaikan berbagai usulan dan kendala Daerah. Wako Alfin juga menyampaikan pemanfaatan lahan produktif diwilayah sentra produksi tanaman pangan RKE.</div><div>Sebagai bentuk respon, Menteri Pertanian RI berkoordinasi dengan Kementerian PUPR. Maksudnya agar usulan yang diajukan benar benar dapat terealisasi.&nbsp;</div><div>\"Hampir 1470 H. lahan sawah tidak bisa garap karena kondisi lahan rusak dan tergenang air. Kami berharap perhatian serta dukungan bapak Menteri, agar sawah bertahun-tahun ditinggalkan kembali produktif dan petani bisa kembali sejahtera\"tutupnya.</div><div>(Mc Diskominfo)</div>','upload/berita/jIAgy1mMW5a483s49EMwtHzNdETzEtNW7B9WHBGe.jpg','mc','wako-alfin-usulkan-normalisasi-sungai-batang-marao-bbi-ke-menteri-pertanian-ri','2025-07-24 19:59:33','2025-07-24 19:59:33'),(35,'Masjid Baitul Gapur Dapat Bantuan 5 Juta Diserahkan Wako Alfin','<div>SUNGAI PENUH- Masjid Baitul Gapur Desa Pinggir Air Kecamatan Kumun Debai Kota Sungai Penuh mendapat bantuan sebesar Rp. 5.000.000.</div><div>Bantuan bersumber dari program Corporate Social Responsibility (CSR) Bank 9 Jambi. Diserahkan langsung oleh Walikota Sungai Penuh, Alfin, SH setelah melaksanakan ibadah Sholat Jum’at berjamaah bersama masyarakat di Masjid Baitul Gapur. Jumat 25/7/2025.</div><div>Kehadiran Wako Alfin juga disambut baik para jamaah dan masyarakat sekitar. Hal ini menunjukkan solidaritas termasuk menjaga tali silaturahmi dengan masyarakat.</div><div>Selain itu, dalam sambutan dan arahan&nbsp; Walikota Alfin di masjid tersebut juga mengajak masyarakat untuk terus menjaga kebersihan lingkungan. Menurutnya hal ini merupakan tanggung jawab bersama.&nbsp;</div><div>\"Dalam hal ini, Pemerintah Kota Sungai Penuh terus berkomitmen meningkatkan kesejahteraan masyarakat melalui program Pemerintah. Yakni, pembangunan infrastruktur serta penyaluran bantuan sosial\" ujarnya.</div><div>\"Sebagai bentuk dukungan terhadap pembangunan rumah ibadah, bantuan sebesar Rp5.000.000 untuk pembangunan Masjid Baitul Gapur. Bantuan ini merupakan program dana CSR dari Bank 9 Jambi\"tutupnya.</div><div>(MC Diskominfo)</div>','upload/berita/bwdi9llNZjPCTcrUhS4HNtT8YGdALsZCexcOITXl.jpg','mc','masjid-baitul-gapur-dapat-bantuan-5-juta-diserahkan-wako-alfin','2025-07-26 11:08:50','2025-07-26 11:08:50'),(36,'Walikota Sungai Penuh Alfin Menghadiri Acara HKG PKK Ke 53','<div>SUNGAI PENUH- Wali Kota Sungai Penuh Alfin, SH menghadiri acara peringatan Hari Kesatuan Gerak (HKG) PKK ke 53 dan Hut Dekranasda ke 45 tahun. Pesanya, anggota PKK adalah orang terpilih, maka jangan kita sia siakan tugas dan tanggung jawab.</div><div>Bertempat di Gedung Nasional Kota Sungai Penuh, juga hadir Wakil Walikota Sungai Penuh Azhar Hamzah, Sekda Alpian, Ketua TP PKK Kota Sungai Penuh Sri Kartini Alfin, Ketua Gow Mawarti Azhar, Ketua Darma Wanita Winda Alpian, Kepala SKPD, Camat, Kepala Desa lingkup Kota Sungai Penuh. 26/7/2025</div><div>Kegiatan HKG dan Hut Dekranasda diapresiasi oleh Wako Alfin. Katanya, Dalam hal ini PKK telah menunjukkan eksistensi termasuk bagian dari pilar untuk Pembangunan Daerah.</div><div>“Terima kasih semua pihak yang terlibat dalam kegiatan acara HKG. Melalui acara ini, Gerakan PKK telah menunjukkan Eksistensinya dalam memperdayakan keluarga melalui 10 program pokok PKK. Selain itu PPK juga termasuk pilar untuk memperkuat pembangunan yang berkelanjutan” ujarnya</div><div>“PKK sangat diprerlukan untuk pembangunan Daerah. Sinergi ini akan diperkuat bersama Pemerintah Daerah. Selain itu PKK Kota Sungai Penuh telah berkontribusi untuk Daerah Kota Sungai Penuh. PKK adalah orang orang terpilih, maka jangan kita sia siakan hal itu’’ []&nbsp;</div><div>(Mc Diskominfo)</div>','upload/berita/n8IGbQDNg5BezCd6fGYD8r8BJIza6gAvA7B7ExpZ.jpg','mc','walikota-sungai-penuh-alfin-menghadiri-acara-hkg-pkk-ke-53','2025-07-28 13:08:45','2025-07-28 13:08:45'),(37,'IMKS UIN Jambi Resmi Dilantik, Sekda Alpian Apresiasi Semangat Mahasiswa','<div>SUNGAI PENUH- Sekretaris Daerah Kota Sungai Penuh Alpian mengapresiasi semangat Mahasiswa Kerinci Sungai Penuh.&nbsp;</div><div>Hal ini disampaikannya saat pelantikan Badan Pengurus Harian Ikatan Mahasiswa Kerinci Sungai Penuh (IMKS) Universitas Islam Negeri (UIN) Sultan Taha Saifuddin Jambi Periode 2025. Sabtu 26/7</div><div>Mewakili Walikota Sungai Penuh Alfin, SH. Sekretaris Daerah (Sekda) Alpian juga mensuport IMKS UIN Jambi tentang membangun solidaritas dan kontribusi nyata untuk Daerah.</div><div>Pelantikan IMKS UIN Jambi bertempat di Aula kantor Walikota Sungai Penuh. Dihadiri oleh Dewan Pembina Dr. Beni Agustin S.Hum MH secara resmi melantik dan pengurus IMKS.</div><div>“Mahasiswa adalah agen perubahan. Saya berharap pengurus yang baru dilantik dapat menjaga kekompakan termasuk membawa nama baik Daerah kita ke tingkat Nasional nantinya\"[]&nbsp;</div><div>(MC Diskominfo)</div>','upload/berita/2MqEPzHEunBqCRAlEiL7pAYWFSZY1HOV3NEA5Gkc.jpg','mc','imks-uin-jambi-resmi-dilantik-sekda-alpian-apresiasi-semangat-mahasiswa','2025-07-29 12:54:25','2025-07-29 12:54:25'),(38,'Tabligh Akbar Peringatan 1 Muharam 1447 H, Wako Alfin: Semoga kebersamaan kita Bisa Membawa Berkah','<div>SUNGAI PENUH - Tabligh Akbar Peringatan 1 Muharam 1447 H/2025 M di Kecamatan Tanah Kampung pada Minggu 27/7/2025. Walikota Sungai Penuh Alfin, SH merasa bangga dan bahagia atas hadirnya qori internasional Ustad H. Syamsuri Firdaus serta masyarakat.</div><div>Tabligh Akbar Peringatan 1 Muharam di Kecamatan Tanah Kampung yang dihadiri oleh Qori Internasional berasal dari Nusa tenggara Barat (NTB). Disela itu tabligh Akbar ini juga diisi dengan Tausiyah disampaikan oleh Buya Syafwandi.</div><div>Turut hadir yakni Bupati Kerinci, Para Forkompinda, Pimpinan DPRD, Para Kepala Perangkat Daerah, Asisten Camat, Kades Tokoh masyarakat dan undangan lainnya. Selain kegiatan ini, Walikota Sungai Penuh Alfin, SH melakukan peresmian Rumah Qur\'an H.Syeh M.Sekin Kecamatan Tanah Kampung.&nbsp;</div><div>Dikegiatan ini, Masyarakat yang hadir juga memadati Lapangan Kantor Camat Tanah Kampung. Tujuannya, untuk mendengarkan lantunan ayat-ayat suci Al-Quran yang dibacakan oleh Ust. H. Syamsuri Firdaus, sang juara pertama dalam ajang Musabaqah Tilawatil Quran (MTQ) Internasional 2024 di Kuwait.&nbsp;</div><div>\"Tahun baru islam bukan hanya penanda pergantian waktu, tapi menjadi pengingat akan hijrah Rasulullah SAW dari Madinah ke Mekkah. Sebuah perjalanan perjuangan dan perubahan menuju kehidupan lebih baik, penuh keimanan dan keadilan\"ujarnya</div><div>\"Semoga kebersamaan kita dalam peringatan 1 Muharam 1447 H ini bisa membawa berkah dan menambah semarak syir agama Islam di Kota Sungai Penuh khususnya Kecamatan Tanah Kampung\'\'[]</div><div>(MC Diskominfo)</div>','upload/berita/ppCsv202CP3LeFZeHBj0NSGT4MLyWMPIwX43alz4.jpg','mc','tabligh-akbar-peringatan-1-muharam-1447-h-wako-alfin-semoga-kebersamaan-kita-bisa-membawa-berkah','2025-07-29 12:56:08','2025-07-29 12:56:08'),(39,'Kota Sungai Penuh Gelar TC Kafilah Untuk Persiapan MTQ','<div>SUNGAI PENUH - Wakil Walikota Sungai Penuh, Azhar Hamzah, secara resmi membuka kegiatan Training Center (TC) Kafilah Kota Sungai Penuh dalam rangka persiapan menghadapi Musabaqah Tilawatil Qur’an (MTQ) ke-54 Tingkat Provinsi Jambi.</div><div>MTQ tingkat Provinsi Jambi 2025 digelar di Kabupaten Muaro Jambi. Pembukaan tersebut berlangsung di aula Kantor Walikota Sungai Penuh, Pada Senin 28/7/2025</div><div>Wakil Walikota Azhar Hamzah menyampaikan apresiasi dan dukungan penuh kepada seluruh peserta TC yang merupakan utusan terbaik dari Kota Sungai Penuh. Dalam hal ini menurutnya pentingnya persiapan yang matang melalui pelatihan intensif guna meraih prestasi maksimal penuh dedikasi dan kedisiplinan.</div><div>\"Kegiatan TC ini sangat penting sebagai bentuk pembinaan dan penguatan kapasitas peserta sebelum tampil di MTQ. Kita berharap kafilah Kota Sungai Penuh dapat memberikan penampilan terbaik dan membawa prestasi yang membanggakan,\" ujar Azhar Hamzah.</div><div>Selain itu, Wakil Walikota Azhar Hamzah juga menekankan agar para peserta memanfaatkan kesempatan ini dengan sungguh-sungguh, bukan saja tampil maksimal di panggung MTQ Ke-54 akan tetapi mampu mencerminkan nilai-nilai Qur\'ani serta menjaga kedisiplinan selama mengikuti pelatihan.</div><div>Kegiatan TC ini juga akan berlangsung selama beberapa hari ke depan yang dipusatkan di Hotel Masgo dengan melibatkan pelatih-pelatih provinsi dan lokal yang berpengalaman di berbagai cabang lomba yang akan diikuti. Pemerintah Kota Sungai Penuh melalui Lembaga Pengembangan Tilawatil Qur’an (LPTQ) mengutuskan 40 peserta untuk mengikuti MTQ Ke-54&nbsp; tingkat Provinsi Jambi.&nbsp; []&nbsp;</div><div>(Mc Diskominfo)</div>','upload/berita/Fd8E3Ux4DnLUEIEhRHH5baOSXi9IoGIV3jkJvd7f.jpg','mc','kota-sungai-penuh-gelar-tc-kafilah-untuk-persiapan-mtq','2025-07-29 12:57:58','2025-07-29 12:57:58'),(40,'Motivasi Wako Alfin Tentang Kepemimpinan: Bertanggung Jawab, Berinovasi di Tengah Tantangan Zaman','<div>SUNGAI PENUH - Walikota Sungai Penuh, Alfin, SH, mengatakan perlunya menanam, memberikan nilai kepemimpinan terhadap anak sejak usia dini. Hal ini dikhususkan untuk generasi muda, tujuannya ialah untuk menjadi calon pemimpin masa depan.</div><div>Hal ini disampaikan oleh Wako Alfin saat hadir menjadi narasumber dikegiatan Latihan Dasar Kepemimpinan (LDK) SMA Negeri 1 Kota Sungai Penuh di Gedung Nasional Kota Sungai Penuh, Rabu 30/7/2025.</div><div>Dalam acara ini, parade berbagai organisasi termasuk penampilan siswa siswi berprestasi SMA Negeri 1 Kota Sungai Penuh yang telah meraih juara berbagai lomba ditingkat Provinsi maupun Nasional. Wako Alfin juga apresiasi menandatangani karya ilmiah para siswa siswi prestasi.</div><div>Kepala Sekolah Smansa, Marwazi, apresiasi, atas kehadiran Walikota Alfin. Berharap motivasi ini dapat menjadi bekal berharga bagi para peserta dalam perjalanan kepemimpinan mereka untuk masa depan atau mendatang.</div><div>Pentingnya menanamkan nilai nilai kepemimpinan sejak dini, khususnya bagi generasi muda yang akan menjadi calon pemimpin masa depan.&nbsp;</div><div>\"Kepemimpinan bukan hanya soal memimpin orang lain, tapi juga tentang bagaimana kita bisa memimpin diri sendiri, bersikap disiplin, bertanggung jawab, serta mampu berinovasi di tengah tantangan zaman,\"ujarnya</div><div>\"Para siswa untuk terus mengembangkan potensi diri, menjaga semangat belajar, serta aktif dalam kegiatan organisasi sebagai wadah pembentukan karakter\"katanya</div><div>\"Pemerintah Kota Sungai terus berkomitmen mendukung kemajuan dunia pendidikan di Kota Sunga Penuh dan InsyaAllah dalam waktu dekat kita akan mempersiapkan beasiswa kartu juara bagi siswa siswi Kota Sungai Penuh\"[ ]</div><div>(Mc Diskominfosta)</div>','upload/berita/XcbDwnmmAlUc5gixlINOlspy6JS9afIn6YKz8lBN.jpg','mc','motivasi-wako-alfin-tentang-kepemimpinan-bertanggung-jawab-berinovasi-di-tengah-tantangan-zaman','2025-08-05 08:32:16','2025-08-05 08:32:16'),(41,'Wako Alfin Bahas Stabilitas Pasokan dan Harga Pangan','<div>SUNGAI PENUH- Walikota Sungai Penuh membahas tentang penjagaan Stabilitas dan Harga Pangan. Pembahasan ini bersama tim Pengendalian Inflasi Daerah (TPID) Semester II Tahun 2025, bertempat di Ruang Pola Kantor Walikota Sungai Penuh. Rabu 30/7/2025</div><div>Dihadiri oleh Staf Ahli Bidang Perekonomian dan Pembangunan Provinsi Jambi Muktamar Hamdi, Kepala Perwakilan BI Provinsi Jambi Warsono, Plt Kepala Datun Kejaksaan Negeri Yupran Susanto SH MH, Kepala Statistik Kota Sungai Penuh Yudi Friamara, Kepala Bulog serta Para Kepala OPD Pemkot Sungai Penuh.</div><div>Kegiatan ini dalam rangka membahas langkah strategis menjaga stabilitas Pasokan dan Harga Pangan. Dalam Sambutannya Wako Alfin SH menyampaikan paparan strategi daerahnya dalam rangka pengendalian inflasi.&nbsp;</div><div>\"Pertemuan ini menjadi momentum penting untuk memperkuat sinergi seluruh pihak. Kita berkomitmen menjaga stabilitas pasokan dan harga pangan, agar daya beli masyarakat tetap terjaga dan inflasi bisa kita kendalikan bersama.” Ujar Wako&nbsp;</div><div>Peningkatan koordinasi antar OPD dalam pengendalian inflasi daerah, dan Evaluasi bulanan progres enam langkah konkret Kemendagri serta Pelaporan aktif melalui platform Kemendagri dan koordinasi dengan Bank Indonesia. Walikota juga menekankan pentingnya penerapan early warning system dan data sharing antar instansi. [ ] ( MC Diskominfo)</div>','upload/berita/mKkyDfQrEUF43TayIeMKC6WMao1d4YdwpmaYuCJl.jpg','mc','wako-alfin-bahas-stabilitas-pasokan-dan-harga-pangan','2025-08-05 08:33:48','2025-08-05 08:33:48'),(42,'Kadis Kominfosta Kota Sungai Penuh Hadiri Peresmian Room Record  center LPP TVRI Jambi','<div>JAMBI- Kepala Diskominfosta kota sungai penuh H. Josrizal Helman. S.Si.Apt menghadiri Peresmian Room Record&nbsp; center LPP TVRI Jambi yang bertempat di Stasiun TVRI Jambi. Minggu 3/8/2025</div><div>Acara tersebut dibuka langsung oleh gubernur jambi Al-Haris, didampingi kepala stasiun TVRI Jambi Herly Marjoni. Acara tersebut juga dilakukan penandatanganan prasasti.</div><div>Hal ini sebagai simbol peresmian Room Record Center sekaligus melakukan peninjauan langsung ke fasilitas Room Record dan berdiskusi bersama tim produksi&nbsp; LPP TVRI Jambi. dihadiri oleh kepala daerah kota/kabupaten se- provinsi jambi serta dimeriahkan dengan penampilan seni, Bazaar Gerakan Pangan Murah, dan berbagai kuliner.</div><div>Atas nama walikota sungai penuh Alfin SH, Kepala Dinas Diskominfosta kota sungai penuh menyampaikan apresiasinya terhadap TVRI Jambi yang terus berinovasi dan meningkatkan kualitas siaran.</div><div>\"TVRI sebagai lembaga penyiaran publik memiliki peran penting dalam menyebarkan informasi dan edukasi kepada masyarakat. Saya berharap dengan adanya Room Record Center yang baru ini, TVRI dapat terus meningkatkan kualitas konten dan menjadi lebih dekat dengan masyarakat\"ujarnya</div><div>\"Dengan adanya Room Record yang baru ini, diharapkan TVRI Jambi dapat terus menjadi lembaga penyiaran publik yang terpercaya dan memberikan kontribusi positif bagi masyarakat Kota jambi secara luas\"tambahnya</div><div>Sementara itu, Direktur Utama TVRI Jambi Herly Majoni menjelaskan bahwa Room Record yang baru ini dilengkapi dengan teknologi terkini dan fasilitas yang lebih baik untuk mendukung produksi konten yang berkualitas.</div><div>\"Kami berkomitmen untuk terus meningkatkan kualitas siaran dan memberikan konten yang bermanfaat bagi masyarakat. Kami berharap dengan adanya Room Record ini, kami dapat lebih dekat dengan masyarakat dan memenuhi kebutuhan informasi mereka\"[ ]</div><div>&nbsp;(MC Diskominfosta)</div>','upload/berita/QLTnmdlVt84shVQAvTVHUbIWC0bm7KPujRGQRsYP.jpg','mc','kadis-kominfosta-kota-sungai-penuh-hadiri-peresmian-room-record-center-lpp-tvri-jambi','2025-08-05 08:35:07','2025-08-05 08:35:07'),(43,'Wawako Azhar Hamzah Meriahkan Presisi Merdeka Run 2025 di Jambi','<div>JAMBI - Ribuan peserta dari berbagai penjuru daerah memadati Lapangan Kantor Gubernur Jambi pada Minggu (3/8) pagi untuk mengikuti ajang Presisi Merdeka Run 2025. Kegiatan lari yang penuh semangat ini menjadi bagian dari rangkaian peringatan HUT Kemerdekaan RI ke-80, yang diselenggarakan oleh Polda Jambi bekerja sama dengan pemerintah provinsi serta sejumlah mitra.</div><div>Tampak hadir dalam kemeriahan acara ini, Wakil Walikota Sungai Penuh, Azhar Hamzah, yang ikut menyaksikan langsung Flag Off Ceremony sebagai tanda dimulainya lomba. Kehadiran Wawako menambah semangat peserta, sekaligus mempererat hubungan antara pemerintah daerah dengan masyarakat lintas wilayah.</div><div>Dalam keterangannya, Azhar Hamzah menyampaikan apresiasi terhadap kegiatan tersebut yang menurutnya bukan sekadar ajang olahraga, melainkan juga momentum kebersamaan dan wujud cinta Tanah Air.</div><div>“Presisi Merdeka Run ini bukan hanya soal fisik dan kebugaran, tetapi juga simbol persatuan, semangat nasionalisme, serta gaya hidup sehat. Harapannya, kegiatan positif seperti ini bisa terus digelar secara berkelanjutan,” ujarnya.</div><div>Presisi Merdeka Run 2025 menjadi bukti nyata sinergi antara aparat kepolisian dan masyarakat dalam merayakan kemerdekaan dengan cara yang inspiratif dan menyenangkan. Selain meningkatkan antusiasme warga terhadap olahraga, kegiatan ini juga memperkuat nilai-nilai persatuan di tengah keberagaman.</div><div>(MC Kominfo)</div>','upload/berita/NPG9fM0Q0ax9YR3eP1H96Ynbjaxd9kXCxaTluTuI.jpg','mc','wawako-azhar-hamzah-meriahkan-presisi-merdeka-run-2025-di-jambi','2025-08-05 08:36:59','2025-08-05 08:36:59'),(44,'Objek Kunjungan Silaturahmi Walikota Jambi Ke Sungai Penuh Untuk Bekerja Sama Antar Daerah','<div>Sungai Penuh- Kehadiran Walikota Jambi&nbsp; H. Maulana dan Ketua TP PKK Hj. Nadiya Maulana bersama rombongan di Kota Sungai Penuh disambut baik.</div><div>Dalam kunjungannya, disambut baik oleh Walikota Sungai Penuh, Alfin, SH di Rumah Dinas pada Jumat 1/8/2025. Hal ini sebagai momen penting untuk bekerjasama antar Daua Daerah yakni Kota Jambi dan Sungai Penuh.</div><div>Selain Itu, Wakil Walikota Sungai Penuh Azhar Hamzah, Sekretaris Daerah Alpian, Ketua TP PKK Sri Kartini Alfin, Ketua Darma Wanita Winda Alpian juga menyambut baik kedatangan Walikota Jambi.</div><div>Walikota Alfin, SH mengatakan keyakinan hubungan antar Daerah membuka peluang besar untuk mencapai pemanfaatan yang menguntungkan bagi kedua Daerah.</div><div>\"Kami meyakini hubungan antar daerah yang harmonis seperti ini akan memberikan manfaat dan kemajuan besar bagi daerah,\". sampainya&nbsp;</div><div>Searah dengan Walikota Jambi, ia mengatakan melalui silaturahmi ini dapat membuka peluang yang baik untuk bekerjasama. Tujuannya, untuk keuntungan kedua Daerah.</div><div>\"Dalam pertemuan kita kali ini, kedepannya semoga silaturahmi tetap kuat dan erat dan mampu menguntungkan kedua daerah\" [ ]</div><div>(Mc Kominfo)</div>','upload/berita/8KOZ7sRUodrEr1Uxtv00ZgZzJWct1qGTP1rl4UzP.jpg','mc','objek-kunjungan-silaturahmi-walikota-jambi-ke-sungai-penuh-untuk-bekerja-sama-antar-daerah','2025-08-05 08:38:15','2025-08-05 08:38:15'),(45,'Wawako Azhar Hamzah Hadiri Arahan Menteri Terkait Adipura Baru','<div>JAKARTA - Wakil Walikota Sungai Penuh, Azhar Hamzah menghadiri kegiatan penyampaian arahan Menteri Lingkungan Hidup/Kepala Badan Pengelola Lingkungan Hidup (BPLH) terkait pelaksanaan program Adipura. Senin 4/8/2025</div><div>Kegiatan ini juga diikuti oleh para kepala daerah dari seluruh Indonesia. Sebagai bagian dari komitmen Nasional untuk penguatan tata kelola lingkungan, khususnya dalam rangka reformulasi program Adipura yang kini mengedepankan pendekatan green leadership dan circular economy.</div><div>Menteri Lingkungan Hidup menekankan pentingnya peran kepala daerah memastikan keberlanjutan pengelolaan sampah, ruang terbuka hijau, termasuk peningkatan partisipasi masyarakat terhadap kebersihan dan pelestarian lingkungan.</div><div>Wakil Walikota Azhar Hamzah mengatakan kesiapan Kota Sungai Penuh untuk menyesuaikan standar indikator baru yang ditetapkan dalam skema Adipura Baru.</div><div>\"Ini menjadi momentum bagi kita untuk memperkuat komitmen dalam mewujudkan Sungai Penuh yang bersih, hijau, dan berkelanjutan. Kami akan mendorong kolaborasi lintas sektor dan partisipasi masyarakat secara aktif\". [ ]</div><div>(Mc Diskominfo)</div>','upload/berita/3k3eoDK8Nfqu00eCyRZ62izX7a26N6fl5oc9sxuy.jpg','mc','wawako-azhar-hamzah-hadiri-arahan-menteri-terkait-adipura-baru','2025-08-05 08:39:39','2025-08-05 08:39:39'),(46,'Tim Pembina Posyandu Kota Sungai Penuh Periode 2025-2029 Dilantik Wako Alfin','<div>SUNGAI PENUH - Tim Pembina Posyandu Kota Sungai Penuh masa bakti 2025-2029 secara resmi telah dilantik. Senin 4/8/2025</div><div>Dilantik oleh Walikota Sungai Penuh Alfin, SH. disaksikan oleh Sekda Alpian, Asisten, Staf Ahli, Para Kepala SKPD, Camat, Lurah,dan Ketua DWP Kota Sungai Penuh.&nbsp;</div><div>Ketua TP Posyandu Ny Sri Kartini Alfin dalam sambutannya mengatakan kepengurusan posyandu untuk bersama sama. Tujuanya, untuk memperkuat komitmen dalam mewujudkan masyarakat sehat dan sejahtera.&nbsp;</div><div>“Dengan amanah ini, kami ingin Posyandu di Kota Sungai Penuh menjadi semakin aktif, dekat dengan masyarakat, dan memberikan dampak nyata bagi kesehatan keluarga\'\' ujarnya.</div><div>Walikota Sungai Penuh Alfin mengatakan, sebagai ujung tombak pelayanan kesehatan dasar bagi masyarakat, khususnya ibu hamil, balita, dan lansia. Kepada seluruh tim yang dilantik untuk bekerja maksimal, bersinergi dengan pemerintah Daerah serta masyarakat.</div><div>“Posyandu adalah garda terdepan dalam pelayanan kesehatan masyarakat. Saya berharap Tim Pembina Posyandu yang baru dilantik dapat bekerja dengan penuh semangat, bersinergi dengan semua pihak, dan memberikan pelayanan terbaik bagi ibu, anak, serta masyarakat Kota Sungai Penuh\". [ ]</div><div>(Mc Diskominfo)</div>','upload/berita/KsVZUeIcKAyoGCbH5X7jiKYXhsjNk7amlwZRs8Ke.jpg','mc','tim-pembina-posyandu-kota-sungai-penuh-periode-2025-2029-dilantik-wako-alfin','2025-08-05 13:33:40','2025-08-05 13:33:40'),(47,'Wako Alfin Hadiri Ground Breaking SPPG Polres Kerinci','<div>SUNGAI PENUH- Walikota Sungai Penuh, Alfin, SH, menghadiri kegiatan Ground Breaking peletakan batu pertama pembangunan satuan Pelayanan Pemenuhan Gizi (SPPG) Polres Kerinci yang di Kompleks Asrama Polisi Kecamatan Pondok Tinggi. Rabu 6/8/2025</div><div>Acara dilakukan secara daring melalui Zoom Meeting yang diikuti oleh Kapolda Jambi Irjen Pol. Krisno H. Siregar, jajaran Kepolisian se-Provinsi Jambi. Hadir secara langsung yakni Bupati Kerinci, Kapolres Kerinci, Kodim 0417/Kerinci, Kejari Sungai Penuh, SKPD.</div><div>Dalam sambutannya, Wali Kota Alfin mengatakan apresiasi setinggi tingginya terhadap langkah Polri dalam meningkatkan fasilitas pelatihan termasuk profesionalisme Sumber Daya Manusia.</div><div>“Pemerintah daerah mendukung penuh pembangunan SPPG ini sebagai bentuk sinergi dengan aparat penegak hukum dalam menjaga keamanan dan ketertiban masyarakat\"ujarnya</div><div>Menurutnya Wako Alfin, pembangunan SPPG Polres Kerinci merupakan kebutuhan strategis. Tujuannya untuk mewujudkan Polri yang presisi, profesional, serta memiliki pendekatan yang humanis untuk melayani masyarakat.</div><div>Keberadaan SPPG juga diharapkan dapat memperkuat daya saing dan ketahanan institusi kepolisian dalam menghadapi tantangan sosial yang terus berkembang.</div><div>“Fasilitas ini akan menjadi tempat pelatihan yang modern dan representatif guna mencetak personel kepolisian yang tangguh, berintegritas dan berorientasi pada pelayanan publik. Pemerintah Kota Sungai Penuh menilai pembangunan ini selaras dengan upaya Nasional dalam membentuk masyarakat yang sehat, cerdas, dan sejahtera\'\'. [ ]&nbsp;</div><div>(Mc Kominfo)</div>','upload/berita/UrfgjGlNdHqj6irHAJ1hx0JjbxSHy0asm3J9DKK4.jpg','mc','wako-alfin-hadiri-ground-breaking-sppg-polres-kerinci','2025-08-06 11:30:26','2025-08-06 11:30:26'),(48,'Wawako Azhar Hamzah Buka Kegiatan Minilok Lintas Sektor Pencegahan Stunting','<div>SUNGAI PENUH - Minilok Lintas Sektor Kecamatan Tanah Kampung resmi dibuka oleh Wakil Walikota Sungai Penuh, Azhar Hamzah. Rabu 6/8/2025</div><div>Kegiatan ini bertujuan untuk mendukung percepatan penurunan stunting di setiap Kecamatan dalam wilayah Kota Sungai Penuh. Selain itu Wawako Azhar juga menyerahkan bantuan pangan berupa beras, telor kepada masyarakat yang beresiko stunting di Kecamatan Tanah Kampung.</div><div>Wawako, Azhar Hamzah mengatakan pentingnya kerja sama lintas sektor serta kaloborasi yang kuat antara Pemerintah Desa dan Kecamatan agar nantinya penyelesaian permasalahan stunting dapat teratasi.</div><div>\" Stunting masih menjadi salah satu permasalahan kesehatan yang harus diatasi, untuk itu melalui kegiatan ini kita berharap penanganan dan pencegahan stunting dapat berjalan efektif yang di mulai dari tingkat desa\" [ ]</div><div>(Mc Diskominfo)</div>','upload/berita/oWdpCheK6ttyHFx0o4Xe6HTJ1wOOFLtGuMVw6Tf8.jpg','mc','wawako-azhar-hamzah-buka-kegiatan-minilok-lintas-sektor-pencegahan-stunting','2025-08-07 07:16:20','2025-08-07 07:16:20'),(49,'Wawako Azhar Tinjau Pelaksanaan Normalisasi Sungai Batang Bungkal','<div>SUNGAI PENUH - Wakil Walikota Sungai Penuh, Azhar Hamzah, melakukan peninjauan langsung terhadap pelaksanaan kegiatan normalisasi Sungai Batang Bungkal. Senin 6/8/2025</div><div>Kegiatan ini merupakan bagian dari upaya Pemerintah Kota Sungai Penuh dalam mengantisipasi banjir dan menjaga kelestarian lingkungan di wilayah aliran sungai strategis tersebut.</div><div>Ada beberapa titik Normalisasi pengerjaan yang ditinjau oleh Wawako Azhar Hamzar. Pengecekkan ini sekaligus memastikan bahwa proses normalisasi berjalan sesuai dengan rencana dan standar teknis yang telah ditetapkan.</div><div>\"Dengan terlaksananya normalisasi Sungai Batang Batang Bungkal dapat kembali berfungsi optimal sebagai jalur aliran air yang bersih, tertata, dan aman bagi lingkungan sekitarnya\'\' [ ]</div><div>(Mc Diskominfo)</div>','upload/berita/PfyntFOJCW1eQYM5GW5ytPlSS2BtoqpntdA1VGGw.jpg','mc','wawako-azhar-tinjau-pelaksanaan-normalisasi-sungai-batang-bungkal','2025-08-07 07:18:11','2025-08-07 07:18:11'),(50,'Ny Sri Kartini Alfin Dilantik Sebagai Ibunda Guru Kota Sungai Penuh','<div>JAMBI- Ny Sri Kartini Alfin ditunjuk sebagai Ibunda Guru Kota Sungai Penuh. Dalam hal ini secara resmi dilantik oleh Ketua Umum Pengurus Besar Persatuan Guru Republik Indonesia (PB PGRI) Prof. Dr. Unifah Rosyidi, M.Pd. Kamis 7/8/2025&nbsp;</div><div>Bertempat di Aula Rumah Dinas Gubernur Jambi, termasuk Pengukuhan dan pelantikan Ibunda Pendidikan Provinsi Jambi dan Kabupaten/ Kota.&nbsp;</div><div>Dalam hal ini, Ibunda Pendidikan memiliki keterlibatan sebagai garda untuk membangun Dunia Pendidikan atau penggerak peningkatan kualitas Pendidikan yang berperan memberikan dorongan, sosialisasi, dan advokasi.&nbsp;</div><div>Ketua PB PGRI Prof. Dr. Unifah Rosyidi, M.Pd mengatakan. Berdasarkan surat Keputusan tentang Penetapan Ibunda Pendidikan Provinsi Jambi termasuk Kota dan Kabupaten di wilayah dimaksud yang telah menyatakan memiliki kesiapan dan berkembang.</div><div>\"Ibunda Guru diharapkan menjadi contoh dan teladan bagi para guru, termasuk memberikan memotivasi untuk terus berkarya dan meningkatkan kualitas pendidikan. Baik itu berbagai program dan kegiatan. Selain itu juga memberikan semangat para guru\"ujarnya</div><div>Ibunda Guru Kota Sungai Penuh Sri Kartini Alfin mengapresiasi pengurus besar PGRI serta memberikan dukungan baik itu kegiatan dalam memajukan Dunia Pendidikan.</div><div>\"Melalui pengukuhan ini, semoga dapat memperkuat peran organisasi guru termasuk memajukan pendidikan, memberikan perhatian, dukungan dan masukan terhadap kualitas pendidikan di Kota Sungai Penuh\" [ ]</div><div>(Mc Diskominfo)</div>','upload/berita/xi8sTYt7YGTWXVGmkV9EJTVE23FGvEElye4MH0Vo.jpg','mc','ny-sri-kartini-alfin-dilantik-sebagai-ibunda-guru-kota-sungai-penuh','2025-08-12 08:40:09','2025-08-12 08:40:09'),(51,'Wawako Azhar: Penanganan Stunting Tidak Bisa Hanya Dilakukan Dalam Satu Sektor','<div>SUNGAI PENUH- Pemerintah Kota Sungai Penuh berkomitmen untuk terus memperkuat berbagai program kesehatan masyarakat, khususnya dalam percepatan penurunan angka stunting. Tujuannya ialah menciptakan generasi yang sehat, cerdas, dan berkualitas di masa depan.</div><div>Dalam hal ini Wakil Walikota Sungai Penuh, Azhar Hamzah, didampingi Ketua GOW Kota Sungai Penuh, Marwati Azhar Hamzah dalam kegiatan Minilok (Mini Lokakarya) Lintas Sektor Tingkat Kecamatan Kota Sungai Penuh. Kunjungannya dalam rangka percepatan penurunan stunting tahun 2025.&nbsp;</div><div>Program ini merupakan lintas sektor untuk memperkuat sinergi dan koordinasi antar instansi serta pemangku kepentingan dalam menangani isu stunting yang masih menjadi tantangan di Kota Sungai Penuh.</div><div>Dalam sambutannya, Wakil Walikota Azhar Hamzah mengungkapkan pentingnya kerja sama semua pihak, baik dari pemerintah, tenaga kesehatan, tokoh masyarakat, hingga peran keluarga, dalam menekan angka stunting. Katanya saat menghadiri Kegiatan minilok di Kantor Camat Koto Baru, Kamis 7/8/2025</div><div>\"Penanganan stunting tidak bisa hanya dilakukan satu sektor saja. Harus ada kolaborasi yang kuat di tingkat kecamatan hingga ke desa dan keluarga. Kegiatan seperti ini sangat strategis dalam menyatukan persepsi dan langkah\'\' [ ]&nbsp;</div><div>(Mc Diskominfo)</div>','upload/berita/sdAl0rDOULKkuZ6ODwIgmjDaC1yRiPWdPuVjcOwb.jpg','mc','wawako-azhar-penanganan-stunting-tidak-bisa-hanya-dilakukan-dalam-satu-sektor','2025-08-12 08:45:52','2025-08-12 08:45:52'),(52,'Semarak Lomba Tradisional Pemkot Sungai Penuh','<div>SUNGAI PENUH- Dalam Rangka menyambut Hari Ulang Tahun Kemerdekaan Republik Indonesia ke-80. Pemerintah Kota Sungai Penuh menggelar lomba Trradisional.</div><div>Lomba ini diikuti oleh OPD se Kota Sungai Penuh. Bertempat di Lapangan Merdeka, dihadiri oleh Wakil Wali Kota Sungai Azhar Hamzah, Sekda Alpian, Ketua PKK, Ketua GOW, Ketua DW, dan seluruh OPD. 10/8/2025</div><div>Momen kergiatan ini tampak semarak, dibuka langsung oleh Wali Kota Sungai Penuh Alfin, SH. Cabang lomba tradisonal ini terdiri dari Balap Karung, Terompah Panjang, Tarik Tambang. Lomba-lomba tersebut diselenggarakan untuk memperkuat kerjasama antar OPD sekaligus memeriahkan HUT RI ke 80.</div><div>Wako Alfin mengatakan, Kemeriahan lomba ini bertujuan untuk memperkuat tali silaturahmi dan persaudaraan antar OPD di lingkungan Pemerintah Kota Sungai Penuh. Melalui lomba lomba tersebut, diharapkan dapat menjaga kekompakanya. Selain itu, acara ini juga diharapkan dapat memupuk solidaritas dan kerja sama dari tiap-tiap OPD.</div><div>\"perlombaan ini adalah penghormatan terhadap perjuangan para pahlawan dalam merebut dan mempertahankan kemerdekaan. Semangat patriotisme dan persatuan melalui lomba-lomba ini tidak hanya menghibur, tetapi juga menyiratkan makna yang lebih dalam. Di balik setiap gerakan lucu dan kreatif, terdapat kenangan akan perjuangan panjang dan semangat juang yang membawa bangsa ini hingga ke titik ini\"</div><div>\"Lomba lomba seperti ini adalah bukti bahwa semangat kemerdekaan tetap berkobar\".</div><div>&nbsp;(MC Diskominfosta)</div>','upload/berita/h8Md3Cw81ogJjEy9hkD0jvrWFjkCVohmqCWDQcdU.jpg','mc','semarak-lomba-tradisional-pemkot-sungai-penuh','2025-08-12 08:47:16','2025-08-12 08:47:16'),(53,'Launching 3 S, Sekda Alpian: Mencegah Dan Menangani Stunting','<div>SUNGAI PENUH- Pemerintah Kota Sungai Penuh Provinsi Jambi secara resmi telah melaunching Inovasi 3S ( Segenggam Beras, Sebutir Telur dan Seribu Rupiah). Senin 11/8/2025</div><div>Launching ini dilaksanakan di halaman Kantor Walikota Sungai Penuh. Hal ini merupakan gerakan sosial untuk mengajak seluruh Aparatur Sipil Negara (ASN) termasuk masyarakat agar berpartisipasi membantu warga yang membutuhkan. Tujuannya ialah sebagai pemenuhan gizi dan kebutuhan pokok.</div><div>Disampaikan oleh Sekretaris Daerah (Sekda) Alpian SE, MM. saat melaunching inovasi 3S, mewakili Walikota Alfin, SH. Tekannya, Kegiatan ini diakukan bersama sama karena memberikan dampak besar bagi yang membutuhkan.</div><div>&nbsp;“Perlu kita ingat, gerakan ini sederhana. Kalau dilakukan sama sama pasti akan memberikan dampak besar bagi mereka yang membutuhkan. Ini perlu untuk diketahui bahwa segenggam beras, sebutir telur dan seribu rupiah dari setiap orang bisa menciptakan kebahagiaan untuk banyak keluarga. Yakni mencegah dan menangani Stunting”tegasnya.</div><div>“Harapan kita, 3S dapat menjadi budaya gotong royong terus menerus, tumbuhkan rasa kepedulian sosial, kuatkan solidaritas kita&nbsp; di tengah tengah masyarakat Kota Sungai Penuh tercinta ini” [ ]</div><div>(Mc Diskominfosta).</div>','upload/berita/ZHbOhU8auFgufrtlIMOuoUWIF45rV88Hi7qkfwo0.jpg','mc','launching-3-s-sekda-alpian-mencegah-dan-menangani-stunting','2025-08-12 08:49:10','2025-08-12 08:49:10'),(54,'Rapat Koordinasi Pengelolaan Persampahan, Wako Alfin: Pentingnya Kebersamaan Kita','<div>SUNGAI PENUH- Walikota Sungai Penuh Alfin, SH menghadiri Rapat Koordinasi Pengelolaan Persampahan tingkat Kota Sungai Penuh. Selasa 12/8/2025</div><div>Acara ini bertempat di Gedung Aula Kantor Walikota Sungai Penuh. Adapun tema pada agenda dimaksud yakni \"Menuju Sungai Penuh Juara, bebas polusi sampah plastik dan meraih Adipura tahun 2028\".</div><div>Turut hadir yakni, Wakil Walikota Kota Sungai Penuh Azhar Hamzah, Ketua DPRD Kota Sungai Penuh Hutri Randa, Sekda Alpian, Kepala SKPD, Camat dan Kepala Desa lingkup Kota Sungai Penuh.</div><div>Dalam sambutannya Wako Alfin, SH menekankan bahwa pentingnya kerja sama dan sinergi yang baik dari semua pihak dalam menangani persampahan di Kota Sungai Penuh.</div><div>\"Pentingnya kerja sama kita dalam menangani persampahan di Kota Sungai Penuh ini demi mewujudkan Kota yang bersih, sehat dan banyak dikunjungi. Berharap langkah ini dapat berjalan seutuhnya, baik itu pada tata kelola TPS 3 R maupun masyarakat. Untuk kita ketahui bahwa tidak cukup hanya tangan Dinas Lingkungan Hidup (DLH) untuk melakukan penanganan ini yang kita butuhkan ialah kesadaran semua pihak\" pungkasnya.&nbsp;</div><div>(MC Diskominfosta)</div>','upload/berita/6hJvhjPe4eCcOXnldSufYLHZwWnOoS17e7Yd070L.jpg','mc','rapat-koordinasi-pengelolaan-persampahan-wako-alfin-pentingnya-kebersamaan-kita','2025-08-12 12:33:51','2025-08-12 12:33:51'),(55,'Kegiatan Minilok Di Kecamatan Sungai Penuh Di Buka Wawako Azhar','<div>SUNGAI PENUH - Wakil Walikota Sungai Penuh, Azhar Hamzah membuka Minilok lintas sektor di Kecamatan Sungai Penuh. Selasa 13/8/2025</div><div>Bertempat di UPTD Puskesmas Desa Gedang. Kegiatan ini melibatkan berbagai pemangku kepentingan yang terdiri dari perangkat Daerah, tenaga Kesehatan, tokoh masyarakat.</div><div>Kegiatan ini merupakan langkah dalam penguatan sinergi tentang penanganan stunting. Sebelumnya kegiatan Minilok ini juga dilakukan dibeberapa Kecamatan lingkup Kota Sungai Penuh termasuk diskusi pembahasan langkah konkrit.</div><div>Disela itu Wawako, Azhar juga menyerahkan bantuan pangan kepada masyarakat yang terdampak pada beresiko stunting di Kecamatan Sungai Penuh.</div><div>Wawako Azhar mengatakan pentingnya komitmen bersama, aksi nyata di lapangan. Dengan maksud untuk menekankan angka Stunting. Sasaran utama ialah fokus pada intervensi gizi, edukasi termasuk peningkatan kualitas layanan ibu dan anak.&nbsp;</div><div>\"Percepatan penurunan stunting tidak bisa hanya mengandalkan satu pihak, tetapi perlu dukungan seluruh elemen masyarakat. Sinergi ini menjadi kunci untuk mewujudkan generasi Sungai Penuh yang sehat, cerdas, dan berdaya saing\" [ ].</div><div>(Media Center Diskominfosta)</div>','upload/berita/TqbuDkXKyHDCmg0dwroynUS53TsnzfaLbd5Irqol.jpg','mc','kegiatan-minilok-di-kecamatan-sungai-penuh-di-buka-wawako-azhar','2025-08-13 11:01:23','2025-08-13 11:01:23'),(56,'Diskominfota Kota Sungai Penuh Mengadakan Kegiatan 3S','<div>SUNGAI PENUH- Dinas Komunikasi Informasi dan Statistik Kota Sungai Penuh melaksanakan kegiatan 3 S (Segenggam Beras, Sebutir Telur dan Seribu Rupiah). Rabu 13/8/2025</div><div>Bertempat di halaman Diskominfo Kota Sungai Penuh. Kegiatan ini sekaligus menyambut hari ulang Tahun Kemerdekaan Republik Indonesia yang ke 80.</div><div>Kegiatan 3 S ini merupakan Program dari Pemerintah Daerah Kota Sungai Penuh. Sebelumya, telah dilaunching, tujuanya untuk melakukan penanganan stunting.</div><div>Kepala Dinas Diskominfo H. Josrizal Helman, <a href=\"https://l.facebook.com/l.php?u=http%3A%2F%2FS.Si%2F%3Ffbclid%3DIwZXh0bgNhZW0CMTAAYnJpZBExbkhFSVZsRXhxeFQ5bGFDYQEe_VgZcy3E74zaAIVFbIxsBwdFAL2wb7YiSYhBn4JIpehjVEar9GCtgFzmwsE_aem_2eawQ48Mu_etCMOHAkB6Iw&amp;h=AT36JECPaIg5bHpj4N3-Je4ofKeYikPBo0bYKDrIDQaelH0ugAV4WIHYpXXmjPTrlziP3SCEBqhFlWN1ZzQnv7NI8NHIEzYBc6hgBWknKDNum7poL3-pH71bAvI5rcFWHMlr3HBegkRt2Q&amp;__tn__=-UK-R&amp;c[0]=AT2acoXfaTHQXhZJt81pEtLBE838sZboeeaJzLjf7sDoWXozG6ducNq4QFB05yCJl02FQdD_lvjJEuHz6T_uwMK9AysyZF_ODVKp3XRyp5u4RRd3fGNX6T-remEM-l_xLk0vZzMe5prkKshbBIVw4SYyJjSMzkMKYve_h5kcRIUKV01ZjAk6r1aE-jjlCZ4kWVKVelBBF6IrtHg3WeOw7FwV0A\"><strong>S.Si</strong></a>, Apt menjelaskan. Kegiatan 3 S merupakan kesadaran seluruh kerabat di Diskominfo yang terdiri dari ASN dan Non ASN dalam menjalankan himbauan Walikota dan Wakil Walikota Sungai Penuh.</div><div>“Kegiatan 3 S ini merupakan inisiatif dan gerakan seluruh ASN dan Non ASN Diskominfo Kota Sungai Penuh, yang mana inisiatifnya membawa beras, telur dan iuran. Hal ini adalah bentuk Kepedulian Diskominfo dalam mendukung penaganan Stunting dan suatu respon mejalankan Program pemerintah Daerah termasuk Intruksi Walikota dan Wakil Walikota Sungai Penuh\'\' [ ]</div><div>(Mc Diskominfosta)</div>','upload/berita/AQ1MCF3BBQFjKafYl13cKTKUgbBhKeUNksGzDMRz.jpg','mc','diskominfota-kota-sungai-penuh-mengadakan-kegiatan-3s','2025-08-14 09:59:04','2025-08-14 09:59:04'),(57,'Sambut HUT RI Ke 80, Diskominfosta Kota Sungai Penuh Gelar Lomba Tradisional','<div>SUNGAI PENUH- Dinas Komunikasi Informasi dan Statstik Kota Sungai Penuh menggelar lomba tradisional. Kegiatan ini bertujuan untuk menyambut Hari Ulang Tahun Republik Indonesia yang ke- 80. Rabu 13/8/2025</div><div>Acara ini dilaksnakan di halaman Kantor Diskominfosta Kota Sungai Penuh yang diikuti oleh ASN dan Non ASN. Selain itu, hal ini merupakan bentuk kekompakan sekaligus menjaga tali silatulrahmi.</div><div>Kepala Dinas Diskominfo Kota Sungai Penuh H. Josrizal Helman, <a href=\"https://l.facebook.com/l.php?u=http%3A%2F%2FS.Si%2F%3Ffbclid%3DIwZXh0bgNhZW0CMTAAYnJpZBExbkhFSVZsRXhxeFQ5bGFDYQEeIIDOQlChMCUdfq3u5d2_Hms7T3Ucr8JdL6wfoaASPYYjvg_peC5biKj_PMs_aem_wwBNoKKfQY-NLTRlswSAgw&amp;h=AT1AV8hBi12A7aFpgBs-x6sVIpHMTZduAmHQdZqZDE2og0gZH5Rtkz8xOI-vCfmQtl30v7PhfH2JDhankQCDJnVeKbisGBWNwuz9T8zkKLfCTVOAxrQJ2DxG_h9rAq-N0tYGvm8mGoxJvw&amp;__tn__=-UK-R&amp;c[0]=AT0Dfub08B9DSYOeEbTAF9AkVthrB9pdo9_mI_MA_Nd4gyNTsj29IU3jv2k4qpeiCy1Y2YLExLlypy8wCfcGHOnRlwlmfF6eYobpcsOnKLy4fQsYf9CWSNTfpjhIC1lXHt7ZsQqvwJb-rZyDZWo72VSQorK4JaF6bSb1nJ45K8etGyO8wmQyJh0ObLoQ36xyxZTvD8QDoIBBVob3ZTLWAOlbIg\"><strong>S.Si</strong></a>, Apt mengatakan hal ini merupakan partisipasi dalam menyambut HUT RI ke-80.&nbsp;</div><div>“Kegiatan ini sengaja diadakan guna menyambut HUT RI ke- 80. Adapun pesertanya ialah ASN dan Non ASN, kita berharap kegiatan seperti ini bisa berlanjut ditahun depan. Semoga kekompakan dan silatulrahmi kita tetap terjaga’’ [ ]. (Mc Diskominfosta)</div>','upload/berita/KQNLktEp1yiZ6TOQF5orLgGGRHLCGdqBpSBALNFL.jpg','mc','sambut-hut-ri-ke-80-diskominfosta-kota-sungai-penuh-gelar-lomba-tradisional','2025-08-14 10:00:37','2025-08-14 10:00:37'),(58,'Wawako Azhar Hamzah Pimpin Upacara Renungan Dan Ulang Janji ke-64 Hari Pramuka Kota Sungai Penuh','<div>SUNGAI PENUH - Suasana khidmat menyelimuti Lapangan Kantor Wali Kota Sungai Penuh saat Kwartir Cabang (Kwarcab) Gerakan Pramuka Kota Sungai Penuh menggelar upacara Renungan Dan&nbsp; ulang janji memperingati Hari Pramuka ke-64 pada Rabu malam (13/8/2025).</div><div>Upacara dipimpin langsung oleh Wakil Wali Kota Sungai Penuh, Azhar Hamzah, dan diikuti jajaran pengurus Kwarcab, para pembina, serta anggota Pramuka dari berbagai gugus depan.</div><div>Rangkaian prosesi dimulai dengan penyalaan api unggun oleh Pemimpin Upacara sebagai simbol semangat, keberanian, dan pengabdian yang tak pernah padam. Setelah itu, dilanjutkan dengan pengucapan ulang janji Pramuka, yang menjadi momen peneguhan komitmen seluruh anggota dalam menjunjung tinggi nilai Dwi Satya dan Dwi Dharma.</div><div>Dalam amanatnya, Azhar Hamzah menegaskan bahwa renungan dan ulang janji bukan hanya tradisi tahunan, melainkan juga pengingat akan peran Pramuka sebagai wadah pembinaan generasi muda yang berkarakter, disiplin, dan peduli terhadap sesama.</div><div>“Api unggun yang kita nyalakan malam ini adalah simbol semangat yang harus terus menyala. Melalui ulang janji, kita meneguhkan kembali tekad untuk mengabdi kepada bangsa dan negara,” ujarnya.</div><div>Upacara ini menjadi pembuka rangkaian peringatan Hari Pramuka ke-64 di Kota Sungai Penuh, yang akan diisi dengan kegiatan sosial dan berbagai agenda pembinaan anggota. (Mc Diskominfosta)</div>','upload/berita/4nZamoQ4jzxMAMmDKqhJPYdYYHLSJqXVAIWM5j6N.png','mc','wawako-azhar-hamzah-pimpin-upacara-renungan-dan-ulang-janji-ke-64-hari-pramuka-kota-sungai-penuh','2025-08-14 10:02:46','2025-08-14 10:02:46'),(59,'Diskominfosta Sungai Penuh Bersama Pers Galang Gerakan 3S Dukung Atasi Stunting','<div>BERITA SUNGAI PENUH- Dalam semangat menyambut HUT Kemerdekaan RI ke-80, Dinas Komunikasi, Informatika, dan Statistik (Diskominfosta) Kota Sungai Penuh bersama insan pers menggelar gerakan 3S – Segenggam Beras, Sebutir Telur, Seribu Rupiah. 14/8/2025</div><div>Inssan Pers yang dimaksud mewakili Wartawan Kota Sungai Penuh dan Kabupaten Kerinci. Kepala Diskominfosta, H. Josrizal Helman, <a href=\"https://l.facebook.com/l.php?u=http%3A%2F%2FS.Si%2F%3Ffbclid%3DIwZXh0bgNhZW0CMTAAYnJpZBExS25yYXBuU09uZ3M2SThjcQEePB42IDM-BhTq7vK5MX5RHtAzjTVO3vrUV2Rv7DXm4p_Vte8OsxfJGBjikbk_aem_e0ch9wS2D01sT8KRUKj4Mg&amp;h=AT0waqM1rSche5_lb9PIUWKDtW7t9eYrbAzMT9JgC01g96p-kv4BpGySLHGICyfuMvFQ0xmNe7HrQ_JdU-bXPaJzVt97BXXDP7uQvdcQARmT5dVOpbFozBLFBFME-3dqyt4hOX8SswTM3A&amp;__tn__=-UK-R&amp;c[0]=AT1_5-t8xJx19zifmrG9eglJsV897TmNMG_50Z96LAo281t1qwX9syzv0hUHbrGY5vDoESwK6ExU6e7IPvvUcAhDvhaSmGUSX_5Wro9og5ZRIYB9-AHY8upBWMSPR5hHuoOgOJwJZ5ABHWQT7w7-3TvPfRu8cFeRXgRQqkzyikAKVBNcBxmapiMuit1OvsHU6JnuieZ1h16tAmScMtdW0fnDBg\"><strong>S.Si</strong></a>, Apt, mengatakan gerakan ini merupakan tindak lanjut instruksi Wali Kota dan Wakil Wali Kota Sungai Penuh untuk mendukung program penanganan stunting.&nbsp;</div><div>“ASN dan Non ASN datang membawa beras, telur, dan sumbangan seribu rupiah. Ini bentuk kepedulian kami sekaligus dukungan nyata terhadap program pemerintah daerah,” ujarnya.</div><div>Kegiatan ini menjadi bukti bahwa kepedulian dapat dimulai dari langkah sederhana. Setiap beras, telur, dan rupiah yang terkumpul menjadi simbol solidaritas demi memastikan anak-anak Sungai Penuh tumbuh sehat dan bebas stunting.</div><div>Suasana hangat terasa sejak pagi hingga siang, diwarnai senyum tulus, tangan yang saling membantu, dan persaudaraan antara pemerintah, insan pers, serta masyarakat. Gerakan ini mengingatkan bahwa makna kemerdekaan sejati adalah ketika kita saling peduli dan berbagi.</div><div>(Mc Diskominfo)</div>','upload/berita/p96CuwytA7J56FB674pVoSD0Sdwsb2qQQ3UkFWwb.jpg','mc','diskominfosta-sungai-penuh-bersama-pers-galang-gerakan-3s-dukung-atasi-stunting','2025-08-15 07:14:59','2025-08-15 07:14:59'),(60,'Apel Besar Hari Pramuka ke-64, Arahan Wako Alfin: Mari Dijadikan Bekal Masa Depan','<div>SUNGAI PENUH- Walikota Sungai Penuh memimpin Apel besar Hari Pramuka yang ke- 64 tahun 2025 yang diikuti oleh ratusan anggota Gerakan Pramuka terdiri dari tingkat siaga, penggalang, penegak, hingga pandega serta para pembina, tokoh masyarakat, dan unsur Forkopimda.</div><div>Apel yang dipimpin Wako Alfin Walikota Sungai Penuh, Alfin, SH bertindak sebagai inspektur bertempat di Lapangan Merdeka Kota Sungai Penuh, Kamis 14/8/2025</div><div>Dalam hal ini Wako Alfin apresiasi pada seluruh anggota Pramuka yang terus menjaga semangat persatuan, disiplin, dan pengabdian kepada masyarakat. Selain itu juga ditampilkan keterampilan baris berbaris, yel yel kreatif, dan atraksi pionering dari berbagai pangkalan Pramuka.</div><div>Wako Alfin menambahkan bahwa nila pramuka membentuk generasi muda yang berkarakter, kreatif, dan berkontribusi bagi bangsa.</div><div>\"Gerakan Pramuka bukan hanya kegiatan seremonial, tetapi wadah pembentukan watak, keterampilan, dan kepemimpinan. Mari kita jadikan semangat Pramuka sebagai bekal menghadapi tantangan global, tanpa meninggalkan jati diri bangsa\" [ ]</div><div>(Mc Diskominfo)</div>','upload/berita/qnaiqQAhmqMD65UTDdqQhFshYBBSCbKF7pU2eDCq.jpg','mc','apel-besar-hari-pramuka-ke-64-arahan-wako-alfin-mari-dijadikan-bekal-masa-depan','2025-08-15 07:18:02','2025-08-15 07:18:02'),(61,'Wako Alfin Berkunjung Ke Panti Asuhan Di Kota Sungai Penuh','<div>SUNGAI PENUH- Walikota Sungai Penuh Alfin SH dan Ketua TP PKK Kota Sungai Penuh Sri Kartini Alfin melakukan kunjungan sosial ke Panti Asuhan Anjangsana.</div><div>Adapun kunjungan Walikota Sungai Penuh dan Ketua PKK Kota Sungai Penuh yakni ke Panti asuhan Putera Aisyah dan Panti Asuhan Yatim Putri Muhammadiyah. Jumat 1516/08/2025</div><div>Kunjungan ini merupakan bagian dari rangkaian kegiatan sosial Pemerintah Kota Sungai Penuh dalam rangka memperingati HUT Kemerdekaan Republik Indonesia yang ke 80.</div><div>Dalam kunjungan tersebut, Walikota didampingi oleh Wakil Walikota, Ketua DPRD, Forkopimda, Sekda, Asisten, Staf Ahli, Kepala OPD, Ketua TP PKK, Ketua GOW dan Camat Lingkup Kota Sungai Penuh.&nbsp;</div><div>Kunjungan ini tidak hanya bertujuan untuk bersilaturahmi dengan anak-anak asuh di panti asuhan, tetapi juga untuk menyalurkan bantuan berupa uang, kebutuhan pokok dan peralatan sekolah.</div><div>Walikota Alfin menyampaikan dedikasinya terhadap pengurus panti asuhan atas keikhlasan hatinya dalam mengasuh dan membimbing anak anak disini, semoga segala kebaikan itu dicatat sebagai ladang pahala buat bapak ibu semua.&nbsp;</div><div>Panti asuhan Aisyiyah semakin menunjukkan konsistensi dan kemanfaatannya dalam membina dan mendidik anak asuh yang kurang beruntung mulai dari yatim piatu, fakir miskin sampai anak-anak terlantar yang mempunyai hak yang sama dengan anak-anak yang lainnya dan dalam Undang-undangpun eksistensinya sudah dijamin seratus persen. Dalam pelaksanaan misi sosial tersebut terkadang para pengelola mengalami berbagai permasalahan yang membutuhkan bantuan pihak lain.</div><div>Untuk itulah Pemkot Sungai Penuh setiap tahunnya secara bergilir melakukan kegiatan anjang sana ke panti asuhan Putra Aisyiyah dan Panti Asuhan Yatim Putri Muhammadiyah Kota Sungai Penuh secara selektif dengan memberikan bantuan dan pembinaan sehingga sedikit permasalahan yang dihadapinya dapat terbantu penyelesaiannya.</div><div>Anjang sana merupakan rangkaian kegiatan peringatan Hari Ulang Tahun Republik Indonesia ke- 80. Selain untuk bersilaturahmi anjang sana juga bertujuan berbagi rasa kebahagiaan dan rasa kasih sayang dengan anak-anak yang ada di panti asuhan ini. Pimpinan panti asuhan Aisyiyah sangat berterima kasih atas sumbangan yang diberikan pihak Pemkot Sungai Penuh. Karena sedikit banyak membantu anak panti dalam menjalankan aktifitas di panti.</div><div>Walikota Sungai Penuh Alfin merasa terharu dan senang dengan penampilan mereka. Alfin menutup acara tersebut dengan harapan semoga sumbangan yang diberikan pemkot Sungai Penuh dapat memberikan manfaat kepada anak panti. Dan kedepannya anak panti dapat memberikan prestasi yang lebih baik untuk kemajuan panti asuhan Putra Aisyiyah dan Panti Asuhan Yatim Putri Muhammadiyah khususnya dan Kota Sungai Penuh pada umumnya. [ ]</div><div>(MC Diskominfosta)</div>','upload/berita/RqDf9MwfubtPwuCXvqPU6SveFq4dUCpFnecLfXVv.jpg','mc','wako-alfin-berkunjung-ke-panti-asuhan-di-kota-sungai-penuh','2025-08-19 11:58:39','2025-08-19 11:58:39'),(62,'WAKO ALFIN IKUTI PARIPURNA DPRD KOTA SUNGAI PENUH','<div>SUNGAI PENUH- Wali Kota Sungai Penuh Alfin mengikuti dan mendengar sidang tahunan MPR RI dan pidato kenegaraan Presiden Republik Indonesia dalam rangka HUT ke 80 Kemerdekaan RI dalam sidang bersama Tahunan DPR RI – DPD RI Tahun 2025 serta mengikuti dan mendengar pidato ketua DPR RI dalam rangka pembukaan masa persidangan I tahun sidang 2025 - 2026 dan pidato Presiden Republik Indonesia dalam rangka penyampaian RUU tentang APBN tahun anggaran 2026 disertai nota keuangan dan dokumen pendukungnya.&nbsp;</div><div>Rapat Paripurna DPRD ini dilaksanakan di Ruang Sidang DPRD Kota Sungai Penuh, pada Jum\'at (15/08) pagi. Rapat Paripurna juga dihadiri Wakil Wali Kota, Forkopimda, pimpinan dan anggota DPRD Kota Sungai Penuh, Sekretaris Daerah, Kepala OPD, Ketua TP PKK, Ketua GOW dan Camat se-Kota Sungai Penuh. 15/8/2028</div><div>Forum dipimpin oleh Ketua DPRD Kota Sungai Penuh Hutri Randa, dengan menyaksikan dan mendengarkan Pidato Kenegaraan Presiden RI Prabowo Subianto melalui live streaming. Dengan tema “Bersatu, Berdaulat, Rakyat Sejahtera, Indonesia Maju” &nbsp;</div><div>Salah satu arahan yang ditekankan oleh sosok yang akrab disapa Prabowo Subianto ini adalah&nbsp;</div><div>Dalam rangka mengenang kembali jasa-jasa para pahlawan bangsa. Marilah kita memohon kepada Allah SWT. Semoga segala pengorbanan mereka memperoleh balasan yang setimpal, dan kita selaku generasi penerus senantiasa dapat terus mensyukuri, dan menjaga anugerah kemerdekaan ini.</div><div>(Mc Diskominfosta)</div>','upload/berita/jYxqRyRmisjsAomM7LAV0fhRUDQZDMSdoEO5WoRS.jpg','mc','wako-alfin-ikuti-paripurna-dprd-kota-sungai-penuh','2025-08-19 12:00:15','2025-08-19 12:00:15'),(63,'Pasukan Pengibar Bendera Pusaka Resmi Dikukuhkan Wako Alfin','<div>SUNGAI PENUH- Walikota Sungai Penuh Alfin, SH mengukuhkan anggota Pasukan Pengibar Bendera Pusaka (Paskibraka) untuk Upacara Hari Ulang Tahun (HUT) ke 80 Republik Indonesia. Jum\'at 15/8/2025&nbsp;</div><div>Sebanyak 30 orang anggota Paskibraka Kota Sungai Penuh. Terdiri dari 16 laki laki dan 14 perempuan. Mereka adalah orang orang yang siap melaksanakan amanah, tanggung jawab sebagai pengibar bendera merah putih.&nbsp;</div><div>Pengukuhan ini bertempat di Gedung Aula Kantor Walikota Sungai Penuh. Dihadiri oleh, Wakil Walikota Azhar Hamzah, Forkopimda, DPRD, Sekda Alpian, Ketua Tp PKK, Ketua Gow, Ketua Dharma Wanita dan para Kepala SKPD.&nbsp;</div><div>Walikota Alfin, SH menyampaikan Paskibraka&nbsp; adalah orang orang terpilih dan sebagai generasi muda yang potensial dan berbakat.&nbsp;</div><div>\"Laksanakan amanah ini dengan penuh tanggung jawab. Mari menjaga marwah Kemerdekaan Republik Indonesia. Melalui pengukuhan ini, anggota Paskibraka merupakan orang orang terpilih, berprestasi dan memiliki bakat sebagai generasi muda\" [ ]&nbsp;</div><div>(MC Diskominfosta)</div>','upload/berita/8VlKveDZqveEdAxc5iG7QZAHADbfrhF9Kz2wJd5N.jpg','mc','pasukan-pengibar-bendera-pusaka-resmi-dikukuhkan-wako-alfin','2025-08-19 12:01:31','2025-08-19 12:01:31'),(64,'Penjemputan Duplikat Bendera Merah Putih','<div>SUNGAI PENUH- Upacara Hari Ulang Tahun (HUT) ke-80 Republik Indonesia diawali dengan penjemputan duplikat Bendera Merah Putih di Rumah Dinas Walikota Sungai Penuh. minggu 17/8/2025</div><div>Penjemputan duplikat Bendera Merah Putih di rumah dinas Walikota Sungai Penuh merupakan bagian dari rangkaian acara peringatan Hari Ulang Tahun (HUT) ke-80 Kemerdekaan Republik Indonesia.</div><div>Prosesi khidmat ini diawali di Aula Rumah Dinas Walikota Sungai Penuh, dengan penyerahan Duplikat Bendera Merah Putih oleh Walikota Sungai Penuh Alfin kepada Pasukan Pengibar Bendera Pusaka (Paskibraka) Kota Sungai Penuh. Selanjutnya, pasukan membawa bendera menuju Lapangan Merdeka Kota Sungai Penuh dalam iringan upacara resmi.</div><div>Turut hadir dalam acara ini, yakni Wakil Walikota Sungai Penuh, Pimpinan DPRD, Forkopimda, Sekda, Ketua TP PKK Kota Sungai Penuh, Ketua GOW dan Ketua DW Kota Sungai Penuh.</div><div>Penyerahan dan pengibaran duplikat Bendera Pusaka memiliki makna simbolis penting dalam memperingati kemerdekaan dan menjaga semangat persatuan bangsa.&nbsp;</div><div>(Mc Diskominfo)</div>','upload/berita/iWjTjPRAqXubTh4jxQFfnnaqUx5HHOKCfYCrv0IF.jpg','mc','penjemputan-duplikat-bendera-merah-putih','2025-08-19 12:03:14','2025-08-19 12:03:14'),(65,'Renungan Suci: Wako Alfin Beri Penghormatan Dan Mengenang Pahlawan Bangsa Indonesia','<div>KERINCI- Walikota Sungai Penuh Alfin, SH memberikan penghormatan serta mengenang Pahlawan perjuangan bangsa Indonesia.</div><div>Penghormatan yang diberikan oleh Walikota Sungai Penuh Alfin yakni saat pelaksanaan Apel Renungan Suci di Makam Pahlawan Desa Semumu Kecamatan Depati Tujuh Kabupaten Kerinci. 17/8/2025</div><div>Bersama Bupati Kerinci Monadi, Wakil Walikota Sungai Penuh Azhar Hamzah, Forkopimda, DPRD. Apel pada renungan suci ini dipimpin oleh Komandan Kodim 0417 Kerinci Letkol Inf. Eko Budiarto.</div><div>Renungan suci adalah penghormatan serta mengenang parah pahlawan yang telah berkorban untuk meraih Kemerdekaan Republik Indonesia. &nbsp;</div><div>Walikota Sungai Penuh Alfin,S.H mengatakan melalui renungan suci terdapat makna yakni mengajarkan keberanian dan tanggung jawab.</div><div>“Harapan kita semoga menjadi inspirasi bagi generasi penerus untuk melanjutkan perjuangan, menjaga nilai nilai kemerdekaan RI. Momen ini juga sebagai makna untuk menjaga persatuan kita. [ ]</div><div>(Mc Diskominfosta)</div>','upload/berita/ooe8OW86IHTCNi2EJpOygHMrpPzfFIPAPkJNMKMW.jpg','mc','renungan-suci-wako-alfin-beri-penghormatan-dan-mengenang-pahlawan-bangsa-indonesia','2025-08-19 12:04:29','2025-08-19 12:04:29'),(66,'Wako Alfin Hadiri Penyerahan Remisi HUT RI ke-80 di Rutan Kelas IIB','<div>SUNGAI PENUH- Dalam rangka memperingati Hari Ulang Tahun (HUT) ke-80 Republik Indonesia, Rumah Tahanan Negara (Rutan) Kelas IIB Sungai Penuh menggelar acara penyerahan remisi bagi warga binaan, Minggu (17/8/2025).</div><div>Acara tersebut dihadiri oleh Walikota Sungai Penuh, Alfin, didampingi Wakil Walikota Sungai Penuh, Azhar Hamzah. Turut hadir Bupati dan Wakil Bupati Kerinci, Ketua DPRD Kota Sungai Penuh, Dandim 0417/Kerinci, jajaran Polres Kerinci, Kepala Transmigrasi Kerinci, Perwakilan Kejaksaan, serta sejumlah pejabat SKPD lingkup Kota Sungai Penuh.</div><div>Dalam sambutannya, Walikota Sungai Penuh menyampaikan apresiasi terhadap upaya pembinaan di Rutan. Ia berharap momen remisi ini dapat menjadi motivasi bagi warga binaan untuk memperbaiki diri dan menjadi pribadi yang lebih baik setelah bebas nanti.</div><div>“Remisi merupakan bentuk penghargaan pemerintah kepada warga binaan yang telah berkelakuan baik serta mengikuti program pembinaan selama menjalani masa hukuman. Kami ingin warga binaan yang mendapat remisi bisa benar-benar mengambil hikmah, agar kelak kembali ke masyarakat dengan bekal yang lebih positif,” ujar Walikota Alfin.</div><div>Kepala Rutan Kelas IIB Sungai Penuh menambahkan, pada tahun 2025 sebanyak 226 orang warga binaan menerima remisi. Terdiri dari 90 orang penerima Remisi Umum dan 136 orang penerima Remisi Dasawarsa. Untuk Remisi Umum diberikan pemotongan masa hukuman selama 3 bulan, sedangkan Remisi Dasawarsa diberikan selama 90 hari.</div><div>Walikota Sungai Penuh juga menegaskan bahwa pemerintah daerah siap mendukung program pembinaan, sehingga para mantan warga binaan dapat diterima kembali di tengah masyarakat, aktif dalam kegiatan sosial, serta tidak mengulangi perbuatan yang melanggar hukum. [ ]</div><div>(MC. Diskominfo)</div>','upload/berita/rDEEJd2u1BiajqM16nggwxL5y3WXdU3qu095Z83n.jpg','mc','wako-alfin-hadiri-penyerahan-remisi-hut-ri-ke-80-di-rutan-kelas-iib','2025-08-19 12:06:08','2025-08-19 12:06:08'),(67,'Pemkot Sungai Penuh Gelar Malam Resepsi Kenegaraan HUT RI Ke 80','<div>SUNGAI PENUH- Pemerintah Kota Sungai Penuh menggelar Malam Resepsi Kenegaraan dalam rangka memperingati Hari Ulang Tahun (HUT) ke-80 Republik Indonesia, Minggu malam (17/8), di Aula Kantor Walikota Sungai Penuh. Acara ini berlangsung meriah dengan suasana kebersamaan yang hangat.</div><div>Wali Kota Alfin yang hadir didampingi Ketua TP PKK, Ny. Sri Kartini Alfin, serta Wakil Walikota Azhar, menyampaikan bahwa resepsi kenegaraan menjadi momen penting untuk merayakan kemerdekaan dan mempererat silaturahmi.</div><div>“Terima kasih kepada seluruh petugas upacara yang telah menjalankan tugas dengan penuh kehormatan. Kalian adalah kebanggaan Kota Sungai Penuh dan teladan bagi generasi muda,” ujar Wali Kota Alfin.</div><div>Acara ini dihadiri oleh Ketua DPRD Hutri Randa beserta anggota DPRD, unsur Forkopimda, Sekda, para Asisten, Kepala SKPD, Ketua GOW, Ketua DWP, anggota Paskibraka, dan tamu undangan lainnya. Kehadiran berbagai unsur ini menegaskan kebersamaan seluruh elemen pemerintah dan masyarakat dalam merayakan kemerdekaan.</div><div>Di akhir acara, Wali Kota Alfin dan Wakil Walikota Azhar bersama Ketua DPRD dan unsur Forkopimda menyerahkan piagam penghargaan Lomba Tradisional antar SKPD. Acara kemudian dilanjutkan dengan hiburan, menandai rasa syukur dan kebersamaan atas kemerdekaan yang diraih para pendahulu bangsa. [ ]</div><div>(Mc Diskominfo)</div>','upload/berita/WlEx5hnKEl0PYrjwFtHV6ugEWNRqPniAtgBETePA.jpg','mc','pemkot-sungai-penuh-gelar-malam-resepsi-kenegaraan-hut-ri-ke-80','2025-08-19 12:08:02','2025-08-19 12:08:02'),(68,'Wako dan Wawako  Lepas Pawai Pembangunan dan Barisan Indah HUT RI ke-80','<div>SUNGAI PENUH – Pemerintah Kota Sungai Penuh menggelar Pawai Pembangunan, Pawai Budaya, serta Lomba Barisan Indah dalam rangka memeriahkan Hari Ulang Tahun (HUT) ke-80 Kemerdekaan Republik Indonesia Tahun 2025. Kegiatan dipusatkan di Lapangan Merdeka Kota Sungai Penuh dan secara resmi dilepas oleh Walikota Sungai Penuh, Alfin, SH, Senin (18/8/25).</div><div>Pawai Barisan Indah berlangsung penuh semangat dan antusiasme. Ribuan peserta dari pelajar SD, SMP hingga SMA menampilkan barisan rapi, kreatif, sekaligus menjadi hiburan bagi masyarakat yang memadati rute pawai.</div><div>Tercatat sebanyak 10 Sekolah Dasar (SD), 16 Sekolah Menengah Pertama (SMP), dan 13 Sekolah Menengah Atas (SMA) ikut serta dalam lomba barisan indah. Suasana semakin semarak dengan penampilan drum band dari 17 SD dan 6 SMP yang memukau penonton.</div><div>Turut dihadiri yakni jajaran Forkopimda Kota Sungai Penuh, Wakil Wali Kota Azhar Hamzah, Sekretaris Daerah Alpian, SE, MM, Ketua TP-PKK Ny. Sri Kartini Alfin, Ketua GOW, Ketua Dharma Wanita.</div><div>Dalam sambutannya, Wali Kota Alfin menyampaikan apresiasi atas antusiasme peserta dan dukungan masyarakat.</div><div>“Pawai ini bukan hanya menjadi ajang perlombaan, tetapi juga momentum memperkuat semangat persatuan dan kebersamaan dalam membangun Kota Sungai Penuh yang lebih maju\'\'katanya.</div><div>(Mc Diskominfosta)</div>','upload/berita/lBJceMcwMf0MiiHk8BVlKhmA0ZWqGAGSiKqI4b7C.jpg','mc','wako-dan-wawako-lepas-pawai-pembangunan-dan-barisan-indah-hut-ri-ke-80','2025-08-19 12:09:39','2025-08-19 12:09:39'),(69,'Sistem Pengelolaan Sampah, Wako Alfin: Ini Penting','<div>SUNGAI PENUH- Walikota Sungai Penuh Alfin menekankan bahwa system pengelolaan persampahan merupakan hal yang terpenting.</div><div>Hal ini sebagai target terhadap pengurangan sampah yang ada di Kota Sungai Penuh. Menurutnya, sampah merupakan bagaian utama yang perlu diatasi dengan bijak. Maksudnya ialah agar tata kelola dapat berjalan optimal sebagai mana mestinya.</div><div>Aadapun sasaran utama ialah dengan memanfaatkan TPS 3 R aktif atau Bank Sampah. Tujuanya ialah agar benar benar dapat terintegrasi. Sebagai upaya yang telah dilakukan yakni mendaur ulang atau pengolahan yang dapat menghasilkan manfaat bagi kebutuhan masyarakat. Seperti, pupuk jenis kompos dan lain sebagainya.&nbsp;</div><div>Dalam hal ini Pemerintah Kota Sungai Penuh telah melakukan upaya atau dorongan ke SKPD ataupun himbuan melalui sektor Pendidikan.</div><div>Wako Alfin juga telah berkoordinasi dengan Pemerintah Pusat. Katanya, penanganan ini tidak hanya cukup dilakukan oleh Dinas Lingkungan Hidup. Ungkapnya saat rapat koordinasi tentang Persampahan di Aula Kantor Walikota Sungai Penuh pada Selasa 12/8/2025</div><div>“Persoalan ini menjadi hal yang utama untuk mewujdkan Kota Kita benar benar benar bersih atau bebas dari sampah. Ini penting, mulai dari lingkungan yang ada di setiap Desa Lingkup Kota Sungai Penuh. Penanganan juga diminta Kepala Desa agar terus melakukan tata kelola sampah dengan baik dengan cara menghimbau masyarakat untuk terus menjaga kebersihan lingkungan. Tidak hanya itu, SKPD, Sekolah juga ikut terlibat. Target kita ialah demi Kota bersih dan banyak&nbsp; dikunjungi\" pungkasnya.</div><div>(Mc Diskominfo)</div>','upload/berita/OYg86WPoF6sbGuGt6S0R72OAMrtwySxs2LcsynUm.jpg','mc','sistem-pengelolaan-sampah-wako-alfin-ini-penting','2025-08-21 10:19:53','2025-08-21 10:19:53'),(70,'Kreatif: Anak Hebat Indonesia Maju Di Penampilan Carnaval TK Kota Sungai Penuh','<div>SUNGAI PENUH – Momentum kegiatan kreatif Carnaval Murid Taman Kanak kanak RA se Kota Sungai Penuh dalam memeriahkan Hari Ulang Tahun Republik Indonesia ke 80. Acara berlangsung meriah, diselenggarakan oleh Ikatan Guru Taman Kanak-kanak Indonesia (IGTKI) PGRI.&nbsp;</div><div>Kegiatan ini berbentuk pawai dengan kostum model budaya Kota Sungai Penuh dan lain sebagainya. Acara tampak berlangsung meriah. Momen ini juga merupakan edukasi anak serta pameran barisan dalam menysukseskan HUT RI ke 80 di Kota Sungai Penuh.</div><div>Dalam semangat memeriahkan hari kemerdekaan kegiatan ini juga Bertema Anak Hebat, Indonesia Maju Terus Melaju untuk Indonesia Maju. Sekaligus memperingati Hari Anak Nasional (HAN)</div><div>Dibuka oleh Walikota Sungai Penuh, Alfin, SH didampingi oleh Ketua TP PKK Sri Kartini Alfin, Sekda Alpian, Ketua DWP, Ketua Bhayangkari termasuk&nbsp; Dinas terkait. bertempat di Jalan Protokol Lapangan Merdeka. Selasa 19/8/2025</div><div>Walikota Alfin apresiasi dengan kegiatan ini. Baginya anak anak adalah generasi penerus bangsa. Dididiklah mereka dan bekali dengan semangat kebangsaan.</div><div>\"Peringatan Hari Anak Nasional sekaligus momentum HUT RI ke 80 ini menjadi pengingat bagi kita semua bahwa anak hebat adalah investasi masa depan bangsa atau generasi penerus’’. [ ]</div><div>(Mc Diskominfosta)</div>','upload/berita/8qB86sJTwS5lQzdZg1h5kysSUMO02cjiAxTvhqdu.jpg','mc','kreatif-anak-hebat-indonesia-maju-di-penampilan-carnaval-tk-kota-sungai-penuh','2025-08-21 10:21:42','2025-08-21 10:21:42'),(71,'Kemenkes RI Anugerahkan Sertifikat Eliminasi Kusta dan Frambusia untuk Kota Sungai Penuh','<div>SUNGAI PENUH- Pemerintah Kota Sungai Penuh kembali menorehkan prestasi membanggakan di bidang kesehatan. Walikota Sungai Penuh, Alfin, SH secara resmi menerima Sertifikat Eliminasi Kusta dan Sertifikat Bebas Frambusia dari Menteri Kesehatan Republik Indonesia.</div><div>Penyerahan penghargaan tersebut berlangsung di Ruang Siwabessy, Gedung Sujudi Kemenkes RI, Jakarta, Rabu (20/8/2025).</div><div>Penghargaan ini menjadi bukti nyata keberhasilan Kota Sungai Penuh dalam memenuhi standar kesehatan masyarakat yang tinggi. Capaian tersebut juga menegaskan komitmen pemerintah daerah untuk terus melindungi serta meningkatkan kualitas hidup warganya.</div><div>Walikota Alfin menyampaikan apresiasi dan rasa bangga atas pencapaian ini. Menurutnya, keberhasilan tidak lepas dari kerja keras Dinas Kesehatan Kota Sungai Penuh, jajaran tenaga kesehatan, serta dukungan penuh dari masyarakat.</div><div>“Sinergi dan kepedulian bersama telah mengantarkan Kota Sungai Penuh meraih prestasi ini. Penghargaan ini adalah hasil dari komitmen kita semua dalam menjaga kesehatan lingkungan dan diri sendiri,” ungkapnya.</div><div>Dengan diraihnya sertifikat tersebut, Pemkot Sungai Penuh berkomitmen memperkuat program kesehatan masyarakat. Pemerintah akan terus meningkatkan pelayanan, memperluas upaya pencegahan penyakit, dan menjaga keberlanjutan sebagai kota yang sehat, maju, dan sejahtera.</div><div>Penghargaan dari Kemenkes ini diharapkan menjadi motivasi seluruh jajaran dan masyarakat untuk terus berperan aktif dalam menciptakan lingkungan yang bebas penyakit serta meningkatkan derajat kesehatan bersama. [ ]</div><div>( Mc Diskominfo)</div>','upload/berita/pH51CPx4CIoa7oBAFi6afdLLd3NJaYMhaKydvBR5.jpg','mc','kemenkes-ri-anugerahkan-sertifikat-eliminasi-kusta-dan-frambusia-untuk-kota-sungai-penuh','2025-08-21 10:23:34','2025-08-21 10:23:34'),(72,'Pemkot Sungai Penuh Gelar Fun Run 2025, Sosialisasi Stunting dan 3S','<div>Sungai Penuh -&nbsp; Pemerintah Kota Sungai Penuh kembali menggelar Fun Run 2025 sebagai bagian dari sosialisasi pencegahan stunting dan gerakan 3S (Secanting Beras, Sebutir telur dan Seribu Rupiah) Kegiatan berlangsung meriah di Lapangan Merdeka Kota Sungai Penuh, Minggu 24/8/2025</div><div>Event Fun Run tahun 2025, dilepas langsung oleh Wali Kota Sungai Penuh, Alfin, SH didampingi Ketua DPRD Hutri Randa, Wakil Wali Kota Azhar Hamzah, Sekda Alpian, Ketua TP-PKK Kota Sungai Penuh, serta sejumlah pejabat dan tamu undangan.</div><div>Kegiatan Fun Run diikuti lebih dari 500 peserta, tidak hanya dari Sungai Penuh dan Kerinci, tetapi juga dari berbagai daerah mulai Jambi hingga Bali. Para peserta menempuh jarak 5 kilometer dengan rute start dari Lapangan Merdeka, melewati Pos Polantas, Kantor Lurah Sungai Penuh, Simpang 5, Kantor Pajak KPPN, Masjid Raya, Jalan Baru Desa Gedang, Dinas Perpustakaan, SMA 1, MAN 2, Simpang Raya, Simpang Panik, Bundaran PKK, dan kembali finish di Lapangan Merdeka.</div><div>Dalam sambutannya, Wali Kota Alfin menyampaikan apresiasi atas dukungan berbagai pihak. Ia menegaskan bahwa Fun Run bukan hanya kegiatan olahraga, melainkan juga ajang mempererat persaudaraan, menumbuhkan kesadaran hidup sehat, serta bagian dari komitmen bersama untuk menurunkan angka stunting.</div><div>“Mari kita jaga kebersihan kota, jangan membuang sampah sembarangan, agar Sungai Penuh menjadi kota yang sehat dan layak dikunjungi wisatawan,” ujar wakoAlfin.</div><div>Selain Fun Run, Pemkot Sungai Penuh juga menggelar pelatihan wirausaha muda untuk mendorong generasi muda menjadi pelaku ekonomi kreatif, serta sosialisasi bahaya narkoba sebagai upaya melindungi generasi dari ancaman narkotika.</div><div>Kegiatan ini mendapat dukungan dari berbagai sponsor dan komunitas yang turut menyukseskan acara. Dengan terselenggaranya Fun Run 2025, Pemkot Sungai Penuh berharap semangat hidup sehat, kebersamaan, dan kepedulian terhadap pencegahan stunting semakin tumbuh di tengah masyarakat. [ ]</div><div>(MC Diskominfo)</div>','upload/berita/xHVBsE0rMLg1YrTYPZ8gfTWuBuFZ5SO8Krs6j8xo.jpg','mc','pemkot-sungai-penuh-gelar-fun-run-2025-sosialisasi-stunting-dan-3s','2025-08-25 10:41:39','2025-08-25 10:41:39'),(73,'Wako Alfin Hadiri Verifikasi Lanjutan Penghargaan Kota Sehat','<div>SUNGAI PENUH- Walikota Sungai Penuh Alfin, SH menghadiri Verifikasi Lanjutan Penghargaan Kabupaten Kota Sehat Tingkat Nasional Tahun 2025. Senin 25/8/2025</div><div>Kegiatan Verifikasi ini dilakukan melalui Zoom Metting bersama Kementrian Kesehatan Republik Indonesia. Turut hadir yakni, Sekretaris Daerah Kota Sungai Penuh Alpian, Asisten, Ketua TP PKK, Ketua Dharma Wanita, Ketua Gow, Kepala SKPD, Camat dan Tamu Undangan lainya.</div><div>Bertempat di Gedung Aula Kantor Walikota Sungai Penuh. Melalui Penghargaan Kota Sehat, Wako Alfin mengatakan, pelunya masyarakat menjaga budaya kebersihan lingkungan, olahraga teratur.&nbsp;</div><div>Selain itu dongkrak upaya dalam penurunan Stunting termasuk pelayanan Kesehatan yang memadai untuk mencegah kematian Ibu dan Bayi. Dalam hal ini, Kesehatan merupakan hal yang utama pada kehidupan manusia. Tidak hanya tentang segi perekonomian, namun lingkunan yang bersih merupakan hal yang wajib di delapan Kecamatan Kota Sungai Penuh.</div><div>“Peningkatan perekonomian masyarakat itu perlu. Kemudian menjaga lingkungan yang bersih melalui Kota Sehat adalah bagian dari Program Pemerintah Daerah. Termasuk menurunkan angka Stunting, menjalankan Program 3 S ( Scanting Beras, Sebutir Telur dan Seribu Rupiah) dengan cara menghimbau ke seluruh ASN, P3K yang ada di wilayah Kota Sungai Penuh termasuk inovasi soal konseling Pramuka\"ujarnya</div><div>“Dalam hal ini telah kita lakukan pembahasan sebagai dorongan untuk masyarakat menjaga budaya bersih baik itu diri pribadi dan lingkungan, olahraga secara teratur dan tidak merokok di dalam ruangan\"katanya</div><div>“mengurangi resiko tinggi pada kematian ibu dan bayi. Kemudian terkait perekonomian masyarakat juga memiliki peningkatan. Selain itu upaya dalam menemukan kasus TBC. Ini sangat penting, pengurangan angka stunting. Tujaunya ialah untuk mewujudkan keluarga sehat dan bahagia. [ ]</div><div>(Mc Diskominfosta</div>','upload/berita/KanzMRMPEsqOdBs8BER12WTTASQ11cB4J0nS5nNP.png','mc','wako-alfin-hadiri-verifikasi-lanjutan-penghargaan-kota-sehat','2025-08-26 09:41:20','2025-08-26 09:41:20'),(74,'Pemkot Sungai Penuh Resmi Miliki Tim Tanggap Insiden Siber, Diakui Secara Nasional','<div>JAMBI- Pemerintah Kota Sungai Penuh resmi memiliki tim tanggap insiden siber diakui secara Nasional dan terintegrasi dalam jaringan Pemerintah.</div><div>Pengesahan ini melalui surat tanda registrasi tim tanggap insiden siber untuk Kota dan Kabupaten di lingkup Provinsi Jambi. Verifikasi ini dilakukan kegiatan penyerahan bertempat di Auditorium Rumah Dinas Gubernur Jambi, Senin 25/8/2025</div><div>Pada kegiatan dimaksud, Wakil Walikota Sungai Penuh Azhar Hamzah, Kepala Dinas Komunikasi Informasi dan Statistik hadir dalam acara ini. Kegiatan tersebut juga dirangkai dengan penyerahan penghargaan apresiasi terhadap Pemerintah Provinsi Jambi atas upaya dan kontribusi dalam mendukung penguatan sistem keamanan siber di Daerah.</div><div>Registrasi dilakukan langsung oleh Komjen Pol. A. Rachman Wibowo, S.K.I juga dituju ke Wakil Walikota Sungai Penuh, Azhar Hamzah. Dengan diterimanya registrasi ini, Kota Sungai Penuh resmi memiliki tim tanggap insiden siber yang diakui secara nasional dan terintegrasi dalam jaringan keamanan siber Pemerintah.</div><div>Wawako Azhar Hamzah menyampaikan apresiasi atas dukungan Badan Siber dan Sandi Negara (BSSN) serta Pemerintah Provinsi Jambi.&nbsp;</div><div>Ia menegaskan bahwa keberadaan tim tanggap insiden siber akan memperkuat perlindungan data atau informasi Pemerintahan dan memberikan rasa aman bagi masyarakat di era digital.</div><div>“Di tengah perkembangan teknologi informasi yang begitu cepat, penguatan keamanan siber menjadi kebutuhan mendesak. Dengan adanya tim tanggap insiden, diharapkan seluruh potensi ancaman siber dapat diantisipasi secara cepat dan tepat”. [ ]&nbsp;</div><div>(Mc Diskominfo)</div>','upload/berita/yhtqfBuzWKyUdKI6tF1N9gp1YEOn4w9Y7aZlUY6p.jpg','mc','pemkot-sungai-penuh-resmi-miliki-tim-tanggap-insiden-siber-diakui-secara-nasional','2025-08-27 12:17:15','2025-08-27 12:17:15'),(75,'Wujud Nyata Normalisasi Di Kota Sungai Penuh, Antisipasi Banjir Dan Memperlancar Aliran Sungai','<div>SUNGAI PENUH- Pemerintah Kota Sungai Penuh telah melakukan upaya penangan antisipasi banjir yakni melakukan normalisasi Sungai.&nbsp;</div><div>Adapun pelaksanaan normalisasi yakni terdiri dari Sungai Bungkal, Muara Jaya, Air Sempit, Batang Merao. Hal ini merupakan Visi dan Misi Walikota Alfin, SH dan Wakil Walikota Sungai Penuh Azhar Hamzah.</div><div>Tujuan dilaksanakan normalisasi sungai ini ialah untuk mencegah risiko banjir, meningkatkan kapasitas pelancaran aliran sungai, termasuk memulihkan fungsi aliran agar lebih efektif.&nbsp;</div><div>Normalisasi dilakukan pengerukan, pelebaran, pendalaman sungai, perapian, serta penguatan tebing. Kegiatan ini merupakan keseriusan Pemerintah Daerah Kota Sungai Penuh.</div><div>Sebelumnya, Walikota Sungai Penuh Alfin telah berkoordinasi dengan Kementrian Pekerjaan Umum dan Perumahan Rakyat (PUPR) sekaligus meminta perhatian terhadap Pemerintah Pusat terkait penanganan pencegahan banjir.</div><div>“Berbagai langkah konkrit telah dilakukan. Terkait dengan Normalisasi merupakan bagian antisipasi banjir. PUPR Kota Sungai Penuh telah diintruksikan untuk memperhatikan kegiatan normalisasi sungai. Selain itu juga membersihkan sampah. Kita juga bersinergi dengan PU Provinsi Jambi dan BWSS VI. [ ]</div><div>(Mc Diskominfosta)</div>','upload/berita/BBbsYebgEdXaM9y7OSi0LM5YF7flRzx6ku36Xokc.jpg','mc','wujud-nyata-normalisasi-di-kota-sungai-penuh-antisipasi-banjir-dan-memperlancar-aliran-sungai','2025-08-28 18:31:23','2025-08-28 18:31:23'),(76,'Warga Antusias, Pemkot Sungai Penuh Ikut Gerakan Pangan Murah Serentak','<div>SUNGAI PENUH - Pemerintah Kota Sungai Penuh menunjukkan komitmennya dalam menjaga stabilitas harga dan pasokan pangan. Hal ini ditandai dengan keikutsertaan Pemkot dalam Gerakan Pangan Murah (GPM) serentak yang digelar bersama Kementerian Dalam Negeri melalui telekonferensi, Sabtu (30/8).</div><div>Kegiatan dipusatkan di depan Kantor Dinas Ketahanan Pangan Kota Sungai Penuh. Wali Kota Alfin, SH diwakili oleh Sekretaris Daerah Alpian, SE, MM yang hadir langsung pada kesempatan tersebut.</div><div>Gerakan Pangan Murah serentak ini digelar sebagai langkah nyata pemerintah dalam mengantisipasi gejolak harga, terutama menjelang periode tertentu yang rawan inflasi.</div><div>Sekda Alpian menegaskan bahwa Pemkot Sungai Penuh sangat mendukung program ini karena manfaatnya langsung dirasakan masyarakat.</div><div>“Melalui kegiatan ini, kita berharap kebutuhan pangan warga bisa terpenuhi dengan harga yang lebih terjangkau,” ujarnya.</div><div>Dalam arahannya, Menteri Dalam Negeri menekankan pentingnya kerja sama antara pemerintah pusat dan daerah dalam menjaga ketahanan pangan nasional. Menurutnya, program GPM tidak hanya membantu masyarakat memenuhi kebutuhan sehari-hari, tetapi juga berperan menekan laju inflasi di berbagai daerah.</div><div>Pelaksanaan Gerakan Pangan Murah di Kota Sungai Penuh mendapat sambutan hangat dari masyarakat. Sejak pagi, warga berbondong-bondong mendatangi lokasi kegiatan untuk membeli kebutuhan pokok dengan harga yang lebih murah dibandingkan pasar.</div><div>Berbagai komoditas pangan seperti beras, minyak goreng, gula, hingga bahan pokok lainnya disediakan dengan harga terjangkau. Kehadiran program ini pun menjadi angin segar bagi warga di tengah tingginya kebutuhan rumah tangga (Mc Kominfosta)</div>','upload/berita/flLrg1WmiruYks3jkauw1KV6hKnR90kaPJKfteFn.jpg','mc','warga-antusias-pemkot-sungai-penuh-ikut-gerakan-pangan-murah-serentak','2025-09-01 12:19:54','2025-09-01 12:19:54'),(77,'SK PPPK Diserahkan Wako Alfin','<div>SUNGAI PENUH – Walikota Sungai Penuh, Alfin, SH didampingi Wakil Walikota Azhar Hamzah, secara resmi melantik dan menyerahkan Surat Keputusan (SK) Pegawai Pemerintah dengan Perjanjian Kerja (PPPK) di lingkungan Pemerintah Kota Sungai Penuh, minggu 31/8/2025</div><div>Sebanyak 821 PPPK yang menerima SK pada kesempatan tersebut, yang terdiri dari 585 tenaga teknis, 104 tenaga kesehatan, dan 132 tenaga guru. Bertempat di halaman Kantor Walikota Sungai Penuh.</div><div>Dalam sambutannya, Walikota Alfin menegaskan agar seluruh PPPK yang baru dilantik dapat bekerja dengan sungguh-sungguh, serta mengutamakan pelayanan kepada masyarakat.</div><div>“Jadilah aparatur yang berintegritas, profesional, dan selalu mengutamakan kepentingan pelayanan publik di atas kepentingan pribadi. Karena kehadiran PPPK merupakan salah satu wujud upaya pemerintah untuk memperkuat kualitas layanan masyarakat,” ujar Alfin.</div><div>Wakil Walikota Azhar Hamzah juga memberikan pesan motivasi agar para PPPK menjaga etos kerja dan disiplin. “Tugas yang diemban bukan hanya sebatas jabatan, tetapi amanah untuk memberikan yang terbaik bagi daerah dan masyarakat Kota Sungai Penuh\" [ ]</div><div>(Mc Diskominfo)</div>','upload/berita/0C9ikyTfWfzocqZCjptN93bpMZEUskAxvtR81YIN.jpg','mc','sk-pppk-diserahkan-wako-alfin','2025-09-01 19:02:37','2025-09-01 19:02:37'),(78,'Anggota Paskibraka Terima Penghargaan Dari Walikota','<div>SUNGAI PENUH- Walikota Sungai Penuh Alfin, SH memberikan penghargaan pada anggota Pengibar Bendera Pusaka (Paskibraka) di Hari Kemerdekaan Republik Indonesia (HUT RI) ke 80 tahun.&nbsp;</div><div>Wako Alfin bangga terhadap putra dan putri Kota Sungai Penuh&nbsp; yang telah berhasil menjalankan tugas mulia dalam pengibaran bendera pusaka pada peringatan Hari Kemerdekaan Republik Indonesia Ke 80 Tahun pada tingkat Nasional, Provinsi dan Kabupaten/Kota, Senin 1/9/2025</div><div>Turut hadir Sekda Alpian pada serta pelaksana Apel kerja Aparatur Sipil Negara (ASN) lingkup Pemkot Sungai Penuh, Senin 1/9/2025</div><div>\" Menjadi anggota paskibraka tidaklah mudah, butuh kedisiplinan kuat, mental tanguh serta semangat juang luar biasa, prestasi yang telah dicapai perlu kita jadikan tauladan bersama\" ujar Wako Alfin.</div><div>Anggota paskibraka tingkat Nasional&nbsp; Nindya Eltsani Fawwaz yang berhasil bertugas mengibarkan Sang Saka Merah Putih di Istana Negara pada peringatan HUT ke-80 Republik Indonesia.</div><div>\" Kebanggaan ini bukan hanya dirasakan oleh orang tua dan keluarga tetapi kebanggaan dirasakan seluruh masyarakat Kota Sungai Penuh,\" sampainya [ ]</div><div>(Mc Diskominfosta)</div>','upload/berita/DnRi3gI8mb5wezlKLFiHRxa5N3VnNPicwcDZBtfs.jpg','mc','anggota-paskibraka-terima-penghargaan-dari-walikota','2025-09-01 19:04:13','2025-09-01 19:04:13'),(79,'Pemerintah Berikan Respon Positif Pada Aksi Damai Mahasiswa Kerinci Sungai Penuh','<div>SUNGAI PENUH- Ratusan mahasiswa yang tergabung dalam Cipayung Plus dan Badan Eksekutif Mahasiswa (BEM) se-Kabupaten Kerinci dan Kota Sungai Penuh menggelar aksi damai di Mapolres Kerinci dan Kantor DPRD Kota Sungai Penuh, Selasa (2/9/2025).&nbsp;</div><div>Aksi tersebut mendapat sambutan dan respon positif dari Pemerintah Daerah. Wakil Wali Kota Sungai Penuh, Azhar Hamzah, didampingi Sekretaris Daerah Alpian, SE, MM, hadir langsung menyambut kedatangan mahasiswa.</div><div>Tema, mengusut tuntas dan mengadili aparat kepolisian yang diduga terlibat dalam peristiwa meninggalnya almarhum Affan Kurniawan, membebaskan massa aksi demonstrasi yang masih ditahan tanpa syarat serta menghentikan segala bentuk kekerasan dan intervensi aparat kepolisian terhadap masyarakat.</div><div>Wakil Wali Kota Azhar Hamzah menegaskan, pemerintah daerah menghargai setiap bentuk aspirasi mahasiswa yang disampaikan secara tertib dan damai.</div><div>“Kami mendengar dan memahami apa yang menjadi tuntutan adik-adik mahasiswa. Kami mengapresiasi dan berharap seluruh proses berjalan dengan aman dan tidak ada tindakan yang merugikan masyarakat,” ujar Wawako Azhar.</div><div>Sementara itu, Sekda Alpian, SE, MM juga turut menyampaikan apresiasi atas kepedulian mahasiswa terhadap keadilan dan perlindungan hak-hak rakyat.</div><div>“Kami mengapresiasi aksi damai dan tertib ini. Pemerintah daerah akan mendukung setiap aspirasi yang berpihak kepada masyarakat\'\'tegasnya.</div><div>Dari pantauan di lapangan, aksi damai berlangsung kondusif dan diisi dengan dialog terbuka. Usai menyampaikan aspirasi di Mapolres Kerinci, massa aksi bergerak ke DPRD Kota Sungai Penuh. Kedatangan mahasiswa diterima langsung oleh Ketua DPRD Hutri Randa, unsur pimpinan dewan, serta anggota DPRD Kota Sungai Penuh. [ ]</div><div>(Mc Diskominfosta)</div>','upload/berita/PknLuOBJR9OgulJTe1vTBnsjCmMhMz1FQh2WPao9.jpg','mc','pemerintah-berikan-respon-positif-pada-aksi-damai-mahasiswa-kerinci-sungai-penuh','2025-09-02 19:49:48','2025-09-02 19:49:48'),(80,'Pastikan Pembangunan Pasar Beringin Jaya Dimulai, Wako Alfin Temui Kepala Satker Strategis Jambi','<div>SUNGAI PENUH- Walikota Sungai Penuh Alfin, SH, mengatakan bahwa Pembangunan Pasar Beringin Jaya otimis telah memasuki tahap persiapan tender.</div><div>Upaya Walikota Alfin melakukan loby sebagai sinergitas antara Pemerintah Daerah Kota Sungai Penuh dengan Kementrian Pekerjaan Umum. Maksudnya ialah terkait kejelasan pembangunan Pasar Beringin Jaya yang dinantikan oleh masyarakat.&nbsp;</div><div>Pembahasan ini dilakukan bersama Kepala Satuan Kerja Pelaksanaan Prasarana Strategis Jambi, Edia Putra, ST, dipastikan bahwa pembangunan Pasar Beringin Jaya akan direalisasikan. Jumlah pagu anggaran senilai Rp55 miliar dengan Skema multi years, Anggaran awal 2025 Rp11 miliar.</div><div>“Pembangunan dilaksanakan oleh Kementerian PU melalui Satuan Kerja Pelaksanaan Strategis Jambi, sebagai bagian dari penguatan prasarana strategis Nasional di sektor perdagangan rakyat.</div><div>“Pembangunan Pasar Beringin Jaya saat ini telah memasuki tahap tender. Kami berharap prosesnya lancar sehingga pembangunan dapat segera dimulai’’tambahnya</div><div>Wako Alfin juga menjelaskan bahwa proyek ini akan menjadi tonggak penting dalam mendorong ekonomi kerakyatan serta menghadirkan tata kota yang lebih baik.</div><div>“Kita berharap dengan adanya pembangunan Pasar Beringin Jaya ini mampu menjadi penggerak ekonomi lokal sekaligus memberi kenyamanan bagi pedagang dan masyarakat’’ [ ]</div><div>(Mc Diskominfosta)</div>','upload/berita/GJBJRKOA3GV6i5PtJQXuzXppQruVXdAY9Y7vpyTI.png','mediacenter','pastikan-pembangunan-pasar-beringin-jaya-dimulai-wako-alfin-temui-kepala-satker-strategis-jambi','2025-09-09 11:00:18','2025-09-09 11:00:18'),(81,'Wako Alfin & Wawako Azhar Hadiri Pengukuhan IPIM Kota Sungai Penuh','<div>SUNGAI PENUH – Walikota Sungai Penuh, Alfin, SH bersama Wakil Walikota Azhar Hamzah menghadiri acara pengukuhan Pengurus Ittihad Persaudaraan Imam Masjid (IPIM) Kota Sungai Penuh masa bhakti 2025–2030, Sabtu (6/9/2025) di Gedung Nasional.</div><div>Dalam pengukuhan tersebut, Prof. Dr. Muhammad Yusuf Gayo resmi ditetapkan sebagai Ketua IPIM Kota Sungai Penuh. Prosesi pengukuhan dilakukan langsung oleh Pimpinan IPIM Provinsi Jambi, Dr. Dailami Julis.</div><div>Acara turut dihadiri pimpinan DPRD, unsur Forkopimda, Ketua TP PKK Sri Kartini Alfin, Sekda Alpian, Ketua MUI, organisasi BKMT, tokoh agama, serta tamu undangan lainnya.</div><div>Walikota Alfin dalam sambutannya menyampaikan apresiasi dan ucapan selamat kepada pengurus IPIM yang baru dilantik.</div><div>“Semoga kepengurusan IPIM dapat memberikan kontribusi nyata dalam membangun masyarakat Kota Sungai Penuh yang religius, harmonis, dan beradab,” ujar Wako.</div><div>MC diskominfo</div>','upload/berita/xftghlyt2rvGnBcaWUiI1x86lgmFfhgyK28FZhf7.png','mediacenter','wako-alfin-wawako-azhar-hadiri-pengukuhan-ipim-kota-sungai-penuh','2025-09-09 11:02:17','2025-09-09 11:02:17'),(85,'Rapat Paripurna DPRD dan Pemkot Sungai Penuh, Wako Alfin: Pentingnya Sinergitas','<div>SUNGAI PENUH- Penyampaian Pengantar Walikota Sungai Penuh pada Perubahan Rancangan Anggaran Pendapatan dan Belanja Daerah (RAPBD) tahun anggaran 2025 berlangsung tanpa adanya kendala.&nbsp;</div><div>Rapat berlangsung di aula kantor DPRD Kota Sungai Penuh, Wakil Walikota Azhar Hamzah, Sekda Alpian, SKPD, Staf Ahli, Asisten, Camat dan tamu undangan lainnya hadir di kegiatan ini. Senin 8/9/2025</div><div>Adapun tujuan pelaksanaan kegiatan tersebut sebagai langkah penyaluran ide, gagasan untuk pembangunan Kota Sungai Penuh kedepannya. Dibahas oleh Pemerintah Daerah bersama DPRD.&nbsp;</div><div>Seluruh fraksi DPRD Kota Sungai Penuh menyampaikan pandangan umum atau masukan terhadap Ranperda Perubahan APBD Tahun Anggaran 2025.&nbsp;</div><div>Dalam rapat tersebut, Dewan mengatakan. Menghadapi efisiensi perlunya transparansi dalam tata kelola anggaran. Kemudian agar menjadi perhatian utama dan diharapkan terus memperkuat sistem manajemen Pemerintah Daerah.</div><div>Fraksi fraksi di DPRD memberi usulan pentingnya perubahan APBD diarahkan pada program program prioritas yang menyentuh langsung pada kepentingan masyarakat diantaranya ialah:</div><div>1. Peningkatan Infrastruktur Dasar.</div><div>2. Layanan Kesehatan.</div><div>3. Layanan Pendidikan.</div><div>4. Pemberdayaan Ekonomi Kerakyatan.&nbsp;</div><div>Walikota Sungai Penuh Alfin, SH mengungkapkan bahwa Pemkot Sungai Penuh telah menyepakati nota perubahan RAPBD tahun anggaran 2025. Kemudian, pentingnya sinergitas antara Pemerintah Daerah dan DPRD.&nbsp;</div><div>“Pentingnya sinergi antara pemerintah daerah dan DPRD dalam menjaga kelanjutan pembangunan termasuk memastikan alokasi anggaran tepat sasaran dan bermanfaat bagi masyarakat. Penyampaian pengantar perubahan RAPBD ini merupakan bagian dari proses pembangunan daerah agar pelaksanaan program dapat lebih baik sesuai kebutuhan masyarakat\'\' [ ]&nbsp;</div><div>(Mc Diskominfosta)</div>','upload/berita/XHJi83tOdJg1FT4iQUibBK8hxE2uQMwTkS4IH59k.png','mediacenter','rapat-paripurna-dprd-dan-pemkot-sungai-penuh-wako-alfin-pentingnya-sinergitas-2','2025-09-09 12:57:08','2025-09-09 12:57:08'),(83,'Rapat Paripurna DPRD, Wako Alfin Sampaikan Pengantar Perubahan RAPBD 2025','<div>SUNGAI PENUH – Walikota Sungai Penuh, Alfin, SH bersama Wakil Walikota Azhar Hamzah menghadiri rapat paripurna DPRD Kota Sungai Penuh dengan agenda penyampaian pengantar perubahan Rancangan Anggaran Pendapatan dan Belanja Daerah (RAPBD) Tahun Anggaran 2025, Senin (8/9/2025).</div><div>Rapat paripurna yang digelar di aula kantor DPRD tersebut dipimpin Wakil Ketua DPRD Kota Sungai Penuh, Hardizal, S.Sos, M.H, serta dihadiri jajaran Forkopimda, Sekda Alpian, SE, MM, staf ahli, asisten, kepala OPD, dan undangan lainnya.</div><div>Dalam penyampaiannya, Walikota Alfin menyebut bahwa Pemkot Sungai Penuh bersama DPRD sebelumnya telah menyepakati nota perubahan RAPBD 2025 untuk kemudian dibahas lebih lanjut. Hal itu dilakukan agar program pembangunan dapat berjalan lebih optimal dan memberikan manfaat langsung bagi masyarakat.</div><div>“Penyampaian pengantar perubahan RAPBD ini merupakan bagian dari proses pembangunan daerah agar pelaksanaan program bisa lebih tepat sesuai kebutuhan masyarakat,” ujar Wako Alfin.</div><div>Ia juga menegaskan pentingnya sinergi pemerintah daerah dan DPRD dalam menjaga kesinambungan pembangunan, serta memastikan anggaran yang ada benar-benar bermanfaat bagi masyarakat Kota Sungai Penuh. [ ]</div><div>(Mc Diskominfosta)</div>','upload/berita/kiDEhC3VJRyUp9Cb7b7f8O8kFrJ4ps8mz49Frg6c.png','mediacenter','rapat-paripurna-dprd-wako-alfin-sampaikan-pengantar-perubahan-rapbd-2025','2025-09-09 11:08:09','2025-09-09 11:08:09'),(84,'Rapat Paripurna DPRD dan Pemkot Sungai Penuh, Wako Alfin: Pentingnya Sinergitas','<div>SUNGAI PENUH- Penyampaian Pengantar Walikota Sungai Penuh pada Perubahan Rancangan Anggaran Pendapatan dan Belanja Daerah (RAPBD) tahun anggaran 2025 berlangsung tanpa adanya kendala.&nbsp;</div><div>Rapat berlangsung di aula kantor DPRD Kota Sungai Penuh, Wakil Walikota Azhar Hamzah, Sekda Alpian, SKPD, Staf Ahli, Asisten, Camat dan tamu undangan lainnya hadir di kegiatan ini. Senin 8/9/2025</div><div>Adapun tujuan pelaksanaan kegiatan tersebut sebagai langkah penyaluran ide, gagasan untuk pembangunan Kota Sungai Penuh kedepannya. Dibahas oleh Pemerintah Daerah bersama DPRD.&nbsp;</div><div>Seluruh fraksi DPRD Kota Sungai Penuh menyampaikan pandangan umum atau masukan terhadap Ranperda Perubahan APBD Tahun Anggaran 2025.&nbsp;</div><div>Dalam rapat tersebut, Dewan mengatakan. Menghadapi efisiensi perlunya transparansi dalam tata kelola anggaran. Kemudian agar menjadi perhatian utama dan diharapkan terus memperkuat sistem manajemen Pemerintah Daerah.</div><div>Fraksi fraksi di DPRD memberi usulan pentingnya perubahan APBD diarahkan pada program program prioritas yang menyentuh langsung pada kepentingan masyarakat diantaranya ialah:</div><div>1. Peningkatan Infrastruktur Dasar.</div><div>2. Layanan Kesehatan.</div><div>3. Layanan Pendidikan.</div><div>4. Pemberdayaan Ekonomi Kerakyatan.&nbsp;</div><div>Walikota Sungai Penuh Alfin, SH mengungkapkan bahwa Pemkot Sungai Penuh telah menyepakati nota perubahan RAPBD tahun anggaran 2025. Kemudian, pentingnya sinergitas antara Pemerintah Daerah dan DPRD.&nbsp;</div><div>“Pentingnya sinergi antara pemerintah daerah dan DPRD dalam menjaga kelanjutan pembangunan termasuk memastikan alokasi anggaran tepat sasaran dan bermanfaat bagi masyarakat. Penyampaian pengantar perubahan RAPBD ini merupakan bagian dari proses pembangunan daerah agar pelaksanaan program dapat lebih baik sesuai kebutuhan masyarakat\'\' [ ]&nbsp;</div><div>(Mc Diskominfosta)</div>','upload/berita/37X6WPtG4q6rrCqfcp7CsX2vmFZJTv77UDIkqAK6.png','mediacenter','rapat-paripurna-dprd-dan-pemkot-sungai-penuh-wako-alfin-pentingnya-sinergitas','2025-09-09 11:13:32','2025-09-09 11:13:32'),(86,'Wawako Azhar Jawab Pandangan Umum Fraksi DPRD, APBD Perubahan 2025','<div><br></div><div><strong>BERITA SUNGAI PENUH</strong> – Pemerintah Kota Sungai Penuh melalui Wakil Walikota Azhar Hamzah menyampaikan jawaban atas pandangan umum fraksi-fraksi DPRD terhadap Raperda Perubahan APBD Tahun Anggaran 2025. Agenda ini berlangsung dalam rapat paripurna ketiga masa persidangan kesatu DPRD Kota Sungai Penuh, Selasa (9/9/25).<br><br></div><div>Dalam penyampaiannya, Wawako Azhar memberikan apresiasi dan ucapan terima kasih kepada seluruh fraksi DPRD yang telah memberikan saran, masukan, serta kritik membangun untuk perbaikan tata kelola keuangan daerah.<br><br></div><blockquote>“Segala masukan dari fraksi-fraksi DPRD akan menjadi perhatian serius bagi Pemerintah Kota Sungai Penuh. Semangat kolaborasi ini adalah wujud komitmen kita bersama dalam mewujudkan pengelolaan APBD yang transparan, akuntabel, serta berpihak kepada kepentingan masyarakat,” ujar Wawako Azhar.<br><br></blockquote><div>Lebih lanjut, Wawako menjelaskan bahwa perubahan APBD 2025 diarahkan untuk:<br><br></div><ul><li>Menyesuaikan perkembangan kondisi dan kebutuhan riil masyarakat.</li><li>Penyesuaian belanja prioritas dan penguatan program pelayanan publik.</li><li>Penertiban titik parkir dan penyelesaian tapal batas.</li><li>Optimalisasi pendapatan daerah yang saat ini progresnya mencapai 48,95 persen.</li></ul><div>“Dengan adanya APBD Perubahan ini, kita berharap roda pembangunan tetap berjalan efektif dan mampu menjawab tantangan yang ada. Fokus utama diarahkan pada peningkatan pelayanan publik, kemudahan perizinan, infrastruktur, serta pemulihan ekonomi daerah,” jelasnya.<br><br></div><div>Rapat paripurna tersebut dipimpin langsung oleh Ketua DPRD Kota Sungai Penuh, Hutri Randa S.Sos, M.M. Acara turut dihadiri oleh unsur Forkopimda, para anggota dewan, serta jajaran kepala OPD di lingkungan Pemerintah Kota Sungai Penuh.(MC.KOMINFO)<br><br></div><div><br></div>','upload/berita/X9X11IozJiQzoPs0pTpkZ0sqjnWLEOYmS7dDelD7.jpg','mediacenter','wawako-azhar-jawab-pandangan-umum-fraksi-dprd-apbd-perubahan-2025','2025-09-09 13:10:31','2025-09-09 13:10:31'),(87,'Wawako Azhar Pimpin Sosialisasi Kerja Bakti Massal Sambut World Cleanup Day 2025','<div><br></div><div>SUNGAI PENUH- Wakil Wali Kota Sungai Penuh bersama camat dan dinas terkait menghadiri sosialisasi kerja bakti massal dalam rangka World Cleanup Day (WCD) 2025.&nbsp;</div><div>Kegiatan ini digelar pada Selasa, 9 September 2025, bertempat di ruang kerja Wakil Wali Kota.</div><div>Sosialisasi ini menjadi langkah awal persiapan gerakan bersih-bersih serentak yang akan dilaksanakan untuk menyambut World Cleanup Day.&nbsp;</div><div>Tahun ini, Indonesia mengangkat tema “Menuju Indonesia Bersih 2029” yang sejalan dengan target nasional “Sampah Terkelola 100% Tahun 2029”.</div><div>Wawako menegaskan pentingnya dukungan semua pihak, mulai dari pemerintah, camat, hingga masyarakat, agar gerakan kebersihan ini berjalan sukses.&nbsp;</div><div>“Kerja bakti massal bukan hanya kegiatan seremonial, tapi wujud nyata kepedulian kita menjaga lingkungan,” ujarnya.</div><div>Melalui sosialisasi ini, Pemkot Sungai Penuh berharap partisipasi aktif seluruh masyarakat untuk bersama-sama menciptakan kota yang bersih, sehat, dan berkelanjutan. [ ]</div><div>(Mc Diskominfosta)</div>','upload/berita/8e5a73WNyu2okISps9URlh5gvrsjg6n89wGRxnwi.jpg','mediacenter','wawako-azhar-pimpin-sosialisasi-kerja-bakti-massal-sambut-world-cleanup-day-2025','2025-09-09 15:23:22','2025-09-09 15:23:22'),(88,'Wako Alfin Ikuti Gerakan Percepatan Tanam di Koto Dian','<div><br></div><div>SUNGAI PENUH - Walikota Sungai Penuh, Alfin, SH, menghadiri Gerakan Serempak Percepatan Tanam Menuju Swasembada Pangan Provinsi Jambi yang dipusatkan di Desa Koto Dian, Kecamatan Hamparan Rawang, Selasa 16/9/2025</div><div>Kegiatan yang digelar secara telekonferensi, dengan tema “Gerakan Serempak Tanam Padi Menyapa Sahabat Tani”. Diikuti jajaran Forkopimda Kota Sungai Penuh, Kepala Dinas DTPHP, Camat Hamparan Rawang, serta Kepala Desa Koto Dian.&nbsp;</div><div>Usai seremoni, para peserta bersama petani setempat turun langsung ke lahan melakukan penanaman padi secara serentak.</div><div>Dalam kesempatan itu, Wako Alfin memaparkan capaian target penanaman padi di Kota Sungai Penuh. Dari target seluas 709 hektare, telah terealisasi 429 hektare atau sekitar 65 persen. Untuk mempercepat realisasi, ia mengusulkan dukungan tambahan alat dan mesin pertanian (alsintan) berupa hidroteler.</div><div>“Kota Sungai Penuh memiliki potensi lebih dari 1.000 hektare lahan olah. Dengan dukungan alsintan, kita optimistis mampu berkontribusi besar menjadikan Provinsi Jambi sebagai salah satu lumbung padi nasional,” ungkapnya.</div><div>Wako juga mengapresiasi peran Balai Wilayah Sungai (BWS) Provinsi Jambi yang telah melakukan normalisasi sungai secara bertahap, termasuk Batang Merao dan Batang Bungkal.&nbsp;</div><div>Kepala BWS melalui telekonferensi menegaskan komitmen melanjutkan program tersebut, meski masih ditemui sejumlah kendala teknis di lapangan.</div><div>Menanggapi hal itu, Walikota Alfin menegaskan dukungan Pemkot Sungai Penuh terhadap upaya optimalisasi lahan dan normalisasi sungai.</div><div>“Pemerintah Kota Sungai Penuh akan terus berupaya maksimal bersama seluruh pihak. Dukungan masyarakat sangat kami harapkan demi kemajuan pertanian dan pembangunan Kota Sungai Penuh\'\'.&nbsp;</div>','upload/berita/rD49twYs9hX4l1luWzY8dMHKTXklrr1vplAnkT4E.jpg','mediacenter','wako-alfin-ikuti-gerakan-percepatan-tanam-di-koto-dian','2025-09-16 11:59:08','2025-09-16 11:59:08'),(89,'Wako Alfin Pantau Pemberkasan PPPK Paruh Waktu, Apresiasi Layanan Polres Kerinci','<div>BERITA SUNGAI PENUH – Walikota Sungai Penuh, Alfin, SH, turun langsung memantau proses pemberkasan Pegawai Pemerintah dengan Perjanjian Kerja (PPPK) Paruh Waktu di Polres Kerinci, Senin (15/9/25). Kehadiran Wako Alfin didampingi Bupati Kerinci, Monadi, menjadi bukti komitmen pemerintah daerah dalam mendukung kelancaran dan kenyamanan para calon PPPK.</div><div>Di lokasi, keduanya menyaksikan langsung proses pengurusan Surat Keterangan Catatan Kepolisian (SKCK) yang tengah dijalani oleh para calon PPPK Paruh Waktu, baik dari lingkup Pemerintah Kota Sungai Penuh maupun Kabupaten Kerinci.</div><div>Walikota Alfin memberikan apresiasi kepada jajaran Polres Kerinci yang dinilai mampu memberikan pelayanan cepat, tertib, dan ramah. Menurutnya, pelayanan SKCK yang optimal akan sangat membantu para calon PPPK dalam menyelesaikan pemberkasan.</div><div>“Kami mengapresiasi Polres Kerinci yang telah memberikan pelayanan terbaik. Hal ini tentu mempermudah proses pemberkasan calon PPPK Paruh Waktu dan menjadi contoh pelayanan publik yang baik,” ujar Wako Alfin.</div><div>Pada kesempatan itu, ia juga menyampaikan informasi terbaru terkait perpanjangan waktu pemberkasan oleh Badan Kepegawaian Negara (BKN). Awalnya batas akhir pada 15 September, kini diperpanjang hingga 22 September 2025.</div><div>“Insyaallah semua berkas bisa rampung sebelum tanggal 21 September,” tambahnya.</div><div>Wako Alfin menegaskan bahwa pemerintah daerah akan terus berkomitmen meningkatkan kualitas pelayanan publik, sekaligus memastikan setiap proses administrasi berjalan transparan dan sesuai aturan. (Mc.Kominfo)</div>','upload/berita/ZPtrcNfbcC6gyaRiZGxYHqqxtMQLHngJob8HpJMU.jpg','mediacenter','wako-alfin-pantau-pemberkasan-pppk-paruh-waktu-apresiasi-layanan-polres-kerinci','2025-09-16 12:04:00','2025-09-16 12:04:00'),(90,'Wako Alfin Pimpin Upacara Hari Kesaktian Pancasila di Sungai Penuh','<div>&nbsp;SUNGAI PENUH - Pemerintah Kota Sungai Penuh memperingati Hari Kesaktian Pancasila Tahun 2025 dengan menggelar upacara di Lapangan Kantor Walikota, Rabu (1/10). Upacara dipimpin langsung oleh Walikota Sungai Penuh, Alfin, SH.</div><div>Hadir dalam kesempatan tersebut Wakil Walikota Azhar Hamzah, Ketua DPRD Hutri Randa, Unsur Forkopimda, Sekretaris Daerah Alpian, TNI/Polri, serta seluruh ASN lingkup Pemkot Sungai Penuh.</div><div>Pembacaan ikrar dilakukan oleh Ketua DPRD Hutri Randa, yang menegaskan kembali komitmen bangsa Indonesia untuk mempertahankan dan mengamalkan nilai-nilai Pancasila. Ikrar tersebut juga mengingatkan bahwa sejak kemerdekaan 17 Agustus 1945, Indonesia menghadapi berbagai rongrongan dari dalam maupun luar negeri. Namun berkat semangat kebersamaan yang berlandaskan Pancasila, bangsa ini tetap mampu menjaga keutuhan NKRI.</div><div>Momentum peringatan Hari Kesaktian Pancasila ini menjadi pengingat sekaligus tekad bersama untuk menjadikan Pancasila sebagai sumber kekuatan dalam memperjuangkan kebenaran, menegakkan keadilan, serta menjaga persatuan dan kesatuan bangsa.(Mc Diskominfosta)&nbsp;</div>','upload/berita/OOVZW3eJ0HB8U0CUgNuTvhntd77tPds3g2R7QSK7.jpg','mediacenter','wako-alfin-pimpin-upacara-hari-kesaktian-pancasila-di-sungai-penuh','2025-10-01 10:28:24','2025-10-01 10:28:24'),(91,'Wako Alfin Tinjau Persiapan Akhir TPST Renah Kayu Embun di Tengah Hujan','<div>Wako Alfin Tinjau Persiapan Akhir TPST Renah Kayu Embun di Tengah Hujan</div><div>BERITA SUNGAI PENUH – Walikota Sungai Penuh, Alfin SH, tetap mengebut persiapan pengoperasian Tempat Pengolahan Sampah Terpadu (TPST) di Renah Kayu Embun meski diguyur hujan, Selasa sore (30/9/25).</div><div>Alfin turun langsung meninjau lokasi bersama Sekretaris Daerah Alpian SE, MM, Kepala OPD terkait, dan tokoh masyarakat Kota Sungai Penuh, H. Muradi. Menurutnya, percepatan ini menjadi bagian dari komitmen pemerintah daerah untuk mengatasi persoalan sampah secara berkelanjutan serta mengejar kembali penghargaan Adipura.</div><div>“Pengoperasian TPST ini harus dipersiapkan matang. Kita ingin pengelolaan sampah di Kota Sungai Penuh berjalan lebih efektif, efisien, dan memberi nilai tambah bagi masyarakat,” tegas Alfin.</div><div>Ia menjelaskan, TPST Renah Kayu Embun dirancang sebagai pusat pengolahan sampah modern berbasis prinsip reduce, reuse, recycle (3R). Kehadiran fasilitas tersebut diharapkan mampu menekan volume sampah yang menumpuk di Tempat Pembuangan Akhir (TPA) sekaligus mengurangi dampak lingkungan.</div><div>Pemerintah Kota Sungai Penuh kini menyiapkan sumber daya manusia, sarana pendukung, hingga mekanisme pengelolaan agar TPST berfungsi optimal. Alfin juga mengajak masyarakat ikut memilah sampah sejak dari rumah tangga sebagai bagian penting dalam sistem pengolahan terpadu.</div><div>Dengan dukungan semua pihak, Alfin optimistis TPST Renah Kayu Embun segera beroperasi dan menjadi solusi strategis untuk mewujudkan Sungai Penuh yang bersih, sehat, dan berdaya saing. (Mc. Kominfosta)</div>','upload/berita/vMhVl51dhcjdswnHaTeqkB4Y7PsfMhbWN8XgCFHN.png','mediacenter','wako-alfin-tinjau-persiapan-akhir-tpst-renah-kayu-embun-di-tengah-hujan','2025-10-01 11:04:25','2025-10-01 11:04:25'),(92,'Wako Alfin Sampaikan Rancangan KUA-PPAS 2026 di DPRD Sungai Penuh','<div>Wako Alfin Sampaikan Rancangan KUA-PPAS 2026 di DPRD Sungai Penuh</div><div>SUNGAI PENUH - Walikota Sungai Penuh, Alfin, SH menyampaikan Rancangan Kebijakan Umum Anggaran (KUA) dan Rancangan Prioritas serta Plafon Anggaran Sementara (PPAS) APBD Kota Sungai Penuh Tahun 2026. Penyampaian ini berlangsung di Aula DPRD Kota Sungai Penuh dan dihadiri Ketua DPRD Hutri Randa, S.Sos.,Pimpinan Dan Anggota DPRD, Sekretaris Daerah Alpian, Forkopimda, serta jajaran OPD lingkup Pemkot Sungai Penuh. Selasa (30/9)</div><div>Dalam sambutannya, Walikota Alfin menegaskan bahwa rancangan KUA-PPAS 2026 dirumuskan untuk menghadirkan program prioritas yang berdampak langsung bagi masyarakat, serta selaras dengan pembangunan nasional, provinsi, dan daerah. Hal ini, kata Alfin, merupakan bagian dari upaya mewujudkan visi Kota Sungai Penuh yang maju, adil, dan sejahtera atau Sungai Penuh Juara.</div><div>Adapun fokus prioritas pembangunan tahun 2026 meliputi:</div><div>Perekonomian yang berdaya saing dan berkelanjutan.</div><div>Sumber daya manusia yang berkualitas dan kompetitif.</div><div>Pembangunan infrastruktur merata, berkualitas, serta tangguh menghadapi bencana.</div><div>Tata kelola pemerintahan yang berintegritas, melayani, serta optimalisasi pendapatan asli daerah.</div><div>Di akhir sambutannya, Walikota Alfin berharap pembahasan rancangan KUA-PPAS dapat berjalan lancar. Ia juga mengingatkan Tim Anggaran Pemerintah Daerah (TAPD) dan seluruh perangkat daerah untuk mengikuti proses pembahasan sesuai jadwal yang telah ditentukan.</div><div>(Mc Diskominfosta)</div>','upload/berita/42jxtJlDlEabAnVuiqLzZAjAXgrxLDU4uOdhp3Zc.png','mediacenter','wako-alfin-sampaikan-rancangan-kua-ppas-2026-di-dprd-sungai-penuh','2025-10-01 11:05:57','2025-10-01 11:05:57'),(93,'Diskominfosta Ikut Goro Tanam Bunga Serentak Pemkot Sungai Penuh','<div>Diskominfosta Ikut Goro Tanam Bunga Serentak Pemkot Sungai Penuh</div><div>Sungai Penuh-Kepala Dinas Komunikasi, Informatika, dan Statistik (Diskominfosta) bersama jajaran Pemkot Sungai Penuh ikut berpartisipasi dalam kegiatan gotong royong (Goro) tanam bunga serentak yang digelar Pemerintah Kota Sungai Penuh.</div><div>Kegiatan yang berlangsung di Taman Bunga ini bertujuan memperindah kembali kawasan yang sudah lama tidak terurus. Dengan adanya penanaman serentak, taman diharapkan lebih asri, nyaman, dan bisa menjadi ruang terbuka hijau yang bermanfaat bagi masyarakat.</div><div>Kadis Kominfo menyampaikan apresiasi atas terselenggaranya kegiatan ini. Ia berharap seluruh OPD dan masyarakat dapat terus menjaga kebersihan serta keindahan lingkungan sekitar.</div><div>(MC DISKOMINFO)</div>','upload/berita/2ZSV1pusylEv7AuRCr3ymW3Q5K0lQz9t7TRvjsHm.png','mediacenter','diskominfosta-ikut-goro-tanam-bunga-serentak-pemkot-sungai-penuh','2025-10-01 11:07:52','2025-10-01 11:07:52'),(94,'Pelantikan Ketua dan Wakil Ketua Mabicab & DKC Pramuka Sungai Penuh Masa Bakti 2024 - 2029','<div>Pelantikan Ketua dan Wakil Ketua Mabicab &amp; DKC Pramuka Sungai Penuh Masa Bakti 2024 - 2029</div><div>Sungai Penuh - Bertempat di Aula Kantor Walikota Sungai Penuh, Kamis (25/9/2025), dilaksanakan pelantikan Ketua dan Wakil Ketua Majelis Pembimbing Cabang (Mabicab) serta Dewan Kerja Cabang (DKC) Pergantian Antar Waktu Gerakan Pramuka Kota Sungai Penuh masa bakti 2024-2029</div><div>Acara ini dihadiri langsung oleh Walikota Alfin, Wakil walikota Azhar Hamzah, jajaran SKPD, camat, unsur Forkopimda, kepala OPD lingkup Pemerintah Kota Sungai Penuh, serta perwakilan Kwarda Jambi, Dr.H.Sudirman,SH, MH</div><div>Dalam sambutannya, Wako Alfin menyampaikan apresiasi atas pelantikan kepengurusan baru ini. Ia menekankan bahwa Gerakan Pramuka memiliki peran besar dalam membina generasi muda agar berkarakter, disiplin, dan mampu bersaing di masa depan.</div><div>“Pramuka adalah wadah pembinaan generasi penerus bangsa yang harus terus kita dukung. Pemerintah Kota Sungai Penuh siap bersinergi dengan Pramuka untuk membangun daerah dan mencetak pemuda yang tangguh,” ujar Wako Alfin.</div><div>Dengan dilantiknya pengurus baru Mabicab dan DKC, diharapkan sinergi Gerakan Pramuka dengan pemerintah semakin kuat, serta semakin memberi manfaat bagi masyarakat dan pembangunan Kota Sungai Penuh.</div><div>(MC DISKOMINFO)</div>','upload/berita/ojlCzflalT5tvdbcn8vLkxSRe9ZZGzgp8BLaY4aS.png','mediacenter','pelantikan-ketua-dan-wakil-ketua-mabicab-dkc-pramuka-sungai-penuh-masa-bakti-2024-2029','2025-10-01 11:11:00','2025-10-01 11:11:00'),(95,'TPST RKE Diresmikan Walikota Sungai Penuh, Alfin','<div>TPST RKE Diresmikan Walikota Sungai Penuh, Alfin&nbsp;</div><div>Sungai Penuh- Walikota Sungai Penuh Alfin, SH meresmikan Tempat Pengolahan Sampah Terpadu, lokasi, Desa Renah Kayu Embun Kecamatan Kumun Debai. Rabu 1/10/2025</div><div>Wakil Walikota Sungai Penuh Azhar Hamzah, Sekda Alpian, DPRD, Kepala SKPD, Dandim 0417/ Kerinci, Kepala Desa beserta tamu undangan lainya juga hadir dalam kegiatan ini.</div><div>TPST di Kota Sungai Penuh merupakan edukasi, yang mana sebuah fasilitas dimulai dari pengumpulan, pemilahan, daur ulang, pengolahan, hingga pemrosesan akhir sampah yang berpotensi menjadi produk bernilai seperti kompos atau lainya.&nbsp;</div><div>Selain itu, pada peresmian TPST ini, Wako Alfin juga menanam bibit pohon di area itu, bersama, Wawako Azhar Hamzah, Sekda Alpian, DPRD dan Dandim 0417/ Kerinci.</div><div>Terkait dengan tata kelola TPST. Wako Alfin berharap dengan adanya lokasi ini, sampah di Kota Sungai Penuh teratasi dengan baik termasuk dongkrak potensi dari hasil olahan.</div><div>“Dengan adanya TPST, Sampah di Kota Sungai Penuh akan teratasi dengan baik. Kita Sudah melakukan koordinasi dengan pihak terkait, dimulai dari izin hingga peninjauan. Dalam hal ini sudah dilakukan penelitian bahwa tidak akan memiliki dampak yang merugikan masyarakat”pungkasnya</div><div>(Mc Diskominfosta)</div>','upload/berita/TJvILxtI2PDxMTu5qfX8ELM8o0aL28YwVt6o7KkF.png','mediacenter','tpst-rke-diresmikan-walikota-sungai-penuh-alfin','2025-10-10 11:10:31','2025-10-10 11:10:31'),(96,'Wawako Azhar Buka Bimtek Ketahanan Pangan Dukung Asta Cita','<div>Wawako Azhar Buka Bimtek Ketahanan Pangan Dukung Asta Cita</div><div>Jambi - Wakil Walikota Sungai Penuh, Azhar Hamzah, membuka secara resmi Bimbingan Teknis (Bimtek) Ketahanan Pangan dalam rangka mendukung program Asta Cita menuju Indonesia Maju, yang digelar di Jambi. Rabu (8/10).</div><div>Dalam sambutannya, Wawako Azhar menegaskan bahwa ketahanan pangan merupakan salah satu pilar utama dalam pembangunan bangsa. Tanpa ketahanan pangan yang baik, berbagai tantangan bisa muncul dan menghambat kemajuan daerah maupun nasional.</div><div>\"Program ini selaras dengan visi besar pemerintah pusat melalui Asta Cita, yang bertujuan membawa Indonesia menuju masa depan yang lebih maju, adil, dan sejahtera,\"ujar Azhar Hamzah.</div><div>Ia juga menekankan bahwa ketahanan pangan bukan hanya tanggung jawab pemerintah, tetapi tanggung jawab bersama seluruh elemen masyarakat. Melalui kolaborasi dan sinergi yang kuat, diharapkan ketersediaan pangan yang cukup, aman, dan bergizi bagi seluruh masyarakat Sungai Penuh dapat terjamin.</div><div>Wawako Azhar juga menjabarkan sejumlah langkah strategis yang menjadi komitmen Pemerintah Kota Sungai Penuh, di antaranya:</div><div>Mendukung pengembangan pertanian dan usaha pangan lokal dengan bantuan teknis, penerapan teknologi pertanian modern, serta peningkatan kapasitas petani dan kelompok tani di desa.</div><div>Memperkuat sinergi antara pemerintah daerah, pelaku usaha, akademisi, dan masyarakat dalam menciptakan inovasi produksi dan distribusi pangan.</div><div>Mendorong diversifikasi pangan lokal agar tidak bergantung pada satu komoditas utama serta sesuai kebutuhan gizi masyarakat.</div><div>Mengembangkan infrastruktur pendukung seperti irigasi, pasar desa, dan akses transportasi guna memperlancar distribusi pangan.</div><div>Melakukan pengawasan dan evaluasi berkala agar setiap program tepat sasaran dan berdampak langsung bagi kesejahteraan masyarakat.</div><div>\"Saya mengajak seluruh elemen masyarakat, terutama kepala desa dan perangkatnya, untuk berperan aktif dan bersinergi dalam menyukseskan program ini. Ketahanan pangan adalah tanggung jawab kita bersama, dan desa merupakan garda terdepan yang harus kuat dan mandiri,\" tambahnya.</div><div>Lebih lanjut, Wawako Azhar berharap kegiatan ini tidak hanya menjadi ajang pembekalan teknis semata, tetapi juga momentum untuk memperkuat inovasi dan kontribusi nyata dalam pembangunan ketahanan pangan yang berkelanjutan.</div><div>Kegiatan ini turut dihadiri oleh Dr. H. Ma’mun Hermawan selaku narasumber dari Kementerian Dalam Negeri,&nbsp; Perwakilan dari PT Manta Ananda Sejahtera Jakarta Selaku Narasumber tentang Infrastruktur, serta Kodim 0417/Kerinci Yang Diwakili Pabung Mayor Inf Widi Purwoko, S.E. Serta Seluruh Kepala Desa Dan BPD Se-Kota Sungai Penuh Selaku Peserta.</div><div>(MC Kominfo Kota Sungai Penuh)</div>','upload/berita/b0WoJFZqvjEVB2bvW1hFur2Avrwz6hR1DYUdQPpp.png','mediacenter','wawako-azhar-buka-bimtek-ketahanan-pangan-dukung-asta-cita','2025-10-10 11:13:39','2025-10-10 11:13:39'),(97,'Kominfo Sungai Penuh Konsisten, Jalankan Gerakan Peduli Gizi Anak Dan Lawan Stunting','<div>SUNGAI PENUH-Dinas Komunikasi, Informatika, dan Statistik (Diskominfosta) Kota Sungai Penuh terus menunjukkan komitmen kuat dalam mendukung program Wali Kota untuk menekan angka stunting di daerah. Melalui gerakan Inovasi 3S (Segenggam Beras, Sebutir Telur, Seribu Rupiah), Diskominfosta kembali melanjutkan aksi nyata dalam gerakan peduli gizi anak pada minggu keempat bulan Oktober 2025, tepatnya Selasa (14/10/2025).<br><br></div><div>Kepala Diskominfosta Kota Sungai Penuh, H. Josrizal Helman, S.Si., Apt., menyampaikan bahwa kegiatan ini merupakan bentuk nyata kepedulian sosial jajaran Diskominfosta terhadap peningkatan gizi masyarakat, terutama anak-anak dari keluarga kurang mampu.<br><br></div><div>” Gerakan ini sederhana tapi sangat bermakna. Dengan kebersamaan, kita bisa membantu pemenuhan gizi anak dan menekan angka stunting di Kota Sungai Penuh,” ujar Josrizal.<br><br></div><div>“Program Inovasi 3S ini dilaksanakan secara rutin setiap minggu oleh seluruh pegawai Diskominfosta. Masing-masing pegawai berpartisipasi dengan menyumbangkan segenggam beras, sebutir telur, dan seribu rupiah, yang kemudian disalurkan langsung kepada masyarakat yang membutuhkan,” Tambahnya.<br><br></div><div>Josrizal berharap gerakan ini dapat menjadi inspirasi bagi masyarakat dan instansi lain untuk ikut serta dalam membangun kesadaran gizi serta semangat kepedulian sosial.<br><br></div><div>” Kita berharap, semua ikut serta dalam mencegah stunting, stunting bukan hanya persoalan kesehatan, tapi tanggung jawab bersama. Lewat Inovasi 3S, kita ingin membangun semangat gotong royong demi melahirkan generasi Sungai Penuh yang sehat dan kuat,” Harapnya.<br><br></div><div>Gerakan sosial ini menjadi bukti nyata bahwa Kominfo Sungai Penuh tidak hanya fokus pada bidang informasi, tetapi juga aktif dalam kegiatan sosial yang berdampak langsung bagi kesejahteraan masyarakat.&nbsp;<br><br></div><div>(MC Diskominfosta)<br><br></div>','upload/berita/ZACX4gOz1b4G9bLo4wbriCLA6RUKMPwx2VAztTPw.png','mediacenter','kominfo-sungai-penuh-konsisten-jalankan-gerakan-peduli-gizi-anak-dan-lawan-stunting','2025-10-16 10:19:01','2025-10-16 10:19:01'),(98,'Walikota Sungai Penuh Lantik Pengurus APDESI Periode 2025–2030','<div>Walikota Sungai Penuh Lantik Pengurus APDESI Periode 2025–2030</div><div>SUNGAI PENUH - Walikota Sungai Penuh secara resmi melantik jajaran pengurus Asosiasi Pemerintah Desa Seluruh Indonesia (APDESI) Kota Sungai Penuh periode 2025–2030, Bertempat Di Aula Kantor Walikota, Selasa (14/10).</div><div>Dalam kepengurusan baru ini, Amrizal dipercaya sebagai Ketua APDESI Kota Sungai Penuh, didampingi Jon Afrizal, Alpi Pinaldi, Armadi, dan Supriadi, SE sebagai Wakil Ketua. Posisi Sekretaris diisi oleh Andika Putra, S.Pd, dengan Nafrial sebagai Wakil Sekretaris. Sementara Jonimo Hendra menjabat sebagai Bendahara, dibantu Edi Zulfnadi sebagai Wakil Bendahara.</div><div>Dewan Pertimbangan Organisasi diisi oleh tokoh-tokoh berpengalaman, di antaranya Eva Haryadi, Antorudin, S.Sos., MM, Ir. Efdal Taufik, Yuhanis Miftah, Fitria Zydova, ST, Damzurizal, David Indra G., dan Jonfrianto.</div><div>Selain jajaran inti, APDESI juga menempatkan sejumlah koordinator di bidang strategis seperti:</div><div>Organisasi &amp; Kelembagaan: Ustia Esa (Koordinator), Zarman Efendi, Eri Susirial.</div><div>Pemberdayaan: Rudi Hartono (Koordinator), Syaftuni, Hermandanus.</div><div>Ekonomi &amp; Koperasi: Azwardi (Koordinator), Hazmal, Khairul Saleh, Itarlis.</div><div>Pendidikan &amp; Pelatihan: Zaharman (Koordinator), Mat Nazir, Jandri Irman.</div><div>Informasi &amp; Komunikasi: Juma Tesman (Koordinator), Hendri Fetrialdi, Idon, Arussalam.</div><div>Hukum, HAM &amp; Perundangan: Indra Jaya (Koordinator), Afrizal DN, Repelman, Dahirzal.</div><div>Percepatan Pembangunan Desa Tertinggal: Marmin Elvian (Koordinator), Tansrila, Afrizal.</div><div>Hubungan Antar Lembaga: Ahmad Kamil (Koordinator), Diantoni, Mairizon.</div><div>Kebudayaan &amp; Pariwisata: Alparis (Koordinator), Efiar, Adnan, <a href=\"https://l.facebook.com/l.php?u=http%3A%2F%2FS.Ag%2F%3Ffbclid%3DIwZXh0bgNhZW0CMTAAYnJpZBExWUdtbGRWWWdqU0xLWmtNSQEe1tMq7jkorIn4UnM2dOsMWL25HmMNMUkl5Ov8Ta0mLSAoomLlzvgWyoOSgKs_aem_SINGxsKys5aXT3LdI5b3LA&amp;h=AT2ulB83FlSWwjCuDEF3wCiiwPt0CFpdm-5ss3JcrxFvU_p7WS3BEDTRqnGuycJoo_zxvXVjVi_syrDjymDgyr0g7Z7AqgSOKY8nUbmlH0pbY6C5b8vLnVFglonL6G9UUsRyExbnbnw033RGwjVDcA&amp;__tn__=-UK-R&amp;c[0]=AT0RFl7rNBMBV1uK8urbbtUNrbLY_cBDv8zIrY-doWoJJg9t4M7xSwmO7N9bsdexq0NralqydGgc7VIeDNb618wDHKGvbT2ecnSC2U-kUZk6agDLhf9-zZ92ponfQKtymi_Q-Ye76deeGyhCHjgZpgNKb194ME-dnBweD1n2L12s3VpzFeQ-o_g6rxoMm9-lELYmhcSggKhmDLUhuggK5-2XJg\"><strong>S.Ag</strong></a>, Zulfajri.</div><div>Pemuda &amp; Olahraga: Romi Jon Fitra (Koordinator), Feri Putra, Noka Putra, Nodi Saputra.</div><div>Kemasyarakatan: Mattakin (Koordinator), Ainal Fari, Hendrin, H. Amrizal.</div><div>Lingkungan Hidup: Hendrika (Koordinator), Dapuwadi, Arman.</div><div>Dalam sambutannya, Walikota Sungai Penuh menegaskan bahwa APDESI merupakan mitra strategis pemerintah dalam mewujudkan pembangunan yang merata dan berkelanjutan.</div><div>\"Dalam konteks otonomi daerah, desa memegang peranan penting sebagai entitas pemerintahan terdepan yang langsung bersentuhan dengan masyarakat,\" ujarnya.</div><div>Ia menegaskan bahwa Pemerintah Kota Sungai Penuh berkomitmen penuh mendukung penguatan pemerintahan desa agar semakin maju, mandiri, dan sejahtera.</div><div>\"Sinergi antara pemerintah kota dan pemerintah desa harus semakin erat, saling mendukung, dan saling menguatkan,\" tambahnya.</div><div>Walikota juga berharap kepengurusan baru APDESI dapat memperkuat sinergi antara pemerintah desa dan pemerintah kota, menjadi wadah komunikasi dan koordinasi yang konstruktif, serta pelopor inovasi desa dan penggerak pemberdayaan masyarakat.</div><div>Selain itu, ia menekankan pentingnya integritas dan profesionalisme dalam pengelolaan dana desa serta pelayanan publik. Pemerintah Kota Sungai Penuh juga siap memberikan pendampingan agar aparatur desa semakin profesional, transparan, dan akuntabel.</div><div>\"Mari kita letakkan kepentingan masyarakat di atas segalanya. Jadikan desa sebagai ruang tumbuhnya partisipasi dan kemandirian warga. Kita bergerak menuju pemerintahan desa digital yang transparan, cepat, dan efisien,\" tutupnya.</div><div>Sementara itu, Amrizal, Ketua APDESI terpilih, mengucapkan terima kasih atas kepercayaan yang diberikan kepadanya untuk memimpin organisasi ini. Ia menegaskan bahwa APDESI siap mendukung setiap program dan kebijakan Pemerintah Kota Sungai Penuh demi kemajuan desa-desa di wilayah tersebut.</div><div>Senada dengan itu, Samsul Fuad, Ketua APDESI Provinsi Jambi, dalam sambutannya mengajak seluruh pengurus yang baru dilantik untuk berkolaborasi dengan pemerintah daerah serta mendukung visi dan misi Pemerintah Kota Sungai Penuh.</div><div>Kepengurusan baru ini diharapkan mampu menjadi motor penggerak dalam memperkuat sinergi antara pemerintah desa dan kota, sekaligus mempercepat pembangunan berbasis potensi lokal di setiap desa di Kota Sungai Penuh.</div><div>Dengan semangat baru dan komitmen kuat, APDESI Kota Sungai Penuh bertekad mewujudkan pemerintahan desa yang profesional, mandiri, dan berdaya saing, menuju kesejahteraan masyarakat desa yang berkelanjutan.</div><div>(MC KOMINFO)</div>','upload/berita/WoNRG3r4ZjFgbaAugECbr3gknkWYApchyvbzIllh.png','mediacenter','walikota-sungai-penuh-lantik-pengurus-apdesi-periode-2025-2030','2025-10-16 10:20:23','2025-10-16 10:20:23'),(99,'Wako Alfin Pimpin Rapat Persiapan Jambore PKK 2025','<div>Wako Alfin Pimpin Rapat Persiapan Jambore PKK 2025</div><div>SUNGAI PENUH - Menjelang pelaksanaan Jambore PKK 2025, Walikota Sungai Penuh, Alfin, SH, memimpin langsung rapat persiapan yang digelar di Rumah Dinas Walikota, Rabu (15/10/2025).</div><div>Rapat tersebut membahas secara detail kesiapan kegiatan, mulai dari pemetaan lokasi, rangkaian acara, hingga teknis pelaksanaan di lapangan. Selain itu, juga dibahas opsi sektor parkir dan pengaturan lalu lintas untuk memastikan seluruh kegiatan berjalan tertib, aman, dan lancar.</div><div>Turut hadir dalam rapat, Wakil Walikota Sungai Penuh Azhar Hamzah, Ketua TP PKK Kota Sungai Penuh Sri Kartini Alfin beserta jajaran, serta para Kepala SKPD terkait.</div><div>Jambore PKK Kota Sungai Penuh dijadwalkan berlangsung pada 1 hingga 8 November 2025 di Lapangan Merdeka dan sejumlah titik kegiatan di sekitarnya.</div><div>Walikota Alfin menegaskan pentingnya dukungan penuh dari seluruh SKPD agar pelaksanaan Jambore berjalan sukses dan menjadi momentum mempererat kebersamaan antarwarga.</div><div>“Kita semua harus mendukung Jambore PKK ini agar berjalan lancar dan meriah. Kegiatan ini melibatkan banyak pihak, jadi perlu koordinasi dan partisipasi dari semua elemen,” ujar Wako Alfin.</div><div>Ia juga mengingatkan agar pengaturan parkir dilakukan secara tertib serta setiap atraksi dan pertunjukan budaya disusun dengan jadwal yang teratur.</div><div>Sementara itu, Wakil Walikota Azhar Hamzah menambahkan bahwa kegiatan Jambore PKK merupakan agenda besar yang membutuhkan kerja sama dan kekompakan seluruh unsur.</div><div>“Ini kegiatan besar yang harus kita sukseskan bersama. Mari berpartisipasi dan tunjukkan semangat kebersamaan di ajang Jambore PKK 2025 ini,” ungkapnya.</div>','upload/berita/CH55um9aJmqgSo4GYio2gIFbOzYmJSe4oTQUfNjU.png','mediacenter','wako-alfin-pimpin-rapat-persiapan-jambore-pkk-2025','2025-10-16 10:22:00','2025-10-16 10:22:00'),(100,'Pemkot Sungai Penuh Terima Bantuan 20 Unit Hydroteler dari Menteri Pertanian','<div>Pemkot Sungai Penuh Terima Bantuan 20 Unit Hydroteler dari Menteri Pertanian</div><div>SUNGAI PENUH - Pemerintah Kota Sungai Penuh menerima bantuan alat dan mesin pertanian (Alsintan) berupa 20 unit hydroteler dari Menteri Pertanian Republik Indonesia, Andi Amran Sulaiman.</div><div>Bantuan ini merupakan hasil dari permintaan langsung Walikota Sungai Penuh, Alfin, SH, kepada Menteri Pertanian saat kunjungan kerja ke Sungai Penuh dan Kerinci beberapa waktu lalu. Tujuannya untuk mempercepat proses tanam, meningkatkan produktivitas petani, dan mendukung program ketahanan pangan nasional yang digagas Presiden Prabowo Subianto.</div><div>“Kita telah menyerahkan proposal kepada Kementan saat kunjungan kerja ke Sungai Penuh dan Kerinci. Alhamdulillah, bantuan tersebut kini sudah terealisasi,” ujar Walikota Alfin.</div><div>Wako Alfin menegaskan, bantuan ini menjadi bukti komitmen Kementerian Pertanian dalam memperkuat sektor pertanian di daerah. Ia juga mengapresiasi perhatian Menteri Amran yang terus mendorong peningkatan produktivitas pertanian secara merata di seluruh Indonesia.</div><div>“Bantuan ini bukan sekadar hadiah, tapi akan dikontrol dan diawasi secara berkelanjutan oleh Kementerian Pertanian. Harapannya, alat ini benar-benar dimanfaatkan untuk meningkatkan kesejahteraan petani dan pertumbuhan ekonomi daerah,” tambahnya.</div><div>Sementara itu, Kepala Dinas Pertanian dan Hortikultura Kota Sungai Penuh, Armen, SP, menjelaskan bahwa 20 unit hydroteler tersebut akan disalurkan kepada kelompok tani di berbagai wilayah.</div><div>“Alat ini diperuntukkan bagi kelompok tani untuk percepatan tanam dan pengolahan lahan pertanian. Kami harap bantuan ini benar-benar dimanfaatkan secara maksimal,” ujarnya.</div><div>Dengan adanya dukungan ini, diharapkan para petani di Sungai Penuh dapat meningkatkan hasil panen dan memperkuat kontribusi sektor pertanian terhadap pembangunan ekonomi daerah.</div><div>(MC KOMINFO)</div>','upload/berita/vQje1SfTMCwBPPWKIjWf5TSfrrmmNfHII0QCwp8a.png','mediacenter','pemkot-sungai-penuh-terima-bantuan-20-unit-hydroteler-dari-menteri-pertanian','2025-10-16 15:43:07','2025-10-16 15:43:07'),(101,'Bunda PAUD Sungai Penuh Dorong Sinergi Keluarga dan Sekolah Wujudkan Generasi Emas','<div>Bunda PAUD Sungai Penuh Dorong Sinergi Keluarga dan Sekolah Wujudkan Generasi Emas&nbsp;</div><div>SUNGAI PENUH - Bunda PAUD Kota Sungai Penuh, Ny. Sri Kartini Alfin, S.Kep., Ns., membuka secara resmi Workshop Pendidikan Keluarga bagi guru PAUD se-Kota Sungai Penuh Tahun 2025.</div><div>Kegiatan ini digelar di Aula Hotel Arafah, Kamis (16/10/2025), dan dihadiri oleh Ketua Pokja Bunda PAUD, para pengawas TK, pemilik PAUD dan PNF, serta kepala sekolah TK, KB, SPS, dan TPA.</div><div>Workshop ini bertujuan memperkuat sinergi antara satuan PAUD, keluarga, dan lingkungan dalam membangun generasi emas Indonesia yang cerdas dan berkarakter.</div><div>Dalam sambutannya, Bunda PAUD Sri Kartini Alfin menegaskan bahwa keluarga merupakan pendidik pertama dan utama dalam kehidupan anak sejak lahir hingga usia sekolah.</div><div>“Keluarga menjadi lingkungan pertama yang membentuk kepribadian, nilai moral, agama, serta kebiasaan dasar anak dalam kehidupan,” ujarnya.</div><div>Ia menekankan pentingnya peran orang tua, bukan hanya dalam memenuhi kebutuhan fisik anak, tetapi juga memberikan dukungan emosional, stimulasi intelektual, serta keteladanan dalam pembentukan karakter di rumah.</div><div>Sri Kartini berharap melalui kegiatan ini para guru PAUD dapat memperdalam pemahaman tentang pentingnya peran keluarga sebagai bagian yang tidak terpisahkan dari pendidikan di sekolah.</div><div>“Guru PAUD bukan hanya pendidik di kelas, tetapi juga mitra strategis bagi keluarga dalam mendampingi tumbuh kembang anak secara holistik dan integratif,” jelasnya.</div><div>Bunda PAUD juga mengajak seluruh peserta untuk menjadikan workshop ini sebagai momentum memperkuat komitmen bersama dalam membangun kolaborasi antara sekolah, keluarga, dan masyarakat.</div><div>“Mari kita wujudkan generasi emas Indonesia yang sehat, cerdas, ceria, dan berakhlak mulia,” pesannya.</div><div>Sebagai penutup kegiatan, Bunda PAUD Sri Kartini Alfin menandatangani Nota Kesepahaman (MoU) dengan Dinas Pemberdayaan Perempuan, Perlindungan Anak, dan Pengendalian Penduduk (DP3A) Kota Sungai Penuh.</div><div>Kesepakatan ini menjadi langkah nyata dalam memperkuat program kolaboratif yang mendukung Pokja Bunda PAUD, terutama dalam bidang pendidikan keluarga, perlindungan anak, dan pemberdayaan perempuan.</div><div>Melalui kerja sama ini, diharapkan sinergi antar lembaga semakin optimal dalam menciptakan lingkungan belajar yang aman, inklusif, dan berkelanjutan bagi anak usia dini di Kota Sungai Penuh.</div><div>(Mc Kominfo)</div>','upload/berita/I6pIXtPgEKsmRY0vypvNE4C8rWXPs1fUGPd1VsfG.png','mediacenter','bunda-paud-sungai-penuh-dorong-sinergi-keluarga-dan-sekolah-wujudkan-generasi-emas','2025-10-16 15:44:42','2025-10-16 15:44:42'),(102,'Wako Alfin Apresiasi Program Bedah Rumah BSPS','<div>Wako Alfin Apresiasi Program Bedah Rumah BSPS&nbsp;</div><div>SUNGAI PENUH - Walikota Sungai Penuh, Alfin, SH, menyampaikan apresiasi tinggi terhadap Program Bantuan Stimulan Perumahan Swadaya (BSPS) atau yang lebih dikenal dengan Program Bedah Rumah dari Kementerian Perumahan dan Kawasan Permukiman Republik Indonesia.</div><div>Pernyataan tersebut disampaikan Wako Alfin saat membuka secara resmi kegiatan Launching BSPS Tahun 2025 yang digelar di Aula Kantor Walikota Sungai Penuh, Kamis (16/10/2025).</div><div>Acara turut dihadiri oleh Wakil Walikota Sungai Penuh Azhar Hamzah, Ketua DPRD Hutri Randa, Kepala Balai Pelaksana Penyedia Perumahan dan Kawasan Permukiman Sumatera yang diwakili oleh Kasi Wilayah II Gusman, ST, MM, serta Kepala Satker Perumahan dan Kawasan Permukiman Provinsi Jambi Yusra Dwi Yani Safrini, ST.</div><div>Turut hadir pula Ketua TP PKK Sri Kartini Alfin, Ketua Dharma Wanita Winda Rahayu, para kepala SKPD, dan tamu undangan lainnya.</div><div>Dalam sambutannya, Wako Alfin menyampaikan bahwa Program Bedah Rumah merupakan solusi nyata untuk membantu masyarakat yang memiliki rumah tidak layak huni sekaligus menumbuhkan semangat gotong royong dan kemandirian melalui swadaya masyarakat.</div><div>“Pemerintah Kota Sungai Penuh sangat mengapresiasi program ini sebagai bentuk kepedulian pemerintah pusat terhadap masyarakat. Program BSPS tidak hanya sebatas bantuan, tetapi juga mendorong partisipasi warga untuk bergotong royong memperbaiki rumah mereka agar lebih layak huni,” ujar Wako Alfin.</div><div>Diketahui, tahun 2025 ini terdapat 146 unit rumah di Kota Sungai Penuh yang menerima bantuan program BSPS. Program ini diharapkan dapat menjadi stimulan bagi masyarakat untuk terus meningkatkan kualitas tempat tinggal dan lingkungan sekitar.</div><div>Lebih lanjut, Walikota Alfin menegaskan bahwa pemerintah daerah siap mendukung penuh berbagai program pusat yang memberikan dampak langsung bagi masyarakat, terutama dalam peningkatan kesejahteraan dan kualitas hidup warga.(Mc Kominfo)</div>','upload/berita/kJc5buUSThxFu4a5x6PZJsqbmoPmXqJPR5XoaJXb.png','mediacenter','wako-alfin-apresiasi-program-bedah-rumah-bsps','2025-10-16 15:46:10','2025-10-16 15:46:10'),(103,'Wako dan Wawako Sungai Penuh Tinjau Madrasah di Tanjung Muda','<div>Wako dan Wawako Sungai Penuh Tinjau Madrasah di Tanjung Muda&nbsp;</div><div>SUNGAI PENUH - Pemerintah Kota Sungai Penuh terus menunjukkan komitmennya terhadap kemajuan dunia pendidikan.</div><div>Walikota Sungai Penuh Alfin, SH, bersama Wakil Walikota Azhar Hamzah, meninjau langsung Madrasah Ibtidaiyah di Desa Tanjung Muda, Kecamatan Hamparan Rawang, Jumat (17/10/2025).</div><div>Turut hadir dalam kegiatan ini Anggota DPRD Kota Sungai Penuh Dapil 2 Dakir Yahya, Camat Hamparan Rawang, Kepala Desa Tanjung Muda, serta pihak yayasan dan dewan guru madrasah. Kehadiran unsur pemerintahan dan legislatif ini menjadi bentuk nyata kepedulian bersama terhadap dunia pendidikan.</div><div>Kunjungan tersebut bertujuan meninjau kondisi sarana pendidikan sekaligus mendengarkan langsung berbagai kendala yang dihadapi pihak sekolah di bawah naungan Kementerian Agama itu.</div><div>Dalam dialog dengan guru dan pengurus yayasan, Wako dan Wawako menerima sejumlah aspirasi, termasuk mengenai status tanah sekolah yang diketahui merupakan Tanah Kas Desa (TKD) dan belum memiliki Nomor Induk Berusaha (NIB).</div><div>Selain itu, pihak sekolah juga menghadapi kendala administratif seperti pelaporan NPWP 2025, yang menjadi syarat penting dalam pengajuan bantuan pendidikan baik dari pemerintah pusat maupun daerah.</div><div>Menanggapi hal tersebut, Walikota Alfin menegaskan bahwa Pemerintah Kota Sungai Penuh siap memfasilitasi pengurusan izin dan legalitas sekolah, agar pihak madrasah tidak lagi terkendala dalam pengajuan bantuan pembangunan maupun peningkatan sarana pendidikan.</div><div>“Pemerintah kota akan membantu pengurusan izin dan legalitas tanah sekolah agar tidak ada lagi hambatan bagi madrasah untuk berkembang,” ujar Wako Alfin.</div><div>Ia juga menegaskan, perhatian terhadap pendidikan keagamaan seperti madrasah merupakan bagian penting dari visi misi Pemkot Sungai Penuh dalam membangun sumber daya manusia yang unggul dan berakhlak mulia.</div><div>Menurutnya, pendidikan agama sejak dini menjadi pondasi utama dalam membentuk karakter generasi penerus bangsa.</div><div>Kunjungan tersebut pun disambut antusias oleh pihak sekolah dan masyarakat setempat yang mengaku senang atas perhatian pemerintah kota terhadap dunia pendidikan.</div><div>Dalam kesempatan itu, pihak sekolah juga menyampaikan harapan agar Pemkot Sungai Penuh dapat membantu proses alih status dari madrasah swasta menjadi madrasah negeri, sehingga kualitas pelayanan pendidikan semakin meningkat.</div><div>Langkah ini menjadi bukti bahwa Pemkot Sungai Penuh bersama DPRD, kecamatan, dan perangkat desa berkolaborasi nyata dalam memajukan sektor pendidikan sebagai investasi jangka panjang untuk kemajuan Kota Sungai Penuh.(Tim)</div>','upload/berita/lhkw5u279d64yHndsMjIMXukxN748r54BnsN6o21.png','mediacenter','wako-dan-wawako-sungai-penuh-tinjau-madrasah-di-tanjung-muda','2025-10-23 13:07:22','2025-10-23 13:07:22'),(104,'Wako Alfin Tinjau Relokasi Pedagang Pasar Beringin, Instruksikan Pembenahan Fasilitas Kincai Plaza','<div>Wako Alfin Tinjau Relokasi Pedagang Pasar Beringin, Instruksikan Pembenahan Fasilitas Kincai Plaza</div><div>SUNGAI PENUH – Upaya Pemerintah Kota Sungai Penuh untuk menata kembali kawasan perdagangan terus berjalan. Sabtu (18/10/25), Wali Kota Sungai Penuh Alfin, S.H., turun langsung meninjau lokasi relokasi pedagang eks Pasar Beringin di lantai dua Kincai Plaza guna memastikan aktivitas jual beli berjalan lancar dan fasilitas umum dalam kondisi layak.</div><div>Kunjungan ini menjadi bagian dari rangkaian penataan pasar tradisional sekaligus memastikan pedagang mendapat tempat usaha sementara yang aman dan nyaman menjelang selesainya pembangunan Pasar Sungai Penuh (Pasar Beringin) yang baru.</div><div>Di lokasi, Wako Alfin menyapa satu per satu pedagang dan berdialog langsung dengan mereka. Ia ingin memastikan seluruh pedagang sudah menempati kios relokasi sesuai peruntukan dan tetap bisa berjualan seperti biasa.</div><div>Selain memantau aktivitas perdagangan, Wako juga meninjau kondisi umum Kincai Plaza, termasuk fasilitas publik seperti toilet, saluran air, dan tempat pembuangan sampah. Ia meminta pengelola segera melakukan perbaikan agar kenyamanan pengunjung dan pedagang tetap terjaga.</div><div>“Perbaiki segera fasilitas umum seperti toilet, saluran air, dan tempat pembuangan sampah agar nyaman ditinggali dan dikunjungi,” tegas Wako Alfin kepada pengelola Kincai Plaza.</div><div>Sebelumnya, Wako Alfin juga memantau langsung proses pembongkaran Pasar Beringin sebagai langkah awal pembangunan Pasar Sungai Penuh yang modern dan representatif. (MC. KOMINFO)</div>','upload/berita/xjHHhdWICHQUguTAt5VjAPB85wIVyhozsMpcTDHw.png','mediacenter','wako-alfin-tinjau-relokasi-pedagang-pasar-beringin-instruksikan-pembenahan-fasilitas-kincai-plaza','2025-10-23 13:10:07','2025-10-23 13:10:07'),(105,'Wako Alfin Hadiri Reuni Akbar Ke 3 dan HUT ke-79 SMPN 1 Sungai Penuh','<div>Wako Alfin Hadiri Reuni Akbar Ke 3 dan HUT ke-79 SMPN 1 Sungai Penuh</div><div>SUNGAI PENUH - Wali Kota Sungai Penuh, Alfin, SH, menghadiri Reuni Akbar Ikatan Alumni (Iluni) SMP Negeri 1 Sungai Penuh lintas angkatan ke-3 yang dirangkaikan dengan peringatan Hari Ulang Tahun (HUT) ke-79 SMPN 1 Sungai Penuh, Sabtu (18/10/2025).&nbsp;</div><div>Acara berlangsung meriah dan penuh keakraban di halaman sekolah, dihadiri ratusan alumni dari berbagai angkatan dan daerah. Momen reuni ini menjadi ajang bernostalgia sekaligus mempererat silaturahmi keluarga besar SMPN 1 Sungai Penuh.</div><div>Turut hadir dalam kegiatan tersebut unsur pimpinan DPRD Kota Sungai Penuh Hardizal, para staf ahli wali kota, asisten sekda, kepala perangkat daerah, serta pejabat di lingkungan Pemerintah Kota Sungai Penuh.&nbsp;</div><div>Hadir pula Ketua Umum Iluni SMPN 1 Sungai Penuh Ir. Havizal Rahman, M.M., Kepala Sekolah Gopi Indra Saputra, S.Pd., beserta majelis guru dan Ketua Panitia Reuni Akbar ke-3, Drs. Zulkifli.&nbsp;</div><div>Dalam sambutannya, Wali Kota Alfin menyampaikan rasa syukur dan kebahagiaan bisa hadir di tengah keluarga besar alumni SMPN 1 Sungai Penuh. Ia menyebut kegiatan reuni bukan sekadar ajang temu kangen, tetapi juga wadah memperkuat kebersamaan dan solidaritas antaralumni.&nbsp;</div><div>“Reuni seperti ini adalah kesempatan berharga untuk mempererat silaturahmi, menjaga hubungan baik antaralumni, serta membangun sinergi antara alumni dan almamater,” ujar Alfin.&nbsp;</div><div>Mengangkat tema \"Bertemu, Bersatu, dan Bernostalgia dalam Menggapai Kesuksesan\" kegiatan ini dinilai sangat relevan. Menurut Wali Kota, reuni menjadi pengingat akan nilai-nilai pendidikan dan karakter yang telah membentuk semangat para alumni dalam meniti karier dan kehidupan.&nbsp;</div><div>Alfin juga menyampaikan apresiasi kepada para guru yang telah mengabdikan diri bagi kemajuan pendidikan. Ia menegaskan, berkat jasa dan dedikasi para pendidik, banyak alumni SMPN 1 Sungai Penuh yang kini berkiprah di berbagai bidang, mulai dari akademisi, birokrat, hingga wirausaha dan tokoh masyarakat.&nbsp;</div><div>“Guru-guru kita adalah fondasi lahirnya generasi hebat. Karena merekalah, banyak alumni SMPN 1 yang sukses berkontribusi di berbagai sektor,” ungkapnya. Di akhir sambutannya, Wali Kota Alfin mengajak seluruh alumni untuk terus berperan aktif mendukung kemajuan almamater, baik melalui bantuan pendidikan, beasiswa, peningkatan fasilitas sekolah, maupun pelatihan soft skills bagi siswa.&nbsp;</div><div>Ia juga mengingatkan agar tali silaturahmi antaralumni terus terjaga sebagai kekuatan besar bagi masyarakat. Sebagai bentuk dukungan nyata, Wali Kota Alfin turut menyerahkan bantuan CSR sebesar Rp10 juta untuk pembangunan di SMP Negeri 1 Sungai Penuh.&nbsp;</div><div>(MC KOMINFO)</div>','upload/berita/6LSLobw3lmv0xTE6lJHSwUmrZR3N2qNfvmkJUiHq.png','mediacenter','wako-alfin-hadiri-reuni-akbar-ke-3-dan-hut-ke-79-smpn-1-sungai-penuh','2025-10-23 13:46:45','2025-10-23 13:46:45'),(106,'Transformasi Pasar Beringin Jaya, Wako Alfin Pastikan Pembangunan Berjalan Aman dan Terencana','<div>Transformasi Pasar Beringin Jaya, Wako Alfin Pastikan Pembangunan Berjalan Aman dan Terencana</div><div>SUNGAI PENUH - Suara alat berat menggema di kawasan Pasar Beringin Jaya, Minggu (18/10/2025), saat Wali Kota Sungai Penuh Alfin, SH, memantau langsung proses pembongkaran bangunan lama. Kehadirannya menjadi bentuk komitmen pemerintah kota dalam memastikan proyek revitalisasi pasar berjalan tertib, aman, dan tepat waktu.</div><div>Bangunan pasar yang sudah berdiri puluhan tahun itu kini mulai diratakan untuk memberi ruang bagi pembangunan gedung baru tiga lantai dengan fasilitas parkir yang lebih memadai. Proyek senilai Rp55 miliar tersebut dijadwalkan mulai dikerjakan awal November 2025.</div><div>Dalam peninjauan itu, Wako Alfin didampingi jajaran Dinas PUPR dan Dinas Perdagangan. Ia memastikan seluruh tahapan pembongkaran berjalan sesuai prosedur serta tidak menimbulkan gangguan bagi warga sekitar.</div><div>“Alhamdulillah, sejauh ini pembongkaran berjalan aman dan tidak mengganggu aktivitas masyarakat maupun pedagang,” ujar Alfin.</div><div>Selama proses berlangsung, para pedagang dialihkan ke Kincai Plaza Lantai 2 sebagai lokasi penampungan sementara agar kegiatan jual beli tetap berjalan lancar. (MC.KOMINFO)</div>','upload/berita/R23fZjlzYBEe3ZCXvQ51tzTF1VDW765b43MsfuWF.png','mediacenter','transformasi-pasar-beringin-jaya-wako-alfin-pastikan-pembangunan-berjalan-aman-dan-terencana','2025-10-23 13:48:05','2025-10-23 13:48:05'),(107,'Sekda Alpian Pimpin Rapat Persiapan HUT ke-17 Kota Sungai Penuh','<div>Sekda Alpian Pimpin Rapat Persiapan HUT ke-17 Kota Sungai Penuh</div><div>SUNGAI PENUH - Menjelang peringatan Hari Jadi ke-17 Kota Sungai Penuh tahun 2025, Pemerintah Kota Sungai Penuh menggelar rapat pemantapan yang juga dirangkaikan dengan persiapan upacara Hari Sumpah Pemuda. Rapat berlangsung di Aula Kantor Walikota Sungai Penuh, Selasa (21/10).</div><div>Sekretaris Daerah Kota Sungai Penuh, Alpian, memimpin langsung jalannya rapat yang turut dihadiri para asisten, staf ahli, kepala SKPD, camat, Ketua DWP, serta pejabat struktural dan fungsional lingkup Pemkot Sungai Penuh.&nbsp;</div><div>Dalam arahannya, Sekda Alpian menegaskan pentingnya kerja sama dan sinergi lintas perangkat daerah agar pelaksanaan dua agenda besar ini dapat berjalan sukses dan meriah.&nbsp;</div><div>“Peringatan Hari Jadi Kota Sungai Penuh dan Hari Sumpah Pemuda harus kita maknai sebagai momentum memperkuat semangat persatuan dan kebersamaan dalam membangun daerah,” ujar Sekda Alpian.&nbsp;</div><div>Ia juga mengimbau setiap OPD berperan aktif dalam berbagai rangkaian kegiatan, baik seremonial, hiburan, maupun aksi sosial yang melibatkan partisipasi masyarakat secara luas.</div><div>Adapun rangkaian kegiatan peringatan Hari Jadi ke-17 Kota Sungai Penuh akan dimulai pada akhir Oktober hingga awal November 2025. Sementara upacara Hari Sumpah Pemuda dijadwalkan berlangsung pada 28 Oktober di halaman Kantor Walikota Sungai Penuh.&nbsp;</div><div>(MC KOMINFO)</div>','upload/berita/yuwAx0A0CzkuiDsTO9nn2Vw5dGZDaF0yAJwDPMCc.png','mediacenter','sekda-alpian-pimpin-rapat-persiapan-hut-ke-17-kota-sungai-penuh','2025-10-23 13:50:16','2025-10-23 13:50:16'),(108,'Diskominfo Kota Sungai Penuh Adakan Pemeriksaan Kesehatan Secara Gratis','<div>Diskominfo Kota Sungai Penuh Adakan Pemeriksaan Kesehatan Secara Gratis</div><div>SUNGAI PENUH- Wartawan (Pers), Aparatur Sipil Negara (ASN) Dinas Komunikasi, Informasi dan Statistik Kota Sungai Penuh memeriksa kesehatan yang dilakukan secara gratis.</div><div>Kegiatan tersebut bertempat di Aula Kantor Diskominfosta Kota Sungai Penuh. Tidak hanya ASN dan Wartawan, Non ASN juga ikut serta dalam pemeriksaan kesehatan itu.</div><div>Tujuannya, mengupayakan pendeteksi atau mencegah penyakit. Pengecekkan kesehatan ini dilakukan oleh tim Medis dalam naungan Dinas Kesehatan Kota Sungai Penuh.&nbsp;</div><div>Kegiatan ini diadakan pihak Diskominfosta Kota Sungai Penuh, berkerja sama dengan Dinkes. Kemudian giat pemeriksaan kesehatan seperti ini nantinya juga akan dilakukan secara merata oleh Dinkes ke Masyarakat bekerja sama dengan Intansi yang ada di Kota Sungai Penuh.</div><div>Kepala Dinas Diskominfosta Kota Sungai Penuh H. Josrizal Helman, <a href=\"https://l.facebook.com/l.php?u=http%3A%2F%2FS.si%2F%3Ffbclid%3DIwZXh0bgNhZW0CMTAAYnJpZBExZWk4MDZEVUhsTHIyOVROZwEeKC9lvhYtdV5cPO2em-o6YEwig_C0qMXSReuoJ0TWAuLOdU71SRFF9eHNUkA_aem_gP3gUBcTyUdKZMUxk5p5Qw&amp;h=AT05xe1gUAOjLaJr9vKJ7QiJh92uBUoE2FqwaHJZMkhsJOSZq6g_9rsEeXA-GQn0WWJtF-5i_BChgW4RQbulWyy5ClAhCHWz5ZgxM-nF7-JXT88SwY9-FCfGg0S6sDSp6uXkn5rAPQle44-CH7HuDA&amp;__tn__=-UK-R&amp;c[0]=AT0bV_5FP9AzJ9bueM2i2BBSVtOkklzXq36IevlFCuk_jQmAdkg65vOXHFhe6hVfZtl3BFojuiKYxl4h7fVJqhP740rNzDas3l0tLoUZyOA8YC0b5_2teh-04b0fLfynDE7OidbxhC4g4GzG-zg0td4KZmzTphjn-A1YZLEnLQ\"><strong>S.si</strong></a>, Apt mengapresiasi kegiatan pemeriksaan kesehatan ini. Baginya, sebagai langkah untuk menju Kota sehat, selain itu mendeteksi gaguan kesehatan serta penangananya.</div><div>“Kami sangat mengapresiasi kegiatan dimaksud, hal ini sangat bermanfaat dan sebagai bentuk kontribusi atau langkah nyata pihak Dinkes dan tim medis. Yang mana sangat berguna bagi para ASN, non ASN di Diskominfo Kota Sungai Penuh, Wartawan termasuk masyarakat”ungkapnya</div><div>Perwakilan Wartawan, Khairi, mengatakan pihaknya sangat berterima kasih adanya pemeriksaan yang dilakukan secara gratis. Semoga bermanfaat demi Kota Sehat.</div><div>\"Kami mengucapkan ribuan terima kasih atas kegiatan ini, terutama Dinkes, tim medis dan Diskominfo Kota Sungai Penuh, semoga dapat bermanfaat untuk menuju Kota Sehat\"katanya. [ ]</div><div>(Mc Diskominfosta)</div>','upload/berita/9UMA6CN8Qo57q2FrtnjAjIM0mDtuik2qreG1h03R.png','mediacenter','diskominfo-kota-sungai-penuh-adakan-pemeriksaan-kesehatan-secara-gratis','2025-10-23 13:51:29','2025-10-23 13:51:29'),(109,'Wawako Azhar Hamzah Pimpin Apel Hari Santri di MAN 1 Sungai Penuh','<div>Wawako Azhar Hamzah Pimpin Apel Hari Santri di MAN 1 Sungai Penuh</div><div>SUNGAI PENUH - Wakil Wali Kota Sungai Penuh, Azhar Hamzah, memimpin apel peringatan Hari Santri Nasional tahun 2025 yang digelar di halaman Madrasah Aliyah Negeri (MAN) 1 Kota Sungai Penuh, Rabu (22/10).&nbsp;</div><div>Apel peringatan ini dihadiri oleh jajaran Forkopimda, Kepala Kantor Kemenag Kota Sungai Penuh Hardiman, <a href=\"https://l.facebook.com/l.php?u=http%3A%2F%2FS.Ag%2F%3Ffbclid%3DIwZXh0bgNhZW0CMTAAYnJpZBExZWk4MDZEVUhsTHIyOVROZwEeFRddmdzlJ5xDxxETywxox2evE1M8WD8EcWP799K3t-1D_sDEF_iDdv7ELz8_aem_j3-A0-sutBd8OdFrkUPy0w&amp;h=AT1Nfm9b8zeDndez-AvuGBJOqiYsDggyL-NrKEI0h2tH7OXc47y_dMOmHet2zi4nJVYlkTfB_sPvH7fxKUhuGdgaYYt-UvxZVr3GOkeXmDa6cDKmdOvSKouEPeU6-Ad60kqUqNK21UyhB1o_XUHMhQ&amp;__tn__=-UK-R&amp;c[0]=AT3hEfzMVPYJqGoQc33O7A3-FN4wYiNPNvAThybPG0A683KFK-AtxxQAGMt0jPj1Wy2kZkSU_whXzfMZsHg9-TqBRWZ6Jtm_Xep3YFUx-prckZr3znxw204yfe_pAVs4OLUl2TsvabuhcB_hzxz8JsGToW2P1jdl2ph7O1CUBrR_ZX2SQRclCHow6uDdxhg6VpSI40B15TK1CPmTvW-EcVgW0Q\"><strong>S.Ag.</strong></a>, MM, Ketua MUI, Ketua PBNU, Ketua PD Muhammadiyah, para pengasuh pondok pesantren, serta seluruh kepala sekolah di bawah naungan Kementerian Agama Kota Sungai Penuh.</div><div>Dalam kesempatan tersebut, Wawako Azhar Hamzah membacakan amanat Menteri Agama Republik Indonesia yang berisi pesan penting bagi seluruh santri di Indonesia.&nbsp;</div><div>Menteri Agama menyampaikan duka cita mendalam atas wafatnya 67 santri Pesantren Al-Khoziny, Sidoarjo. Kementerian Agama telah turun langsung memberikan bantuan dan memastikan proses pemulihan berjalan baik. Tragedi ini menjadi momentum bagi seluruh pihak untuk berbenah dalam pengelolaan pesantren agar lebih aman dan layak.&nbsp;</div><div>Lebih lanjut, Menteri Agama menegaskan bahwa penetapan 22 Oktober sebagai Hari Santri merujuk pada Resolusi Jihad KH. Hasyim Asy’ari tahun 1945 yang menyalakan semangat perjuangan mempertahankan kemerdekaan. Hari Santri menjadi refleksi atas perjuangan, kontribusi, serta dedikasi santri dalam membangun bangsa.</div><div>Pesantren disebut memiliki peran strategis sejak sebelum kemerdekaan sebagai pusat pendidikan, pembentukan karakter, dan moral bangsa. Dari lingkungan pesantren, lahir banyak tokoh besar yang berkontribusi di berbagai bidang kehidupan nasional.&nbsp;</div><div>Di era modern saat ini, santri diharapkan tidak hanya ahli dalam ilmu agama, tetapi juga mampu menguasai teknologi, sains, dan bahasa asing. Dunia digital menjadi ruang baru bagi santri untuk berdakwah, berinovasi, dan memberikan manfaat luas bagi masyarakat.&nbsp;</div><div>Pemerintah juga terus memberikan dukungan nyata bagi pesantren melalui sejumlah kebijakan, di antaranya:&nbsp;</div><div>- Undang-Undang Nomor 18 Tahun 2019 tentang Pesantren&nbsp;</div><div>- Peraturan Presiden Nomor 82 Tahun 2021 tentang Pendanaan Pesantren dan Dana Abadi Pesantren&nbsp;</div><div>- Program Makan Bergizi Gratis (MBG) dan Cek Kesehatan Gratis (CKG) bagi santri&nbsp;</div><div>Menteri Agama juga menyampaikan apresiasi kepada Presiden RI Prabowo Subianto atas komitmennya dalam memperhatikan kebutuhan pesantren dan santri di seluruh Indonesia.&nbsp;</div><div>Dalam penutup amanatnya, Menteri Agama berpesan agar para santri menjadi generasi berilmu, berakhlak, dan berdaya. Santri harus mampu menjaga tradisi pesantren sekaligus adaptif terhadap kemajuan zaman.&nbsp;</div><div>“Barang siapa menanam ilmu, ia menanam masa depan,” ujarnya.&nbsp;</div><div>Hari Santri 2025 menjadi momentum kebangkitan santri Indonesia untuk terus mengawal kemerdekaan, memperkuat nilai-nilai keislaman yang rahmatan lil ‘alamin, serta mewujudkan peradaban dunia yang damai.</div><div>(Mc Diskominfosta)</div>','upload/berita/oJ40jv3wIumETFWmSECiijHGCLduvlTpFwFpDSAq.png','mediacenter','wawako-azhar-hamzah-pimpin-apel-hari-santri-di-man-1-sungai-penuh','2025-10-23 13:53:11','2025-10-23 13:53:11'),(110,'Sekda Alpian Buka Manasik Haji Tingkat TK di Kota Sungai Penuh','<div>Sekda Alpian Buka Manasik Haji Tingkat TK di Kota Sungai Penuh</div><div>SUNGAI PENUH - Sekretaris Daerah Kota Sungai Penuh, Alpian, secara resmi membuka kegiatan simulasi manasik haji bagi murid Taman Kanak-kanak se-Kota Sungai Penuh tahun 2025. Kegiatan ini Berlangsung Di Lapangan Merdeka Kota Sungai Penuh, Kamis (23/10).</div><div>Turut hadir dalam kegiatan tersebut Bunda PAUD Kota Sungai Penuh, Ibu Sri Kartini Alfin, Ketua Pokja PAUD Kota Sungai Penuh, Winda Rahayu Alpian, serta para guru pendamping, orang tua murid, dan pejabat di lingkungan Pemerintah Kota Sungai Penuh.&nbsp;</div><div>Dalam sambutannya, Sekda Alpian menyampaikan apresiasi dan ucapan terima kasih kepada Ikatan Guru Taman Kanak-kanak Indonesia (IGTKI) Kota Sungai Penuh yang telah menyelenggarakan kegiatan ini. Ia menilai kegiatan manasik haji merupakan bentuk pendidikan karakter dan spiritual yang penting bagi anak-anak sejak usia dini.</div><div>“Kegiatan seperti ini memberikan pengalaman berharga bagi anak-anak untuk mengenal tata cara pelaksanaan ibadah haji. Meskipun bersifat simulasi, melalui pendekatan yang menyenangkan dan penuh makna, nilai-nilai luhur ibadah haji akan tertanam dalam hati dan ingatan mereka,” ujar Sekda Alpian.</div><div>Ia menambahkan, pendidikan usia dini merupakan pondasi utama dalam membentuk karakter anak-anak. Karena itu, peran pendidik dan orang tua sangat besar dalam menanamkan nilai moral, akhlak, serta kecintaan anak terhadap agamanya.</div><div>Sekda Alpian juga mengajak seluruh pihak, baik pendidik, orang tua, maupun masyarakat, untuk terus bersinergi menciptakan lingkungan pendidikan yang ramah anak, penuh kasih sayang, dan bernilai islami. Kepada para peserta, Sekda Alpian berpesan agar mengikuti kegiatan dengan semangat dan gembira.&nbsp;</div><div>&nbsp;Di akhir sambutannya, Sekda Alpian menyampaikan terima kasih kepada seluruh panitia, guru, dan orang tua yang telah berperan aktif menyukseskan acara tersebut. Ia berharap kegiatan ini membawa manfaat besar dan menjadi langkah positif dalam membentuk generasi berakhlak mulia. [ ]</div><div>&nbsp;(MC KOMINFO)</div>','upload/berita/MTxFkkg8I1IHlVS63sIy2s8MfnGa8knBPJXJccSx.png','mediacenter','sekda-alpian-buka-manasik-haji-tingkat-tk-di-kota-sungai-penuh','2025-10-23 13:54:43','2025-10-23 13:54:43'),(111,'Dalam Rangka Memeriahkan HUT Kota Sungai Penuh, Sekda Alpian Buka Pekan Olahraga Pelajar','<div>Dalam Rangka Memeriahkan HUT Kota Sungai Penuh, Sekda Alpian Buka Pekan Olahraga Pelajar&nbsp;</div><div>SUNGAI PENUH- Dalam rangka memeriahkan Hari Ulang Tahun Kota Sungai Penuh ke 17 Tahun.</div><div>Pemkot Kota Sungai Penuh melalui Dinas Kepemudaan dan Olahraga (Diskepora) menggelar kegiatan Pekan Olahraga Pelajar.&nbsp;</div><div>Tujuannya, untuk menuju POPDA 2026 dan menjunjung tinggi Sportifitas. Ajang Pekan Olahraga Pelajar Kota Sungai Penuh ini terdiri dari Voli, Takraw, Badminton, Basket. Adapun pesertanya yakni tingkat SLTP dan SLTA.</div><div>Tema, “Ayo Kibarkan Semangat Juang Demi Meraih Prestasi Yang Gemilang”.</div><div>Kegiatan dimaksud dibuka langsung oleh Sekretaris Daerah (Sekda) Alpian, SE, MM, Mewakili Walikota Sungai Penuh Alfin, SH. Bertempat di Gedung Olahraga Koni, turut hadir juga Kepala SKPD, Camat, Pelajar dan tamu undangan lainya. Kamis 23/10/2025</div><div>Sekda Alpian mengatakan, Ajang ini bagian dari semangat untuk membina generasi muda dalam mewujudkan prestasi di bidang olahraga.</div><div>“Salam olahraga, kegiatan olahraga pelajar saat ini menjadi bagian program dalam menyambut Hut Kota Sungai Penuh ke 17 Tahun\"ujarnya&nbsp;</div><div>\"Tema tersebut merupakan semangat yang kolektif untuk membangun olahraga. Kemudian menjadi sarana untuk generasi muda dalam menjaga nilai leluhur. Ayo kita tunjukkan pelajar yang berprestasi agar dapat mengharumkan Kota Sungai Penuh, tunjukkan semangat baru’’. [ ]</div><div>(Mc Kominfo)</div>','upload/berita/mPE4djB7DtvXVtkQ6cKPDHYWrrG1vF7A5onb1yHa.png','mediacenter','dalam-rangka-memeriahkan-hut-kota-sungai-penuh-sekda-alpian-buka-pekan-olahraga-pelajar','2025-10-23 13:56:04','2025-10-23 13:56:04'),(112,'Normalisasi Di Kota Sungai Penuh Memiliki Manfaat Besar, Banjir Teratasi','<div>Normalisasi Di Kota Sungai Penuh Memiliki Manfaat Besar, Banjir Teratasi&nbsp;</div><div>SUNGAI PENUH- Normalisasi di Kota Sungai Penuh kini memiliki manfaat besar di Kota Sungai Penuh. Karena dapat mengatasi atau menghindari banjir besar atau berkepanjangan.</div><div>Program Walikota Sungai Penuh Alfin, SH sangat diapresiasi Warga. Hingga kini, beberapa wilayah rawan banjir di sekitaran Sungai Batang Merao sudah tidak mengalami dampak bencana dimaksud, selain itu tingginya curah hujan di Kota Sungai Penuh mulai turun.</div><div>Adapun titik wilayah yang sering menjadi langganan banjir saat ini tidak dalam keadaan parah ataupun merosot cepat faktor lancarnya aliran sungai.</div><div>\" Ya, sekarang genangan air hujan relatif cepat menyusut, tidak lagi menyebabkan banjir di daerah kami. Kalau dulu, jika musim hujan datang seperti saat&nbsp; ini, sudah langsung banjir. Terima kasih kepada pemerintah yang sudah melakukan normalisasi sungai\" ungkap warga Tanah Kampung, Erik.</div><div>Dalam hal ini, Pemerintah Kota Sungai Penuh telah bekerja sama dengan pihak Balai Wilayah Sungai Sumatera VI dan Dinas PU Provinsi Jambi tentang kegiatan normalisasi.</div><div>Berikut kegiatan Normalisasi di Kota Sungai Penuh, diantaranya :</div><div>1. Sungai Bungkal</div><div>2. Muara Jaya</div><div>3. Air Sempit</div><div>4. Batang Merao.</div><div>Ini merupakan visi dan misi Walikota Alfin, SH, bersama Wakil Walikota Azhar Hamzah dalam mewujudkan Kota Sungai Penuh yang aman dan nyaman bagi masyarakat.</div><div>“Berbagai langkah konkret telah dilakukan. Normalisasi ini merupakan bagian dari antisipasi banjir. PUPR Kota Sungai Penuh telah kami instruksikan untuk memprioritaskan kegiatan normalisasi sungai, termasuk pembersihan sampah. Kami juga bersinergi dengan PU Provinsi Jambi dan BWSS VI,”&nbsp; papar Wako Alfin. [ ]</div><div>(Mc Diskominfosta)</div>','upload/berita/iTJ8nrkLGbspevN1B75LezDM4NokA89RGu1mBPsq.png','mediacenter','normalisasi-di-kota-sungai-penuh-memiliki-manfaat-besar-banjir-teratasi','2025-10-29 14:38:31','2025-10-29 14:38:31'),(113,'Wako Alfin Ajak Warga Kumun Debai Goro Bersihkan Eks Terminal','<div>Wako Alfin Ajak Warga Kumun Debai Goro Bersihkan Eks Terminal</div><div>SUNGAI PENUH - Walikota Sungai Penuh, Alfin, S.H., bersama masyarakat Kumun Debai melaksanakan kegiatan gotong royong membersihkan kawasan eks Terminal Kumun, Jumat (24/10).&nbsp;</div><div>Kegiatan ini digelar sebagai bentuk kepedulian terhadap kebersihan lingkungan sekaligus mempererat sinergi antara pemerintah dan masyarakat dalam menciptakan lingkungan yang bersih, nyaman, dan sehat.&nbsp;</div><div>Dalam kesempatan tersebut, Wako Alfin menyampaikan apresiasi kepada seluruh peserta gotong royong yang berpartisipasi aktif menjaga kebersihan wilayahnya.</div><div>“Gotong royong adalah bagian dari budaya kita yang harus terus dijaga. Sinergi antara pemerintah dan masyarakat ini menjadi contoh nyata semangat kebersamaan dalam membangun Kota Sungai Penuh yang bersih dan indah,” ujar Wako Alfin.&nbsp;</div><div>Turut hadir dalam kegiatan tersebut sejumlah kepala OPD, Camat Kumun Debai, para kepala desa, tokoh adat, tokoh masyarakat, Ketua TP PKK Ny. Sri Kartini Alfin, civitas akademika STKIP Muhammadiyah Sungai Penuh, siswa SMK Negeri 4 Kota Sungai Penuh, serta masyarakat setempat yang antusias bergotong royong membersihkan kawasan terminal dan sekitarnya.</div><div>Kegiatan goro ini diharapkan menjadi momentum untuk menumbuhkan kembali semangat kebersamaan dan kepedulian warga terhadap kebersihan lingkungan di seluruh wilayah Kota Sungai Penuh.&nbsp;</div><div>(MC KOMINFO)</div>','upload/berita/Uphz3KWxJLb7Xl3ksqSy4HmTxPO1sW38526RiN7c.png','mediacenter','wako-alfin-ajak-warga-kumun-debai-goro-bersihkan-eks-terminal','2025-10-29 14:39:49','2025-10-29 14:39:49'),(114,'Pemkot Sungai Penuh Goro di Stadion Pancasila Jelang HUT ke-17','<div>Pemkot Sungai Penuh Goro Jelang HUT ke-17</div><div>SUNGAI PENUH - Dalam rangka memperingati Hari Ulang Tahun (HUT) ke-17 Kota Sungai Penuh, Pemerintah Kota Sungai Penuh menggelar kegiatan gotong royong bersama di Lapangan Stadion Pancasila, Tanah Kampung, Sabtu (25/10).</div><div>Kegiatan ini dipimpin langsung oleh Walikota Sungai Penuh, Alfin, S.H., didampingi Wakil Walikota Azhar Hamzah dan Sekda Alpian, S.E., M.M. Turut hadir para kepala OPD, ASN, dan masyarakat yang antusias bergotong royong membersihkan area stadion serta lingkungan sekitarnya.&nbsp;</div><div>Walikota Alfin menyampaikan, gotong royong ini merupakan bagian dari semangat kebersamaan dalam memperingati HUT ke-17 Kota Sungai Penuh yang mengusung tema “Spirit Baru, Wujudkan Kota Sungai Penuh Juara.\" Gotong royong adalah tradisi luhur yang harus terus dijaga.&nbsp;</div><div>Melalui kegiatan ini, kita perkuat rasa memiliki dan semangat membangun Kota Sungai Penuh yang bersih dan indah,” ujar Alfin.&nbsp;</div><div>Kegiatan berlangsung meriah dan penuh semangat, mencerminkan kekompakan antara pemerintah dan masyarakat dalam mewujudkan Kota Sungai Penuh yang lebih maju dan berdaya saing.</div><div>(MC KOMINFO)</div>','upload/berita/XlstXYsnEfo8pvAbjXQQpRRHHd10it5fJOM1wfMW.png','mediacenter','pemkot-sungai-penuh-goro-di-stadion-pancasila-jelang-hut-ke-17','2025-10-29 14:41:11','2025-10-29 14:41:11'),(115,'Wako Alfin Pimpin Apel Sumpah Pemuda ke-97 dan Serahkan Penghargaan','<div>Wako Alfin Pimpin Apel Sumpah Pemuda ke-97 dan Serahkan Penghargaan</div><div>SUNGAI PENUH - Walikota Sungai Penuh, Alfin, SH, memimpin langsung apel peringatan Hari Sumpah Pemuda ke-97 tahun 2025 yang digelar di lapangan kantor Walikota Sungai Penuh, Selasa (28/10).</div><div>Upacara berlangsung khidmat dan penuh semangat kebangsaan, diikuti oleh seluruh Organisasi Perangkat Daerah (OPD) di lingkungan Pemerintah Kota Sungai Penuh. Turut hadir Wakil Walikota Sungai Penuh Azhar Hamzah, Unsur Pimpinan DPRD Kota Sungai Penuh, unsur Forkopimda, serta pimpinan BUMN dan BUMD dalam wilayah Kota Sungai Penuh.</div><div>Dalam kesempatan tersebut, Walikota Alfin membacakan amanat Menteri Pemuda dan Olahraga RI, Erick Thohir, yang menekankan pentingnya semangat persatuan, kerja keras, dan peran pemuda sebagai motor penggerak kemajuan bangsa.</div><div>Tahun ini, peringatan Hari Sumpah Pemuda mengusung tema “Pemuda Indonesia Bersatu, Bergerak, Maju.” Tema tersebut diharapkan dapat menjadi inspirasi bagi generasi muda untuk terus berkontribusi nyata dalam pembangunan daerah dan nasional.</div><div>Selain membacakan amanat Menpora, Walikota Alfin juga menegaskan pentingnya kesadaran lingkungan, terutama dalam pengelolaan sampah di setiap instansi pemerintahan.&nbsp;</div><div>Ia meminta seluruh OPD agar memiliki buku rekening bank sampah sebagai wujud komitmen nyata terhadap kebersihan dan keberlanjutan lingkungan.</div><div>“Kita ingin setiap OPD menjadi teladan dalam pengelolaan sampah. Program bank sampah ini bukan sekadar administrasi, tetapi langkah nyata menuju kota yang bersih dan berdaya,” tegas Walikota Alfin.</div><div>Pada momen yang sama, Walikota juga menyerahkan penghargaan kepada para pemuda berprestasi yang telah memberikan kontribusi positif dalam pengembangan potensi kepemudaan di Kota Sungai Penuh. Selain itu, penghargaan pengelolaan kearsipan perangkat daerah tahun 2025 turut diberikan sebagai bentuk apresiasi atas kinerja OPD yang menjaga tata kelola administrasi dengan baik.</div><div>Sebagai penutup, apel peringatan Sumpah Pemuda ke-97 dimeriahkan dengan penampilan defile baju adat daerah yang menampilkan kekayaan budaya dan semangat kebersamaan masyarakat Kota Sungai Penuh.(MC KOMINFO)</div>','upload/berita/cd6Wpcj71t9PCzwa4ChwJiwy60WwfvdW6Je7yAXj.png','mediacenter','wako-alfin-pimpin-apel-sumpah-pemuda-ke-97-dan-serahkan-penghargaan','2025-10-29 14:42:59','2025-10-29 14:42:59'),(116,'Wako Alfin Dampingi Tim Adipura Pantau TPST RKE','<div>Wako Alfin Dampingi Tim Adipura Pantau TPST RKE</div><div>SUNGAI PENUH - Pemerintah Kota Sungai Penuh menunjukkan keseriusannya dalam mewujudkan kota yang bersih dan berkelanjutan. Hal ini terlihat saat Wali Kota Sungai Penuh, Alfin, SH, bersama Wakil Wali Kota Azhar Hamzah mendampingi langsung kunjungan tim penilai Adipura dari Kementerian Lingkungan Hidup dan Kehutanan (KLHK) di Tempat Pengolahan Sampah Terpadu (TPST) Renah Kayu Embun (RKE), Selasa (28/10).</div><div>Kunjungan ini merupakan bagian dari tahapan penilaian Adipura tahun 2025, di mana tim KLHK melakukan pemantauan tahap II untuk menilai kebersihan, pengelolaan sampah, serta ruang terbuka hijau di wilayah Kota Sungai Penuh.</div><div>Tim KLHK yang dipimpin Muchammad Novan Ardista meninjau berbagai aspek pengelolaan sampah di TPST, mulai dari sistem pemilahan, proses daur ulang, sarana pengangkutan, hingga partisipasi masyarakat dalam menjaga kebersihan lingkungan.&nbsp;</div><div>Dalam kesempatan tersebut, Muchammad Novan Ardista menyampaikan apresiasi atas konsistensi dan komitmen Pemkot Sungai Penuh dalam menata pengelolaan sampah. Menurutnya, berbagai inovasi yang diterapkan menunjukkan kemajuan signifikan menuju tata kelola lingkungan yang lebih baik.</div><div>“Pemkot Sungai Penuh menunjukkan progres positif. Komitmen pemerintah dalam menciptakan lingkungan yang bersih dan sehat patut diapresiasi,” ujarnya.</div><div>Sementara itu, Wali Kota Alfin menegaskan bahwa Pemkot Sungai Penuh terus berupaya memperkuat sistem pengelolaan sampah melalui pembangunan dan optimalisasi TPST Renah Kayu Embun.</div><div>Keberadaan TPST, kata Alfin, tidak hanya berfungsi sebagai pusat pengolahan sampah, tetapi juga menjadi sarana edukasi bagi masyarakat agar lebih peduli terhadap lingkungan.&nbsp;</div><div>“Kami ingin membangun budaya bersih di tengah masyarakat. Dengan sinergi antara pemerintah dan warga, Kota Sungai Penuh bisa menjadi kota yang indah, nyaman, dan berkelanjutan,” tegasnya.</div><div>Kunjungan tim Adipura ini menjadi momentum penting bagi Pemkot Sungai Penuh untuk terus meningkatkan kualitas kebersihan kota sekaligus memperkuat kesadaran masyarakat terhadap pentingnya pengelolaan sampah secara berkelanjutan.(MC KOMINFO)</div>','upload/berita/yxyFVCmAINBaMyu07piw9np86HZSecpQKWWSjkEL.png','mediacenter','wako-alfin-dampingi-tim-adipura-pantau-tpst-rke','2025-10-29 14:44:14','2025-10-29 14:44:14'),(117,'Wako Alfin Menghadiri Paparan Hasil Progres TMMD Kodim Kerinci','<div>Wako Alfin Menghadiri Paparan Hasil Progres TMMD Kodim Kerinci</div><div>SUNGAI PENUH- Walikota Sungai Penuh Alfin, SH menghadiri kegiatan paparan progress TMMD Kodim 0417 Kerinci, kegiatan ini bertempat di ruang rapat Kodim Kerinci. Rabu 29/10/2025</div><div>Selain itu, Wako Alfin juga menyambut baik tim Wasev TMMD ke 126, Tahun 2025 di Wilayah Kodim 0417 Kerinci.</div><div>Dalam hal ini mengusung tema “Dengan Semangat TMMD Mewujudkan Pemerataan Pembangunan dan Ketahanan Nasional di Wilayah”.</div><div>Kehadiran Wako Alfin untuk mendengar secara langsung terkait capaian progress Kegiatan TMMD di Kota Sungai Penuh yang dipaparkan oleh Dandim 0417/ Kerinci Inf Eko Budianto, M.I.P.</div><div>Turut hadir yakni, Pimpinan tim Wasev Klonel Inf Eben Ezer Lumban Tobing, S.A.P, Kapten Andy Akbar,&nbsp; jajaran Pejabat Kodim 0417/ Kerinci, Ketua DPRD Hutri Randa, Kepala SKPD terkait, Perwakilan Polres Kerinci.</div><div>Wako Alfin menyampaikan, apresiasi terhadap Kodim 0417/ Kerinci atas kegiatan TMMD di Kota Sungai Penuh. Hal ini merupakan langkah nyata dalam membangun Kota Sungai Penuh.&nbsp;</div><div>Ia juga berharap, kedepannya, Kodim 0417 Kerinci agar terus bersinergi dengan Pemerintah Daerah Kota Sungai Penuh.</div><div>“Kami mengapresiasi kegiatan TMMD di Desa Sungai Jernih Kecamatan Pondok Tinggi Kota Sungai Penuh, yang mana merupakan wujud pembangunan nyata yang dilakukan oleh Kodim Kerinci\" ujarnya&nbsp;</div><div>\"Dalam hal ini progres dan capaian hampir memasuki tahap akhir. Adanya pembangunan jalan melalui program tersebut semoga dapat bermanfaat bagi masyarakat”pungkasnya</div><div>(Mc Diskominfosta)</div>','upload/berita/NhEvOZJkMF7brCXKdO6TjLmbqon1SuYnlw0IGh3r.png','mediacenter','wako-alfin-menghadiri-paparan-hasil-progres-tmmd-kodim-kerinci','2025-10-30 14:47:05','2025-10-30 14:47:05'),(118,'Program TMMD Kodim Kerinci, Wako Alfin Meresmikan Hasil Rehab RTLH Desa Sungai Jernih','<div>Program TMMD Kodim Kerinci, Wako Alfin Meresmikan Hasil Rehab RTLH Desa Sungai Jernih</div><div>SUNGAI PENUH- Program Tentara Menunggal Membangun Desa (TMMD) Kodim 0417/Kerinci ke 126 tahun 2025 juga terdapat kegiatan Rehab Rumah Tidak Layak Huni (RTLH).&nbsp;</div><div>Dalam hal ini, Walikota Sungai Penuh Alfin, SH meresmikan hasil rehab salah satu rumah warga Desa Sungai Jernih Kecamatan Pondok Tinggi, sebelumnya berstatus RTLH. Rabu 29/10/2025</div><div>Giat ini dilaksanakan oleh Kodim 0417/ Kerinci. Hingga Persemian dimaksud Wako Alfin bersama Dandim 0417/Kerinci Eko Budianto, Pimpinan Wasev TMMD Klonel Inf Eben Ezer Tobing, Ketua DPRD Kota Sungai Penuh.&nbsp;</div><div>Wako Alfin mengatakan, semoga upaya yang dilakukan oleh TNI dapat bermanfaat bagi warga. Selain itu ia mengucapkan terimakasih kepada Kodim Kerinci yang telah melakukan perehapan rumah warga yang berstatus RTLH.</div><div>\"Mudah mudahan apa yang dilakukan ini betul betul menjadikan manfaat, tentu akan menjadi pahala bagi kita. Semoga TNI tetap solid dalam keterlibatan pembangunan, terima kasih atas bantuannya yakni berupa RTLH untuk warga kita\"pungkasnya&nbsp;</div><div>(Mc Diskominfosta)</div>','upload/berita/WGhbpleOd73ly02MaW6WIHB6nMt3aDasfAEE2GIS.png','mediacenter','program-tmmd-kodim-kerinci-wako-alfin-meresmikan-hasil-rehab-rtlh-desa-sungai-jernih','2025-10-30 14:48:19','2025-10-30 14:48:19'),(119,'Wawako Pasang Tonggak Pertama Pasar Bersama Pemangku Lembaga Kerapatan Adat Enam Luhah','<div>Wawako Pasang Tonggak Pertama Pasar Bersama Pemangku Lembaga Kerapatan Adat Enam Luhah&nbsp;</div><div>SUNGAI PENUH – Pembangunan Pasar Sungai Penuh resmi dimulai. Pemerintah Kota Sungai Penuh bersama Ketua Lembaga Kerapatan Adat 6 Luhah Sungai Penuh Dan Ninik Mamak Adat Luhah Pemangku Rajo melakukan pemasangan tonggak pertama di lokasi eks Pasar Beringin Jaya, Jumat (31/10).&nbsp;</div><div>Prosesi pemasangan tonggak dilakukan oleh Wakil Wali Kota Sungai Penuh, Azhar Hamzah, didampingi lembaga kerapatan adat serta pihak pelaksana proyek dari PT Cimedang Sakti Kontra Kindo.</div><div>Tradisi ini menjadi simbol restu adat agar pembangunan pasar berjalan lancar, aman, dan membawa keberkahan bagi masyarakat.</div><div>Dalam sambutannya, Wawako Azhar Hamzah menyampaikan apresiasi dan rasa terima kasih atas dukungan penuh dari pemangku adat serta masyarakat yang turut mendukung rencana pembangunan pasar tersebut.</div><div>&nbsp;“Terima kasih atas doa, restu, dan dukungan seluruh pihak adat serta masyarakat. Kami berharap pembangunan ini dapat berjalan lancar dan memberi manfaat besar bagi warga Sungai Penuh,” ujar Azhar Hamzah.&nbsp;</div><div>Lebih lanjut, Wawako menegaskan bahwa keberadaan pasar ini tidak hanya akan menjadi pusat transaksi ekonomi, tetapi juga diharapkan menjadi ikon kota yang mencerminkan nilai-nilai kearifan lokal.&nbsp;</div><div>“Pasar ini bukan sekadar tempat jual beli, tetapi juga simbol kebangkitan ekonomi dan budaya masyarakat Sungai Penuh,” tambahnya.</div><div>Pembangunan Pasar Sungai Penuh menjadi salah satu upaya pemerintah dalam mendorong pertumbuhan ekonomi daerah sekaligus memperkuat identitas kota yang maju dan berbudaya. (MC KOMINFO)</div>','upload/berita/yLhljqIbGXduE9LkxbjKo65U2YGCnEZlx1PiUDOQ.png','mediacenter','wawako-pasang-tonggak-pertama-pasar-bersama-pemangku-lembaga-kerapatan-adat-enam-luhah','2025-11-02 01:14:30','2025-11-02 01:14:30'),(120,'Wali Kota Alfin Dukung Penguatan Layanan Kesehatan, Hadiri Kunker Menkes di RSUD Raden Mattaher Jambi','<div>Wali Kota Alfin Dukung Penguatan Layanan Kesehatan, Hadiri Kunker Menkes di RSUD Raden Mattaher Jambi</div><div>JAMBI - Wali Kota Sungai Penuh Alfin, SH turut menghadiri kunjungan kerja Menteri Kesehatan Republik Indonesia Budi Gunadi Sadikin di RSUD Raden Mattaher Jambi, Jumat (31/10). Kehadiran Wako Alfin bersama kepala daerah lain se-Provinsi Jambi menjadi bentuk dukungan terhadap penguatan layanan kesehatan di daerah.</div><div>Turut hadir dalam kegiatan tersebut Gubernur Jambi Dr. H. Al Haris, S.Sos., M.H., para bupati dan wali kota se-Provinsi Jambi, serta para direktur RSUD dari berbagai daerah.</div><div>Kunjungan kerja Menkes kali ini digelar dalam rangka operasi perdana bedah jantung terbuka pintas arteri (CABG) dan penandatanganan Perjanjian Kerja Sama (PKS) jejaring pengampuan pelayanan jantung dan pembuluh darah. Acara berlangsung di Aula Diklat Lantai 2 RSUD Raden Mattaher Jambi.</div><div>Dalam sambutannya, Menteri Kesehatan Budi Gunadi Sadikin menyampaikan bahwa operasi bedah jantung terbuka yang berhasil dilakukan di RSUD Raden Mattaher menjadi langkah besar bagi peningkatan mutu layanan kesehatan di Jambi.</div><div>Sekarang masyarakat Jambi tidak perlu lagi jauh-jauh berobat ke luar daerah untuk menjalani tindakan bedah jantung. RSUD Raden Mattaher sudah mampu melayani dengan fasilitas dan tenaga ahli yang memadai,” ujar Menkes.</div><div>Wali Kota Sungai Penuh Alfin, SH menyambut baik langkah tersebut. Ia menilai kolaborasi antara Kementerian Kesehatan dan Pemerintah Provinsi Jambi akan membuka peluang besar bagi pemerataan layanan kesehatan di seluruh daerah.</div><div>Kami sangat mendukung pengembangan layanan jantung ini. Kami juga berharap salah satu rumah sakit di Kota Sungai Penuh, yakni RSUD H. Bakri, bisa menjadi rujukan untuk layanan stroke di wilayah barat Jambi,” kata Alfin.</div><div>Menurutnya, kehadiran layanan-layanan rujukan spesialis seperti ini sangat penting untuk mendekatkan akses kesehatan bagi masyarakat di daerah.</div><div>Tujuannya agar masyarakat tidak lagi kesulitan mendapatkan pelayanan medis berkualitas. Ini bagian dari komitmen kami untuk terus meningkatkan mutu layanan kesehatan di Kota Sungai Penuh,” tambahnya.</div><div>Melalui penandatanganan PKS jejaring pengampuan tersebut, Menkes berharap setiap RSUD di kabupaten dan kota se-Provinsi Jambi dapat saling terhubung dan berkoordinasi dalam meningkatkan kapasitas serta kualitas pelayanan. Dengan begitu, pemerataan layanan kesehatan yang merata dan berkualitas bisa segera terwujud di seluruh wilayah Jambi.</div><div>(MC DISKOMINFO)</div>','upload/berita/qeI4zLPleI0Jm94MGFSxfBN5gJmzlLkNXO88Tl7E.png','mediacenter','wali-kota-alfin-dukung-penguatan-layanan-kesehatan-hadiri-kunker-menkes-di-rsud-raden-mattaher-jambi','2025-11-02 01:15:58','2025-11-02 01:15:58'),(121,'Wako Alfin Hadiri Penandatanganan PJPK dan RAD GDPK Jambi','<div>Wako Alfin Hadiri Penandatanganan PJPK dan RAD GDPK Jambi</div><div>JAMBI-Walikota Sungai Penuh, Alfin, SH, hadir dalam penandatanganan Peta Jalan Pembangunan Kependudukan (PJPK) dan Rencana Aksi Daerah (RAD) Grand Design Pembangunan Kependudukan (GDPK) Provinsi Jambi Tahun 2025–2029, Jumat (31/10). Acara ini menjadi bagian dari persiapan jangka panjang pembangunan kependudukan Provinsi Jambi hingga 2050.</div><div>Kegiatan ini digelar untuk memperkuat kerja sama antara pemerintah provinsi dan kabupaten/kota, supaya arah pembangunan kependudukan di daerah selaras dengan kebijakan nasional. PJPK dan RAD GDPK berfungsi sebagai panduan bagi pemerintah daerah dalam merencanakan, menjalankan, dan mengevaluasi program-program kependudukan.</div><div>Wako Alfin menyatakan dukungannya penuh terhadap langkah ini. Ia menekankan pentingnya pembangunan kependudukan yang terencana, berkelanjutan, dan berbasis data, agar bisa menghasilkan sumber daya manusia yang berkualitas dan siap bersaing.</div><div>Dokumen ini akan menjadi acuan pemerintah daerah dalam menyusun kebijakan dan program kependudukan yang sejalan dengan visi pembangunan nasional maupun daerah,” kata Wako Alfin.</div><div>Acara penandatanganan ini juga dihadiri pejabat Bappeda Provinsi Jambi, Dinas Kependudukan dan Pencatatan Sipil, serta sejumlah kepala daerah dari kabupaten/kota. Penandatanganan PJPK dan RAD GDPK diharapkan menjadi momentum bagi seluruh pihak untuk bekerja sama mewujudkan pembangunan kependudukan yang lebih baik, inklusif, dan berkualitas.</div><div>Wako Alfin menambahkan, Pemkot Sungai Penuh akan segera menindaklanjuti dokumen ini melalui kebijakan lokal, termasuk peningkatan layanan administrasi kependudukan, penguatan data kependudukan, dan program peningkatan kualitas SDM di Kota Sungai Penuh.</div><div>(MC DISKOMINFO)</div>','upload/berita/RfYFZknfKyVnJynGmjEjnNOJyPdlXY4Iyp6nn8M5.png','mediacenter','wako-alfin-hadiri-penandatanganan-pjpk-dan-rad-gdpk-jambi','2025-11-02 01:17:11','2025-11-02 01:17:11'),(122,'Wawako Azhar Hadiri HUT ke-25 Sempoa SIP Gajah Mada Sumbar–Kerinci','<div>Wawako Azhar Hadiri HUT ke-25 Sempoa SIP Gajah Mada Sumbar–Kerinci&nbsp;</div><div>SUNGAI PENUH - Wakil Wali Kota Sungai Penuh, Azhar Hamzah, menghadiri perayaan Anniversary ke-25 Sempoa SIP TC Gajah Mada Sumbar - Kerinci, Sabtu (1/11).</div><div>Acara yang berlangsung meriah ini mengusung tema “Temu Kangen Alumni Sempoa” dan menjadi ajang silaturahmi besar keluarga besar Sempoa SIP.</div><div>Perayaan tersebut juga dihadiri sejumlah tamu penting, di antaranya Bupati Kerinci, perwakilan BUMN dan BUMD, Ketua GOW, Pengurus Sempoa SIP Sumbar - Kerinci, Direktur TC Pondok, Owner Yamaha Sinar Mas, serta para alumni, siswa aktif, orang tua murid, dan para pengajar Sempoa SIP dari berbagai angkatan.</div><div>Momentum ini menjadi ajang kebersamaan sekaligus apresiasi atas kiprah Sempoa SIP yang telah 25 tahun berkontribusi dalam pengembangan kemampuan berhitung dan logika berpikir anak-anak.</div><div>Dalam sambutannya, Wawako Azhar Hamzah menyampaikan ucapan selamat dan apresiasi kepada seluruh pengurus serta keluarga besar Sempoa SIP atas dedikasinya di dunia pendidikan nonformal.</div><div>“Sempoa SIP telah memberikan kontribusi nyata dalam mencerdaskan anak-anak kita. Melalui metode berhitung kreatif dan logis, anak-anak dilatih untuk berpikir cepat, fokus, dan percaya diri. Pemerintah Kota Sungai Penuh sangat mengapresiasi dan berharap Sempoa SIP terus berkembang melahirkan generasi unggul,” ujar Azhar Hamzah.</div><div>Rangkaian kegiatan diisi dengan penampilan kesenian, sesi temu kangen alumni, hingga pemotongan tumpeng sebagai simbol rasa syukur atas perjalanan panjang Sempoa SIP selama seperempat abad.</div><div>Suasana acara berlangsung penuh semangat dan keakraban. Para peserta, baik alumni maupun siswa, tampak antusias mengikuti seluruh rangkaian hingga akhir.(MC KOMINFO)</div>','upload/berita/zo7muhJiZ1SVMGWtp5SVbvTBCeTyyILj7tRgOZbT.png','mediacenter','wawako-azhar-hadiri-hut-ke-25-sempoa-sip-gajah-mada-sumbar-kerinci','2025-11-02 01:18:26','2025-11-02 01:18:26'),(123,'Sinergi Pemkot Sungai Penuh dan Kodim 0417: Wujudkan TPST RKE Bersih dan Hijau','<div>Sinergi Pemkot Sungai Penuh dan Kodim 0417: Wujudkan TPST RKE Bersih dan Hijau</div><div>SUNGAI PENUH - Pemerintah Kota Sungai Penuh bersama Kodim 0417/Kerinci kembali menunjukkan kekompakan lewat kegiatan Gotong Royong (Goro) Akbar di kawasan TPST Renah Kayu Embun (RKE) dan akses jalan menuju wisata Bukit Khayangan, Sabtu (1/11/2025).</div><div>Kegiatan goro ini dipimpin langsung oleh Wali Kota Sungai Penuh, Alfin, SH, dan diikuti oleh jajaran Pemkot serta personel TNI dari Kodim 0417/Kerinci. Fokus kegiatan kali ini yaitu membersihkan tumpukan sampah, memangkas semak belukar, serta menanam berbagai jenis pohon dan bunga hias di sekitar kawasan TPST.</div><div>Wali Kota Alfin menyebutkan, kegiatan ini tidak hanya sekadar bersih-bersih lingkungan, tapi juga sebagai bentuk kebersamaan dan kepedulian terhadap alam sekitar.</div><div>Kita ingin menumbuhkan kembali semangat gotong royong di tengah masyarakat. Menjaga kebersihan dan penghijauan itu tanggung jawab kita bersama,” ujar Wako Alfin.</div><div>Selain menjaga kebersihan, Wako juga menegaskan bahwa Pemkot berkomitmen untuk mengubah pandangan masyarakat terhadap kawasan pengolahan sampah. Menurutnya, tempat pengolahan sampah tidak harus selalu identik dengan hal kotor dan kumuh.</div><div>Kami ingin tempat ini menjadi area yang tertata rapi dan bisa juga menjadi tempat edukasi dan wisata lingkungan,” jelasnya.</div><div>Dalam kegiatan ini, Kodim 0417/Kerinci menanam sekitar 4.000 pohon, sementara Pemkot Sungai Penuh menambah keindahan kawasan dengan berbagai bunga hias dan tanaman pelindung.</div><div>Kegiatan goro akbar ini menjadi bukti nyata sinergi antara Pemkot Sungai Penuh dan TNI dalam membangun lingkungan yang bersih, hijau, dan berkelanjutan untuk masyarakat.</div><div>(MC DISKOMINFO)</div>','upload/berita/ORnApfUtmc4G5sD6ewDeduq5ZbN3i7bBWlD41VF8.png','mediacenter','sinergi-pemkot-sungai-penuh-dan-kodim-0417-wujudkan-tpst-rke-bersih-dan-hijau','2025-11-02 01:19:34','2025-11-02 01:19:34'),(124,'Wako Alfin Apresiasi Talenta Muda di Home Concert Ansamble Class','<div>Wako Alfin Apresiasi Talenta Muda di Home Concert Ansamble Class&nbsp;</div><div>SUNGAI PENUH - Suasana penuh semangat dan keceriaan mewarnai acara Home Concert Ansamble Class yang digelar di Aula Kantor Wali Kota Sungai Penuh, Minggu (2/11/2025). Kegiatan ini dihadiri langsung oleh Wali Kota Sungai Penuh, Alfin, SH, bersama Kapolres Kerinci AKBP Arya Tesa Brahmana, Ketua TP PKK Sri Kartini Alfin, para seniman, generasi muda berbakat di bidang seni, serta tamu undangan lainnya.</div><div>Dalam sambutannya, Wako Alfin menyampaikan apresiasi dan rasa bangga atas terselenggaranya kegiatan tersebut. Ia menilai musik merupakan bahasa universal yang mampu menyatukan perbedaan, menumbuhkan empati, serta membentuk budi pekerti yang luhur.</div><div>“Melalui dunia seni, kita belajar kerja keras, kesabaran, dan keindahan dalam kerja sama. Ini menjadi wujud nyata dalam membangun karakter, disiplin, dan kreativitas generasi muda di Kota Sungai Penuh,” ujar Wako Alfin.</div><div>Ia juga berharap para peserta dapat menjadikan pengalaman di ajang ini sebagai batu loncatan untuk terus berkarya dan berprestasi, baik di tingkat daerah, provinsi, nasional, maupun internasional.</div><div>Tak lupa, Wako Alfin menyampaikan ucapan terima kasih kepada para guru pembimbing yang dengan penuh dedikasi telah membina dan mengarahkan talenta-talenta muda berbakat di bidang seni.</div><div>“Dedikasi para pembimbing dan semangat anak-anak kita adalah modal berharga untuk membangun generasi kreatif dan berprestasi,” tambahnya.</div><div>Kegiatan Home Concert Ansamble Class ini menjadi bukti nyata komitmen Pemerintah Kota Sungai Penuh dalam mendukung pengembangan seni dan kreativitas anak muda sebagai bagian dari pembangunan karakter bangsa.(MC KOMINFO)</div>','upload/berita/grbrJ6ks92B9Bvmy6oggDBcakYyjTcq0TKvj118s.png','mediacenter','wako-alfin-apresiasi-talenta-muda-di-home-concert-ansamble-class','2025-11-11 15:49:39','2025-11-11 15:49:39'),(125,'Semangat Jambore PKK 2025: Ketua TP-PKK Ajak Kader Wujudkan Kota Sungai Penuh Juara','<div>Semangat Jambore PKK 2025: Ketua TP-PKK Ajak Kader Wujudkan Kota Sungai Penuh Juara</div><div>Sungai Penuh - Dalam rangka Hari Ulang Tahun ke-17 Kota Sungai Penuh sekaligus pelaksanaan Jambore Kader PKK Tahun 2025 dan Pasar Rakyat, Ketua TP-PKK Kota Sungai Penuh, Ny. Ns. Sri Kartini Alfin, S.Kep, meninjau langsung kegiatan hari pertama yang dipusatkan di Lapangan Merdeka dan Gedung Nasional Senin, (03 /11/25).</div><div>Momentum jambore ini menjadi rangkaian kegiatan besar PKK yang tidak hanya menampilkan perlombaan antar kader, namun juga dirangkai dengan kegiatan ekonomi kreatif melalui Pasar Rakyat, yang menghadirkan UMKM lokal untuk meningkatkan perputaran ekonomi masyarakat.</div><div>Dalam kesempatan tersebut, Sri Kartini Alfin memberikan apresiasi kepada seluruh kader dan peserta lomba. Ia menekankan pentingnya menjaga kekompakan, menjunjung tinggi sportivitas, dan menjadikan jambore sebagai ajang memperkuat kreativitas serta silaturahmi antar kader PKK.</div><div>“Saya berpesan kepada seluruh peserta untuk tetap menjaga kekompakkan dan sportivitas. Saya berharap momentum ini dapat menumbuhkan semangat dan cinta dalam membangun Kota Sungai Penuh Juara,” ujar Sri Kartini Alfin.</div><div>Kegiatan dimulai sejak pukul 08.00 WIB dengan sejumlah perlombaan:</div><div>• Lomba Gerak dan Lagu Three End – Gedung Nasional (Pokja I)</div><div>• Lomba Permainan Tradisional Terompah Panjang – Lapangan Merdeka (Pokja II)</div><div>• Lomba Presentasi Inovatif PKK – Aula Disbudpar (Pokja III)</div><div>• Lomba Jingle Gelar Pelangi – Gedung Nasional (Pokja II)</div><div>Dilanjutkan dengan lomba penyuluhan dan keterampilan kader seperti:</div><div>• Lomba Penyuluhan Pokja IV (Stunting)</div><div>• Lomba Drama Pola Asuh Anak dan Remaja di Era Digital (PAAREDI)</div><div>Hari Kedua Selasa, 4 November 2025</div><div>Perlombaan digelar di beberapa titik lokasi:</div><div>• Lomba Rangking 1 – Lapangan Merdeka (Pokja II)</div><div>• Lomba Memandikan dan Mengafani Jenazah (Pokja I)</div><div>• Lomba Membacakan Buku Cerita Anak (Pokja II)</div><div>• Lomba Desain dan Fashion Show Busana Muslimah Kreasi Batik Daerah (Pokja III)</div><div>• Lomba Senam Jingle Cerdik (Pokja IV)</div><div>Hari Ketiga Rabu, 5 November 2025</div><div>Agenda perlombaan meliputi:</div><div>• Lomba Penyuluhan PKDRT &amp; PKBN</div><div>• Lomba Keterampilan Kader Posyandu</div><div>• Lomba Penyuluhan “Aku Hatinya PKK”</div><div>• Lomba Berbalas Pantun Keluarga Sehat Tanggap Bencana</div><div>Pembukaan Resmi&nbsp; Kamis, 6 November 2025</div><div>Dilaksanakan pukul 13.00 WIB di Lapangan Merdeka:</div><div>• Pembukaan resmi Jambore PKK 2025</div><div>• Lagu Kebangsaan Indonesia Raya &amp; Mars PKK</div><div>• Sambutan Ketua Panitia Pelaksana</div><div>• Sambutan Ketua TP-PKK Kota Sungai Penuh</div><div>• Sambutan Ketua TP-PKK Provinsi Jambi</div><div>• Sambutan Wali Kota Sungai Penuh</div><div>• Ramah tamah</div><div>Penutupan&nbsp; Jumat, 7 November 2025</div><div>Penutupan digelar pada malam hari di Lapangan Merdeka:</div><div>• Pengumuman dan pembacaan keputusan pemenang lomba</div><div>• Penyerahan hadiah Jambore PKK 2025</div><div>• Api unggun dan hiburan</div><div>Jambore PKK 2025 ini diikuti oleh kader dari seluruh desa dan kelurahan se-Kota Sungai Penuh. Selain sebagai ajang kompetisi, kegiatan ini menjadi ruang pembelajaran bersama untuk memperkuat peran kader PKK dalam membangun keluarga dan masyarakat.</div><div>“Jambore ini bukan sekadar lomba, tetapi momentum memperkuat sinergi PKK dalam mewujudkan keluarga mandiri dan Kota Sungai Penuh Juara.” (Mc Kominfo)</div>','upload/berita/D5T3zrdgGtCnTXfJB0r4FpweyVVgPYh9v1Xkh55R.png','mediacenter','semangat-jambore-pkk-2025-ketua-tp-pkk-ajak-kader-wujudkan-kota-sungai-penuh-juara','2025-11-11 15:53:01','2025-11-11 15:53:01'),(126,'PKK Kota Sungai Penuh Meriahkan HUT ke-17 dengan Beragam Lomba dan Jambore Seru','<div>PKK Kota Sungai Penuh Meriahkan HUT ke-17 dengan Beragam Lomba dan Jambore Seru</div><div>SUNGAI PENUH - Suasana penuh semangat dan keceriaan kegiatan Jambore PKK Kota Sungai Penuh yang digelar dalam rangka memperingati Hari Ulang Tahun (HUT) Kota Sungai Penuh ke-17. Berbagai lomba menarik dan edukatif diselenggarakan oleh Tim Penggerak PKK untuk menambah kemeriahan perayaan tahun ini.</div><div>Acara yang dipusatkan di Kota Sungai Penuh ini diikuti oleh peserta dari PKK tingkat kecamatan hingga desa se-Kota Sungai Penuh. Mereka tampil antusias mengikuti sejumlah perlombaan yang dikemas dengan nuansa kebersamaan dan semangat kompetitif.</div><div>Beberapa perlombaan yang digelar di antaranya lomba Rangking 1, lomba memandikan jenazah, hingga lomba membaca buku cerita. Tak hanya sekadar hiburan, kegiatan ini juga menjadi wadah pembelajaran dan peningkatan kapasitas bagi para anggota PKK.</div><div>Ketua Panitia Jambore PKK, Reni Kurnia, menjelaskan bahwa ajang ini merupakan bagian dari upaya mempererat silaturahmi dan memperkuat peran PKK dalam pembangunan keluarga serta masyarakat.</div><div>“Lomba yang kami adakan tidak hanya untuk hiburan, tetapi juga untuk mengasah wawasan dan kemampuan anggota PKK agar lebih memahami program-program pokok PKK,” ujar Reni.</div><div>Ia juga menambahkan, kegiatan ini diharapkan menjadi momentum bagi seluruh kader PKK untuk terus berkontribusi nyata dalam membangun keluarga yang sehat, sejahtera, dan berdaya.</div><div>Jambore PKK Kota Sungai Penuh tahun ini menjadi bukti semangat kolaborasi dan kekompakan antaranggota dalam menyukseskan visi besar Kota Sungai Penuh yang maju, adil, dan sejahtera. Dengan penuh semangat, para peserta menunjukkan bahwa kebersamaan dan semangat gotong royong adalah kunci menuju Sungai Penuh Juara</div><div>(MC Kominfo)</div>','upload/berita/YptERUbSs4UXB6I0UBlt9IPTIOxE6yeTHuKKIzb0.png','mediacenter','pkk-kota-sungai-penuh-meriahkan-hut-ke-17-dengan-beragam-lomba-dan-jambore-seru','2025-11-11 15:55:28','2025-11-11 15:55:28'),(127,'Wako Alfin Hadiri Pisah Sambut Kepala Kejati Jambi','<div>Wako Alfin Hadiri Pisah Sambut Kepala Kejati Jambi&nbsp;</div><div>JAMBI - Wali Kota Sungai Penuh, Alfin, SH, menghadiri acara pisah sambut Kepala Kejaksaan Tinggi (Kejati) Jambi yang berlangsung di Aula Kejati Jambi, Selasa malam (5/11/2025).</div><div>Suasana acara berlangsung hangat dan penuh keakraban. Turut hadir Gubernur Jambi Al Haris, jajaran Forkopimda Provinsi Jambi, serta para bupati dan wali kota se-Provinsi Jambi yang datang memberikan dukungan dan ucapan selamat.</div><div>Dalam kesempatan itu, Sugeng Hariadi, SH, MH resmi dilantik sebagai Kepala Kejati Jambi menggantikan Dr. Hermon Dekrist, SH, MH, yang kini dipercaya memimpin Kejati Jawa Barat. Sebelumnya, Sugeng menjabat sebagai Direktur Perdata pada Jaksa Agung Muda Bidang Perdata dan Tata Usaha Negara (Jamdatun) Kejaksaan Agung RI.</div><div>Usai acara, Wali Kota Alfin menyampaikan apresiasi dan ucapan terima kasih kepada Dr. Hermon Dekrist atas dedikasi selama menjabat di Jambi.</div><div>“Terima kasih atas pengabdian Bapak Hermon Dekrist di Jambi. Semoga sukses di tempat tugas baru dan terus membawa kemajuan bagi institusi yang dipimpin,” ujar Wako Alfin.</div><div>Wako Alfin juga menyambut hangat kehadiran Kepala Kejati Jambi yang baru, Sugeng Hariadi, dan berharap sinergi antara pemerintah daerah dan kejaksaan terus terjalin dengan baik.</div><div>“Selamat datang di Provinsi Jambi. Semoga kerja sama antara kejaksaan dan pemerintah daerah semakin kuat serta memberi manfaat nyata bagi masyarakat,” pungkasnya.</div><div>(MC KOMINFO)</div>','upload/berita/6Omd0f7fL8PJEkBykr62zSLebzkHQZ7dw0Hn9r9z.png','mediacenter','wako-alfin-hadiri-pisah-sambut-kepala-kejati-jambi','2025-11-11 15:57:06','2025-11-11 15:57:06'),(128,'Azhar Hamzah: Saatnya Kota Sungai Penuh Perang Melawan Sampah','<div>Azhar Hamzah: Saatnya Kota Sungai Penuh Perang Melawan Sampah</div><div>SUNGAI PENUH - Wakil Wali Kota Sungai Penuh, Azhar Hamzah, terus mendorong kesadaran masyarakat untuk peduli terhadap kebersihan lingkungan. Melalui podcast bertema pengelolaan sampah yang digelar di Lapangan Merdeka, Rabu (5/11/2025), Wawako Azhar memaparkan pentingnya sistem pengolahan sampah yang bermanfaat dan berkelanjutan.</div><div>Acara ini menjadi bagian dari Jambore PKK sekaligus rangkaian peringatan HUT ke-17 Kota Sungai Penuh. Hadir dalam kesempatan itu Ketua GOW Kota Sungai Penuh Maryati Azhar, Camat Sungai Penuh, perwakilan media, serta sejumlah tamu undangan.</div><div>Suasana podcast semakin hidup dengan penampilan teater kreatif berjudul “Perang Terhadap Sampah Demi Negeri”, yang menggambarkan perjuangan masyarakat menjaga lingkungan dari ancaman sampah.</div><div>Dalam paparannya, Wawako Azhar menegaskan bahwa upaya mengatasi persoalan sampah harus dimulai dari diri sendiri dan dilakukan secara konsisten. Ia juga memperkenalkan mesin mini pencacah sampah yang bisa dimanfaatkan masyarakat untuk mengolah sampah menjadi produk bermanfaat, seperti kompos.</div><div>“Kita bisa menggunakan teknik ini. Mesin pencacah sampah ini dirancang untuk menghancurkan sampah organik dan menghasilkan kompos yang berguna bagi pertanian,” jelas Azhar.</div><div>“Mari kita nyatakan perang terhadap sampah demi mewujudkan Kota Sungai Penuh yang bersih, sehat, dan nyaman,” tambahnya.</div><div>Melalui kegiatan edukatif seperti ini, Pemerintah Kota Sungai Penuh berharap masyarakat semakin sadar bahwa pengelolaan sampah bukan hanya tanggung jawab pemerintah, tetapi juga menjadi bagian dari gaya hidup sehat dan peduli lingkungan.</div><div>(MC KOMNFO)</div>','upload/berita/dvoRAXvfwl3P82qHbV3djoBgsjdVhhzOaNKUMsYf.png','mediacenter','azhar-hamzah-saatnya-kota-sungai-penuh-perang-melawan-sampah','2025-11-11 15:58:38','2025-11-11 15:58:38'),(129,'Wako Alfin Resmi Buka Sidang Pleno I Badko HMI Jambi','<div>Wako Alfin Resmi Buka Sidang Pleno I Badko HMI Jambi</div><div>SUNGAI PENUH -Wali Kota Sungai Penuh, Alfin, SH, secara resmi membuka Sidang Pleno I Badan Koordinasi Himpunan Mahasiswa Islam (Badko HMI) Jambi periode 2024–2026 yang digelar di Aula Kantor Wali Kota Sungai Penuh, Rabu (5/11).</div><div>Kegiatan ini turut dihadiri oleh Ketua DPRD Kota Sungai Penuh, anggota DPRD Kabupaten Kerinci, Kasat Intel Polres Kerinci, Ketua Ombudsman Provinsi Jambi, Ketua KAHMI Kabupaten Kerinci, Ketua Badko HMI Jambi, serta perwakilan HMI cabang se-Provinsi Jambi.</div><div>Sidang pleno tersebut menjadi momentum penting bagi HMI dalam merumuskan arah kebijakan dan program kerja organisasi ke depan.</div><div>Dalam sambutannya, Wali Kota Alfin menyampaikan apresiasi dan dukungan penuh terhadap peran HMI sebagai organisasi kader yang konsisten mencetak generasi muda intelektual dan berintegritas.</div><div>“HMI telah banyak berkontribusi dalam membangun bangsa melalui peran pemuda dan mahasiswa. Pemerintah Kota Sungai Penuh menyambut baik kegiatan ini dan berharap hasil sidang pleno dapat memberikan manfaat bagi kemajuan organisasi serta daerah,” ujar Wako Alfin.</div><div>Sementara itu, pengurus Badko HMI Jambi menyampaikan terima kasih atas dukungan Pemerintah Kota Sungai Penuh yang telah memfasilitasi penyelenggaraan kegiatan tersebut.</div><div>Sidang Pleno I Badko HMI Jambi dijadwalkan berlangsung selama beberapa hari, dengan agenda pembahasan laporan kerja, evaluasi organisasi, dan penyusunan rekomendasi strategis untuk periode mendatang.( MC KOMINFO )</div>','upload/berita/ECcIJKhJ75EOc44qK9IYycrIRfaLzAbk8a7R8rnF.png','mediacenter','wako-alfin-resmi-buka-sidang-pleno-i-badko-hmi-jambi','2025-11-11 15:59:53','2025-11-11 15:59:53'),(130,'Jambore PKK dan Pasar Rakyat 2025 Resmi Dibuka, Wali Kota Alfin Gaungkan Semangat Kolaborasi','<div>Jambore PKK dan Pasar Rakyat 2025 Resmi Dibuka, Wali Kota Alfin Gaungkan Semangat Kolaborasi</div><div>SUNGAI PENUH - Suasana semarak dan penuh kebersamaan mewarnai Lapangan Merdeka Kota Sungai Penuh, Kamis (6/11/2025), saat digelarnya Jambore PKK dan Pasar Rakyat Kota Sungai Penuh Tahun 2025.</div><div>Wali Kota Sungai Penuh, Alfin, S.H., secara resmi membuka kegiatan akbar tersebut yang diikuti oleh seluruh kecamatan se-Kota Sungai Penuh.</div><div>Dalam sambutannya, Wali Kota Alfin menegaskan bahwa Jambore PKK dan Pasar Rakyat bukan sekadar acara seremonial, melainkan momentum untuk mempererat tali silaturahmi, memperkuat partisipasi masyarakat, serta menumbuhkan semangat gotong royong di seluruh lapisan warga.</div><div>“Melalui kegiatan ini, kita ingin menumbuhkan semangat kebersamaan dan gotong royong di seluruh kecamatan Kota Sungai Penuh. Mari kita jadikan Jambore PKK dan Pasar Rakyat ini sebagai ruang untuk berkolaborasi dan saling menginspirasi,” ujar Wako Alfin.</div><div>Wali Kota juga mengajak masyarakat untuk datang dan meramaikan kegiatan tersebut sebagai bentuk cinta dan kebanggaan terhadap Kota Sungai Penuh.</div><div>Dalam kesempatan itu, Alfin memberikan apresiasi khusus kepada Ketua TP-PKK Kota Sungai Penuh, Ny. Sri Kartini Alfin, S.Kep., Ns., atas inovasi Gerakan 3-S (Segenggam Beras, Sebutir Telur, dan Seribu Rupiah) sebuah program nyata yang berfokus pada upaya penanganan stunting melalui partisipasi keluarga.</div><div>“Gerakan 3-S adalah wujud keikhlasan dan kepedulian sosial. Program ini harus terus dijaga agar dapat menebar manfaat bagi masyarakat luas,” tambahnya.</div><div>Gerakan tersebut kini menjadi inspirasi bagi seluruh kader PKK di berbagai kecamatan dan perangkat daerah, memperlihatkan bahwa kolaborasi kecil bisa berdampak besar bagi masyarakat.</div><div>Selain menjadi wadah silaturahmi, kegiatan ini juga menjadi sarana menggerakkan ekonomi lokal. Pemerintah Kota Sungai Penuh berkomitmen mendorong pengembangan produk unggulan daerah dan pelaku UMKM, termasuk melalui promosi dan digitalisasi pasar.</div><div>“Produk lokal kita harus tampil kreatif dan inovatif. Pemerintah siap mendukung agar UMKM di Sungai Penuh terus tumbuh dan berdaya saing,” tegas Alfin.</div><div>Beragam kegiatan turut meramaikan acara, mulai dari pameran produk UMKM, bazar kuliner, lomba kreativitas antar kecamatan, hingga hiburan rakyat yang melibatkan antusiasme masyarakat dari berbagai penjuru kota.</div><div>Tak hanya menyoroti semangat kebersamaan, Wali Kota Alfin juga mengingatkan pentingnya menjaga kebersihan lingkungan selama kegiatan Jambore dan rangkaian HUT Kota Sungai Penuh berlangsung.</div><div>“Saya mengimbau kepada seluruh peserta, pengunjung, dan pengelola stand UMKM agar menjaga kebersihan dan membuang sampah pada tempatnya. Mari jadikan kegiatan ini bukan hanya meriah, tapi juga ramah lingkungan,” pesannya&nbsp;</div><div>Wali Kota menegaskan bahwa PKK merupakan mitra strategis pemerintah daerah dalam membangun keluarga yang sehat, mandiri, dan berdaya saing. Ia pun menyampaikan apresiasi tinggi kepada seluruh kader PKK atas dedikasi dan kerja nyata mereka di tengah masyarakat.</div><div>Acara pembukaan turut dihadiri oleh Wakil Wali Kota Azhar Hamzah, jajaran Forkopimda, Ketua DPRD, OPD, Camat, Kepala Desa, serta Ketua PKK Kabupaten Kerinci Dan Ketua TP-PKK dari seluruh kecamatan.</div><div>Melalui kegiatan ini, Pemerintah Kota Sungai Penuh berharap dapat memperkuat kolaborasi antara pemerintah, PKK, dan masyarakat dalam mewujudkan Kota JUARA Maju, Adil, dan Sejahtera.(MC KOMINFO)</div>','upload/berita/F1PIKu4xYU07L0WFLDfH0VZgfLhUfY6CJ5apz4mq.png','mediacenter','jambore-pkk-dan-pasar-rakyat-2025-resmi-dibuka-wali-kota-alfin-gaungkan-semangat-kolaborasi','2025-11-11 16:04:58','2025-11-11 16:04:58'),(131,'Wako Alfin Pimpin Apel HUT ke-8 Tirta Khayangan','<div>Wako Alfin Pimpin Apel HUT ke-8 Tirta Khayangan</div><div>SUNGAI PENUH - Wali Kota Sungai Penuh, Alfin, SH, memimpin apel peringatan Hari Ulang Tahun (HUT) ke-8 Perumda Air Minum Tirta Khayangan Kota Sungai Penuh, Jumat (7/11/2025). Kegiatan yang berlangsung penuh khidmat ini diikuti jajaran direksi, pegawai, dan keluarga besar Tirta Khayangan serta sejumlah pejabat BUMN Dan BUMD Pemerintah Kota Sungai Penuh.</div><div>Dalam sambutannya, Wali Kota Alfin menyampaikan ucapan selamat ulang tahun kepada seluruh jajaran Perumda Air Minum Tirta Khayangan. Ia berharap momentum ulang tahun ini menjadi semangat baru bagi seluruh pegawai untuk terus meningkatkan pelayanan air bersih bagi masyarakat.</div><div>“Atas nama Pemerintah Kota Sungai Penuh, saya menyampaikan selamat ulang tahun yang ke-8 kepada seluruh jajaran dan keluarga besar Perumda Air Minum Tirta Khayangan. Semoga momentum ini menjadi titik tolak semangat baru dalam meningkatkan pelayanan kepada masyarakat, memperkuat sinergi, dan memperkokoh komitmen dalam mewujudkan Kota Sungai Penuh yang maju, adil, dan sejahtera,” ujar Wali Kota.</div><div>Lebih lanjut, Wako Alfin menegaskan bahwa delapan tahun perjalanan Tirta Khayangan bukanlah waktu yang singkat. Ia mengapresiasi dedikasi dan semangat seluruh jajaran yang telah menjaga keberlanjutan layanan publik vital ini.</div><div>Mengangkat tema “8 Tahun Melangkah Maju Bersama, Bersatu, Bersinergi, dan Berinovasi Menuju Sungai Penuh Juara”, Wali Kota menilai tema tersebut sangat relevan dengan semangat pembangunan Kota Sungai Penuh saat ini.</div><div>Beliau menekankan pentingnya peningkatan kualitas dan cakupan layanan air bersih hingga menjangkau seluruh lapisan masyarakat, termasuk di wilayah pinggiran kota. Selain itu, ia juga mendorong penguatan tata kelola yang profesional, transparan, dan akuntabel serta pengembangan inovasi digital dalam pelayanan pelanggan dan distribusi air.</div><div>“Perumda Tirta Khayangan juga harus menjaga keberlanjutan sumber daya air dengan memperhatikan aspek lingkungan dan konservasi, serta membangun budaya kerja yang solid, melayani, dan berorientasi pada kepuasan pelanggan,” tegasnya.</div><div>Pada kesempatan itu, Wako Alfin turut menyampaikan dukungan penuh Pemerintah Kota terhadap pengembangan kapasitas dan layanan Tirta Khayangan. Ia mengungkapkan bahwa pada tahun 2026 mendatang akan dibangun Instalasi Pengolahan Air Minum (IPA) di Kecamatan Hamparan Rawang dengan kapasitas 50 liter per detik. Proyek senilai Rp37 miliar ini akan didanai melalui APBN tahun 2026 sebagai upaya menjawab keterbatasan kapasitas produksi dan meningkatnya permintaan sambungan baru dari masyarakat.</div><div>“Pemerintah Kota Sungai Penuh akan terus mendukung langkah-langkah Tirta Khayangan untuk memperkuat kelembagaan dan layanan air bersih bagi masyarakat,” tambahnya.</div><div>Kegiatan apel ditutup dengan penyerahan bantuan sambungan air minum gratis secara simbolis oleh Wali Kota Alfin, penyerahan hadiah kepada pelanggan yang membayar tagihan lebih awal, serta pemotongan kue ulang tahun ke-8 Perumda Tirta Khayangan sebagai simbol kebersamaan dan semangat baru dalam memberikan pelayanan terbaik kepada masyarakat.</div><div>Perayaan sederhana namun penuh makna ini menjadi momentum penting bagi seluruh jajaran Perumda Tirta Khayangan untuk terus berinovasi, bersinergi, dan berkontribusi nyata bagi kemajuan Kota Sungai Penuh.(MC KOMINFO)</div>','upload/berita/jPwj3wJixkoHjn3STPfXTouYR0uPyEYDla8pzoV6.png','mediacenter','wako-alfin-pimpin-apel-hut-ke-8-tirta-khayangan','2025-11-11 16:06:16','2025-11-11 16:06:16'),(132,'Wawako Sungai Penuh Dukung Keberlanjutan Kopi Lokal di Festival Negeri 3 Kopi','<div>Wawako Sungai Penuh Dukung Keberlanjutan Kopi Lokal di Festival Negeri 3 Kopi</div><div>SUNGAI PENUH - Semarak aroma kopi Kerinci terasa di Hotel Grand Kerinci pada Jumat (7/11). Wakil Walikota Sungai Penuh, Azhar Hamzah, hadir langsung membuka Festival Negeri 3 Kopi, sebuah ajang yang digelar Bank Indonesia Provinsi Jambi untuk memamerkan kekayaan kopi lokal.</div><div>Festival ini menampilkan tiga jenis kopi andalan Kerinci: Arabika, Robusta, dan Liberika. Masing-masing punya karakter rasa unik yang menjadikan kopi Kerinci istimewa dan diakui kualitasnya di tingkat nasional bahkan internasional.</div><div>Dalam kesempatan itu, Wawako Azhar menyampaikan dukungan penuh kepada para petani kopi dan Bank Indonesia yang mendorong pengembangan sektor pertanian.</div><div>Kopi bukan sekadar komoditas, tapi juga simbol identitas dan kebanggaan daerah. Dengan kerja sama semua pihak, kita ingin kopi Kerinci makin dikenal luas dan memberi manfaat nyata bagi petani lokal,” ujarnya.</div><div>Acara ditutup dengan penyerahan bibit kopi sebagai bentuk dukungan terhadap keberlanjutan produksi lokal. Tak ketinggalan, penyeduhan kopi bersama menutup festival, diikuti Bupati Kerinci dan perwakilan Bank Indonesia Provinsi Jambi, menciptakan momen hangat dan penuh kebersamaan.</div><div>Selain Wawako Azhar, hadir pula Bupati Kerinci Monadi S.Sos <a href=\"https://l.facebook.com/l.php?u=http%3A%2F%2FM.Si%2F%3Ffbclid%3DIwZXh0bgNhZW0CMTAAYnJpZBExY3pZQTNneXdyazBHRlpueHNydGMGYXBwX2lkEDIyMjAzOTE3ODgyMDA4OTIAAR6KK6KoTfJ3lBCBvUy0okAfeLiqiiBBN7RCDhLWoCa-fsL-ftpioFdGZYGbzA_aem_07eAhjDaBAyP4So8jwt1UQ%26brid%3DQdaz2HfFK-vknA2zxSrsAQ&amp;h=AT2VKx52wyAtIwDulh0DEtT4jJygMpuuI0XZrEhMWKvrPrsFB0OTZUNkdlnlnVevrq8zsddJnl_fGPYOLzuNg6smjjlgPr4QrhKXZ8VZQzbpY9H20TV8WJnt94sKOD3UP9qpoSLCOEUQJyYwJe8vLA&amp;__tn__=-UK-R&amp;c[0]=AT2VWNjFTpvp_S3SUkEsLbU1mvX9fwjugvwa07pRhJsm1jL8eEEhICzljluqELLwfUcSuust3fqO06qLRIEm_xc4olKY4uHOzxQENZGM4WYFdlYjfjinaOmKULJHfOPfIFXZjlyiOGz2-iOl9tq_3UCjKaZYDpaYOw_cgDaN6hK0w22jGjhSlpsc0akWuNfBbdPmVhQqtyx8LIpmjQM6G_cSpA\"><strong>M.Si</strong></a>, perwakilan Bank Indonesia Ny. Nurcahya, ATR/BPN, pimpinan perbankan, pelaku usaha, dan komunitas penggiat kopi dari seluruh Jambi, ikut meramaikan festival yang sarat dengan aroma dan rasa kopi asli Kerinci.</div><div>MC DISKOMINFO</div>','upload/berita/QGMXdU0bG6Qdo6OLFL17V6Bq2ifepKy4t2wL0zhJ.png','mediacenter','wawako-sungai-penuh-dukung-keberlanjutan-kopi-lokal-di-festival-negeri-3-kopi','2025-11-11 16:07:47','2025-11-11 16:07:47'),(133,'Wako Alfin Ajak Warga Jaga Lingkungan dan Pererat Silaturahmi di Safari Jumat Masjid Al-Mukhlisin','<div>Wako Alfin Ajak Warga Jaga Lingkungan dan Pererat Silaturahmi di Safari Jumat Masjid Al-Mukhlisin</div><div>SUNGAI PENUH – Pemerintah Kota Sungai Penuh terus mempererat hubungan dengan masyarakat lewat Safari Jumat dan Silaturahmi. Kali ini kegiatan berlangsung di Masjid Al-Mukhlisin, Desa Koto Tinggi, Kecamatan Sungai Bungkal, Jumat (7/11/2025).</div><div>Wali Kota Sungai Penuh, Alfin, S.H., yang didampingi&nbsp; Wakil Wali Kota Azhar Hamzah, Sekda Alpian, dan sejumlah kepala perangkat daerah.</div><div>Dalam sambutannya, Wako Alfin menegaskan bahwa Safari Jumat bukan sekadar ajang silaturahmi, tapi juga wadah komunikasi antara pemerintah dan masyarakat.</div><div>“Pemerintah tidak bisa bekerja sendiri. Pembangunan akan berhasil jika masyarakat ikut berpartisipasi dan menjaga hasilnya bersama,” ujar Alfin.</div><div>Ia menambahkan, Pemkot terus meningkatkan pelayanan publik, memperbaiki infrastruktur, dan memberdayakan masyarakat melalui berbagai program. Alfin juga mengingatkan pentingnya menjaga kebersihan lingkungan.</div><div>“Kami memperkuat pengelolaan sampah lewat pembangunan dan optimalisasi TPST Renah Kayu Embun. TPST tak hanya mengolah sampah, tapi juga menjadi pusat edukasi agar masyarakat makin peduli lingkungan,” jelasnya.</div><div>Alfin menekankan, sinergi antara pemerintah dan masyarakat menjadi kunci untuk mewujudkan Kota Sungai Penuh yang bersih, nyaman, dan berkelanjutan.</div><div>Sebagai bentuk dukungan terhadap kegiatan keagamaan, Wali Kota Alfin bersama Wawako Azhar Hamzah menyerahkan bantuan Rp5 juta untuk pembangunan Masjid Al-Mukhlisin. Bantuan ini berasal dari Dana CSR Bank Jambi sebagai kolaborasi pemerintah dengan lembaga keuangan daerah.</div><div>Tokoh masyarakat sekaligus pengurus masjid, Marwazy, menyampaikan terima kasih atas perhatian dan kehadiran langsung Wali Kota Alfin beserta jajaran.</div><div>“Kami berterima kasih kepada Bapak Wali Kota dan Wakil Walikota yang datang bersilaturahmi, salat Jumat berjamaah, dan memberikan bantuan untuk pembangunan masjid,” ujar Marwazy.</div><div>Ia berharap kegiatan Safari Jumat terus berlanjut karena membawa manfaat besar bagi hubungan pemerintah dan masyarakat. (MC KOMINFO)</div>','upload/berita/LNXjuxn2ckz8yHUxuz6nrOUqxYbAWYJvBmai20Dz.png','mediacenter','wako-alfin-ajak-warga-jaga-lingkungan-dan-pererat-silaturahmi-di-safari-jumat-masjid-al-mukhlisin','2025-11-11 16:09:00','2025-11-11 16:09:00'),(134,'Tumbuh dan Maju di Usia ke-17, Kota Sungai Penuh Siap Jadi Kota Juara','<div>Tumbuh dan Maju di Usia ke-17, Kota Sungai Penuh Siap Jadi Kota Juara</div><div>SUNGAI PENUH - Kota Sungai Penuh menapaki usia ke-17 dengan semangat baru dan optimisme tinggi untuk terus tumbuh sebagai kota yang berprestasi dan berdaya saing.</div><div>Momentum hari jadi kali ini ditandai dengan pelaksanaan Sidang Istimewa Paripurna DPRD Kota Sungai Penuh, yang digelar di Gedung DPRD, Sabtu (8/11/2025).</div><div>Walikota Sungai Penuh Alfin, SH bersama Wakil Walikota Azhar Hamzah hadir langsung mengikuti rangkaian sidang. Acara berlangsung khidmat dan penuh makna di bawah pimpinan Ketua DPRD Kota Sungai Penuh, Hutri Randa, S.Sos, MH, didampingi Wakil Ketua Hardizal, S.Sos, MH, dan Amrizal, <a href=\"https://l.facebook.com/l.php?u=http%3A%2F%2FS.Pt%2F%3Ffbclid%3DIwZXh0bgNhZW0CMTAAYnJpZBExY3pZQTNneXdyazBHRlpueHNydGMGYXBwX2lkEDIyMjAzOTE3ODgyMDA4OTIAAR4NzhdyyQL6SFdewUDc3Tc8Lr9FoRyQC305IVsH6y2cGQtlLQoM303qZjpbFg_aem_VmuIoMuVa6FE1T1sSC_UiQ%26brid%3DVJKvUUBepHK3UKc_j90ksg&amp;h=AT0sZVSYaumZxaMucOI54saUU7-lk4kjauvkoZnWIA9Zb6r9MpN0uIj5PGPsV4z2AndJlgGsNP97kjSK3j4rmT4zV1oyAj9-BVFzuWUJkp2REdCB8FNWQN-taE5PB0TE_T-1x1fOrV3ZmjcQahCJKg&amp;__tn__=-UK-R&amp;c[0]=AT2cHU4UP6k75o9r5wfwJYWvXKOgagp_GVGZ_ptCB5XlCHiaxo_8nLbRBU-7iGZH06roEvunpLNfQGWjbh6yzf0LU1rrp1zF97hb39lEIzXVM5Kq-d-VX9bNic7j8-HYZEQiFUrPMsOJiSrlm45rRgrWNwOchVPcj0hHy5oDM0m3SdOQYGYcTjcJvGM_1-aZiyr90d_5BhoXTEXzV_RlZfqR8Q\"><strong>S.Pt.</strong></a></div><div>Turut memberikan warna pada peringatan hari jadi ini, Gubernur Jambi, Dr. H. Al Haris, S.Sos, MH, bersama Ketua TP PKK Provinsi Jambi, Hj. Hesnidar Haris, SE, hadir secara langsung bersama sejumlah pejabat dan kepala daerah se-Provinsi Jambi. Forkopimda Kota Sungai Penuh, para anggota DPRD, Sekda, kepala OPD, camat, serta tamu undangan juga turut menyemarakkan peringatan hari bersejarah tersebut.</div><div>Dalam sambutannya, Walikota Alfin menegaskan bahwa peringatan HUT ke-17 bukan sekadar seremoni, tetapi menjadi momentum refleksi atas perjalanan pembangunan daerah serta dorongan untuk menatap masa depan dengan visi yang lebih kuat.</div><div>Atas nama pemerintah dan masyarakat, kami menyampaikan terima kasih kepada seluruh pihak yang telah berkontribusi dalam kemajuan Kota Sungai Penuh. Dukungan dari pemerintah provinsi, legislatif, dan seluruh elemen masyarakat menjadi modal besar untuk mewujudkan kota yang maju, adil, dan sejahtera,” ungkap Wako Alfin.</div><div>Ia juga mengajak seluruh jajaran pemerintah dan masyarakat untuk menjadikan usia ke-17 ini sebagai titik awal semangat baru menuju ‘Sungai Penuh Juara’, yakni kota yang unggul di berbagai bidang dengan masyarakat yang berdaya dan berbahagia.</div><div>Sementara itu, Gubernur Jambi Al Haris dalam sambutannya menyampaikan apresiasi terhadap berbagai capaian yang telah diraih Pemerintah Kota Sungai Penuh dalam kurun waktu 17 tahun terakhir. Menurutnya, Sungai Penuh memiliki potensi besar untuk terus berkembang, terutama jika sinergi antara pemerintah provinsi dan daerah terus diperkuat.</div><div>Selamat ulang tahun untuk Kota Sungai Penuh. Semoga di usia ke-17 ini, semangat membangun semakin kokoh, dan sinergi antara provinsi dan kota makin erat demi kemajuan bersama,” tutur Gubernur Al Haris.</div><div>Peringatan HUT ke-17 Kota Sungai Penuh menjadi simbol semangat kebersamaan dan tekad kolektif untuk membawa daerah ini menuju masa depan yang lebih baik – kota yang benar-benar tumbuh, maju, dan siap menjadi juara.</div><div>(MC DISKOMINFO)</div>','upload/berita/1kkUyPw6lYM964AworHjbtQkUC0SGulA9fywc0bq.png','mediacenter','tumbuh-dan-maju-di-usia-ke-17-kota-sungai-penuh-siap-jadi-kota-juara','2025-11-11 16:10:37','2025-11-11 16:10:37'),(135,'Gubernur Jambi Serahkan Bantuan Bedah Rumah, Wako Alfin Dampingi Langsung','<div>Gubernur Jambi Serahkan Bantuan Bedah Rumah, Wako Alfin Dampingi Langsung</div><div>Sungai Penuh - Gubernur Jambi melakukan kunjungan kerja ke Kota Sungai Penuh, Sabtu (8/11/2025), dalam rangka menyerahkan bantuan program bedah rumah bagi masyarakat kurang mampu. Kegiatan berlangsung hangat dan penuh keakraban di tengah masyarakat penerima manfaat.</div><div>Dalam kesempatan tersebut, Wali Kota Sungai Penuh, Alfin, SH, bersama Wakil Wali Kota Azhar Hamzah, turut mendampingi langsung prosesi penyerahan bantuan. Kehadiran keduanya menjadi bentuk dukungan nyata Pemerintah Kota Sungai Penuh terhadap program peningkatan kesejahteraan masyarakat di daerah.</div><div>Program bedah rumah ini merupakan inisiatif Pemerintah Provinsi Jambi yang bertujuan untuk membantu masyarakat berpenghasilan rendah memperoleh hunian yang layak, sehat, dan nyaman. Melalui program ini, pemerintah berupaya memperkuat komitmen dalam menciptakan pemerataan kesejahteraan di seluruh wilayah provinsi.</div><div>Wali Kota Sungai Penuh, Alfin, SH, menyampaikan apresiasi dan terima kasih yang mendalam kepada Gubernur Jambi atas perhatian serta dukungan yang diberikan kepada masyarakat Sungai Penuh.</div><div>“Atas nama Pemerintah Kota Sungai Penuh dan seluruh masyarakat, kami mengucapkan terima kasih kepada Bapak Gubernur Jambi atas bantuan yang sangat berarti ini. Program bedah rumah menjadi bukti nyata sinergi antara pemerintah provinsi dan kota dalam meningkatkan kesejahteraan masyarakat,” ujar Wako Alfin.</div><div>Sementara itu, Gubernur Jambi menegaskan bahwa program bedah rumah akan terus berlanjut sebagai bentuk komitmen pemerintah dalam menghadirkan tempat tinggal yang layak dan bermartabat bagi seluruh warga Jambi. Ia berharap program ini dapat memberikan dampak positif serta meringankan beban masyarakat yang membutuhkan.</div><div>Kegiatan penyerahan bantuan turut dihadiri oleh jajaran Pemerintah Provinsi Jambi, unsur Forkopimda Kota Sungai Penuh, serta masyarakat penerima bantuan. (MC KOMINFO)</div>','upload/berita/WRTfZNymvFTpApiC1IWA7fAr15rhVxoEfjKWtuNm.png','mediacenter','gubernur-jambi-serahkan-bantuan-bedah-rumah-wako-alfin-dampingi-langsung','2025-11-11 16:16:48','2025-11-11 16:16:48'),(136,'Malam Resepsi HUT ke-17 Kota Sungai Penuh Penuh Kehangatan dan Kebersamaan','<div>Malam Resepsi HUT ke-17 Kota Sungai Penuh Penuh Kehangatan dan Kebersamaan</div><div>SUNGAI PENUH – Suasana hangat dan penuh kebersamaan mewarnai Malam Resepsi Hari Ulang Tahun (HUT) ke-17 Kota Sungai Penuh Tahun 2025 yang digelar di Gedung Nasional Kota Sungai Penuh, Sabtu malam (8/11).</div><div>Acara tersebut dihadiri oleh Bupati Kerinci, Wakil Wali Kota Sungai Penuh, Pimpinan dan Anggota DPRD, unsur Forkopimda, Sekda, Ketua TP-PKK Provinsi Jambi Ny. Hj. Hesnidar Haris, S.E., Ketua TP-PKK Kota Sungai Penuh, para Kepala OPD, pimpinan BUMN/BUMD, tokoh masyarakat, alim ulama, serta tamu undangan lainnya.</div><div>Kehadiran para tokoh dan tamu tersebut menambah semarak suasana malam perayaan yang menjadi puncak rangkaian peringatan HUT ke-17 Kota Sungai Penuh.</div><div>Dalam sambutannya, Wali Kota Sungai Penuh, Alfin, S.H., menyampaikan rasa syukur atas perjalanan pembangunan yang telah dilalui bersama hingga memasuki usia ke-17 tahun.</div><div>“Tujuh belas tahun bukan hanya tentang lamanya waktu, tetapi juga tentang proses, kerja keras, dan kebersamaan seluruh masyarakat. Kita patut bersyukur atas capaian yang diraih, namun masih banyak hal yang harus kita lanjutkan dengan semangat persatuan dan gotong royong,” ungkap Wako Alfin.</div><div>Ia juga mengajak seluruh masyarakat untuk menjadikan momentum hari jadi ini sebagai semangat baru dalam memperkuat tekad bersama menuju Kota Sungai Penuh yang Maju, Adil, dan Sejahtera.</div><div>“Mari terus kita rawat kebersamaan ini. Dengan semangat gotong royong, kita yakin Sungai Penuh akan semakin baik ke depan,” tambahnya.</div><div>Malam resepsi berlangsung meriah dengan berbagai penampilan seni dan budaya daerah, serta persembahan musik dari seniman lokal yang menambah suasana hangat dan akrab di antara seluruh tamu undangan. (MC Kominfosta)</div>','upload/berita/4vgLsPt0Bp8w9370vUHJHHCC6mbNczbH3udhDkD5.png','mediacenter','malam-resepsi-hut-ke-17-kota-sungai-penuh-penuh-kehangatan-dan-kebersamaan','2025-11-11 16:17:53','2025-11-11 16:17:53'),(137,'Wako Alfin Pimpin Upacara Hari Pahlawan, Serahkan Sejumlah Penghargaan dan Bantuan di Kota Sungai Penuh','<div>Wako Alfin Pimpin Upacara Hari Pahlawan, Serahkan Sejumlah Penghargaan dan Bantuan di Kota Sungai Penuh</div><div>SUNGAI PENUH - Wali Kota Sungai Penuh, Alfin, SH, memimpin langsung upacara peringatan Hari Pahlawan tahun 2025 yang berlangsung khidmat di Lapangan Kantor Wali Kota Sungai Penuh, Senin (10/11). Upacara diikuti oleh jajaran Pemerintah Kota, Forkopimda, para pimpinan instansi vertikal, serta perwakilan BUMN dan BUMD.</div><div>Hadir dalam upacara tersebut Wakil Wali Kota Sungai Penuh Azhar Hamzah, Wakil Ketua DPRD Emrizal, <a href=\"https://l.facebook.com/l.php?u=http%3A%2F%2FS.Pt%2F%3Ffbclid%3DIwZXh0bgNhZW0CMTAAYnJpZBExY3pZQTNneXdyazBHRlpueHNydGMGYXBwX2lkEDIyMjAzOTE3ODgyMDA4OTIAAR4NzhdyyQL6SFdewUDc3Tc8Lr9FoRyQC305IVsH6y2cGQtlLQoM303qZjpbFg_aem_VmuIoMuVa6FE1T1sSC_UiQ%26brid%3D2Fek16WP8dHG8vsz2qc9bw&amp;h=AT0MJP0mtg3Abl16xCUrQFVvcuKte4exA5UFPJvBa3VATB7FW_i05GsFQFxtaWa1MCaMqe6eQXrYrbCE1LZSFFgznDw10KqFmqCXFwxD-s0z3syAdHSQDGUCcZs_Y9PyNFVz1lSe6JTh3Zd9IVKyhw&amp;__tn__=-UK-R&amp;c[0]=AT0LFi4nzMfYzJZtcRVsYDMbnV2q_MCZ-dLK1A-6YBAZ_4YoB5_IJji_jk8ABzMIZ1cNme-PrqCZdrz3PGP2VCt-zAYOCnWI7-kle80BFVPmEEERLpqsC7cyaYkSAIF3nsIlgSCZNFa-H_I4L6v1NQXnOfqZdpMo5Ep9S0KYz4P4mv6J9uBpODDYXhs7vA1yDSkh8A0JUVAhkq961mnjekSBEw\"><strong>S.Pt.</strong></a>, Sekretaris Daerah Alpian, S.E., M.M., para staf ahli, asisten Sekda, kepala perangkat daerah, serta pejabat struktural dan fungsional di lingkungan Pemerintah Kota Sungai Penuh.</div><div>Dalam kesempatan itu, Wali Kota Alfin membacakan amanat Menteri Sosial Republik Indonesia, Saifullah Yusuf. Dalam amanatnya, Mensos mengajak seluruh masyarakat untuk menundukkan kepala mengenang jasa para pahlawan bangsa yang telah berjuang merebut kemerdekaan.</div><div>“Para pahlawan bukan sekadar nama di batu nisan, melainkan cahaya yang menerangi jalan kita hingga hari ini,” ujar Wali Kota Alfin saat membacakan amanat tersebut.</div><div>Mensos menekankan bahwa kemerdekaan tidak diraih dengan mudah, tetapi dengan kesabaran, keberanian, kejujuran, dan keikhlasan. Ditekankan pula tiga nilai utama yang dapat diteladani dari para pahlawan, yaitu kesabaran dalam berjuang, semangat mengutamakan kepentingan bangsa di atas segalanya, serta pandangan jauh ke depan untuk generasi mendatang.</div><div>“Perjuangan hari ini tidak lagi dengan bambu runcing, melainkan dengan ilmu, empati, dan pengabdian. Namun semangatnya tetap sama&nbsp; membela yang lemah dan memperjuangkan keadilan,” lanjutnya.</div><div>Upacara Hari Pahlawan tahun ini juga menjadi momentum untuk memperkuat semangat nasionalisme serta mengingatkan masyarakat pentingnya melanjutkan perjuangan para pahlawan melalui kerja nyata.</div><div>Di akhir rangkaian upacara, Wali Kota Alfin menyerahkan sejumlah penghargaan dan bantuan kepada berbagai pihak. Penghargaan pertama diberikan kepada Dandim 0417/Kerinci atas terlaksananya kegiatan TMMD ke-126 Tahun 2025 di Desa Sungai Jernih, Kecamatan Pondok Tinggi, Kota Sungai Penuh.</div><div>Selanjutnya, penghargaan juga diserahkan kepada Kapolres Kerinci atas prestasi meraih Juara 1 Kompolnas Award Polres Tipe B se-Indonesia Tahun 2025. Wako Alfin turut memberikan apresiasi kepada Satuan Reserse Narkoba Polres Kerinci atas keberhasilannya mengungkap tindak pidana pencucian uang dengan predicate crime tindak pidana narkotika.</div><div>Selain itu, secara simbolis Wali Kota Alfin juga menyerahkan bantuan pangan dari Perum Bulog dan bantuan alat dan mesin pertanian (alsintan) dari Kementerian kepada kelompok tani di Kota Sungai Penuh.(MC KOMINFO)</div>','upload/berita/IJc7EqntqxCjHb52lJtK7mSsD9nKALw9A4m9bFvk.png','mediacenter','wako-alfin-pimpin-upacara-hari-pahlawan-serahkan-sejumlah-penghargaan-dan-bantuan-di-kota-sungai-penuh','2025-11-11 16:19:33','2025-11-11 16:19:33'),(138,'Wako Alfin Ziarah Ke Makam Pahlawan','<div>Wako Alfin Ziarah Ke Makam Pahlawan&nbsp;</div><div>SUNGAI PENUH- Dalam rangka memperingati Hari Pahlawan Tahun 2025.&nbsp;</div><div>Tema “Pahlawanku Teladanku, Terus Bergerak Melanjutkan Pembangunan”. Walikota Sungai Penuh Alfin, SH melaksanakan ziarah rombongan di Makam Pahlawan Desa Semumu Kecamatan Depati Tujuh Kabupaten Kerinci.&nbsp;</div><div>Turut hadir, Bupati Kerinci Monadi, Sekda Alpian, DPRD Kota Sungai Penuh dan Kabupaten Kerinci, Kejaksaan, Kapolres Kerinci, Komandan Kodim 0417 Kerinci, Kepala SKPD.</div><div>Wako Alfin mengatakan, kenanglah Jasa jasa para pahlawan yang telah mendahului kita. Berkat Merdeka karena perjuangan mereka.&nbsp;</div><div>Dalam hal ini, Pahlawan adalah teladan dan marilah kita jaga amanah serta bergerak demi pembangunan.</div><div>“Di hari pahlawan ini mengajarkan kita mengingat momentum perjuangan para pahlawan yang telah mendahului kita. Ini patut kita apresiasi, dalam hal ini, berkat Merdeka, bersatu dan berdaulat agar terus mencapai semangat bergerak demi pembangunan kedepanya”. [ ]</div><div>(Mc Diskominfosta)</div>','upload/berita/sophc3BNSvb1C9j9TgRoYIZS3WnmMYUiZRPShbg8.png','mediacenter','wako-alfin-ziarah-ke-makam-pahlawan','2025-11-11 16:20:49','2025-11-11 16:20:49'),(139,'Pemkot Sungai Penuh Dorong Koperasi Modern, Wakil Wali Kota Buka Pelatihan KDKMP 2025','<div>Pemkot Sungai Penuh Dorong Koperasi Modern, Wakil Wali Kota Buka Pelatihan KDKMP 2025</div><div>Sungai Penuh – Pemerintah Kota (Pemkot) Sungai Penuh terus menunjukkan komitmennya dalam meningkatkan kualitas sumber daya manusia (SDM) di sektor koperasi. Komitmen ini diwujudkan melalui kegiatan Pelatihan Peningkatan Kapasitas dan Kompetensi Pengurus Koperasi Desa/Kelurahan Merah Putih (KDKMP) Tahun 2025 yang resmi dibuka oleh Wakil Wali Kota Sungai Penuh, Azhar Hamzah, di Aula IAIN Kerinci, Senin (10/11/2025).</div><div>Pelatihan bertema “SDM dan Talenta Unggul Menuju Indonesia Emas 2045” ini dihadiri oleh Wakil Wali Kota Sungai Penuh Azhar Hamzah, Kepala Dinas Koperasi dan UKM Kota Sungai Penuh Tiarauddin Arsi, S.S.T., <a href=\"https://l.facebook.com/l.php?u=http%3A%2F%2FM.Si%2F%3Ffbclid%3DIwZXh0bgNhZW0CMTAAYnJpZBExY3pZQTNneXdyazBHRlpueHNydGMGYXBwX2lkEDIyMjAzOTE3ODgyMDA4OTIAAR61zhxiVi5Ay5dOujQbedROixnqieYtyf_dhdi2MmZBbEtzL1l55iiaKOyaQw_aem_E2R-m98cIdGuW-G8tchrPA%26brid%3DO0IcBvfyXBf3WPmKF7Qucw&amp;h=AT0ij0G8kTlLkuRQTrx7wy941A4ze4QXv_qA8sNS4qCjHdm8WAXQoC2os8fZc4qPOItnAG0m22xdQDIt-wTyJH95Ne6ear_ylnPSUqfc-aaW2SJi4wu8dz4gHvnXzDVPdeNa4uKzCP2ChCnL1_rCkA&amp;__tn__=-UK-R&amp;c[0]=AT3U9bdvCHIRpw_QQMPGFaUU4qDkdSQ1Q9LXJjsUTB8PsXIByop6VrJ9b5Dq3bjbaUfjvR4ilAmS16jUPSVtlTTPvxHLf_jvb3eO8VRD5WswcioSma2FsLzvayzVa5OtOFAZfgvuM_MI77cy3dJIAQ4f8DAgErGF8hBIPRWXoAYA7pfjSfPLooM-ipgPvOelI-9mrk490OuZ6TsAXZhZtsydkg\"><strong>M.Si</strong></a>, Kepala Bidang Koperasi Provinsi Jambi Hj. Melantri, S.E, narasumber Ir. Zaenal Arifin, <a href=\"https://l.facebook.com/l.php?u=http%3A%2F%2FM.Sc%2F%3Ffbclid%3DIwZXh0bgNhZW0CMTAAYnJpZBExY3pZQTNneXdyazBHRlpueHNydGMGYXBwX2lkEDIyMjAzOTE3ODgyMDA4OTIAAR4wcmGBCpuSBgv7oC63BtnREYWbv24XkEy7VxbhxVd4wrVt7aFGovoLYcBn3Q_aem_dR7Vk79CGpaFgBHnR4rnDw%26brid%3DTxy0pKA4IiDso8qls3mq4w&amp;h=AT3FCcc_myoiOmUdm8HxDPY-meO2Wtg8cyQ5v2ravE0nlY3MRAfsY8bZppSCql66PbSadzdgASNt5hygxg_yfiWVZVYn4zMAtWZcJ1FQDJBHnjFSSc2bFjBhN8vIAGYxrD4ludk1OVip1MKPhY4P8Q&amp;__tn__=-UK-R&amp;c[0]=AT3U9bdvCHIRpw_QQMPGFaUU4qDkdSQ1Q9LXJjsUTB8PsXIByop6VrJ9b5Dq3bjbaUfjvR4ilAmS16jUPSVtlTTPvxHLf_jvb3eO8VRD5WswcioSma2FsLzvayzVa5OtOFAZfgvuM_MI77cy3dJIAQ4f8DAgErGF8hBIPRWXoAYA7pfjSfPLooM-ipgPvOelI-9mrk490OuZ6TsAXZhZtsydkg\"><strong>M.Sc</strong></a>, serta jajaran pejabat struktural Dinas Koperasi dan UKM Kota Sungai Penuh, dan seluruh peserta pelatihan yang berasal dari 69 desa dan kelurahan di Kota Sungai Penuh.</div><div>Sebanyak 138 peserta turut ambil bagian dalam kegiatan yang difokuskan untuk meningkatkan kapasitas pengurus koperasi agar mampu beradaptasi dengan era digital.</div><div>Dalam laporannya, Kadis Koperasi dan UKM Tiarauddin Arsi menegaskan bahwa pelatihan ini merupakan bagian dari strategi besar Pemkot Sungai Penuh dalam mencetak koperasi yang tangguh, modern, dan berdaya saing digital.</div><div>“Tahun 2025 kita targetkan lahir dua koperasi terbaik dengan administrasi lengkap dan sistem digital terintegrasi. Semua pengelolaan koperasi Merah Putih wajib menggunakan SIMKOPDES (Sistem Informasi Manajemen Koperasi Desa/Kelurahan), tidak lagi manual,” ujarnya.</div><div>Menurutnya, pendampingan intensif bersama PMKO dan Badan Akreditasi (BA) akan terus dilakukan untuk memastikan digitalisasi koperasi berjalan efektif di setiap desa dan kelurahan.</div><div>Sementara itu, dalam sambutannya, Wakil Wali Kota Sungai Penuh Azhar Hamzah menegaskan bahwa koperasi merupakan pilar utama ekonomi kerakyatan yang harus diperkuat melalui kolaborasi, inovasi, dan profesionalisme.</div><div>“Koperasi adalah wadah kebersamaan, gotong royong, dan solidaritas ekonomi masyarakat. Jadikan pelatihan ini sebagai momentum memperkuat koperasi agar tangguh dan adaptif di era digital,” tegasnya sebelum membuka kegiatan secara resmi dengan ucapan Bismillahirrahmanirrahim.</div><div>Azhar Hamzah juga menyampaikan apresiasi atas terselenggaranya kegiatan ini dan mengajak seluruh peserta untuk menjadi agen perubahan di lingkungan masing-masing.</div><div>“Kita ingin koperasi menjadi motor penggerak ekonomi masyarakat. Melalui pelatihan ini, para pengurus diharapkan memiliki kemampuan manajerial, tata kelola, dan literasi digital yang baik untuk menghadapi tantangan masa depan,” ujarnya.</div><div>Ia menekankan pentingnya pembangunan SDM unggul dan penguatan talenta sebagai langkah nyata menuju Indonesia Emas 2045. Para peserta diharapkan mampu:</div><div>Memahami prinsip dasar perkoperasian yang sehat dan berkelanjutan,</div><div>Meningkatkan tata kelola keuangan dan organisasi,</div><div>Memanfaatkan teknologi digital dalam layanan koperasi,</div><div>Serta menjadi pelopor ekonomi mandiri di tingkat desa dan kelurahan.</div><div>Pemkot Sungai Penuh optimis, dengan sinergi dan semangat digitalisasi melalui SIMKOPDES, koperasi di tingkat desa dan kelurahan akan semakin maju, efisien, dan berdaya saing tinggi.</div><div>Pelatihan ini menjadi bagian dari visi besar Pemkot untuk mewujudkan “Sungai Penuh Juara” kota yang maju, adil, dan sejahtera, serta berkontribusi aktif dalam mencapai cita-cita Indonesia Emas 2045.</div><div>(Mc. Kominfo)</div>','upload/berita/yAkIxVxCU7r4URkDSLSnZlw6iFmha8VbDgxE7ER3.png','mediacenter','pemkot-sungai-penuh-dorong-koperasi-modern-wakil-wali-kota-buka-pelatihan-kdkmp-2025','2025-11-11 16:22:08','2025-11-11 16:22:08'),(140,'Wawako Azhar Buka Seminar Muatan Lokal Budaya Daerah','<div>Wawako Azhar Buka Seminar Muatan Lokal Budaya Daerah&nbsp;</div><div>SUNGAI PENUH- Wakil Walikota Sungai Penuh Azhar Hamzah menghadiri dan membuka seminar Muatan Lokal Budaya Daerah di Hotel Gran Kerinci. Selasa 11/ 11/ 2025</div><div>Kegiatan seminar ini dilaksanakan oleh Dinas Pendidikan Kota Sungai Penuh, turut hadir yakni, Anggota DPRD Kota Sungai Penuh Maswan, Ketua Perguruan Tinggi Swasta, Budayawan, Sejarahwan, Para Guru SD dan SMP lingkup Kota Sungai Penuh beserta tamu undangan lainya.</div><div>Seminar ini digelar sebagai upaya pemerintah daerah dalam memperkuat pendidikan berbasis kearifan lokal melalui pengembangan buku pelajaran yang memuat nilai nilai budaya dan tradisi khas Kota Sungai Penuh.</div><div>Wawako Azhar dalam sambutanya mengatakan, pentingnya peserta didik lebih mengenal tentang muatan Lokal Budaya Daerah Kota Sungai Penuh. Hal ini merupakan edukasi atau penguatan perawatan terhadap tradisi, bahasa, sejarah dan lain sebagainya terkait dengan budaya.</div><div>Tujuanya, agar peserta didik atau generasi muda lebih memahami sejarah budaya yang ada di Kota Sungai Penuh. Kemudian juga sebagai potensi kreatif dalam mengembangkan bakat dibidang dimaksud.</div><div>“Saya sangat mengapresiasi adanya seminar ini, khususnya dilingkup Sekolah Dasar dan menengah pertama yang ada di Kota Sungai Penuh. Dalam hal ini peserta didik dapat mengenal lebih dalam tentang budaya daerah dan menjadi edukasi atau wawasan mereka tentang muatan lokal Budaya. Selain itu Dengan menghadirkan muatan lokal pembelajaran termasuk memperkuat jati diri anak anak Sungai Penuh sejak dini”pungkasnya</div><div>(Mc Diskominfosta)</div>','upload/berita/FZvBVZ7Bq0L5t338mDb1YEykNhm8M3yxZP9MQb1l.png','mediacenter','wawako-azhar-buka-seminar-muatan-lokal-budaya-daerah','2025-11-11 16:23:23','2025-11-11 16:23:23'),(141,'Wako Alfin Kukuhkan Bunda Literasi, Ajak Generasi Muda Gemar Membaca dan Berkarya','<div>Wako Alfin Kukuhkan Bunda Literasi, Ajak Generasi Muda Gemar Membaca dan Berkarya</div><div>Sungai Penuh - Walikota Sungai Penuh, Alfin, SH, secara resmi mengukuhkan Bunda Literasi Kota Sungai Penuh serta Bunda Literasi Kecamatan se-Kota Sungai Penuh masa bhakti 2025–2029.</div><div>Kegiatan yang digelar oleh Dinas Perpustakaan Kota Sungai Penuh tersebut dirangkaikan dengan Festival Literasi Kota Sungai Penuh 2025, yang berlangsung pada Selasa (11/11).</div><div>Acara turut dihadiri oleh Ketua DPRD Kota Sungai Penuh Hutri Randa, jajaran Forkompimda, Sekda Alpian, Ketua GOW Kota Sungai Penuh Mawarti Azhar, Kerua GOW Kabupaten Kerinci Hj. SAPTI Malinda Murison, Ketua Dharma Wanita Winda Rahayu, para kepala OPD, pelajar, serta undangan lainnya.</div><div>Suasana acara berlangsung meriah dan penuh semangat literasi dari berbagai kalangan masyarakat.</div><div>Bunda Literasi Kota Sungai Penuh, Sri Kartini Alfin, S.Kep., Ns., dalam sambutannya menyampaikan komitmennya untuk bersinergi dengan Pemerintah Kota Sungai Penuh dalam memperkuat budaya literasi melalui pendidikan, perpustakaan, dan pemberdayaan masyarakat.</div><div>Menurutnya, gerakan literasi harus dimulai sejak dini dan melibatkan seluruh elemen, mulai dari keluarga, sekolah, hingga ruang publik.</div><div>“Kami berkomitmen mendukung program Pemerintah Kota Sungai Penuh, khususnya di bidang pendidikan, untuk mewujudkan anak-anak Sungai Penuh yang pintar dan berkarakter,” ungkapnya.</div><div>Sementara itu, Walikota Alfin, SH dalam arahannya menyampaikan apresiasi kepada Bunda Literasi yang baru dikukuhkan. Ia menegaskan bahwa peran Bunda Literasi sangat strategis sebagai penggerak, motivator, sekaligus inspirator dalam menumbuhkan budaya membaca dan menulis di tengah masyarakat.</div><div>“Dengan kolaborasi antara pemerintah daerah, Bunda Literasi, Dinas Perpustakaan, komunitas, dan masyarakat, gerakan literasi di Kota Sungai Penuh akan tumbuh lebih luas dan berkelanjutan,” ujarnya.</div><div>Lebih lanjut, Wako Alfin menjelaskan bahwa Festival Literasi 2025 menjadi momentum penting untuk menumbuhkan semangat membaca, menulis, dan berkarya di kalangan masyarakat, terutama generasi muda.</div><div>Ia berharap, literasi dapat menjadi pondasi dalam membangun karakter dan kreativitas warga Sungai Penuh.</div><div>“Kita ingin menjadikan Sungai Penuh sebagai kota literasi di kaki Gunung Kerinci tempat tumbuhnya ide, kreativitas, dan pengetahuan yang membawa kemajuan daerah,” tutupnya.</div><div>Sebagai penutup acara, Walikota Alfin menyerahkan piala dan penghargaan kepada pemenang Perpustakaan Terbaik Desa/Kelurahan serta pemenang lomba Festival Literasi Kota Sungai Penuh 2025.(MC KOMINFO)</div>','upload/berita/b2KqkPPReSJ2XAEIk58ZMXWy1YLcR6jbqZdYfoz7.png','mediacenter','wako-alfin-kukuhkan-bunda-literasi-ajak-generasi-muda-gemar-membaca-dan-berkarya','2025-11-11 16:24:35','2025-11-11 16:24:35'),(142,'Wako Alfin : Bujang Gadis Harus Jadi Generasi Berkarakter Dan Kreatif','<div>Wako Alfin : Bujang Gadis Harus Jadi Generasi Berkarakter Dan Kreatif</div><div>SUNGAI PENUH - Malam Grand Final Pemilihan Bujang dan Gadis Kota Sungai Penuh Tahun 2025 berlangsung megah dan penuh semangat di Gedung Nasional Kota Sungai Penuh, Selasa malam (11/11/2025).</div><div>Acara yang menjadi puncak dari rangkaian panjang ajang pencarian duta muda Kota Sungai Penuh ini sukses menarik perhatian ratusan penonton dari berbagai kalangan. Sorak dukungan dan tepuk tangan meriah mengiringi setiap penampilan finalis yang tampil penuh percaya diri.</div><div>Walikota Sungai Penuh, Alfin, S.H., hadir langsung didampingi Ketua TP PKK Ny. Sri Kartini Alfin, S.Kep., Ns.. Kehadiran keduanya menambah semangat para peserta yang malam itu berjuang menampilkan yang terbaik.</div><div>Dalam sambutannya, Wako Alfin menyampaikan rasa bangga atas terselenggaranya kegiatan positif yang menjadi wadah pengembangan diri generasi muda. Ia menekankan bahwa Bujang dan Gadis tidak hanya sekadar ajang penampilan, tapi juga bentuk pembinaan karakter dan wawasan.</div><div>Anak-anak muda Sungai Penuh harus tampil sebagai generasi yang berkarakter, kreatif, dan bisa membawa citra positif daerah kita. Jadilah duta muda yang mampu memperkenalkan pariwisata dan budaya Sungai Penuh ke luar daerah,” pesan Wako Alfin.</div><div>Ia juga berharap agar finalis Bujang dan Gadis mampu menjadi inspirasi bagi generasi muda lainnya untuk lebih mencintai budaya sendiri dan berperan aktif dalam kemajuan Kota Sungai Penuh.</div><div>Malam Grand Final ini menampilkan berbagai segmen menarik, mulai dari parade busana adat, sesi tanya jawab, hingga penampilan bakat dari masing-masing finalis. Setiap peserta menunjukkan keunggulan dan keunikan mereka, membuat suasana acara semakin semarak dan berkesan.</div><div>Sebagai puncak acara, Walikota Alfin bersama Ketua TP PKK Ny. Sri Kartini Alfin menyerahkan langsung penghargaan kepada para pemenang Bujang dan Gadis Kota Sungai Penuh Tahun 2025. Sorak gembira pun pecah saat nama pemenang diumumkan, menandai berakhirnya malam penuh kebanggaan bagi generasi muda Sungai Penuh.</div><div>Acara turut dihadiri oleh Ketua DPRD Kota Sungai Penuh Hutri Randa, S.Sos., M.M., Forkopimda, Sekda Alpian, Staf Ahli, Asisten, Kepala OPD, Ketua DWP, serta masyarakat yang memadati Gedung Nasional hingga larut malam.</div><div>Malam Grand Final Bujang Gadis 2025 tak sekadar mencari pemenang, tapi juga melahirkan sosok duta muda yang siap membawa nama baik Kota Sungai Penuh ke kancah yang lebih luas.</div><div>(MC DISKOMINFO)</div>','upload/berita/EAcKNCkqmMjszdq978knWN3RagujmAR2KupDpfCq.png','mediacenter','wako-alfin-bujang-gadis-harus-jadi-generasi-berkarakter-dan-kreatif','2025-11-12 10:59:30','2025-11-12 10:59:30'),(143,'Wako Alfin Dan Wawako Azhar Resmi Melepas Kafilah Kota Sungai Penuh Untuk MTQ Ke 54 Tingkat Provinsi Jambi','<div>Wako Alfin Dan Wawako Azhar Resmi Melepas Kafilah Kota Sungai Penuh Untuk MTQ Ke 54 Tingkat Provinsi Jambi</div><div>SUNGAI PENUH- Walikota Sungai Penuh Alfin, SH bersama Wawako Azhar Hamzah secara resmi melakukan pelepasan Kafilah Musabaqah Tilawatil Qur’an (MTQ) tingkat Provinsi Jambi.</div><div>Pelepasan dilaksanakan di Gedung Aula Kantor Walikota Sungai Penuh, turut hadir yakni, Sekretaris Daerah (Sekda) Alpian, Staf Ahli Walikota, Para Asisten Sekda, Kepala Perangkat Daerah, Pejabat Struktural dan Fungsional, Keta Gow Mawarti Azhar, Ketua Dharma Wanita Winda Alpian, Kafilah, Kepala Kantor Kementrian Agama Kota Sungai Penuh diwakili oleh Kasi Bimas Islam, Ketua LPTQ.</div><div>Pelepasan Kafilah Kota Sungai untuk MTQ Tingkat Provinsi Jambi di Kabupaten Muaro Jambi Tahun 2025 oleh Wako Alfin dan Wawako Azhar Hamzah menjadi momen berharga bagi Pemerintah Daerah Kota Sungai Penuh.</div><div>Termasuk, peserta, dan dukungan seluruh elemen yang terdiri dari, alim ulama, tokoh masyarakat dan lainya.</div><div>Dalam hal ini, Wako Alfin berharap agar kafilah yang terdiri dari qori dan qoriah, Hafidz, Hafidzah serta cabang lainya untuk tampil secara maksimal.&nbsp;</div><div>Tujuannya, agar dapat mencapai prestasi terbaik serta menunjukkan dedikasi demi Kota Sungai Penuh tercinta.</div><div>“Kita berharap agar para kafilah bisa mengukir prestasi terbaik. Untuk itu kepada para peserta agar menunjukkan dedikasi, motivasi termasuk mampu menghadapi tantangan demi mewujudkan prestasi di ajang MTQ tingkat Provinsi Jambi tahun 2025 di Kabupaten Muaro Jambi.\"ujarnya&nbsp;</div><div>\"Kemudian untuk para pelatih pendamping, official, saya mengucapkan terima kasih atas kerja kerasnya serta memberi semangat pada Kafilah Kota Sungai Penuh”tutupnya</div><div>(Mc Diskominfosta)</div>','upload/berita/UYl2JpzfvtErQ10LQrcLoWXEO9WmpqXASJeJoge9.png','mediacenter','wako-alfin-dan-wawako-azhar-resmi-melepas-kafilah-kota-sungai-penuh-untuk-mtq-ke-54-tingkat-provinsi-jambi','2025-11-26 14:43:27','2025-11-26 14:43:27'),(144,'Wako Alfin dan Wawako Azhar Tinjau Langsung Korban Kebakaran di Sungai Jernih','<div>Wako Alfin dan Wawako Azhar Tinjau Langsung Korban Kebakaran di Sungai Jernih</div><div>SUNGAI PENUH - Wali Kota Sungai Penuh, Alfin, SH bersama Wakil Wali Kota Azhar Hamzah, turun langsung meninjau lokasi kebakaran di Desa Sungai Jernih, Rabu (12/11/2025). Turut mendampingi dalam kunjungan tersebut jajaran dari Dinas Sosial, BPBD, serta Dinas Ketahanan Pangan Kota Sungai Penuh.</div><div>Dalam kesempatan itu, Wako Alfin menyampaikan rasa duka mendalam kepada keluarga korban yang terdampak kebakaran. Ia mengajak seluruh masyarakat untuk menjadikan peristiwa tersebut sebagai pengingat pentingnya kewaspadaan.</div><div>“Kita semua harus mengambil pelajaran dari musibah ini. Kebakaran adalah peristiwa berat yang sering kali tidak menyisakan apa pun. Semoga kejadian ini menjadi pengingat agar kita lebih berhati-hati ke depannya,” ujar Alfin.</div><div>Sebagai bentuk kepedulian, Pemerintah Kota Sungai Penuh menyalurkan berbagai bantuan bagi keluarga korban. Melalui Dinas Sosial, disalurkan perlengkapan dasar seperti selimut dan kebutuhan mendesak lainnya. Sementara Dinas Ketahanan Pangan memberikan bantuan beras untuk kebutuhan selama 30 hari bagi lima jiwa terdampak.</div><div>Selain itu, BPBD Kota Sungai Penuh juga turut menyalurkan bantuan bahan bangunan untuk membantu proses perbaikan rumah. Pemerintah mempersilakan pihak keluarga untuk berkoordinasi lebih lanjut dengan BPBD terkait kebutuhan tambahan sesuai kemampuan daerah.</div><div>“Pemerintah Kota Sungai Penuh hadir sepenuh hati. Kami tidak ingin ada warga yang merasa sendiri saat tertimpa musibah. Kehadiran kami di sini adalah bentuk kepedulian dan kebersamaan,” ungkap Alfin.</div><div>Ia menambahkan, meski nilai bantuan tidak besar, diharapkan dapat membantu meringankan beban keluarga korban dalam memenuhi kebutuhan sehari-hari.</div><div>Di akhir kunjungan, Wako Alfin juga menyampaikan apresiasi kepada masyarakat yang sigap melaporkan kejadian sehingga penanganan dapat dilakukan dengan cepat.</div><div>“Kami berterima kasih atas kepedulian dan kerja sama warga. Semoga keluarga Bapak Marbun tetap tabah dan sabar menghadapi ujian ini,” tutupnya.</div><div>(MC KOMINFO)</div>','upload/berita/27pF7nocUAbwbssMD5domnIglV6wYxllTml79iSO.png','mediacenter','wako-alfin-dan-wawako-azhar-tinjau-langsung-korban-kebakaran-di-sungai-jernih','2025-11-26 14:44:36','2025-11-26 14:44:36'),(145,'Wawako Azhar Ajak Tani Merdeka Jadi Mitra Strategis Pemerintah','<div>Wawako Azhar Ajak Tani Merdeka Jadi Mitra Strategis Pemerintah</div><div>SUNGAI PENUH - Wakil Wali Kota Sungai Penuh, Azhar Hamzah, menghadiri sekaligus memberikan sambutan pada acara pelantikan dan pengukuhan pengurus DPD Tani Merdeka Indonesia Kota Sungai Penuh dan Kabupaten Kerinci periode 2025–2030, yang berlangsung di Aula Kantor Wali Kota Sungai Penuh, Kamis (13/11/2025).</div><div>Kegiatan ini turut dihadiri oleh Wakil Bupati Kerinci, H. Murison, yang juga menjabat sebagai Dewan Pembina DPD Tani Merdeka Indonesia Kabupaten Kerinci, Sekretaris Daerah Kota Sungai Penuh, Alpian, serta Ketua DPW Tani Merdeka Indonesia Provinsi Jambi, Candra Andika, bersama jajaran pengurus, Dan Forkopimda.</div><div>Dalam sambutannya, Wawako Azhar menyampaikan ucapan selamat dan sukses kepada seluruh pengurus yang baru dilantik. Ia berharap amanah yang diberikan dapat dijalankan dengan penuh tanggung jawab, keikhlasan, serta semangat pengabdian demi kemajuan petani dan kesejahteraan masyarakat Sungai Penuh dan Kerinci.</div><div>“Pertanian adalah tulang punggung perekonomian masyarakat. Sebagian besar penduduk kita menggantungkan hidup dari sawah, ladang, perkebunan, hingga peternakan dan perikanan. Karena itu, organisasi seperti Tani Merdeka Indonesia memiliki peran strategis dalam memperkuat posisi petani serta memperjuangkan kesejahteraan yang berkeadilan,” ujarnya.</div><div>Wawako Azhar juga menyoroti tantangan besar sektor pertanian ke depan, seperti perubahan iklim, fluktuasi harga komoditas, keterbatasan lahan, dan kebutuhan modernisasi teknologi. Ia mendorong pengurus Tani Merdeka untuk menjadi pelopor dalam inovasi dan digitalisasi pertanian agar petani tidak tertinggal di era industri 4.0.</div><div>Selain itu, ia menekankan pentingnya kolaborasi lintas sektor antara pemerintah daerah, akademisi, dan pelaku usaha untuk memperluas akses pasar dan permodalan, sekaligus menumbuhkan semangat kemandirian di kalangan petani muda.</div><div>“Pemerintah Kota Sungai Penuh berkomitmen untuk terus memperkuat sektor pertanian melalui peningkatan infrastruktur irigasi, penyediaan bibit unggul, pelatihan pertanian modern, serta kemudahan akses pupuk dan alat pertanian. Kami ingin memastikan bahwa petani kita sejahtera, produktif, dan merdeka secara ekonomi,” tegasnya.</div><div>Di akhir sambutan, Wawako Azhar mengajak pengurus Tani Merdeka untuk menjadi mitra strategis pemerintah dalam membangun sektor pertanian.</div><div>“Jadilah mitra pemerintah yang bukan hanya mengkritik, tetapi juga memberi solusi. Mari kita wujudkan pertanian yang tangguh, berdaya saing, dan berkelanjutan demi kesejahteraan petani dan kemajuan daerah kita tercinta,” tutupnya.</div><div>(MC KOMINFO)</div>','upload/berita/FZeoNFF7Kb6RF2YOR7LOmGXadY7iIzsSkXfeQvf5.png','mediacenter','wawako-azhar-ajak-tani-merdeka-jadi-mitra-strategis-pemerintah','2025-11-26 14:45:44','2025-11-26 14:45:44'),(146,'Wawako Azhar Sampaikan RAPERDA APBD 2026 di Sidang Paripurna DPRD Sungai Penuh','<div>Wawako Azhar Sampaikan RAPERDA APBD 2026 di Sidang Paripurna DPRD Sungai Penuh</div><div>SUNGAI PENUH - Wakil Wali Kota Sungai Penuh, Azhar Hamzah, mewakili Wali Kota Alfin, SH, menghadiri Sidang Paripurna DPRD Kota Sungai Penuh dalam rangka penyampaian Rancangan Peraturan Daerah (RAPERDA) tentang APBD Tahun Anggaran 2026, Kamis (13/11/2025).</div><div>Sidang yang digelar di Gedung DPRD Kota Sungai Penuh tersebut dipimpin oleh Ketua DPRD Hutri Randa, S.Sos., MH, didampingi Wakil Ketua DPRD Hardizal, S.Sos., MH, dan Amrizal, <a href=\"https://l.facebook.com/l.php?u=http%3A%2F%2FS.Pt%2F%3Ffbclid%3DIwZXh0bgNhZW0CMTAAYnJpZBExS3paNExsN2VoaGxSS2VjUHNydGMGYXBwX2lkEDIyMjAzOTE3ODgyMDA4OTIAAR5jU-cEg3h7rMC1od-tco-q-__FOk9rN5iK2DcfDOl5l9uQ0LfMUwlxy5sMSg_aem_qaiRT6SduI9xCFr1bUqU4w&amp;h=AT28B6z7CkCRJ37JxM5aHT9Hnr2qu0Q5ulrFIK2dsYLPVMywf7Wuon_QU7SILz3kAcLmH7jwrK_QcHk9XaBcWhk_OCIccecmpqD70tXS6cOh07XKMO_isY2UgtWd-TyixFNEAgbNCRCjSv6cagAgbQ&amp;__tn__=-UK-R&amp;c[0]=AT3PUrtVSO_Hr2G0sW3jIQI3Ji4xdERJZlrc7KaUF40n1MHhb6a6ovfTwnZOlDQ5ygf6XelBu4Qdl6CJT6J1dNkaqRzuvqt0bRAHkBRaPscknhUDA6lyBXHH6rMvT3qS358ufPahaPsfsCNQ_vl2iqYzNp4MNC8ut85YLXxFQLl_Yjgt3lHgfm2i2dd48_uyFrdV6tZws66Yz6-3h3eEr7sEVQ\"><strong>S.Pt.</strong></a> Turut hadir Sekretaris Daerah Kota Sungai Penuh, Alpian, SE., MM., unsur Forkopimda, para Asisten, Kepala OPD, Camat, serta tamu undangan lainnya.</div><div>Dalam penyampaiannya, Wawako Azhar menegaskan bahwa penyusunan RAPERDA APBD 2026 berorientasi pada kepentingan masyarakat, dengan memastikan setiap program dan kegiatan yang direncanakan memberikan manfaat nyata serta mendukung pembangunan berkelanjutan di berbagai sektor.</div><div>“APBD ini dirancang agar setiap rupiah yang digunakan benar-benar mampu meningkatkan kualitas hidup masyarakat baik dalam pelayanan publik, pertumbuhan ekonomi, maupun pembangunan infrastruktur,” ujar Azhar.</div><div>Ia menambahkan, pertumbuhan ekonomi Kota Sungai Penuh terus menunjukkan tren positif dari tahun ke tahun, menjadi bukti komitmen pemerintah daerah dalam menjaga stabilitas dan mendorong kemajuan pembangunan.</div><div>Selain itu, Wawako Azhar juga memaparkan arah kebijakan pendapatan, belanja, dan pembiayaan daerah yang tertuang dalam RAPERDA APBD 2026. Ia berharap proses pembahasan bersama DPRD dapat berjalan lancar, tepat sasaran, dan transparan, sehingga hasil akhirnya benar-benar dapat dirasakan oleh masyarakat luas.</div><div>“Kami berharap APBD ini bukan sekadar angka di atas kertas, tetapi mampu memberi dampak nyata bagi kesejahteraan warga Kota Sungai Penuh,” tutupnya.</div><div>(MC KOMINFO)</div>','upload/berita/7nBL4sAhQ9B3xeX9Guniy1orQi78FvvwpdZIRSm1.png','mediacenter','wawako-azhar-sampaikan-raperda-apbd-2026-di-sidang-paripurna-dprd-sungai-penuh','2025-11-26 14:46:47','2025-11-26 14:46:47'),(147,'Wawako Azhar Hadiri Pembukaan MTQ ke-54 Provinsi Jambi','<div>Wawako Azhar Hadiri Pembukaan MTQ ke-54 Provinsi Jambi</div><div>MUARO JAMBI - Wakil Wali Kota Sungai Penuh, Azhar Hamzah, menghadiri pembukaan Musabaqah Tilawatil Qur’an (MTQ) ke-54 Tingkat Provinsi Jambi yang digelar di Komplek Perkantoran Bukit Cinto Kenang, Sengeti, Muaro Jambi. Sabtu 15/11/2025</div><div>Pelaksanaan MTQ tahun ini berlangsung selama delapan hari dan diikuti 1.235 peserta dari seluruh kabupaten/kota se-Provinsi Jambi, dengan berbagai cabang perlombaan yang dipertandingkan.</div><div>Pembukaan MTQ ditandai dengan pemukulan beduk secara simbolis oleh Gubernur dan Wakil Gubernur Jambi, sebagai tanda dimulainya seluruh rangkaian perlombaan.</div><div>Dalam kesempatan tersebut, Wawako Azhar Hamzah menyampaikan dukungan penuh kepada kafilah Kota Sungai Penuh yang akan bertanding pada MTQ tingkat provinsi tahun ini. Ia menegaskan bahwa para peserta bukan sekadar perwakilan daerah, tetapi juga pembawa nilai-nilai Al-Qur’an.</div><div>“Kafilah Kota Sungai Penuh adalah duta-duta Al-Qur’an. Saya berharap kalian bisa menunjukkan yang terbaik dan membawa nama baik kota kita,” ujar Azhar.</div><div>Wawako menambahkan bahwa dirinya bersama Wali Kota Sungai Penuh, Alfin, akan terus memberikan dorongan dan motivasi kepada seluruh peserta agar tampil maksimal dan meraih prestasi terbaik pada ajang keagamaan bergengsi ini.(MC KOMINFO)</div>','upload/berita/AI1r8bBFhwD0M3UIxOwA2W1gpkOQkhOqmXiQPEtv.png','mediacenter','wawako-azhar-hadiri-pembukaan-mtq-ke-54-provinsi-jambi','2025-11-26 14:47:55','2025-11-26 14:47:55'),(148,'Diskominfosta Kota Sungai Penuh Kembali Mengadakan Giat Kegiatan 3 S','<div>Diskominfosta Kota Sungai Penuh Kembali Mengadakan Giat Kegiatan 3 S</div><div>SUNGAI PENUH- Dalam upaya mencegah terjadinya peningkatan angka Stunting serta mendukung penanganannya.&nbsp;</div><div>Dinas Komunikasi, Informasi dan Statistik Kota Sungai Penuh kembali mengadakan kegiatan 3 S ( Segenggam Beras, Sebutir Telur, Seribu Rupiah). 19/11/2025</div><div>Kegiatan ini dilaksanakan di halaman kantor Diskominfo Kota Sungai Penuh. Turut serta yakni, Kepala Dinas Diskominfosta H. Josrizal Helman <a href=\"https://l.facebook.com/l.php?u=http%3A%2F%2FS.Si%2F%3Ffbclid%3DIwZXh0bgNhZW0CMTAAYnJpZBExS3paNExsN2VoaGxSS2VjUHNydGMGYXBwX2lkEDIyMjAzOTE3ODgyMDA4OTIAAR4lHgzVKZJMWBlkJC4at0rhW_ISexYkv869vIHMZO8_-hKIsiLECLNVx_Yvww_aem_4uYmxAO0QBgJtf1yP0N3GA&amp;h=AT2w15SfvPCG8qzfqCMrVMC777dy9fSNfC643SM9vqBj1JXH8AjF8OXwtrqdSaOZIM3vcRyUs60-cgxiibjl135MHqRHfeZQkzCf_nleGcvlpEkJ2Hm8F10EydUry7UyCbvCtDOCdDERlSku6SqUhg&amp;__tn__=-UK-R&amp;c[0]=AT2Rs6sHwQnN-NSdBL5E0St_DJ4sg_c59wft1z1dGG1gQjr8oK6IaE-KDxsLObFGfolN-yRDN14yhJRs68zXvNjVilh-Qjz_3tx2jy5eKcrz0aY_vkTsdqBbqhuNHwDswOEwIafXIxu9_Mvbp7W3uq9RJ217eGmWr85OyesFyGoajVtw90mys4FMsMxJgYOvGMYZNUO4xDqE0MFHK5ZVKlvS_g\"><strong>S.Si</strong></a>, Apt, Sekretaris Dedi Karyadi, Kepala Bidang, Kasi, Kasubbag, Staf PNS dan Non PNS.</div><div>Kadis Diskominfosta Kota Sungai Penuh H. Josrizal Helman <a href=\"https://l.facebook.com/l.php?u=http%3A%2F%2FS.Si%2F%3Ffbclid%3DIwZXh0bgNhZW0CMTAAYnJpZBExS3paNExsN2VoaGxSS2VjUHNydGMGYXBwX2lkEDIyMjAzOTE3ODgyMDA4OTIAAR4B4bdeG1rM895eIbFmfxprxDzSze6cVHTVQVmI-pXr5pIXMI-WQgQGmLT4vg_aem_WChrVG15GSCh_6vfCWSk8A&amp;h=AT2w15SfvPCG8qzfqCMrVMC777dy9fSNfC643SM9vqBj1JXH8AjF8OXwtrqdSaOZIM3vcRyUs60-cgxiibjl135MHqRHfeZQkzCf_nleGcvlpEkJ2Hm8F10EydUry7UyCbvCtDOCdDERlSku6SqUhg&amp;__tn__=-UK-R&amp;c[0]=AT2Rs6sHwQnN-NSdBL5E0St_DJ4sg_c59wft1z1dGG1gQjr8oK6IaE-KDxsLObFGfolN-yRDN14yhJRs68zXvNjVilh-Qjz_3tx2jy5eKcrz0aY_vkTsdqBbqhuNHwDswOEwIafXIxu9_Mvbp7W3uq9RJ217eGmWr85OyesFyGoajVtw90mys4FMsMxJgYOvGMYZNUO4xDqE0MFHK5ZVKlvS_g\"><strong>S.Si</strong></a>, Apt mengatakan, giat ini bentuk kepedulian dalam mendukung program penanganan stunting.&nbsp;</div><div>Dalam hal ini, gerakan berbagi melalui 3 S sangat diapresiasi sebagaimana program Pemerintah Daerah Kota Sungai Penuh.</div><div>“Kita sangat mengapresiasi adanya program 3 S dalam upaya melakukan penanganan terhadap Stunting. Harapannya dapat bermanfaat nantinya” [ ]</div><div>(MC Diskominfosta)</div>','upload/berita/Ol6r4Qq92RVX3rstrZb1HA1JsSp7LvInnhqbbMp7.png','mediacenter','diskominfosta-kota-sungai-penuh-kembali-mengadakan-giat-kegiatan-3-s','2025-11-26 14:49:10','2025-11-26 14:49:10'),(149,'Diwakili Suhatril, Wako Alfin Terima Lencana Pramuka Perintis Utama','<div>Diwakili Suhatril, Wako Alfin Terima Lencana Pramuka Perintis Utama</div><div>TANJABTIM - Walikota Sungai Penuh, Alfin, SH selaku Kamabicab Gerakan Pramuka Kota Sungai Penuh bersama seluruh bupati dan wali kota se-Provinsi Jambi menerima penghargaan Lencana Tokoh Pramuka Perintis Utama dari Gubernur Jambi selaku Ketua Majelis Pembimbing Daerah Gerakan Pramuka Jambi.</div><div>Penghargaan ini diberikan sebagai bentuk apresiasi atas komitmen Wako Alfin dalam memajukan Gerakan Pramuka, khususnya dalam pembinaan generasi muda Jambi yang berkarakter SIMPATIK Santun, Beriman, Mandiri, Peduli, Berakhlak, Terampil, Berintegritas, dan Berkualitas.</div><div>Penerimaan piagam dan lencana untuk Walikota Sungai Penuh diwakili oleh Kak Suhatril, Staf Ahli Walikota sekaligus Pimpinan Mabicab Gerakan Pramuka Kwarcab Kota Sungai Penuh. Pada kesempatan yang sama, Kak Suhatril juga menerima Lencana Melati dari Kwartir Nasional Gerakan Pramuka yang disematkan langsung oleh Kakak Kwarnas, Komjen Pol (Purn) Budi Waseso.</div><div>Rangkaian penganugerahan ini digelar pada puncak peringatan Hari Pramuka ke-64 Tahun 2025 di Sabak, Kabupaten Tanjung Jabung Timur, pada 19 November 2025. Turut hadir mendampingi utusan Kota Sungai Penuh dalam Apel Besar Hari Pramuka tingkat Kwarda Jambi, yakni Kak Khaidirman selaku Ketua Kwarcab Sungai Penuh dan Kak Wazirman, Andalan Daerah Kwarda Jambi sekaligus Kapusdiklatcab Pramuka Kwarcab Sungai Penuh.&nbsp;<br>(MC KOMINFO)</div>','upload/berita/WIyMF9KKkl3s5wEseEMX85z9L2k7PqOtmOnvlJDJ.png','mediacenter','diwakili-suhatril-wako-alfin-terima-lencana-pramuka-perintis-utama','2025-11-26 14:50:42','2025-11-26 14:50:42'),(150,'Wako Alfin Hadiri Rakornas Kepegawaian BKN 2025','<div>Wako Alfin Hadiri Rakornas Kepegawaian BKN 2025</div><div>SUNGAI PENUH - Walikota Sungai Penuh, Alfin, SH turut menghadiri Rapat Koordinasi Nasional (Rakornas) Kepegawaian Badan Kepegawaian Negara (BKN) Tahun 2025 yang berlangsung di Hotel Pullman Jakarta Central Park, Podomoro City, Rabu (19/11).</div><div>Rakornas tahun ini mengangkat tema “ASN Bergerak Bersama Mewujudkan Asta Cita”, yang menegaskan pentingnya kolaborasi seluruh aparatur sipil negara dalam memperkuat profesionalitas, tata kelola, dan kualitas pelayanan publik di era transformasi digital.</div><div>Acara dibuka langsung oleh Kepala BKN, Prof. Dr. Zudan Arif Fakrulloh, SH., M.H. Dalam arahannya, Zudan menekankan bahwa ASN harus terus beradaptasi dengan perubahan zaman dan dinamika pelayanan publik yang semakin cepat dan komplek.</div><div>Wako Alfin mengapresiasi materi dan arahan yang disampaikan dalam Rakornas tersebut.</div><div>“Kami mendukung penuh penguatan manajemen ASN yang berintegritas, profesional, dan berorientasi pelayanan. Rakornas ini memberi banyak arahan strategis untuk kami terapkan di daerah,” ujarnya usai kegiatan.</div><div>Rakornas Kepegawaian BKN 2025 diikuti oleh kepala daerah, pimpinan instansi pemerintah, serta pejabat kepegawaian dari berbagai provinsi, kabupaten, dan kota. Forum ini diharapkan menjadi momentum penting untuk menyelaraskan kebijakan pengelolaan ASN guna mewujudkan pemerintahan yang semakin efektif dan berdaya saing.(MC KOMINFO)</div>','upload/berita/RLHYI1VtguYwyeRnWX2qnXvZNorCYgpPuMqlmiNV.png','mediacenter','wako-alfin-hadiri-rakornas-kepegawaian-bkn-2025','2025-11-26 14:51:42','2025-11-26 14:51:42'),(151,'Wako Alfin Tinjau Pemondokan Kafilah dan Beri Semangat di MTQ Provinsi Jambi','<div>Wako Alfin Tinjau Pemondokan Kafilah dan Beri Semangat di MTQ Provinsi Jambi</div><div>MUARO JAMBI – Walikota Sungai Penuh, Alfin, SH, bersama Ketua TP PKK Kota Sungai Penuh, Ny. Sri Kartini Alfin, S.Kep, NS, meninjau pemondokan kafilah Kota Sungai Penuh yang tengah berpartisipasi dalam MTQ ke-54 Tingkat Provinsi Jambi di Muaro Jambi, Rabu (19/11).</div><div>Kunjungan tersebut bertujuan untuk memastikan kondisi peserta tetap nyaman dan siap menghadapi perlombaan. Wako Alfin tampak berinteraksi langsung dengan para peserta, pelatih, dan pendamping, memberikan motivasi serta semangat agar seluruh kafilah tampil maksimal.</div><div>Selain memantau pemondokan, Wako Alfin juga menyaksikan babak final tilawah golongan dewasa, di mana salah satu peserta Kota Sungai Penuh berhasil masuk final. Secara keseluruhan, sebanyak 16 peserta dari berbagai cabang lomba berhasil menembus babak final, menjadi bukti kerja keras dan dedikasi kafilah Kota Sungai Penuh.</div><div>Dalam kesempatan itu, Wako Alfin menyampaikan apresiasi kepada seluruh peserta dan tim pendamping:</div><div>Saya bangga dengan perjuangan kalian. Tetap kompak, rendah hati, dan tampilkan yang terbaik. Hasil yang baik pasti mengikuti usaha yang sungguh-sungguh,” ujarnya.</div><div>Ia berharap seluruh peserta tetap fokus menjelang penilaian akhir dan mampu membawa nama baik Kota Sungai Penuh di ajang tingkat provinsi. Kunjungan ini juga menjadi dorongan semangat tambahan bagi para peserta yang sedang bertanding di cabang lain.</div><div>Pemerintah Kota Sungai Penuh menegaskan komitmennya untuk terus mendukung pembinaan keagamaan, menumbuhkan generasi Qur’ani yang berprestasi, dan meningkatkan kualitas para peserta MTQ di setiap jenjang.</div><div>(MC DISKOMINFO)</div>','upload/berita/UASdfW9ePCPn2DoiAMA2BAdt6V2Q1eB2EaPo1mkm.png','mediacenter','wako-alfin-tinjau-pemondokan-kafilah-dan-beri-semangat-di-mtq-provinsi-jambi','2025-11-26 14:52:40','2025-11-26 14:52:40'),(152,'Walikota Alfin Apresiasi Prestasi Kota Sungai Penuh di MTQ Jambi ke-54','<div>Walikota Alfin Apresiasi Prestasi Kota Sungai Penuh di MTQ Jambi ke-54</div><div>Muaro Jambi – Kota Sungai Penuh meraih prestasi membanggakan di Musabaqah Tilawatil Qur’an (MTQ) Tingkat Provinsi Jambi ke-54, yang berlangsung di Kabupaten Muaro Jambi. Penutupan resmi digelar Jumat malam (21/11/2025) oleh Wakil Gubernur Jambi, Drs. H. Abdullah Sani., M.Pd, di Bumi Sahalun Salimbah.</div><div>Kota Sungai Penuh berhasil menempati peringkat ke-4 dengan total 187 poin, naik dibanding tahun sebelumnya. Walikota Sungai Penuh, Alfin, SH, hadir bersama Wakil Walikota Azhar Hamzah untuk menyaksikan langsung pengumuman juara.</div><div>Walikota Alfin menyampaikan apresiasi tinggi kepada seluruh qori dan qoriah Kota Sungai Penuh.</div><div>“Prestasi ini menjadi awal untuk terus membina generasi Qur’ani di Kota Sungai Penuh,” ujarnya.</div><div>Beberapa prestasi individu Kota Sungai Penuh antara lain:</div><div>Dede Putra – Terbaik I Cabang Tilawah Golongan Dewasa Qori.</div><div>Jusmiarti – Terbaik I Cabang Tilawah Golongan Cacat Netra Qori’ah.</div><div>M. Dapiq Assidik – Terbaik I Cabang Hifzh Al-Qur’an Golongan 1 Juz dan Tilawah Hafizh.</div><div>Nayla Aupa Dania – Terbaik I Cabang Hifzh Al-Qur’an Golongan 1 Juz dan Tilawah Hafizhah.</div><div>Suasana haru menyelimuti saat pengumuman juara umum, yang menegaskan peningkatan kualitas pembinaan dan kemampuan para kafilah Kota Sungai Penuh.</div><div>Walikota Alfin menegaskan, keberhasilan ini menjadi motivasi untuk evaluasi dan pembenahan menyeluruh, termasuk pembinaan qori-qoriah dan sistem seleksi, agar Kota Sungai Penuh dapat meraih prestasi lebih tinggi di MTQ berikutnya.</div><div>Acara penutupan dihadiri unsur Forkopimda Provinsi Jambi, Kepala Kementerian Agama Provinsi Jambi, para Walikota/Bupati se-Provinsi Jambi, Sekretaris Daerah, Kepala OPD, dan tamu undangan lainnya.</div><div>“Ke depan, pembinaan qori dan qoriah akan lebih intensif agar Kota Sungai Penuh mampu bersaing hingga tingkat nasional,” tambah Alfin. (Mc.Kominfo)</div>','upload/berita/B3ge4SiT8L9cZw2p1wSRuVJk2vzoblP1JujdJf9n.png','mediacenter','walikota-alfin-apresiasi-prestasi-kota-sungai-penuh-di-mtq-jambi-ke-54','2025-11-26 14:53:52','2025-11-26 14:53:52'),(153,'Wawako Azhar Hadiri High Level Meeting TPID Jambi','<div>Wawako Azhar Hadiri High Level Meeting TPID Jambi</div><div>JAMBI - Wakil Walikota Sungai Penuh, Azhar Hamzah, hadir dalam agenda High Level Meeting TPID Provinsi Jambi yang berlangsung di Swiss-Belhotel Jambi, Senin (24/11/2025). Pertemuan ini digelar sebagai langkah antisipasi menghadapi potensi kenaikan harga kebutuhan pokok menjelang Natal 2025 dan Tahun Baru 2026.</div><div>Kegiatan tersebut mengusung tema Sinergis TPID Se-Provinsi Jambi dalam Menjaga Stabilitas Pasokan dan Harga Pangan Strategis Menjelang Natal 2025 dan Tahun Baru 2026.” Melalui forum ini, pemerintah provinsi bersama kabupaten/kota membahas langkah-langkah konkret dalam menjaga stabilitas harga pangan di seluruh wilayah Jambi.</div><div>Beberapa poin strategis turut menjadi fokus, mulai dari penguatan jalur distribusi, mekanisme kontrol harga, hingga sistem pemantauan stok kebutuhan pokok. Tujuannya, agar masyarakat tetap dapat memenuhi kebutuhan pangan dengan harga terjangkau, terutama pada periode kenaikan permintaan.</div><div>Wawako Azhar menegaskan bahwa Pemerintah Kota Sungai Penuh siap berkolaborasi dan mendukung kebijakan pengendalian inflasi yang dirumuskan bersama TPID Provinsi Jambi.</div><div>Kolaborasi antar daerah sangat penting agar pasokan pangan tetap stabil dan harga tidak melonjak. Pemerintah Kota Sungai Penuh berkomitmen mendukung upaya pengendalian inflasi melalui langkah dan koordinasi bersama,” ujar Azhar.</div><div>Ia juga menambahkan bahwa pemerintah daerah terus memaksimalkan pemantauan lapangan, terutama pada komoditas rawan fluktuasi seperti beras, cabai, gula, dan minyak goreng.</div><div>Melalui pertemuan ini, TPID Provinsi Jambi berharap seluruh daerah dapat bergerak sejalan dalam menjaga stabilitas ekonomi regional, sehingga masyarakat tetap aman dan nyaman menghadapi periode hari besar keagamaan serta pergantian tahun.</div><div>(MC DISKOMINFO)</div><div>JAMBI - Wakil Walikota Sungai Penuh, Azhar Hamzah, hadir dalam agenda High Level Meeting TPID Provinsi Jambi yang berlangsung di Swiss-Belhotel Jambi, Senin (24/11/2025). Pertemuan ini digelar sebagai langkah antisipasi menghadapi potensi kenaikan harga kebutuhan pokok menjelang Natal 2025 dan Tahun Baru 2026.</div><div>Kegiatan tersebut mengusung tema Sinergis TPID Se-Provinsi Jambi dalam Menjaga Stabilitas Pasokan dan Harga Pangan Strategis Menjelang Natal 2025 dan Tahun Baru 2026.” Melalui forum ini, pemerintah provinsi bersama kabupaten/kota membahas langkah-langkah konkret dalam menjaga stabilitas harga pangan di seluruh wilayah Jambi.</div><div>Beberapa poin strategis turut menjadi fokus, mulai dari penguatan jalur distribusi, mekanisme kontrol harga, hingga sistem pemantauan stok kebutuhan pokok. Tujuannya, agar masyarakat tetap dapat memenuhi kebutuhan pangan dengan harga terjangkau, terutama pada periode kenaikan permintaan.</div><div>Wawako Azhar menegaskan bahwa Pemerintah Kota Sungai Penuh siap berkolaborasi dan mendukung kebijakan pengendalian inflasi yang dirumuskan bersama TPID Provinsi Jambi.</div><div>Kolaborasi antar daerah sangat penting agar pasokan pangan tetap stabil dan harga tidak melonjak. Pemerintah Kota Sungai Penuh berkomitmen mendukung upaya pengendalian inflasi melalui langkah dan koordinasi bersama,” ujar Azhar.</div><div>Ia juga menambahkan bahwa pemerintah daerah terus memaksimalkan pemantauan lapangan, terutama pada komoditas rawan fluktuasi seperti beras, cabai, gula, dan minyak goreng.</div><div>Melalui pertemuan ini, TPID Provinsi Jambi berharap seluruh daerah dapat bergerak sejalan dalam menjaga stabilitas ekonomi regional, sehingga masyarakat tetap aman dan nyaman menghadapi periode hari besar keagamaan serta pergantian tahun.</div><div>(MC DISKOMINFO)</div>','upload/berita/0wyu851xEuxplvkdP3wOQxTvflLEmk0rNz4JfvMb.png','mediacenter','wawako-azhar-hadiri-high-level-meeting-tpid-jambi','2025-11-26 14:54:54','2025-11-26 14:54:54'),(154,'Selamat Hari Guru.','<div>Selamat Hari Guru. Terima kasih atas jasa yang tak pernah bisa terbalaskan oleh kata-kata.</div>','upload/berita/bjM6fLJqp8CoDxCL9Kn4hhU4zLqvS6R0gJowcVHv.png','mediacenter','selamat-hari-guru','2025-11-26 14:56:05','2025-11-26 14:56:05'),(155,'Wawako Azhar Hamzah Pimpin Peringatan HKN ke-61, Ajak Masyarakat Dukung Layanan Kesehatan Berkualitas','<div>Wawako Azhar Hamzah Pimpin Peringatan HKN ke-61, Ajak Masyarakat Dukung Layanan Kesehatan Berkualitas</div><div>SUNGAI PENUH – Suasana penuh semangat terlihat di halaman Kantor Walikota Sungai Penuh, Selasa (25/11/2025), saat Wakil Wali Kota, Azhar Hamzah, memimpin Upacara Peringatan Hari Kesehatan Nasional (HKN) ke-61. Acara ini menjadi momen penting bagi pemerintah dan masyarakat untuk memperkuat komitmen meningkatkan kesehatan publik.</div><div>Upacara dihadiri berbagai unsur penting, termasuk Wakil Ketua DPRD Emrizal <a href=\"https://l.facebook.com/l.php?u=http%3A%2F%2FS.Pt%2F%3Ffbclid%3DIwZXh0bgNhZW0CMTAAYnJpZBExS3paNExsN2VoaGxSS2VjUHNydGMGYXBwX2lkEDIyMjAzOTE3ODgyMDA4OTIAAR5xluF5fDRrXh69mS4xUWRAbB6DX8Vr0UcWGGUPV1ow9bDsg-YA4nrgWnBtUQ_aem_9SrGVMhPFyYJxQh625QU1Q&amp;h=AT3Z03_XJaD3FOoRG7Nm9QQ_4CS0L_Iqfov1vP65H3zuJv7N-NJ8763-Zg8HgFbCNHWemZ4UXABqfQ2A42oYtv19DN3-7bIbMia9beDv4hIEDzULzKgCuUg75oGzLAOAV6cwzpI-AtknVAXAwZnf4A&amp;__tn__=-UK-R&amp;c[0]=AT1oRfgP7G2cinQKUJQCgeQDpBtzSx-qCgbQeNFtd7NmD40tVBB1fMYqgesScNaz_rRkI9fRxcv9nEnJxHwYqGVdO6zfCriB5xqZgqlLIhjGVVx4Esv4pqy3DR3itibyNOtm8AwSCjx1E4dXZSt30NMcJ114Htvl6FXjGf4liMwrYYmITx52KrLjFasbvL8\"><strong>S.Pt</strong></a>, Forkopimda, Kepala Dinas Kesehatan Provinsi Jambi, Dr. dr. Ike Silviana <a href=\"https://l.facebook.com/l.php?u=http%3A%2F%2FM.KM%2F%3Ffbclid%3DIwZXh0bgNhZW0CMTAAYnJpZBExS3paNExsN2VoaGxSS2VjUHNydGMGYXBwX2lkEDIyMjAzOTE3ODgyMDA4OTIAAR7xJVv7LWhL0TvHlq50kVFYcYRKSlGOF9VlJDESh2sCPUzodlzwHIP_ST-wJA_aem_-DVijRusl0ImS29Uf45WXA&amp;h=AT3lkUpp6jZeaIfn0lCiY_QrpwQINNS4Ws_U-WP71KkLA4zp232tLV6wkOP75emfcTMQFfyErtxOKRubhyj2drxLCK8b8DPE3bjmnX8KNvQFwU54a-AF9gK7vXCB0qKr8DRuLkTJUctF3mofAPyIfg&amp;__tn__=-UK-R&amp;c[0]=AT1oRfgP7G2cinQKUJQCgeQDpBtzSx-qCgbQeNFtd7NmD40tVBB1fMYqgesScNaz_rRkI9fRxcv9nEnJxHwYqGVdO6zfCriB5xqZgqlLIhjGVVx4Esv4pqy3DR3itibyNOtm8AwSCjx1E4dXZSt30NMcJ114Htvl6FXjGf4liMwrYYmITx52KrLjFasbvL8\"><strong>M.KM</strong></a>, serta tenaga kesehatan, pengurus IDI, pimpinan rumah sakit, dan klinik se-Kota Sungai Penuh.</div><div>Dalam sambutannya, Wawako Azhar membacakan pesan Menteri Kesehatan RI, Budi Gunadi Sadikin, yang menekankan transformasi layanan kesehatan nasional. Menurut Menteri, layanan kesehatan harus mudah diakses, berkualitas tinggi, dan terjangkau bagi semua lapisan masyarakat.</div><div>Mengangkat tema “Generasi Sehat, Masa Depan Hebat”, HKN ke-61 ini menekankan pentingnya membentuk generasi muda yang sehat secara fisik, mental, dan sosial. “Generasi sehat adalah modal utama untuk masa depan Indonesia yang lebih maju,” ujar Azhar Hamzah.</div><div>Selain upacara, kegiatan HKN juga diwarnai pemotongan tumpeng dan pelepasan balon, sebagai simbol harapan baru bagi masyarakat yang lebih sehat dan sejahtera. Para peserta lomba HKN juga mendapatkan penghargaan langsung dari Wawako Azhar.</div><div>Wawako Azhar berharap peringatan ini bisa mendorong partisipasi masyarakat dalam program-program kesehatan, sekaligus menginspirasi tenaga kesehatan untuk terus berinovasi dan memberikan layanan terbaik bagi warga.</div><div>(MC DISKOMINFO)</div>','upload/berita/LSSiZPGMXwFEQ0xt94Wb0ZP1zi8zw6fYaQ4dqNzY.png','mediacenter','wawako-azhar-hamzah-pimpin-peringatan-hkn-ke-61-ajak-masyarakat-dukung-layanan-kesehatan-berkualitas','2025-11-26 14:57:08','2025-11-26 14:57:08'),(156,'Wako Alfin Koordinasi ke Kemendagri, Perjuangkan Peningkatan Dana Transfer','<div>Wako Alfin Koordinasi ke Kemendagri, Perjuangkan Peningkatan Dana Transfer</div><div>SUNGAI PENUH - Wali Kota Sungai Penuh, Alfin, SH melakukan koordinasi langsung dengan Direktorat Jenderal Bina Keuangan Daerah Kementerian Dalam Negeri pada Senin (25/11/2025). Dalam kunjungan tersebut, Wako Alfin didampingi Sekretaris Daerah Kota Sungai Penuh, Alpian.</div><div>Pertemuan ini bertujuan memperjuangkan dukungan pemerintah pusat terkait pembangunan Kota Sungai Penuh, khususnya mengenai peningkatan Dana Transfer Daerah untuk Tahun Anggaran 2026/2027.</div><div>Kedatangan Wako Alfin dan Sekda disambut hangat oleh Dirjen Bina Keuangan Daerah Kemendagri, Dr. Drs. Agus Fatoni, <a href=\"https://l.facebook.com/l.php?u=http%3A%2F%2FM.Si%2F%3Ffbclid%3DIwZXh0bgNhZW0CMTAAYnJpZBExS3paNExsN2VoaGxSS2VjUHNydGMGYXBwX2lkEDIyMjAzOTE3ODgyMDA4OTIAAR69Jd-wvsqOG5rGXTT-2G7sjCWB_oGo1zmqog8FsX_-NDuffcaZ4_mZVQbXAg_aem_3QqB-Y5jToj6xxk9Nxul2w&amp;h=AT0GuCDG3T9ImA5qLtH2jWDhMBohMEuLQo5m3sd2CSFuyrKd6VzctdkEmyB7TfGlP6B1OmZiLH_KgEUEfZqUP3S_k9aK-4odP9qD_nWwn1HRFd3XSvMxbu3QrJL5cKmgGp5BY4sxX_xFDWYMWRiiAQ&amp;__tn__=-UK-R&amp;c[0]=AT3YgMM2PxAV-g7wUIfPTOgRC1LdpAgFuPH5F13tjGPpei5rgfP0yZ-REmuKxICe_O5H3ntrXim8TdoY15dGuhOxPqoH7GlbUxMVfWTXOAcBjtMFVmrPvm14YTYqIbKpkD4Pok1NMSXpDxtDZflKpIwqhbq7hjmwI_XMfIXiT--KvU3HDHYMka0ef_iYDgb8llTMNmm92UpNB1UE1TERrRJ_fQ\"><strong>M.Si</strong></a>, bersama Direktur Fasilitasi Transfer dan Pembiayaan Utang Daerah, Nasrun, SH, serta Kasubdit Fasilitasi Dana Bagi Hasil dan DAU, Azwirman.</div><div>Dalam pertemuan tersebut, Wako Alfin menegaskan bahwa efisiensi anggaran yang tengah dihadapi daerah membutuhkan respons cepat dan langkah strategis agar pelayanan publik tetap optimal.</div><div>“Kami mengajukan penyesuaian dan penguatan dana transfer untuk menjaga stabilitas keuangan daerah. Efisiensi anggaran cukup berdampak pada beberapa sektor prioritas, sehingga perlu perhatian dari pemerintah pusat,” ujar Wako Alfin.</div><div>Dirjen Bina Keuangan Daerah, Agus Fatoni, menyambut baik upaya Pemerintah Kota Sungai Penuh. Ia memberikan arahan agar setiap pengajuan kebutuhan daerah dilengkapi data pendukung yang komprehensif, termasuk proyeksi fiskal, beban belanja wajib, dan rencana strategis pembangunan.</div><div>Kemendagri memastikan akan menindaklanjuti hasil koordinasi ini dalam pembahasan dana transfer untuk tahun anggaran mendatang.(MC KOMINFO)</div>','upload/berita/d2kLGVx1C7kdR2t8GW8KFUKJpL4QXGkBd3tFjmjU.png','mediacenter','wako-alfin-koordinasi-ke-kemendagri-perjuangkan-peningkatan-dana-transfer','2025-11-26 15:22:10','2025-11-26 15:22:10'),(157,'Workshop PWS dan Perhutanan Sosial Resmi Dibuka Wawako Azhar Hamzah','<div>Workshop PWS dan Perhutanan Sosial Resmi Dibuka Wawako Azhar Hamzah</div><div>SUNGAI PENUH – Pemerintah Kota Sungai Penuh membuka Workshop Penguatan Kapasitas Multi Pihak untuk Pengembangan Skema Payment Water Service (PWS) dan Perhutanan Sosial dalam mendukung penerapan Ekonomi Hijau Klaster III Koridor Ekosistem RIMBA. Kegiatan berlangsung di Aula Hotel Grand Kerinci dan dibuka langsung oleh Wakil Walikota Sungai Penuh, Azhar Hamzah, Rabu (26/11/25).</div><div>Program PWS diperkenalkan sebagai instrumen insentif ekonomi bagi pihak yang menjaga kawasan resapan air, sungai, dan hutan. Skema perhutanan sosial bertujuan meningkatkan kesejahteraan masyarakat melalui akses kelola kawasan hutan secara legal dan berkelanjutan.</div><div>Dalam sambutan pembukaan, Wawako Azhar menekankan pentingnya kolaborasi seluruh unsur untuk menjaga kelestarian lingkungan.</div><div>“Melalui skema PWS dan perhutanan sosial, kita ingin memastikan perlindungan hutan dan sumber air tetap memberi manfaat ekonomi bagi masyarakat, sekaligus menjaga kelestarian lingkungan untuk generasi mendatang,” kata Azhar.</div><div>Ia menegaskan komitmen Pemkot Sungai Penuh terhadap penguatan tata kelola lingkungan berbasis ekonomi hijau.</div><div>“Pemkot Sungai Penuh berkomitmen memperkuat tata kelola lingkungan yang inklusif, berkeadilan, dan berkelanjutan. Kolaborasi multi pihak menjadi kunci menjaga ekosistem RIMBA,” tegasnya.</div><div>Workshop ini menghadirkan sejumlah pemangku kepentingan dari berbagai daerah dan lembaga. Hadir di antaranya Direktur Perencanaan Tata Ruang Kementerian ATR/BPN yang diwakili Kasubdit Perencanaan KSN II, Aji Raditio, S.T. <a href=\"https://l.facebook.com/l.php?u=http%3A%2F%2FM.Sc%2F%3Ffbclid%3DIwZXh0bgNhZW0CMTAAYnJpZBExS3paNExsN2VoaGxSS2VjUHNydGMGYXBwX2lkEDIyMjAzOTE3ODgyMDA4OTIAAR69Jd-wvsqOG5rGXTT-2G7sjCWB_oGo1zmqog8FsX_-NDuffcaZ4_mZVQbXAg_aem_3QqB-Y5jToj6xxk9Nxul2w&amp;h=AT3XtMPcMLmIEZQd0WiduLsHLziYISurS0u-bFXJuAK8Fx4OzXq13gFFwyXndQ9knkqIJLdS6uurcARsdsMs0qdO5J0oL3JiBjcehC722NBe328uK4MRDB8TGWt4nBuqyII8Mlr6jO1i0uijUOUiSw&amp;__tn__=-UK-R&amp;c[0]=AT2WWiocVsjrN9jAGz-WEGeZNEOIcSmiCQd_VyuV9bQ1diNKcLPHNbvFBxy8-OlPr1gSgzZ8tN8joAre8ezriMuuhDGYQ7Cy7938EpwqZWTSDAuj-WCLLAXONjS4FGYQ5uFOM-UkqYRPgAjPL93RN_lTuA6fj_xQfoBWKjgzS0n-tbmon76369QyENh8d-JQ-pdoahdWeS10oQB3AqRta-x_kw\"><strong>M.Sc.</strong></a>, Direktur WRI Indonesia Tomi Haryadi, perwakilan Bappeda Provinsi Jambi, Kepala Bappeda Kabupaten Kerinci, serta Kepala Bappeda Kabupaten Merangin secara daring. Selain itu, Kepala Balai TNKS, Kepala Dinas LH, Kepala KPHP Kerinci, Kepala KPHP Merangin, dan seluruh peserta workshop turut mengikuti jalannya kegiatan. (MC. KOMINFO)</div>','upload/berita/rgWUJtgNlpKAyB0OIau86u7P0rTF71fZ3n3s9mjS.png','mediacenter','workshop-pws-dan-perhutanan-sosial-resmi-dibuka-wawako-azhar-hamzah','2025-11-26 15:23:22','2025-11-26 15:23:22'),(158,'Sekda Alpian Hadiri RUPS-LB Bank Jambi di Mahligai 9','<div>Sekda Alpian Hadiri RUPS-LB Bank Jambi di Mahligai 9</div><div>JAMBI – PT Bank Pembangunan Daerah Jambi menggelar Rapat Umum Pemegang Saham Luar Biasa (RUPS-LB) di Grand Ballroom Joseoef Singadekane, Gedung Mahligai 9, Kantor Pusat Bank Jambi, Rabu (26/11/2025) malam. Rapat yang dimulai pukul 20.00 WIB ini dihadiri Sekretaris Daerah sungai penuh Alpian, bersama jajaran manajemen serta para pemegang saham Bank Jambi.</div><div>Dalam sambutannya, Sekda Alpian menyampaikan apresiasi tinggi atas terselenggaranya RUPS-LB yang dinilai sebagai momentum penting dalam memperkuat arah kebijakan perusahaan. Ia menegaskan bahwa Bank Jambi memiliki peran strategis sebagai pilar ekonomi daerah, sehingga pembaruan tata kelola dan penyempurnaan struktur organisasi menjadi langkah yang harus terus dilakukan.</div><div>“Rapat ini menunjukkan komitmen kuat Bank Jambi dalam meningkatkan profesionalisme dan adaptasi terhadap perkembangan industri keuangan,” ujar Alpian.</div><div>Agenda yang dibahas dalam RUPS-LB meliputi perubahan Anggaran Dasar perusahaan, penyampaian hasil Penilaian Kemampuan dan Kepatutan (PKK) dari OJK Pusat sekaligus penetapan Direktur yang membawahkan Fungsi Kepatuhan, serta pemberian wewenang kepada Dewan Komisaris melalui Komite Remunerasi dan Nominasi untuk melakukan proses seleksi calon anggota Dewan Komisaris. Rapat juga mengulas beberapa hal lain yang dinilai mendukung penguatan struktur kelembagaan dan peningkatan kinerja perusahaan.</div><div>Melalui rangkaian pembahasan tersebut, para pemegang saham berharap langkah-langkah strategis ini dapat memperkuat fondasi manajemen serta meningkatkan kualitas layanan Bank Jambi. Selain itu, keputusan yang dihasilkan diharapkan mampu mendorong percepatan transformasi perusahaan menuju institusi keuangan daerah yang lebih modern, berdaya saing, dan berorientasi pada kebutuhan masyarakat.</div><div>Rapat berlangsung kondusif dan penuh komitmen dari seluruh peserta. Di akhir kegiatan, pihak penyelenggara menyampaikan ucapan terima kasih atas kehadiran dan perhatian seluruh pemegang saham yang turut mendukung keberlangsungan Bank Jambi.</div><div>(MC DISKOMINFO)</div>','upload/berita/YD4trJKOENqPjxyjwxtBI9lk8hfEj9WUSesb0DtT.png','mediacenter','sekda-alpian-hadiri-rups-lb-bank-jambi-di-mahligai-9','2025-11-27 11:41:53','2025-11-27 11:41:53'),(159,'Kadis Kominfo Kota Sungai Penuh Sosialisasikan Literasi Digital di SMAN 4','<div>Kadis Kominfo Kota Sungai Penuh Sosialisasikan Literasi Digital di SMAN 4<br><br>SUNGAI PENUH - Dinas Komunikasi dan Informatika Kota Sungai Penuh kembali mendorong peningkatan pemahaman generasi muda terhadap pemanfaatan teknologi melalui kegiatan sosialisasi literasi digital yang digelar di SMAN 4 Kota Sungai Penuh, Rabu. Kegiatan ini menghadirkan Kepala Dinas Kominfo Kota Sungai Penuh, Josrizal Helman, sebagai pemateri utama.<br><br>Sosialisasi tersebut mengangkat tema “Kemampuan Individu untuk Produktif dan Kreatif dalam Memanfaatkan Teknologi Digital secara Efektif dan Bertanggung Jawab”. Tema ini dinilai sangat relevan dengan kondisi perkembangan teknologi saat ini, yang menuntut masyarakat terutama pelajar untuk semakin adaptif dan bijak dalam menggunakan perangkat digital.<br><br>Dalam penyampaiannya, Kadis Kominfo Josrizal Helman menekankan bahwa literasi digital bukan lagi pilihan, melainkan kebutuhan. Ia menjelaskan bahwa kemampuan mengolah informasi, menjaga etika bermedia, serta memanfaatkan teknologi untuk hal-hal produktif merupakan keterampilan yang wajib dimiliki generasi muda.<br><br>Josrizal juga mengingatkan para pelajar mengenai pentingnya menjaga keamanan data pribadi serta memahami risiko-risiko yang dapat muncul dari penggunaan internet. Ia mendorong siswa untuk lebih kreatif memanfaatkan platform digital, seperti membuat konten edukatif, mengembangkan minat teknologi, hingga mengeksplor peluang dunia digital yang terus berkembang.<br><br>Para siswa SMAN 4 Kota Sungai Penuh tampak antusias mengikuti jalannya kegiatan. Mereka terlibat aktif dalam sesi diskusi dan tanya jawab terkait isu-isu literasi digital, seperti penyebaran hoaks, etika penggunaan media sosial, serta upaya membangun jejak digital yang positif.<br><br>Melalui kegiatan ini, diharapkan para pelajar dapat semakin cerdas, produktif, dan bertanggung jawab dalam memanfaatkan teknologi digital. Sosialisasi ini sekaligus menjadi komitmen Pemerintah Kota Sungai Penuh dalam membangun masyarakat yang melek digital dan siap menghadapi tantangan era informasi.<br>(MC KOMINFO)</div>','upload/berita/qinoo53R4ASXafHquwZUWiJVsgXCJ9D40BOYvEtW.png','mediacenter','kadis-kominfo-kota-sungai-penuh-sosialisasikan-literasi-digital-di-sman-4','2025-11-27 13:10:46','2025-11-27 13:10:46'),(160,'Langkah Nyata Wali Kota Alfin: Sungai Penuh Masuk Daftar Pilot Project Penanganan Sampah Nasional','<div>&nbsp;SUNGAI PENUH – Pemerintah Kota Sungai Penuh memastikan penguatan sistem pengelolaan persampahan setelah mendapat dukungan langsung dari pemerintah pusat. Kota Sungai Penuh bahkan diproyeksikan menjadi salah satu pilot project penanganan sampah di wilayah Sumatera.</div><div>Kepastian tersebut diperoleh usai Wali Kota Sungai Penuh, Alfin, SH, bertemu langsung dengan Hanif Faisol Nurofiq di Kantor Kementerian Lingkungan Hidup RI, Jakarta, Kamis (26/2). Dalam pertemuan itu, Wali Kota Alfin memaparkan kondisi aktual pengelolaan sampah di Kota Sungai Penuh, sekaligus mengajukan dukungan sarana dan prasarana dari pemerintah pusat.</div><div>Hasilnya, Kementerian Lingkungan Hidup RI menyatakan komitmen memberikan bantuan konkret untuk memperkuat penanganan persampahan di Kota Sungai Penuh. Bantuan tersebut meliputi alat berat berupa ekskavator serta mesin press sampah yang diharapkan mampu meningkatkan efektivitas pengelolaan dan menekan volume sampah.</div><div>“Alhamdulillah, Pak Menteri menyatakan kesediaannya membantu Kota Sungai Penuh dalam penanganan persampahan. Insya Allah, bantuan dari Kementerian Lingkungan Hidup akan mulai direalisasikan pada Maret 2026,” ujar Wali Kota Alfin usai pertemuan.</div><div>Selain bantuan sarana, Menteri Lingkungan Hidup RI juga menyampaikan rencana menjadikan Kota Sungai Penuh sebagai salah satu daerah percontohan pengelolaan persampahan di Sumatera. Langkah ini menjadi bentuk apresiasi atas keseriusan dan komitmen Pemerintah Kota Sungai Penuh dalam membangun sistem pengelolaan sampah yang terintegrasi, modern, dan berkelanjutan.</div><div>Wali Kota Alfin menjelaskan, dukungan tersebut sangat strategis untuk memperkuat kapasitas daerah, mulai dari pengelolaan Tempat Pengolahan Sampah Terpadu (TPST), optimalisasi sistem pengangkutan, hingga pengurangan sampah berbasis teknologi dan mekanisasi.</div><div>Ia menegaskan bahwa Pemerintah Kota Sungai Penuh siap menindaklanjuti dukungan pemerintah pusat dengan langkah-langkah teknis yang terukur, transparan, dan akuntabel demi mewujudkan lingkungan yang bersih dan sehat bagi masyarakat.</div><div>Dalam kesempatan itu, Wali Kota Alfin juga menyampaikan apresiasi kepada Anggota DPR RI Daerah Pemilihan Jambi, Rocky Chandra, yang telah memfasilitasi pertemuan dengan Kementerian Lingkungan Hidup RI sehingga komunikasi dan koordinasi antara pemerintah daerah dan pemerintah pusat dapat berjalan efektif. (**)</div><div>(MC.Kominfo)&nbsp;</div>','upload/berita/tnXYIe58C07uU2Amfa9i7oesksTrrPpC4xF9rjJU.jpg','mc','langkah-nyata-wali-kota-alfin-sungai-penuh-masuk-daftar-pilot-project-penanganan-sampah-nasional','2026-03-02 14:23:58','2026-03-02 14:23:58'),(161,'Safari Jumat Ramadan: Warga Koto Padang Antusias Sambut Pemerintah Kota Sungai Penuh','<div>&nbsp;SUNGAI PENUH – Pemerintah Kota Sungai Penuh melanjutkan agenda Safari Jumat Ramadan dengan mengunjungi Masjid Nurul Abrar, Desa Koto Padang, Kecamatan Tanah Kampung, Jumat (27/2/26).</div><div>Wakil Wali Kota Sungai Penuh, Azhar Hamzah, mewakili Wali Kota Alfin menyapa masyarakat yang menyambut kedatangannya dengan antusias. Kegiatan ini mempererat silaturahmi sekaligus menyemarakkan Ramadan 1447 Hijriah. Safari Ramadan menjadi sarana dialog langsung antara pemerintah dan warga, menyerap aspirasi masyarakat, serta memaparkan program pembangunan yang sedang dan akan berjalan.</div><div>Agenda ini dihadiri unsur Forkopimda dan tokoh masyarakat.&nbsp;</div><div>Dandim 0417/Kerinci diwakili Pasiter Letnan Satu Inf Mulyadi, Kapolres Kerinci diwakili Kapolsek Sitinjau Laut AKP Sumardi Samad, serta Wakil Rektor I IAIN Kerinci Dr. Faizin, yang bertindak sebagai khatib Jumat.</div><div>Dalam sambutannya, Azhar Hamzah mengajak warga menjaga kerukunan dan keamanan lingkungan selama Ramadan agar ibadah berlangsung khusyuk dan tertib. Ia menegaskan Ramadan menjadi momentum memperkuat ukhuwah dan menjaga suasana aman di tengah masyarakat.</div><div>Azhar Hamzah juga menegaskan bahwa kepemimpinan Wali Kota dan Wakil Wali Kota Sungai Penuh telah memasuki satu tahun sejak 20 Februari lalu. Pemerintah daerah terus menghadirkan pembangunan yang berdampak langsung pada kesejahteraan masyarakat.</div><div>Beberapa program strategis yang disampaikan antara lain pembangunan Pasar Sungai Penuh (dulu Pasar Beringin), normalisasi sungai untuk mengurangi risiko banjir, pembagian pakaian gratis bagi masyarakat kurang mampu, serta penguatan Tempat Pengolahan Sampah Terpadu (TPST).</div><div>Pemerintah juga fokus memperkuat UMKM melalui pembentukan koperasi yang bekerja sama dengan Bank Jambi, memperluas akses permodalan, dan mendukung usaha masyarakat.</div><div>Selain itu, Wakil Wali Kota menyerahkan bantuan Rp10 juta untuk Masjid Nurul Abrar melalui program CSR Bank Jambi guna meningkatkan sarana dan prasarana ibadah.</div><div>Safari Jumat Ramadan ditutup dengan salat Jumat dan doa bersama untuk kemajuan serta kesejahteraan Kota Sungai Penuh.&nbsp;</div>','upload/berita/hTs7BWyccUzatL0fcIJDtGeY3Km1nV1XooHvnl7t.jpg','mc','safari-jumat-ramadan-warga-koto-padang-antusias-sambut-pemerintah-kota-sungai-penuh','2026-03-02 14:26:06','2026-03-02 14:26:06'),(162,'Wako Alfin Ikuti Rakor Operasi Ketupat 2026 Di Aula Polres Kerinci','<div>&nbsp;SUNGAI PENUH - Wali Kota Sungai Penuh, Alfin, SH menghadiri Rapat Koordinasi Lintas Sektoral kesiapan pelaksanaan Operasi Ketupat Tahun 2026 tingkat Mabes Polri yang digelar secara daring di Aula Polres Kerinci, Senin (2/3/2026).</div><div>Rakor tersebut diikuti langsung oleh Kapolres Kerinci AKBP Ramadhanil, S.H., S.I.K., M.H, Bupati Kerinci Di wakili Asisten I Efrawadi, OPD Lingkup Pemerintahan Kota Sungai Penuh Dan Kabupaten Kerinci, Unsur Forkopimda, Dan jajaran Polres Kerinci.</div><div>Kegiatan koordinasi nasional ini dipimpin langsung oleh Kapolri, Listyo Sigit Prabowo, dalam rangka memastikan kesiapan pengamanan Idul Fitri 1447 Hijriah tahun 2026, khususnya arus mudik dan arus balik Lebaran.</div><div>Dalam arahannya, Kapolri menekankan pentingnya sinergi lintas sektoral guna menjamin keamanan, ketertiban, dan kelancaran mobilitas masyarakat selama periode mudik. Tahun ini, Polri mengusung tagline “Mudik Aman, Keluarga Nyaman” sebagai komitmen menghadirkan rasa aman dan pelayanan maksimal bagi masyarakat yang melakukan perjalanan.</div><div>Wali Kota Alfin menyatakan dukungannya terhadap pelaksanaan Operasi Ketupat 2026 serta menegaskan kesiapan Pemerintah Kota Sungai Penuh untuk bersinergi bersama TNI-Polri dan seluruh pemangku kepentingan. Menurutnya, koordinasi yang matang menjadi kunci menciptakan suasana kondusif selama momentum Lebaran.</div><div>“Pemerintah daerah siap mendukung penuh upaya pengamanan dan pelayanan kepada masyarakat, agar perayaan Idul Fitri berjalan aman, tertib, dan lancar,” ujarnya.</div><div>Melalui rakor lintas sektoral ini, diharapkan seluruh unsur terkait dapat memetakan potensi kerawanan, mengantisipasi lonjakan arus kendaraan, serta memastikan ketersediaan sarana dan prasarana pendukung, sehingga perayaan Idul Fitri 1447 H di wilayah Kerinci dan Sungai Penuh berlangsung aman dan nyaman.(MC KOMINFO)&nbsp;</div>','upload/berita/mx0AQosFTUnwTGjZRB0K5SC6bTIPEYu7AuZCZIN0.jpg','mc','wako-alfin-ikuti-rakor-operasi-ketupat-2026-di-aula-polres-kerinci','2026-03-02 14:27:42','2026-03-02 14:27:42'),(163,'Wawako Azhar Buka Rakor Evaluasi KLA 2026','<div>&nbsp;SUNGAI PENUH - Wakil Wali Kota Sungai Penuh, Azhar Hamzah, secara resmi membuka Rapat Koordinasi (Rakor) Penyelenggaraan Evaluasi Kabupaten/Kota Layak Anak (KLA) Tahun 2026 yang digelar di Ruang Pola Bappeda, Senin (2/3/2026).</div><div>Rakor ini dilaksanakan sebagai tindak lanjut dari Keputusan Menteri Pemberdayaan Perempuan dan Perlindungan Anak Republik Indonesia Nomor 24 Tahun 2024 tentang Instrumen Evaluasi Kabupaten/Kota Layak Anak di tingkat kabupaten/kota.</div><div>Dalam sambutannya, Azhar Hamzah menegaskan pentingnya sinergi seluruh perangkat daerah dan pemangku kepentingan untuk memenuhi indikator penilaian KLA. Ia menyebut, komitmen bersama menjadi fondasi utama dalam mewujudkan Kota Sungai Penuh sebagai kota yang ramah dan layak bagi anak.</div><div>“Evaluasi KLA bukan sekadar penilaian administratif, tetapi momentum untuk memastikan pemenuhan hak dan perlindungan anak benar-benar terimplementasi dalam setiap kebijakan dan program pembangunan daerah,” ujar Azhar.</div><div>Ia juga meminta seluruh Organisasi Perangkat Daerah (OPD) terkait agar mempersiapkan data dukung secara lengkap, valid, dan akurat sesuai dengan instrumen evaluasi yang telah ditetapkan pemerintah pusat. Menurutnya, kesiapan data menjadi faktor penting dalam menentukan hasil evaluasi.</div><div>Rakor tersebut diikuti oleh sejumlah kepala OPD, instansi vertikal, serta unsur terkait lainnya. Melalui kegiatan ini, pemerintah daerah berharap terbangun kesamaan persepsi dan koordinasi lintas sektor yang lebih kuat, sehingga upaya mewujudkan Kota Sungai Penuh sebagai Kabupaten/Kota Layak Anak dapat tercapai secara optimal dan berkelanjutan.(MC KOMINFO)&nbsp;</div>','upload/berita/fmUz0VJIZM9DSxwzRLSI1HcKQulPLIpsL7tP9550.jpg','mc','wawako-azhar-buka-rakor-evaluasi-kla-2026','2026-03-02 14:29:21','2026-03-02 14:29:21'),(164,'Wawako Azhar Hamzah Kawal Pembangunan Gerai KMP, Dorong Penguatan Ekonomi Warga','<div>&nbsp;Sungai Penuh - Pembangunan gudang dan gerai KoperasiMerah Putih (KMP) di Kota Sungai Penuh terus menunjukkan kemajuan signifikan. Wakil Wali Kota Sungai Penuh, Azhar Hamzah, turun langsung ke lokasi proyek, Senin (2/4/25), untuk memastikan progres pekerjaan berjalan optimal. Saat ini, pembangunan fisik telah mencapai 82 persen.</div><div>Dalam peninjauan tersebut, Azhar Hamzah memantau langsung kondisi bangunan sekaligus mengevaluasi tahap akhir pengerjaan. Ia meminta seluruh pihak terkait menyelesaikan pekerjaan tepat waktu tanpa mengabaikan mutu, sehingga fasilitas koperasi bisa segera beroperasi.</div><div>Menurutnya, keberadaan gudang dan gerai Koperasi Merah Putih memiliki peran strategis dalam mendukung aktivitas ekonomi masyarakat. Fasilitas ini diharapkan menjadi simpul distribusi kebutuhan pokok sekaligus ruang penguatan usaha lokal.</div><div>Koperasi Merah Putih merupakan program nasional yang digagas Presiden Republik Indonesia, Prabowo Subianto. Program ini dirancang untuk menghidupkan kembali peran koperasi sebagai penggerak ekonomi kerakyatan, khususnya di tingkat desa dan kelurahan, dengan memangkas rantai distribusi yang selama ini membebani masyarakat.</div><div>Pada skala nasional, KMP atau Koperasi Desa/Kelurahan Merah Putih mendapatkan dukungan pembiayaan melalui skema pinjaman modal usaha hingga Rp3 miliar. Fasilitas tersebut disalurkan melalui perbankan yang tergabung dalam Himpunan Bank Milik Negara, guna memperkuat kapasitas usaha koperasi di daerah.</div><div>Selain akses permodalan, pemerintah juga menargetkan program ini mampu menekan harga pangan, membuka peluang usaha baru, serta meningkatkan kesejahteraan masyarakat melalui kemitraan dengan berbagai Badan Usaha Milik Negara.</div><div>Pemerintah Kota Sungai Penuh optimistis kehadiran Koperasi Merah Putih akan memberikan dampak nyata bagi perekonomian daerah. Dengan dukungan infrastruktur yang memadai, koperasi diharapkan menjadi tulang punggung distribusi dan memperkuat posisi pelaku UMKM agar mampu bersaing secara berkelanjutan.</div><div>MC.KOMINFO)&nbsp;</div>','upload/berita/kxitcxSveu33UiROmKr98rZkZ6xoZgadyNDtjYZo.jpg','mc','wawako-azhar-hamzah-kawal-pembangunan-gerai-kmp-dorong-penguatan-ekonomi-warga','2026-03-03 14:32:04','2026-03-03 14:32:04'),(165,'Pemkot Sungai Penuh Gelar Safari Ramadhan di Masjid Baiturrahim, Wako Alfin Ajak Warga Pererat Silaturahmi','<div>&nbsp;SUNGAI PENUH – Pemerintah Kota Sungai Penuh menggelar Safari Ramadhan 2026 di Masjid Baiturrahim, Desa Koto Dian, Kecamatan Hamparan Rawang, Senin (2/3/2026).</div><div>Wali Kota Sungai Penuh, Alfin, hadir bersama Wakil Wali Kota Azhar Hamzah dalam kegiatan tersebut. Safari Ramadhan ini menjadi ajang mempererat silaturahmi antara pemerintah daerah dan masyarakat.</div><div>Kegiatan itu juga dihadiri Sekretaris Daerah Alpian, Dandim 0417/Kerinci, Ketua DPRD Kota Sungai Penuh Hutri Randa, para kepala SKPD, Ketua TP-PKK Sri Kartini Alfin, camat, pimpinan Bank 9 Jambi, kepala desa, serta undangan lainnya.</div><div>Dalam kesempatan tersebut, Wali Kota Alfin menyerahkan bantuan sebesar Rp10 juta untuk Masjid Baiturrahim. Dana itu berasal dari program CSR Bank 9 Jambi sebagai bentuk dukungan terhadap kegiatan keagamaan dan kemasyarakatan.</div><div>Dalam sambutannya, Alfin mengajak masyarakat untuk terus memperkuat silaturahmi, meningkatkan keimanan, serta menjaga kebersamaan.</div><div>“Safari Ramadhan bukan sekadar kegiatan seremonial. Momentum ini memperkuat hubungan antara pemerintah dan masyarakat,” ujarnya.</div><div>Ia juga meminta seluruh Organisasi Perangkat Daerah (OPD) aktif mengikuti rangkaian Safari Ramadhan sebagai wujud pelayanan dan kedekatan pemerintah dengan warga.</div><div>Alfin turut memaparkan sejumlah capaian pembangunan yang telah diperjuangkan pemerintah daerah. Di antaranya pembangunan bronjong serta normalisasi Sungai Batang Merao untuk pengendalian banjir dan perlindungan lingkungan.</div><div>Selain itu, ia mengajak masyarakat menjaga kebersihan lingkungan dengan sikap kompak dan penuh tanggung jawab.</div><div>Terkait penanganan sampah, Alfin menyebut pemerintah daerah telah berkoordinasi dengan Kementerian Lingkungan Hidup Republik Indonesia. Hasilnya, Kota Sungai Penuh akan menerima bantuan dari pemerintah pusat untuk mendukung pengelolaan sampah.</div><div>“Alhamdulillah, dari hasil koordinasi dengan Menteri Lingkungan Hidup RI, kita akan mendapatkan beberapa bantuan. Ini bukti keseriusan Pemkot Sungai Penuh dalam menangani persoalan lingkungan,” pungkasnya.</div><div>(Mc Diskominfosta)&nbsp;</div>','upload/berita/a9PSJhNp2BZLRjuBFZoZdHEWKswUYgM9gyBwYGGx.jpg','mc','pemkot-sungai-penuh-gelar-safari-ramadhan-di-masjid-baiturrahim-wako-alfin-ajak-warga-pererat-silaturahmi','2026-03-03 14:34:28','2026-03-03 14:34:28'),(166,'Safari Ramadan di Kumun Mudik, Wako Alfin Serahkan CSR Rp10 Juta','<div>&nbsp;SUNGAI PENUH - Wali Kota Sungai Penuh Alfin, SH bersama Wakil Wali Kota Azhar Hamzah dan Sekretaris Daerah Alpian menggelar Safari Ramadan di Masjid Nurul Falah, Desa Kumun Mudik, Kecamatan Kumun Debai, Rabu (4/3/2026). Kegiatan ini turut dihadiri jajaran OPD serta unsur Forkopimda lingkup Pemerintah Kota Sungai Penuh.</div><div>Dalam sambutannya, Wali Kota Alfin menyampaikan bahwa Safari Ramadan merupakan agenda rutin pemerintah daerah sebagai ajang silaturahmi dengan masyarakat sekaligus memperkenalkan jajaran OPD agar lebih dekat dengan warga.</div><div>“Safari Ramadan ini bukan hanya ibadah bersama, tetapi juga momentum mempererat hubungan pemerintah dengan masyarakat,” ujar Alfin.</div><div>Pada kesempatan tersebut, Alfin juga memaparkan capaian satu tahun kepemimpinannya bersama Wakil Wali Kota Azhar Hamzah. Sejumlah pembangunan fisik di Kecamatan Kumun Debai telah diselesaikan, di antaranya peningkatan jalan menuju Renah Kayu Embun yang kini mempermudah akses masyarakat.</div><div>Terkait persoalan persampahan, ia mengungkapkan bahwa Pemerintah Kota Sungai Penuh telah mendapatkan bantuan satu unit ekskavator dan mesin pengolah plastik dari Kementerian Lingkungan Hidup. Ia juga menegaskan bahwa Tempat Pengolahan Sampah Terpadu (TPST) di Renah Kayu Embun telah melalui prosedur sesuai aturan yang berlaku.</div><div>“Jangan mudah termakan isu di media sosial. Tidak mungkin pemerintah mendirikan TPST tanpa izin. Semua sudah sesuai ketentuan,” tegasnya.</div><div>Alfin turut mengimbau masyarakat untuk mulai menjaga kebersihan lingkungan dengan memilah sampah dari rumah sebagai langkah awal mendukung pengelolaan sampah yang lebih baik.</div><div>Di bidang sosial, Wali Kota meminta Dinas Sosial untuk mengecek ulang data penerima BPJS dan berkoordinasi dengan pemerintah desa agar data yang digunakan benar-benar valid dan sinkron. Sementara di sektor pendidikan, pemerintah kota telah menyiapkan program seragam sekolah gratis guna memastikan tidak ada lagi anak di Kota Sungai Penuh yang putus sekolah karena alasan ekonomi.</div><div>Sebagai bentuk dukungan terhadap pembangunan rumah ibadah, di akhir kegiatan Wali Kota Alfin menyerahkan bantuan dana CSR sebesar Rp10 juta untuk pembangunan Masjid Nurul Falah Desa Kumun Mudik. Safari Ramadan kali ini juga diisi tausiah oleh Buya Drs. H. Laidamuri, yang menambah kekhusyukan suasana ibadah di bulan suci.(MC KOMINFO)&nbsp;</div>','upload/berita/fk2vbjAEsmuU2K9PWysDspv6DFi7THFvhSpGtUgu.jpg','mc','safari-ramadan-di-kumun-mudik-wako-alfin-serahkan-csr-rp10-juta','2026-03-05 13:04:25','2026-03-05 13:04:25'),(167,'Sidak Ramadan, Wako Alfin Pastikan Layanan Tetap Optimal','<div>&nbsp;SUNGAI PENUH - Wali Kota Sungai Penuh, Alfin, melakukan inspeksi mendadak (sidak) ke sejumlah Organisasi Perangkat Daerah (OPD) di lingkup Pemerintah Kota Sungai Penuh untuk memastikan pelayanan publik tetap berjalan optimal selama bulan Ramadan.</div><div>Sidak yang dimulai sekitar pukul 14.30 WIB itu dilakukan secara langsung tanpa didampingi pejabat lain. Wako Alfin meninjau satu per satu ruangan kerja guna melihat aktivitas aparatur, memastikan kehadiran pegawai, serta memantau kelancaran pelayanan kepada masyarakat hingga jam kerja yang telah ditetapkan selama Ramadan, yakni pukul 15.00 WIB.</div><div>Beberapa dinas strategis yang dikunjungi antara lain Dinas Komunikasi dan Informatika Statistik (Kominfosta), Dinas Penanaman Modal dan Pelayanan Terpadu Satu Pintu (DPMPTSP), Dinas Pendidikan, serta Dinas Pemerintahan Desa.</div><div>Dalam kesempatan tersebut, Alfin memberikan apresiasi khusus kepada jajaran Dinas Kominfosta karena tingkat kehadiran pegawai mencapai 90 persen hingga pukul 15.00 WIB. Ia menilai hal itu sebagai bentuk kedisiplinan dan komitmen aparatur dalam menjaga kualitas pelayanan di bulan suci.</div><div>“Ramadan bukan alasan untuk menurunkan kualitas pelayanan. Justru ini menjadi momentum untuk meningkatkan kedisiplinan dan tanggung jawab sebagai pelayan masyarakat,” tegas Alfin.</div><div>Dari hasil pemantauan, pelayanan di masing-masing dinas terpantau berjalan normal dan sesuai ketentuan jam kerja Ramadan. Kehadiran pegawai relatif baik, serta aktivitas pelayanan kepada masyarakat tetap berlangsung sebagaimana mestinya.</div><div>Langkah sidak ini menjadi bagian dari komitmen Pemerintah Kota Sungai Penuh dalam menjaga kualitas pelayanan publik, sekaligus memastikan roda pemerintahan tetap berjalan efektif, profesional, dan responsif terhadap kebutuhan masyarakat.(MC KOMINFO)&nbsp;</div>','upload/berita/jutMfXHk67SBQJbDpXtlNk9nDcmTVzj0z3UCAZGv.jpg','mc','sidak-ramadan-wako-alfin-pastikan-layanan-tetap-optimal','2026-03-05 13:05:34','2026-03-05 13:05:34'),(168,'Pasar Tertib, Warga Nyaman: Sekda Alpian Pimpin Langkah Nyata Penataan','<div>SUNGAI PENUH – Pemerintah Kota Sungai Penuh terus menunjukkan komitmennya dalam memberikan kenyamanan bagi masyarakat, khususnya dalam aktivitas di pasar. Hal ini terlihat saat Sekretaris Daerah Kota Sungai Penuh, Alpian, SE., MM memimpin rapat koordinasi penertiban dan ketentraman pasar, Rabu (25/04/2026), usai melakukan peninjauan langsung ke Pasar Tanjung Bajure.</div><div>Didampingi Asisten I Pemerintahan dan Kesra, Dianda Putra, S.STP., <a href=\"https://l.facebook.com/l.php?u=http%3A%2F%2FM.Si%2F%3Ffbclid%3DIwZXh0bgNhZW0CMTAAYnJpZBExZllsckJHd2dwZWlhWmFLc3NydGMGYXBwX2lkEDIyMjAzOTE3ODgyMDA4OTIAAR6BtNJ4xpyL2ULE_DRdcGTPEpVptYQJyDcfOloUn2s248TKqoEUCgRY2LBniQ_aem_X4XGhHbcJcA9A9806usb-Q&amp;h=AT4UnB8VgU680xgRhhubEebP6Clt4kVlFYz0sAdpj4tk2rb4hYg9kFZS5yCP0dkypWZzYqtjSdwSSOSqyqi1LPuqxbb6xXSiLKCZEvkYNAa-dRl3Xx5WYfx8szEtpIyxgz82s8J7ZabdeA&amp;__tn__=-UK-R&amp;c[0]=AT6rOV5og0A-lwxqt2m-Jk6x_PIR5meSGjGa2GedtsvE_dsvbsB2Ii6YiXO3YTLgTtqZettn1HaEGnUMnnMPBwdvkFSx0eqZ1thF97cEujo4TlqDYujfv4J9iwPmXYoAcqAwc3X8dkbvfNPS3yDVEQIstxu_CZ6C4pGPWifhmhdE5SpP8cLoGGlVLN0ci4wkRgFM3m0W74TRTkqznfwYrrbI3g\"><strong>M.Si</strong></a>, Sekda Alpian mengajak seluruh perangkat daerah untuk lebih peka terhadap kebutuhan masyarakat, terutama para pedagang dan pengunjung pasar. Rapat ini turut dihadiri berbagai OPD dan instansi terkait, di antaranya Dinas PUPR, Dinas Kominfosta, Badan Kesbangpol, Satuan Polisi Pamong Praja (Satpol PP), Inspektorat, Bappeda, Bapenda, BPKAD, Dinas Perindustrian dan Perdagangan (Disperindag), Dinas Penanaman Modal dan Pelayanan Terpadu Satu Pintu (DPMPTSP), serta para Kepala Bagian di lingkup Setda Kota Sungai Penuh.</div><div>Dalam arahannya, penataan pasar tidak hanya dipandang sebagai upaya penertiban semata, namun juga bagian dari tanggung jawab pemerintah dalam melindungi dan mendukung aktivitas ekonomi masyarakat. Kenyamanan pedagang dalam berjualan serta kemudahan masyarakat dalam berbelanja menjadi prioritas utama yang terus diperjuangkan.</div><div>Selain itu, pemerintah juga menekankan pentingnya penataan pedagang yang adil dan sesuai aturan, agar tidak merugikan pihak manapun. Langkah ini diharapkan mampu menciptakan suasana pasar yang lebih tertib, bersih, dan kondusif, sehingga interaksi antara pedagang dan pembeli dapat berlangsung dengan baik.</div><div>Melalui sinergi lintas sektor, Pemerintah Kota Sungai Penuh berupaya memastikan bahwa setiap kebijakan yang diambil benar-benar berpihak kepada masyarakat.&nbsp;</div><div>Penataan pasar ini pun diharapkan tidak hanya meningkatkan ketertiban, tetapi juga memperkuat perekonomian rakyat secara berkelanjutan.</div><div>MC. Kominfo&nbsp;</div>','upload/berita/vS64VmJbOmCRNlLDY8gRQ1aiNYOfstsgoFaB0Tj3.jpg','mc','pasar-tertib-warga-nyaman-sekda-alpian-pimpin-langkah-nyata-penataan','2026-03-27 15:49:52','2026-03-27 15:49:52'),(169,'Sekda Alpian Kembali Pantau Kondisi Pasar Tanjung Bajure, Tekankan Kebersihan','<div>&nbsp;</div><div>SUNGAI PENUH – Sekretaris Daerah (Sekda) Kota Sungai Penuh, Alpian, meninjau langsung kegiatan penataan dan pembersihan di kawasan Pasar Tanjung Bajure, Rabu (25/3/2026).</div><div>Peninjauan tersebut merupakan wujud komitmen Pemerintah Kota Sungai Penuh dalam menciptakan lingkungan pasar yang bersih, tertib, dan nyaman bagi pedagang maupun pengunjung.</div><div>Kegiatan ini turut melibatkan berbagai pihak, di antaranya Kepala Dinas PUPR, Dinas Lingkungan Hidup, Satuan Polisi Pamong Praja (Satpol PP), Dinas Perdagangan dan Perindustrian (Disperindag), camat, kepala desa, serta unsur terkait lainnya.</div><div>Dalam kunjungannya, Sekda Alpian menekankan pentingnya menjaga kebersihan serta penataan lapak pedagang agar lebih tertib dan rapi. Ia juga mengimbau seluruh pedagang untuk berperan aktif dalam menjaga kebersihan lingkungan pasar.</div><div>“Kebersihan pasar merupakan tanggung jawab bersama. Lingkungan yang bersih dan tertata akan memberikan kenyamanan bagi masyarakat saat berbelanja,” ujarnya.</div><div>Selain itu, ia meminta instansi terkait untuk terus melakukan pengawasan dan pembinaan secara berkelanjutan guna memastikan kondisi pasar tetap terjaga dengan baik.</div><div>Melalui kegiatan penataan dan pembersihan ini, diharapkan Pasar Tanjung Bajure semakin tertib, bersih, dan mampu meningkatkan daya tarik sebagai salah satu pusat aktivitas ekonomi masyarakat di Kota Sungai Penuh.</div><div>(MC Diskominfosta)&nbsp;</div>','upload/berita/VFzs7p6aGnF5NfX75MiVd9qIChI046wACeaZAqrg.jpg','mc','sekda-alpian-kembali-pantau-kondisi-pasar-tanjung-bajure-tekankan-kebersihan','2026-03-27 15:51:02','2026-03-27 15:51:02'),(170,'Penataan Pasar Tanjung Bajure Kian Intensif, Wawako Azhar - Sekda Alpian Turun Langsung','<div>&nbsp;</div><div>SUNGAI PENUH - Wakil Wali Kota Sungai Penuh, Azhar Hamzah bersama Sekretaris Daerah Alpian, didampingi dinas terkait, kembali turun langsung memantau penertiban kawasan Pasar Tanjung Bajure.</div><div>Penertiban difokuskan pada pedagang yang masih menggunakan badan jalan di sepanjang Jalan M. Yamin. Selain itu, pemerintah juga menata bangunan toko atau ruko yang memanfaatkan bahu jalan, dengan mengimbau para pemilik untuk melakukan pembongkaran secara mandiri.</div><div>Tak hanya itu, penataan juga menyasar relokasi pedagang. Para pedagang ayam dipindahkan ke lantai dua Pasar Tanjung Bajure, sementara pedagang ikan diarahkan menempati los ikan yang telah disediakan di dalam area pasar.</div><div>Dalam pelaksanaannya, pendekatan persuasif dan humanis tetap menjadi prioritas. Pemerintah berupaya membangun komunikasi langsung dengan para pedagang agar proses penertiban berjalan kondusif tanpa menimbulkan gesekan.</div><div>Wawako Azhar Hamzah menegaskan, langkah ini merupakan bagian dari komitmen pemerintah dalam menata ulang wajah Pasar Tanjung Bajure agar lebih tertib, rapi, dan nyaman bagi masyarakat.</div><div>Selain penataan fisik, pemerintah juga melakukan pendataan terhadap pedagang kaki lima guna memastikan penempatan yang lebih teratur, baik dari sisi lokasi maupun administrasi ke depannya.</div><div>Melalui upaya ini, Pemerintah Kota Sungai Penuh berharap kawasan pasar dapat menjadi lebih tertib dan representatif, sekaligus mendukung aktivitas ekonomi masyarakat yang lebih nyaman dan berkelanjutan.(MC KOMINFO)&nbsp;</div>','upload/berita/YCtsGwq3L3zhgodQN8qjouzyllI8Jt6q7bvtGxL3.jpg','mc','penataan-pasar-tanjung-bajure-kian-intensif-wawako-azhar-sekda-alpian-turun-langsung','2026-03-27 15:52:18','2026-03-27 15:52:18'),(171,'Halal Bihalal Luhah Rio Singaro, Wako Alfin dan Wawako Azhar Hamzah Tekankan Pentingnya Persatuan','<div>&nbsp;</div><div>SUNGAI PENUH – Kebersamaan dan kehangatan terasa kental saat Wali Kota Sungai Penuh, Alfin, S.H., bersama Wakil Wali Kota Azhar Hamzah menghadiri Halal Bihalal dan silaturahmi masyarakat Luhah Rio Singaro di Laheik Jajun (Laheik Dahot), Pondok Tinggi, Kamis (26/3/2026).</div><div>Kehadiran kedua pimpinan daerah tersebut disambut penuh suka cita oleh masyarakat. Suasana kekeluargaan yang terbangun mencerminkan kedekatan emosional antara pemerintah dan warga, sekaligus menjadi momen mempererat tali silaturahmi pasca Idulfitri 1447 Hijriah.</div><div>Dalam sambutannya, Wali Kota Alfin mengajak seluruh masyarakat untuk terus menjaga kebersamaan dan memperkuat rasa persaudaraan dalam kehidupan sehari-hari.</div><div>“Halal Bihalal bukan sekadar tradisi, tetapi menjadi ruang untuk saling memaafkan dan mempererat hubungan. Dari kebersamaan inilah lahir kekuatan untuk membangun daerah,” ungkapnya.</div><div>Ia juga menyampaikan apresiasi atas kekompakan masyarakat Luhah Rio Singaro yang dinilai tetap menjaga nilai-nilai adat dan budaya, serta terus menjalin hubungan yang harmonis dengan pemerintah daerah.</div><div>Rangkaian acara berlangsung sederhana namun penuh makna. Tausiyah singkat tentang pentingnya silaturahmi, suasana saling bermaafan, hingga makan bersama menjadi bagian dari kehangatan yang menyatukan seluruh yang hadir.</div><div>Melalui momentum ini, diharapkan keharmonisan antara pemerintah dan masyarakat semakin terjalin erat, sehingga tercipta sinergi yang kuat dalam mewujudkan Kota Sungai Penuh yang lebih maju, damai, dan sejahtera.</div><div>(MC Diskominfosta)&nbsp;</div>','upload/berita/fFoOb2tgpXrGIbxEOvW8swWMH6PRXgCGJH5Ew0UL.jpg','mc','halal-bihalal-luhah-rio-singaro-wako-alfin-dan-wawako-azhar-hamzah-tekankan-pentingnya-persatuan','2026-03-27 15:54:07','2026-03-27 15:54:07'),(172,'Wawako Azhar Hamzah Hadiri Evaluasi KDKMP, Perkuat Ekonomi Masyarakat dari Desa','<div>&nbsp;</div><div>SUNGAI PENUH – Upaya memperkuat ekonomi masyarakat berbasis desa terus menjadi perhatian Pemerintah Kota Sungai Penuh. Hal ini terlihat dari kehadiran Wakil Wali Kota Azhar Hamzah dalam kegiatan evaluasi percepatan pembangunan Koperasi Desa/Kelurahan Merah Putih (KDKMP) di Desa Aur Duri, Jumat (27/03/26).</div><div>Kegiatan yang digelar secara daring ini dipimpin oleh Wakil Panglima TNI, Tandyo Budi Revita, dan diikuti oleh berbagai unsur, di antaranya Kasdim 0417/Kerinci, Danramil 417-06/Sungai Penuh beserta jajaran, OPD terkait dari Kota Sungai Penuh dan Kabupaten Kerinci, para kepala desa, pengurus koperasi, serta masyarakat.</div><div>Dalam suasana penuh kebersamaan, evaluasi tersebut membahas langkah percepatan pembangunan Koperasi Merah Putih yang diharapkan mampu menjadi penggerak ekonomi masyarakat di tingkat desa. Program ini merupakan bagian dari target nasional pembangunan 35.000 koperasi hingga Juli mendatang.</div><div>Data sementara menunjukkan sebanyak 3.252 koperasi telah siap untuk diluncurkan pada pertengahan April. Sementara itu, puluhan ribu lainnya masih dalam proses pembangunan dan terus dikebut agar target dapat tercapai sesuai waktu yang ditetapkan.</div><div>Wakil Wali Kota Azhar Hamzah menyampaikan bahwa Pemerintah Kota Sungai Penuh menyambut baik program tersebut sebagai peluang besar dalam meningkatkan kesejahteraan masyarakat.</div><div>“Program ini bukan hanya tentang membangun koperasi, tetapi juga membangun kemandirian ekonomi masyarakat. Dengan kebersamaan dan sinergi, kita optimistis target yang ditetapkan dapat tercapai,” ungkapnya.</div><div>Ia juga berharap Koperasi Merah Putih benar-benar dirasakan manfaatnya oleh masyarakat.</div><div>“Kita ingin koperasi ini tumbuh dan berkembang di tengah masyarakat, menjadi wadah yang mampu menggerakkan ekonomi desa serta meningkatkan kesejahteraan secara nyata,” tutupnya.</div><div>MC.KOMINFO&nbsp;</div>','upload/berita/RkGKSiJ4FzUkbTDezJ1GYjWhn0n7lrI5ROKe1k3M.jpg','mc','wawako-azhar-hamzah-hadiri-evaluasi-kdkmp-perkuat-ekonomi-masyarakat-dari-desa','2026-03-27 15:55:26','2026-03-27 15:55:26'),(173,'Kembali Tinjau Pasar Tanjung Bajure, Pemkot Sungai Penuh Dorong Penataan dan Kesejahteraan Pedagang','<div>&nbsp;</div><div>SUNGAI PENUH – Wakil Wali Kota Sungai Penuh Azhar Hamzah bersama Sekretaris Daerah Alpian kembali melakukan peninjauan ke Pasar Tanjung Bajure, Sabtu (3/2025), guna memastikan kondisi pasar sekaligus menyerap aspirasi pedagang dan pekerja.</div><div>Dalam kunjungan tersebut, keduanya meninjau langsung aktivitas perdagangan serta berdialog dengan para pedagang. Sejumlah masukan, keluhan, hingga harapan terkait pengelolaan pasar disampaikan secara terbuka oleh para pelaku usaha.</div><div>Wawako Azhar menekankan bahwa keberadaan pasar memiliki peran strategis sebagai salah satu sumber Pendapatan Asli Daerah (PAD), sehingga diperlukan tata kelola yang baik dan berkelanjutan.</div><div>Selain menyerap aspirasi, Wawako Azhar dan Sekda Alpian juga melakukan pemantauan terhadap pemasangan tenda sosial di kawasan pasar. Mereka turut menanggapi berbagai aspirasi yang disampaikan para buruh yang bekerja di lingkungan pasar tersebut.</div><div>Kunjungan ini juga menjadi bagian dari upaya pemerintah daerah untuk memperkuat komunikasi dengan masyarakat, sekaligus menciptakan suasana pasar yang lebih tertata, nyaman, dan produktif.</div><div>“Pemerintah daerah berharap adanya keterlibatan aktif masyarakat, khususnya para pedagang, dalam memberikan masukan demi perbaikan sektor pasar. Dengan pengelolaan yang baik, pasar tidak hanya menjadi pusat ekonomi, tetapi juga mampu memberikan kontribusi optimal bagi daerah,” ujar Wawako Azhar.</div><div>Mc.Kominfo&nbsp;</div>','upload/berita/ZDIq5Qf2wPttYyXBnB5aSru6eNIuEU9uwl60ECpB.jpg','mc','kembali-tinjau-pasar-tanjung-bajure-pemkot-sungai-penuh-dorong-penataan-dan-kesejahteraan-pedagang','2026-03-30 11:47:51','2026-03-30 11:47:51'),(174,'Perkuat Sinergi Usai Lebaran, Pemkot Sungai Penuh Gelar Apel dan Halal Bihalal','<div>&nbsp;</div><div>SUNGAI PENUH – Pemerintah Kota Sungai Penuh menggelar apel pagi yang dirangkaikan dengan halal bihalal bersama seluruh Aparatur Sipil Negara (ASN) pasca perayaan Idulfitri 1447 Hijriah, Senin (30/3/2026).</div><div>Kegiatan yang berlangsung di Lapangan Kantor Wali Kota Sungai Penuh itu dihadiri Sekretaris Daerah Alpian, para asisten, kepala Organisasi Perangkat Daerah (OPD), serta seluruh ASN di lingkungan Pemkot Sungai Penuh.</div><div>Apel berlangsung tertib dan khidmat, sekaligus menjadi momentum untuk memperkuat sinergi dan kedisiplinan aparatur setelah libur Lebaran.</div><div>Sekda Alpian dalam arahannya menyampaikan apresiasi kepada seluruh ASN atas dedikasi dan tanggung jawab dalam menjalankan tugas, baik sebelum maupun setelah libur Idulfitri.</div><div>Ia menilai tingkat kehadiran dan kedisiplinan pada apel perdana pasca libur mencerminkan komitmen kuat ASN dalam memberikan pelayanan kepada masyarakat.</div><div>“Ini menunjukkan kesiapan dan keseriusan kita dalam kembali menjalankan tugas pelayanan publik secara optimal,” ujarnya.</div><div>Selain sebagai ajang silaturahmi, halal bihalal juga dimaknai sebagai momentum untuk saling memaafkan dan memperkuat kebersamaan dalam lingkungan kerja.</div><div>Sekda Alpian turut mengajak seluruh jajaran untuk menjaga kekompakan, meningkatkan etos kerja, serta memperkuat kolaborasi antar perangkat daerah guna mendorong kemajuan dan kesejahteraan masyarakat Kota Sungai Penuh.</div><div>(MC Diskominfo)&nbsp;</div>','upload/berita/wQKD2lx8gX323QCkxMCAldL73jJapfXeFf6iLSUi.jpg','mc','perkuat-sinergi-usai-lebaran-pemkot-sungai-penuh-gelar-apel-dan-halal-bihalal','2026-03-30 11:49:20','2026-03-30 11:49:20'),(175,'Langkah Berkelanjutan, Pemkot Sungai Penuh Perkuat Koordinasi dengan BPBPK Jambi','<div>&nbsp;</div><div>SUNGAI PENUH – Wali Kota Sungai Penuh, Alfin, S.H., melakukan kunjungan koordinasi ke Balai Penataan Bangunan Prasarana dan Kawasan (BPBPK) Jambi, Direktorat Jenderal Cipta Karya Kementerian PUPR, Senin (30/04/2026), bertempat di Aula BPBPK Jambi.</div><div>Dalam kunjungan tersebut, Wako Alfin didampingi Kepala Dinas PUPR, Kepala Dinas Lingkungan Hidup, Kabag Prokopim, serta jajaran Pemerintah Kota Sungai Penuh. Kehadiran rombongan disambut langsung oleh Kepala Balai BPBPK Jambi Muhammad Rusli, S.T., M.D.M., bersama Kepala Satker Pelaksanaan Cipta Karya Provinsi Jambi Yusrizal, S.T., M.T., serta Kasi Pelaksanaan II/PPK Perencanaan Adrial Munis, S.T., M.T.</div><div>Suasana pertemuan berlangsung hangat dan penuh keakraban, mencerminkan komitmen bersama dalam memperkuat sinergi pembangunan. Sejumlah program strategis menjadi fokus pembahasan, di antaranya percepatan pembangunan Instalasi Pengolahan Air (IPA) Hamparan Rawang, pengembangan Tempat Pengolahan Sampah Terpadu (TPST) RKE, serta usulan dukungan alat berat berupa backhoe loader untuk menunjang operasional Dinas Lingkungan Hidup.</div><div>Dalam kesempatan tersebut, Wako Alfin menyampaikan kondisi dan kebutuhan daerah, khususnya terkait peningkatan layanan air bersih serta pengelolaan persampahan yang berkelanjutan. Ia berharap dukungan dari pemerintah pusat dapat semakin mempercepat realisasi program-program prioritas tersebut.</div><div>“Kami berharap pembangunan IPA Hamparan Rawang dapat berjalan optimal guna meningkatkan pelayanan air minum masyarakat. Selain itu, kehadiran TPST RKE diharapkan menjadi solusi pengelolaan sampah yang lebih terpadu, serta dukungan alat berat akan sangat membantu operasional di lapangan,” ujarnya.</div><div>Menanggapi hal tersebut, pihak BPBPK Jambi menyampaikan apresiasi atas berbagai usulan yang diajukan dan menyatakan kesiapan untuk menindaklanjuti sesuai dengan ketentuan yang berlaku di lingkungan Direktorat Jenderal Cipta Karya Kementerian PUPR.</div><div>Melalui pertemuan ini, diharapkan hubungan kerja sama antara pemerintah daerah dan pemerintah pusat semakin erat, sehingga mampu mendorong percepatan pembangunan infrastruktur sekaligus meningkatkan kualitas lingkungan hidup di Kota Sungai Penuh secara berkelanjutan.</div><div>MC. KOMINFO&nbsp;</div>','upload/berita/cM3XEb0r02sPFHx6qcGXdLPBYfhL1LutwVLgmWQ0.jpg','mc','langkah-berkelanjutan-pemkot-sungai-penuh-perkuat-koordinasi-dengan-bpbpk-jambi','2026-03-31 07:10:47','2026-03-31 07:10:47'),(176,'Wawako Azhar Sampaikan LKPj 2025 di DPRD','<div>SUNGAI PENUH - Wakil Wali Kota Sungai Penuh, Azhar Hamzah menyampaikan pengantar Laporan Keterangan Pertanggungjawaban (LKPj) Tahun Anggaran 2025 dalam Rapat Paripurna DPRD Kota Sungai Penuh, Selasa (31/3/2026).</div><div>Dalam penyampaiannya, ia menegaskan bahwa LKPj merupakan bentuk pertanggungjawaban pemerintah daerah atas pelaksanaan program dan kinerja selama tahun 2025, sekaligus bahan evaluasi bersama DPRD untuk perbaikan ke depan.</div><div>Dari sisi keuangan, pendapatan daerah terealisasi sebesar Rp758,05 miliar atau 91,08 persen dari target, sementara belanja daerah mencapai Rp762,82 miliar atau 91,03 persen.</div><div>Secara makro, pertumbuhan ekonomi Kota Sungai Penuh tercatat 4,39 persen dengan peningkatan Indeks Pembangunan Manusia menjadi 78,89. Sementara itu, angka kemiskinan berada di level 3,23 persen, terendah di Provinsi Jambi.</div><div>Pemerintah juga mencatat kemajuan di berbagai sektor, mulai dari pendidikan, kesehatan, hingga infrastruktur seperti peningkatan kondisi jalan, akses air minum, dan sanitasi.</div><div>Mengakhiri penyampaiannya, Wawako Azhar mengajak seluruh pihak untuk terus memperkuat sinergi dalam mendukung pembangunan daerah.</div><div>“Kolaborasi dan dukungan semua pihak sangat penting demi mewujudkan kesejahteraan masyarakat Kota Sungai Penuh,” ujarnya.</div><div>(MC KOMINFO)&nbsp;</div>','upload/berita/vOY1n9foVjCbtWgRDKiF2nUFom8eaezr1LdZJ5en.jpg','mc','wawako-azhar-sampaikan-lkpj-2025-di-dprd','2026-04-01 10:58:36','2026-04-01 10:58:36'),(177,'Wako Alfin Serahkan LKPD 2025 ke BPK Jambi','<div>&nbsp;</div><div>JAMBI - Wali Kota Sungai Penuh, Alfin secara resmi menyerahkan Laporan Keuangan Pemerintah Daerah (LKPD) Tahun Anggaran 2025 (unaudited) kepada Badan Pemeriksa Keuangan (BPK) Perwakilan Provinsi Jambi, Selasa (31/3).</div><div>Penyerahan dokumen LKPD tersebut dilakukan langsung oleh Wako Alfin kepada Kepala BPK Perwakilan Provinsi Jambi, Muhamad Toha Arafat, dalam kegiatan yang berlangsung di Auditorium Sultan Thaha.</div><div>Kegiatan ini juga diikuti oleh seluruh pemerintah kabupaten/kota se-Provinsi Jambi sebagai bagian dari agenda penyampaian laporan keuangan daerah sesuai dengan ketentuan yang berlaku.</div><div>Dalam kesempatan tersebut, Wako Alfin menegaskan bahwa penyampaian LKPD merupakan kewajiban tahunan pemerintah daerah sebagai bentuk pertanggungjawaban atas pelaksanaan Anggaran Pendapatan dan Belanja Daerah (APBD).</div><div>“Ini merupakan komitmen kami dalam menjaga transparansi dan akuntabilitas pengelolaan keuangan daerah,” ujarnya.</div><div>Ia berharap, melalui penyampaian laporan ini, kepercayaan publik terhadap pemerintah daerah semakin meningkat serta mendorong pengelolaan keuangan yang lebih efektif dan efisien ke depannya.</div><div>Turut mendampingi Wali Kota dalam kegiatan tersebut, Sekretaris Daerah Alpian, Kepala BKAD, serta Inspektorat Kota Sungai Penuh.</div><div>(Mc Kominfo)&nbsp;</div>','upload/berita/EkK0dd88iAusfVUAIGDRqjiAiaWs2m0wdlefvXgr.jpg','mc','wako-alfin-serahkan-lkpd-2025-ke-bpk-jambi','2026-04-01 11:00:10','2026-04-01 11:00:10'),(178,'Azhar Hamzah Tegaskan Kesiapan Pemkot Sungai Penuh Hadapi Pemeriksaan LKPD 2025','<div>&nbsp;</div><div>SUNGAI PENUH – Pemerintah Kota Sungai Penuh menyatakan kesiapan penuh dalam menghadapi pemeriksaan Laporan Keuangan Pemerintah Daerah (LKPD) Tahun 2025. Hal tersebut disampaikan Wakil Wali Kota Sungai Penuh, Azhar Hamzah, usai mengikuti entry meeting bersama Badan Pemeriksa Keuangan (BPK) RI Perwakilan Provinsi Jambi, Kamis (2/4/26).</div><div>Kegiatan entry meeting yang dilaksanakan secara daring melalui Zoom ini merupakan agenda awal sebelum tim BPK melakukan pemeriksaan lebih lanjut terhadap laporan keuangan pemerintah daerah. Pertemuan tersebut digelar oleh Direktorat Jenderal Pemeriksaan Keuangan Negara V dan diikuti sejumlah kepala daerah dari wilayah Jawa dan Sumatera.</div><div>Dalam kesempatan itu, Azhar Hamzah menegaskan komitmen pemerintah daerah untuk bersikap terbuka dan kooperatif selama proses pemeriksaan berlangsung. Ia memastikan seluruh perangkat daerah siap mendukung kebutuhan data yang diperlukan tim auditor.</div><div>Menurutnya, pemeriksaan LKPD merupakan bagian penting dalam memastikan pengelolaan keuangan daerah berjalan sesuai prinsip transparansi dan akuntabilitas.</div><div>“Pemerintah Kota Sungai Penuh siap menjalin komunikasi yang baik dengan tim pemeriksa, serta memberikan data secara lengkap dan tepat waktu,” ujarnya.</div><div>Ia juga berharap proses pemeriksaan dapat berjalan lancar dan menghasilkan evaluasi yang konstruktif bagi peningkatan tata kelola keuangan daerah ke depan. (MC KOMINFO)&nbsp;</div>','upload/berita/8UUnrY9jwmuhjwMQeLEfsz0J6xYopOSFolC0YkNs.jpg','mc','azhar-hamzah-tegaskan-kesiapan-pemkot-sungai-penuh-hadapi-pemeriksaan-lkpd-2025','2026-04-06 10:46:58','2026-04-06 10:46:58'),(179,'Wawako Azhar Pimpin Evaluasi Penertiban Pasar Bajure','<div>&nbsp;</div><div>SUNGAI PENUH - Wakil Wali Kota Sungai Penuh, Azhar Hamzah memimpin rapat evaluasi penertiban pedagang Pasar Tanjung Bajure, Kamis (2/4).</div><div>Rapat yang digelar di rumah dinas Wakil Wali Kota tersebut turut dihadiri Sekretaris Daerah Alpian, para asisten, kepala perangkat daerah terkait, serta camat.</div><div>Dalam pertemuan itu, pemerintah membahas langkah strategis untuk menata kembali aktivitas perdagangan agar lebih tertib, nyaman, dan sesuai aturan. Evaluasi ini merupakan tindak lanjut dari penertiban yang sebelumnya telah dilakukan di kawasan Pasar Tanjung Bajure.</div><div>Wawako Azhar Hamzah menegaskan bahwa penataan pasar sangat penting untuk menciptakan kondisi yang kondusif, baik bagi pedagang maupun masyarakat. Ia juga menekankan pentingnya sinergi semua pihak agar kebijakan yang dijalankan dapat berjalan efektif tanpa menimbulkan konflik.</div><div>Selain itu, pemerintah tetap mengedepankan pendekatan persuasif dalam proses penertiban, sembari menyiapkan solusi agar para pedagang tetap dapat menjalankan usahanya dengan lebih tertib.</div><div>“Melalui evaluasi ini, kita berharap penataan Pasar Tanjung Bajure dapat berjalan lebih optimal dan memberikan dampak positif bagi perekonomian daerah,” ujarnya.</div><div>(MC KOMINFO)&nbsp;</div>','upload/berita/uqslZfQBNfUmq8KBOTptxvwbMtjZppMq4455S7Dk.jpg','mc','wawako-azhar-pimpin-evaluasi-penertiban-pasar-bajure','2026-04-06 10:48:36','2026-04-06 10:48:36'),(180,'Pastikan Pasar Tertib, Wawako Azhar Hamzah Tinjau Langsung Pasar Tanjung Bajure','<div>&nbsp;</div><div>SUNGAI PENUH – Upaya penataan kawasan pasar terus dilakukan Pemerintah Kota Sungai Penuh. Wakil Wali Kota Azhar Hamzah turun langsung meninjau kondisi Pasar Tanjung Bajure, Jumat (3/4/2026), guna memastikan hasil penertiban berjalan sesuai harapan.</div><div>Dalam kunjungan tersebut, Azhar Hamzah didampingi Sekretaris Daerah Alpian serta jajaran terkait. Peninjauan ini dilakukan sebagai bentuk komitmen pemerintah dalam menjaga ketertiban dan menciptakan lingkungan pasar yang lebih nyaman.</div><div>Wawako menelusuri sejumlah titik di area pasar untuk melihat langsung kondisi lapak pedagang setelah dilakukan penataan. Ia memastikan tidak ada lagi aktivitas yang melanggar aturan di lokasi yang sebelumnya telah ditertibkan.</div><div>Menurutnya, langkah penertiban merupakan bagian dari upaya bersama untuk menciptakan suasana pasar yang lebih tertib, bersih, dan aman bagi seluruh pihak.</div><div>“Penataan ini kita lakukan demi kenyamanan bersama. Kita ingin pasar menjadi tempat yang rapi dan tertib, sehingga aktivitas jual beli dapat berlangsung dengan lebih baik,” ungkapnya.</div><div>Azhar Hamzah juga mengingatkan para pedagang agar terus menjaga kebersihan dan mematuhi aturan yang telah ditetapkan, termasuk tidak kembali menempati area yang sudah dilarang untuk berjualan.</div><div>Pemerintah Kota Sungai Penuh, lanjutnya, akan terus melakukan pengawasan secara rutin serta melakukan pembenahan secara bertahap demi meningkatkan kualitas fasilitas pasar.</div><div>Dengan langkah ini, diharapkan Pasar Tanjung Bajure dapat menjadi pusat perdagangan yang lebih tertata, nyaman, serta mampu mendukung pertumbuhan ekonomi masyarakat setempat.&nbsp;</div><div>(MC. KOMINFO)&nbsp;</div>','upload/berita/2z7jZ9Vau1Gr8JWlZk3Y1LbolWhdjrksi58ERcuP.jpg','mc','pastikan-pasar-tertib-wawako-azhar-hamzah-tinjau-langsung-pasar-tanjung-bajure','2026-04-06 10:50:19','2026-04-06 10:50:19'),(181,'Wawako Azhar Hamzah Tinjau Progres Gerai Koperasi Desa Merah Putih di Tanah Kampung','<div>&nbsp;</div><div>SUNGAI PENUH – Wakil Wali Kota Sungai Penuh, Azhar Hamzah, turun langsung meninjau progres pembangunan Gerai Koperasi Desa Merah Putih di Desa Koto Baru, Kecamatan Tanah Kampung, Minggu (5/4). Kunjungan ini dilakukan untuk memastikan proses pembangunan berjalan sesuai rencana dan target yang telah ditetapkan.</div><div>Di lokasi, Wawako melihat secara langsung kondisi pembangunan yang saat ini masih dalam tahap pengerjaan. Ia juga berdialog dengan pihak pelaksana guna mengetahui perkembangan serta kendala yang dihadapi di lapangan.</div><div>Azhar Hamzah menegaskan, kehadiran gerai koperasi ini diharapkan mampu menjadi motor penggerak ekonomi masyarakat desa, khususnya di wilayah Kecamatan Tanah Kampung. Menurutnya, koperasi memiliki peran strategis dalam memperkuat ekonomi kerakyatan dan meningkatkan kesejahteraan warga.</div><div>“Pembangunan gerai koperasi ini merupakan langkah strategis dalam mendorong pertumbuhan ekonomi masyarakat, terutama di Desa Koto Baru. Kita berharap prosesnya dapat selesai tepat waktu sehingga segera bisa dimanfaatkan oleh masyarakat,” ujarnya.</div><div>Sementara itu, Pemerintah Kota Sungai Penuh terus memacu percepatan pembangunan gerai koperasi di berbagai wilayah. Upaya ini dilakukan sebagai bagian dari komitmen pemerintah dalam memperkuat ekonomi berbasis kerakyatan serta memperluas akses usaha bagi masyarakat.</div><div>Dengan percepatan tersebut, diharapkan gerai Koperasi Desa Merah Putih dapat segera beroperasi dan memberikan dampak nyata bagi peningkatan perekonomian warga di Kota Sungai Penuh, khususnya di Kecamatan Tanah Kampung. (MC.KOMINFO)&nbsp;</div>','upload/berita/GYB1fEZkwrSQXd8EdEVWmj0Zc2U1SUAuPRMMd5KH.jpg','mc','wawako-azhar-hamzah-tinjau-progres-gerai-koperasi-desa-merah-putih-di-tanah-kampung','2026-04-06 10:52:26','2026-04-06 10:52:26'),(182,'Fraksi DPRD Apresiasi Kinerja Pemkot Sungai Penuh dalam LKPJ 2025','<div>&nbsp;</div><div>SUNGAI PENUH – DPRD Kota Sungai Penuh menggelar rapat paripurna dengan agenda penyampaian pandangan umum fraksi terhadap Laporan Keterangan Pertanggungjawaban (LKPJ) Wali Kota Sungai Penuh Tahun Anggaran 2025, Minggu (6/4/2026).</div><div>Dalam rapat tersebut, masing-masing fraksi DPRD menyampaikan evaluasi, kritik, serta masukan terhadap pelaksanaan program dan kinerja Pemerintah Kota Sungai Penuh sepanjang tahun 2025.</div><div>Rapat paripurna dihadiri langsung oleh Wali Kota Sungai Penuh Alfin, Wakil Wali Kota, Sekretaris Daerah Alfian, pimpinan dan anggota DPRD, serta jajaran kepala perangkat daerah.</div><div>Menanggapi pandangan fraksi, Wali Kota Alfin menyampaikan apresiasi atas masukan yang diberikan. Ia menegaskan bahwa seluruh catatan dari DPRD akan menjadi bahan evaluasi untuk memperbaiki kinerja pemerintah daerah ke depan.</div><div>“Masukan dari fraksi DPRD menjadi perhatian serius bagi pemerintah daerah dalam meningkatkan kualitas pelayanan kepada masyarakat,” ujarnya.</div><div>Pembahasan LKPJ merupakan bagian dari fungsi pengawasan DPRD terhadap jalannya pemerintahan daerah. Proses ini juga menjadi tolok ukur dalam mendorong tata kelola pemerintahan yang transparan, akuntabel, dan responsif terhadap kebutuhan masyarakat.</div><div>MC.KOMINFO&nbsp;</div>','upload/berita/W8HQwINjwxgQAx6nRof1BsSTPDPtQchyqfx0URUM.jpg','mc','fraksi-dprd-apresiasi-kinerja-pemkot-sungai-penuh-dalam-lkpj-2025','2026-04-06 15:42:32','2026-04-06 15:42:32'),(183,'Pemkot Sungai Penuh dan Kejari Perkuat Sinergi Hukum Lewat Penandatanganan MoU','<div>&nbsp;</div><div>SUNGAI PENUH – Pemerintah Kota Sungai Penuh bersama Kejaksaan Negeri (Kejari) Sungai Penuh resmi menandatangani Naskah Kesepakatan Bersama (MoU) dan Perjanjian Kerja Sama di bidang Perdata dan Tata Usaha Negara (Datun), Senin (6/4/2026).</div><div>Penandatanganan dilakukan langsung oleh Wali Kota Sungai Penuh, Alfin, SH, bersama Kepala Kejaksaan Negeri Sungai Penuh, Robi Harianto, SH., MH. Kegiatan ini turut dihadiri Wakil Wali Kota Azhar Hamzah, Sekretaris Daerah Alpian, para kepala perangkat daerah, serta jajaran Kejari Sungai Penuh.</div><div>Kerja sama tersebut bertujuan memperkuat sinergi antara pemerintah daerah dan aparat penegak hukum, khususnya dalam penanganan persoalan di bidang perdata dan tata usaha negara. Selain itu, kolaborasi ini diharapkan mampu mendorong terciptanya tata kelola pemerintahan yang baik, transparan, dan akuntabel.</div><div>Wali Kota Alfin menegaskan bahwa kesepakatan ini merupakan langkah preventif guna memastikan setiap kebijakan pembangunan tetap berjalan sesuai koridor hukum.</div><div>“Sinergi menjadi kekuatan bersama dalam mewujudkan pemerintahan yang bersih, transparan, dan berlandaskan hukum,” ujarnya.</div><div>Ia juga menyampaikan apresiasi kepada Kejaksaan Negeri Sungai Penuh atas komitmennya dalam memberikan pendampingan dan pertimbangan hukum bagi pemerintah daerah.</div><div>Alfin berharap, kerja sama tersebut dapat berjalan optimal dan memberikan manfaat nyata dalam mendukung pelaksanaan pembangunan di Kota Sungai Penuh, sekaligus meminimalisir potensi permasalahan hukum di kemudian hari.&nbsp;</div><div>MC. KOMINFO&nbsp;</div>','upload/berita/bwqlSoQDpW3sgOsQmNJmAv7EOIFRrWfWoJCLYCmM.jpg','mc','pemkot-sungai-penuh-dan-kejari-perkuat-sinergi-hukum-lewat-penandatanganan-mou','2026-04-07 09:30:30','2026-04-07 09:30:30');
/*!40000 ALTER TABLE `berita` ENABLE KEYS */;
UNLOCK TABLES;

