INSERT INTO `profil` VALUES (1,'Dinas Komunikasi Informatika & Statistik','H. JOSRIZAL HELMAN, S.Si, Apt','Jl. Prof. Dr. Sri Sidewi','<div>Dinas Komunikasi Informatika dan Statistik Kota Sungai Penuh didirikan pada tahun 2017. Berdasarkan Peraturan Walikota Sungai Penuh No.44 Tahun 2016.<br>Yang terdiri dari beberapa bidang yaitu Teknologi Informatika, Komunikasi dan Informasi, Statistik dan Persandian.<br>Teknologi Informatika dan Persandian merupakan turunan dari Bidang PDE Setda Kota Sungai Penuh. Komunikasi dan Informasi merupakan turunan dari Dinas Perhubungan Kota Sungai Penuh. dan Statistik merupahan turunan dari Bappeda Kota Sungai Penuh.<br>Sehingga pada tahun 2017 terbentuklah Dinas Komunikasi Informatika dan Statistik Kota Sungai Penuh. Yang dipimpin oleh Bpk. Alpian, SE.,MM, yang kemudian dilanjutkan oleh Bpk. Heri Amperawanto., SE,MM, dan sekarang ini dipimpin oleh Bpk H. Josrizal Helman, S.Si, Apt.</div>','<div>Mewujudkan Kota Sungai Penuh Maju, Adil, Dan Sejahtera. dengan slogan <strong>\"JUARA\"</strong></div>','<div>1. Meningkatkan Perekonomian Yang Inklusif.<br>2. Meningkatkan Kualitas Pendidikan, Keagamaan, Kesehatan, Serta Pengarusutamaan Gender untuk SDM Yang Berdaya Saing.<br>3. Meningkatkan Pembangunan Infrastruktur Kewilayahan Dan Ketahanan Bencana<br>4. Menciptakan Tata Kelola Pemerintahan Yang Bersih Dan Pelayanan Publik Yang Prima Serta Pengembangan Inovasi Untuk Kemandirian Daerah&nbsp;</div>','upload/profil/amPvcg2Lt3z36z5J36UYEybHUolQpCEOTxpG6KAI.jpg','<div>BERDASARKAN PERATURAN PERATURAN WALI KOTA SUNGAI PENUH NOMOR 15 TAHUN 2026&nbsp;</div><div>TENTANG KEDUDUKAN, SUSUNAN ORGANISASI, TUGAS DAN FUNGSI SERTA TATA KERJA DINAS KOMUNIKASI, INFORMATIKA DAN STATISTIK KOTA SUNGAI PENUH&nbsp;</div><div><br>(1) Dinas Komunikasi, Informatika dan Statistik mempunyai tugas membantu Wali Kota melaksanakan urusan pemerintahan dibidang komunikasi, informasi, teknologi informatika, statistik dan persandian yang menjadi kewenangan daerah dan tugas pembantuan yang diberikan kepada daerah.&nbsp;<br>(2) Dalam melaksanakan tugas sebagaimana dimaksud pada ayat (1), Dinas Komunikasi, Informatika dan Statistik menyelenggarakan fungsi:&nbsp;<br><br>a. perumusan kebijakan di bidang pengelolaan opini dan aspirasi publik di lingkup pemerintah daerah, pengelolaan informasi untuk mendukung kebijakan nasional dan pemerintah daerah, penyediaan konten lintas sektoral dan pengelolaan media komunikasi publik, pelayanan informasi publik, layanan hubungan media, penguatan kapasitas sumber daya komunikasi publik dan penyediaan akses informasi, layanan infrastuktur dasar data center, disaster recovery center dan TIK, layanan pengembangan intranet dan penggunaan akses internet, layanan sistem komunikasi intra pemerintah daerah kota, layanan keamanan informasi e Government, layanan manajemen data dan informasi e-Government, layanan pengembangan dan pengelolaan aplikasi generik dan spesifik dan suplemen yang terintegrasi, integrasi layanan publik dan kepemerintahan, penyelenggaraan ekosistem TIK Smart City, penyelenggaraan Government Chief Information Officer (GCIO) pemerintah daerah kota, pengembangan sumber daya TIK pemerintah daerah kota dan masyarakat, layanan nama domain dan sub domain bagi lembaga, pelayanan publik dan kegiatan kota;&nbsp;<br><br>b. pelaksanaan kebijakan di bidang pengelolaan opini dan aspirasi publik di lingkup pemerintah daerah, pengelolaan informasi untuk mendukung kebijakan nasional dan pemerintah daerah, penyediaan konten lintas sektoral dan pengelolaan media komunikasi publik, pelayanan informasi publik, layanan hubungan media, penguatan kapasitas sumber daya komunikasi publik dan penyediaan akses informasi, layanan infrastuktur dasar data center, disaster recovery center dan TIK, layanan pengembangan intranet dan penggunaan akses internet, layanan sistem komunikasi intra pemerintah daerah kota, layanan keamanan informasi e-Government, layanan manajemen data dan informasi e-Government, layanan pengembangan dan pengelolaan aplikasi generik dan spesifik dan suplemen yang terintegrasi, integrasi layanan publik dan kepemerintahan, penyelenggaraan ekosistem TIK Smart City, penyelenggaraan Government Chief Information Officer (GCIO) pemerintah daerah kota, pengembangan sumber daya TIK pemerintah daerah Kota dan masyarakat, layanan nama domain dan sub domain bagi lembaga, pelayanan publik dan kegiatan kota;&nbsp;<br><br>c. pelaksanaan evaluasi dan pelaporan di bidang pengelolaan opini dan aspirasi publik di lingkup pemerintah daerah, pengelolaan informasi untuk mendukung kebijakan nasional dan pemerintah daerah, penyediaan konten lintas sektoral dan pengelolaan media komunikasi publik, pelayanan informasi publik, layanan hubungan media, penguatan kapasitas sumber daya komunikasi publik dan penyediaan akses informasi, layanan infrastuktur dasar data center,disaster recovery center dan TIK, layanan pengembangan intranet danpenggunaan akses internet, layanan sistem komunikasi intrapemerintah daerah kota, layanan keamanan informasi e-Government, layanan manajemen data dan informasi e-Government, layanan pengembangan dan pengelolaan aplikasi generik dan spesifik dan suplemen yang terintegrasi, integrasi layanan publik dan kepemerintahan, penyelenggaraan ekosistem TIK Smart City, penyelenggaraan Government Chief Information Officer (GCIO) pemerintah daerah kota, pengembangan sumber daya TIK pemerintah daerah kota dan masyarakat, layanan nama domain dan sub domain bagi lembaga, pelayanan publik dankegiatan kota;&nbsp;<br>d. pembinaan kelompok jabatan fungsional;&nbsp;<br>e. pelaksanaan administrasi dinas sesuai dengan lingkup tugasnya; dan&nbsp;<br>f. pelaksanaan fungsi lain yang diberikan oleh Wali Kota sesuai dengan tugas dan fungsinya&nbsp;</div>','diskominfo@sungaipenuhkota.go.id',NULL,'https://www.facebook.com/diskominfostatistik.kotasungaipenuh',NULL,NULL,'upload/profil/j4LE2WP8ptL7p3mvWTFBFknjQDXZyo7wVZiY1uwD.jpg','upload/profil/Yd9IeqxfP5XiVhytEp0LtouVb6ioDjdja1ZA662H.png',_binary '','2023-07-08 13:26:24','2026-03-05 14:22:52');
/*!40000 ALTER TABLE `profil` ENABLE KEYS */;
UNLOCK TABLES;

